def _constraint_numeric(value: Any) -> float:
    if isinstance(value, bool):
        return 1.0 if value else 0.0
    if isinstance(value, (int, float)):
        return float(value)
    if isinstance(value, (list, tuple, set, dict)):
        return float(len(value))
    return 0.0


def _constraint_state_snapshot(obj: Any) -> Dict[str, Any]:
    for attr in ("get_stats", "get_status", "status", "to_dict", "get_info"):
        fn = getattr(obj, attr, None)
        if callable(fn):
            try:
                data = fn()
                if isinstance(data, dict):
                    return dict(data)
            except Exception:
                continue
    raw = getattr(obj, "__dict__", None)
    if isinstance(raw, dict):
        snapshot = {}
        for key, value in raw.items():
            if key.startswith("_") and not isinstance(value, (int, float, bool, str, list, tuple, set, dict)):
                continue
            if isinstance(value, (int, float, bool, str)):
                snapshot[key] = value
            elif isinstance(value, (list, tuple, set, dict)):
                snapshot[key] = value
        return snapshot
    return {}


def _genealogy_axis_weights(genealogy: str) -> Dict[str, float]:
    counts = {axis: 0.0 for axis in ("X", "T", "N", "B", "A")}
    for axis in str(genealogy or ""):
        if axis in counts:
            counts[axis] += 1.0
    total = sum(counts.values()) or 1.0
    return {axis: counts[axis] / total for axis in counts}


def _generic_pressure_axes(state: Dict[str, Any]) -> Dict[str, float]:
    axes = {"X": 0.0, "T": 0.0, "N": 0.0, "B": 0.0, "A": 0.0}
    for key, value in dict(state or {}).items():
        lower = str(key).lower()
        numeric = min(1.0, _constraint_numeric(value) / 100.0)
        if numeric <= 0.0:
            continue
        if any(token in lower for token in ("queue", "pending", "delay", "latency", "age", "history", "cycle", "turn")):
            axes["T"] = max(axes["T"], numeric)
        if any(token in lower for token in ("error", "reject", "fail", "quarantine", "gap", "block", "miss", "uncertain")):
            axes["B"] = max(axes["B"], numeric)
        if any(token in lower for token in ("total", "count", "processed", "emitted", "express", "event", "memory", "relation", "node")):
            axes["N"] = max(axes["N"], numeric)
        if any(token in lower for token in ("auto", "action", "explore", "search", "checkpoint", "sync", "save", "write")):
            axes["A"] = max(axes["A"], numeric)
        if any(token in lower for token in ("ready", "exists", "loaded", "active", "present")):
            axes["X"] = max(axes["X"], numeric)
    return axes


def _install_constraint_surface(
    obj: Any,
    *,
    unit_id: str,
    unit_kind: str,
    operational_role: str,
    genealogy: str,
) -> None:
    if obj is None:
        return
    if all(hasattr(obj, name) for name in ("constraint_profile", "runtime_regime", "language_projection", "universal_representation")):
        return

    def _constraint_profile_bound(self):
        state = _constraint_state_snapshot(self)
        return build_constraint_profile(
            unit_id=unit_id,
            unit_kind=unit_kind,
            operational_role=operational_role,
            genealogy=genealogy,
            axis_weights=_genealogy_axis_weights(genealogy),
            pressure_axes=_generic_pressure_axes(state),
        )

    def _runtime_regime_bound(self):
        return self.constraint_profile().runtime_regime()

    def _language_projection_bound(self):
        return self.constraint_profile().language_projection()

    def _universal_representation_bound(self):
        rep = self.constraint_profile().universal_representation()
        rep["unit_state"] = _constraint_state_snapshot(self)
        return rep

    if not hasattr(obj, "constraint_profile"):
        obj.constraint_profile = MethodType(_constraint_profile_bound, obj)
    if not hasattr(obj, "runtime_regime"):
        obj.runtime_regime = MethodType(_runtime_regime_bound, obj)
    if not hasattr(obj, "language_projection"):
        obj.language_projection = MethodType(_language_projection_bound, obj)
    if not hasattr(obj, "universal_representation"):
        obj.universal_representation = MethodType(_universal_representation_bound, obj)


def _install_support_constraint_surfaces(systems: Dict[str, Any]) -> None:
    for key, spec in _SUPPORT_CONSTRAINT_SPECS.items():
        _install_constraint_surface(
            systems.get(key),
            unit_id=key,
            unit_kind=spec["unit_kind"],
            operational_role=spec["operational_role"],
            genealogy=spec["genealogy"],
        )


