def _collect_response_pressure_guides(
    systems: Dict[str, Any],
    window: int = 64,
) -> List[Tuple[str, Dict[str, Any]]]:
    guides: List[Tuple[str, Dict[str, Any]]] = []

    autonomy = systems.get('autonomy')
    tuner = getattr(autonomy, 'response_tuner', None) if autonomy else None
    if tuner is not None:
        try:
            guides.append(('autonomy', tuner.guidance(window)))
        except Exception:
            pass

    chat_tuner = systems.get('_chat_response_pressure_tuner')
    if chat_tuner is not None:
        try:
            guides.append(('chat', chat_tuner.guidance(window)))
        except Exception:
            pass

    corpus_tuner = systems.get('_corpus_response_pressure_tuner')
    if corpus_tuner is not None:
        try:
            guides.append(('corpus', corpus_tuner.guidance(window)))
        except Exception:
            pass

    return guides


def _build_response_pressure_training_plan(
    systems: Dict[str, Any],
    phase: str = 'train',
) -> Dict[str, Any]:
    from aurora_internal.aurora_response_pressure_tuner import (
        RESPONSE_PRESSURE_AXIS_MAP,
        build_training_plan_from_guides,
    )

    guides = _collect_response_pressure_guides(systems)
    plan = build_training_plan_from_guides(guides, phase=phase)
    understanding_contract = systems.get('understanding_contract')
    if understanding_contract is not None and hasattr(understanding_contract, 'training_guidance'):
        try:
            contract_guidance = dict(understanding_contract.training_guidance(systems=systems) or {})
        except Exception:
            contract_guidance = {}
        if contract_guidance:
            pressure_targets = dict(plan.get('pressure_targets', {}) or {})
            constraint_axes = dict(plan.get('constraint_axes', {}) or {})
            rationale = list(plan.get('rationale', []) or [])
            for dim, value in dict(contract_guidance.get('pressure_targets', {}) or {}).items():
                pressure_targets[dim] = max(float(pressure_targets.get(dim, 0.0) or 0.0), float(value or 0.0))
            for axis, value in dict(contract_guidance.get('constraint_axes', {}) or {}).items():
                constraint_axes[axis] = max(float(constraint_axes.get(axis, 0.0) or 0.0), float(value or 0.0))
            rationale.extend(list(contract_guidance.get('rationale', []) or []))
            metrics = dict(contract_guidance.get('metrics', {}) or {})
            if metrics:
                rationale.append(
                    "contract_metrics: "
                    + ", ".join(
                        f"{key}={float(val):.2f}" for key, val in list(metrics.items())[:4]
                        if isinstance(val, (int, float))
                    )
                )
            plan['pressure_targets'] = {
                key: float(round(val, 4))
                for key, val in pressure_targets.items()
                if float(val or 0.0) > 0.0
            }
            plan['constraint_axes'] = {
                key: float(round(val, 4))
                for key, val in constraint_axes.items()
                if float(val or 0.0) > 0.0
            }
            plan['rationale'] = rationale[:12]
    dream_trainer = systems.get('dream_trainer')
    if dream_trainer is not None and hasattr(dream_trainer, 'ledger'):
        try:
            top_fails = list(dream_trainer.ledger.get_top_fails(5) or [])
        except Exception:
            top_fails = []
        if top_fails:
            fail_rank_intensity = [0.9, 0.84, 0.78, 0.72]
            pressure_targets = dict(plan.get('pressure_targets', {}) or {})
            behavior_modes = dict(plan.get('behavior_modes', {}) or {})
            rationale = list(plan.get('rationale', []) or [])
            semantic_bundle = {
                'coherence_maintenance',
                'context_carryover',
                'semantic_precision',
                'multi_turn_stability',
                'implied_intent_inference',
            }
            ranked_fails = []
            for idx, (dim, _score) in enumerate(top_fails[:4]):
                intensity = fail_rank_intensity[min(idx, len(fail_rank_intensity) - 1)]
                pressure_targets[dim] = max(float(pressure_targets.get(dim, 0.0) or 0.0), intensity)
                ranked_fails.append(dim)
            if any(dim in semantic_bundle for dim in ranked_fails):
                pressure_targets['coherence_maintenance'] = max(
                    float(pressure_targets.get('coherence_maintenance', 0.0) or 0.0),
                    0.88,
                )
                pressure_targets['context_carryover'] = max(
                    float(pressure_targets.get('context_carryover', 0.0) or 0.0),
                    0.84,
                )
                pressure_targets['semantic_precision'] = max(
                    float(pressure_targets.get('semantic_precision', 0.0) or 0.0),
                    0.8,
                )
                behavior_modes['test_cross_turn_memory'] = max(
                    float(behavior_modes.get('test_cross_turn_memory', 0.0) or 0.0),
                    0.8,
                )
                behavior_modes['present_conflicting_evidence'] = max(
                    float(behavior_modes.get('present_conflicting_evidence', 0.0) or 0.0),
                    0.58,
                )
            if 'uncertainty_signaling' in ranked_fails:
                behavior_modes['ask_about_confidence'] = max(
                    float(behavior_modes.get('ask_about_confidence', 0.0) or 0.0),
                    0.72,
                )
            if 'semantic_precision' in ranked_fails:
                behavior_modes['use_vague_phrasing'] = min(
                    float(behavior_modes.get('use_vague_phrasing', 0.0) or 0.0),
                    0.2,
                )

            ranked_targets = sorted(
                pressure_targets.items(),
                key=lambda kv: float(kv[1]),
                reverse=True,
            )[:4]
            plan['pressure_targets'] = {
                dim: float(round(val, 4))
                for dim, val in ranked_targets
            }
            axis_scores: Dict[str, float] = {}
            for dim, intensity in ranked_targets:
                axis = RESPONSE_PRESSURE_AXIS_MAP.get(dim, '')
                if axis:
                    axis_scores[axis] = max(axis_scores.get(axis, 0.0), float(intensity))
            plan['constraint_axes'] = {
                axis: float(round(val, 4)) for axis, val in axis_scores.items()
            }
            plan['behavior_modes'] = {
                key: float(round(val, 4))
                for key, val in behavior_modes.items()
                if float(val or 0.0) > 0.0
            }
            study_topics = [dim.replace('_', ' ') for dim, _ in ranked_targets[:4]]
            plan['study_topics'] = study_topics[:4]
            rationale.append(
                "fail_ledger: " + ", ".join(ranked_fails[:4])
            )
            plan['rationale'] = rationale[:10]
    quasiarch = systems.get('quasiarch_observer')
    if quasiarch is not None and hasattr(quasiarch, 'advise_training_plan'):
        try:
            plan = quasiarch.advise_training_plan(plan, phase=phase)
        except Exception:
            pass
    return plan


def _compose_memory_sweep_response(memory_sweep: Dict[str, Any]) -> str:
    lines: List[str] = [
        "Check yourself: here is what my memory systems registered across the stack."
    ]
    current_topic = memory_sweep.get("current_topic") or "none"
    lines.append(f"- Active topic: {current_topic}")
    facts = memory_sweep.get("facts", [])
    if facts:
        fact_desc = "; ".join(
            f"{item['topic']} → {item['description']}" for item in facts[:3]
        )
        lines.append(f"- Stored facts: {fact_desc}")
    concepts = memory_sweep.get("concepts", [])
    if concepts:
        concept_desc = "; ".join(
            f"{item['term']}={item['meaning']}[{', '.join(item['axes'] or []) or 'no axes'}]"
            for item in concepts[:3]
        )
        lines.append(f"- Clarified meanings: {concept_desc}")
    claims = memory_sweep.get("claims", [])
    if claims:
        lines.append(f"- Recent claims: {claims[:3]}")
    conv_summary = memory_sweep.get("conversation_memory", {})
    if conv_summary:
        entries = conv_summary.get("entries_summary", [])
        if entries:
            excerpt = "; ".join(
                f"{entry['topic']} → {entry['aurora']}"
                for entry in entries[:2]
            )
            lines.append(f"- Conversation memory entries: {excerpt}")
        topics = conv_summary.get("topics", [])
        if topics:
            lines.append(f"- Top conversation topics: {', '.join(topics[:4])}")
    locations = memory_sweep.get("locations", [])
    if locations:
        loc_notes = []
        for loc in locations:
            counts = loc.get("counts", {})
            summary = loc.get("summary", "")
            loc_notes.append(
                f"{loc.get('name')}: {counts.get('facts', 0)} facts, "
                f"{counts.get('concepts', 0)} meanings, {counts.get('claims', 0)} claims"
                + (f" ({summary})" if summary else "")
            )
        lines.append(f"- Memory locations: {' | '.join(loc_notes[:2])}")
    return "\n".join(lines)


def _apply_response_pressure_training_plan(
    systems: Dict[str, Any],
    plan: Dict[str, Any],
    episode_budget: int,
) -> int:
    from aurora_internal.aurora_response_pressure_tuner import queue_plan_on_session

    systems['_last_response_pressure_training_plan'] = dict(plan or {})
    if not plan or not plan.get('pressure_targets'):
        return 0

    simulation = systems.get('simulation')
    session = getattr(simulation, 'session', None) if simulation else None
    queued = queue_plan_on_session(session, plan, episode_budget=episode_budget)

    autonomy = systems.get('autonomy')
    if autonomy:
        for topic in list(plan.get('study_topics', []) or [])[:2]:
            try:
                autonomy.add_study_topic(topic)
            except Exception:
                pass

    return queued


def _record_training_epoch_fail_points(
    systems: Dict[str, Any],
    episode_results: List[Any],
    *,
    phase_name: str,
) -> Dict[str, Any]:
    """
    Feed simulation episode traces through the conversation rubric so
    DreamTrainer's fail-point ledger reflects training performance.
    """
    out: Dict[str, Any] = {
        'scored_conversations': 0,
        'recorded_failures': 0,
        'weakest_dimensions': [],
        'relational_probe': {},
    }
    dream_trainer = systems.get('dream_trainer')
    if dream_trainer is None or not episode_results:
        return out

    try:
        from aurora_internal.aurora_conversation_rubric_engine import ConversationRubricEngine
    except Exception:
        return out

    rubric_engine = ConversationRubricEngine()
    rubric_scores = []
    weakest_rollup: Dict[str, float] = {}
    conversation_contexts: Dict[str, Dict[str, Any]] = {}

    for episode in episode_results:
        trace = list(getattr(episode, 'conversation_trace', []) or [])
        if not trace and isinstance(episode, dict):
            trace = list(episode.get('conversation_trace', []) or [])
        if not trace:
            continue

        messages: List[Tuple[str, str]] = []
        for turn in trace:
            if not isinstance(turn, dict):
                continue
            user_text = str(turn.get('user_text', '') or turn.get('topic', '') or '').strip()
            asst_text = str(turn.get('assistant_text', '') or '').strip()
            if user_text:
                messages.append(('user', user_text))
            if asst_text:
                messages.append(('assistant', asst_text))

        if len(messages) < 2:
            continue

        episode_id = str(
            getattr(episode, 'episode_id', '') or
            (episode.get('episode_id', '') if isinstance(episode, dict) else '')
        )
        conversation_id = f"{phase_name}:{episode_id}"
        score = rubric_engine.score_conversation(conversation_id, messages)
        rubric_scores.append(score)
        conversation_contexts[conversation_id] = {
            'conversation_id': conversation_id,
            'source': phase_name,
            'user_turns': [text for role, text in messages if role == 'user'],
            'assistant_turns': [text for role, text in messages if role == 'assistant'],
        }
        for dim, val in score.weakest_dimensions(3):
            weakest_rollup[dim] = min(float(val), float(weakest_rollup.get(dim, 1.0)))

    if not rubric_scores:
        return out

    recorded = []
    if hasattr(dream_trainer, 'record_rubric_failures'):
        try:
            recorded = list(dream_trainer.record_rubric_failures(
                rubric_scores,
                threshold=0.62,
                source=phase_name,
                conversation_contexts=conversation_contexts,
            ) or [])
        except Exception:
            recorded = []

    relational_probe = {}
    if hasattr(dream_trainer, 'record_relational_probe_outcomes'):
        try:
            relational_probe = dict(
                dream_trainer.record_relational_probe_outcomes(
                    systems,
                    episode_results,
                    phase_name=phase_name,
                ) or {}
            )
        except Exception:
            relational_probe = {}

    weakest = sorted(weakest_rollup.items(), key=lambda kv: kv[1])[:4]
    out['scored_conversations'] = len(rubric_scores)
    out['recorded_failures'] = len(recorded)
    out['weakest_dimensions'] = weakest
    out['relational_probe'] = relational_probe
    return out


def show_understanding(systems: Dict[str, Any]):
    """Display Aurora's OETS understanding report."""
    perception = systems['perception']
    if not perception.oets:
        print("  [OETS] Not available.")
        return

    report = perception.oets.get_understanding_report()
    print()
    print(report)
    print()


_CONVERSATIONAL_LEADIN_WORDS = {
    "so", "well", "yeah", "yea", "right", "okay", "ok", "and", "but", "then", "also",
    "uh", "um", "hmm", "like",
}


def _strip_conversational_leadin(text: str) -> str:
    t = str(text or "").strip()
    while t:
        match = re.match(r"^([A-Za-z']+)\b[\s,.-]*(.*)$", t)
        if not match:
            break
        lead = str(match.group(1) or "").strip().lower()
        rest = str(match.group(2) or "").strip()
        if lead not in _CONVERSATIONAL_LEADIN_WORDS or not rest:
            break
        t = rest
    return t


def _looks_like_question(text: str) -> bool:
    t = (text or "").strip()
    if not t:
        return False

    # direct punctuation heuristic
    if t.endswith("?"):
        return True

    core = _strip_conversational_leadin(t)
    if core.endswith("?"):
        return True

    # interrogative prefixes
    prefixes = (
        "what", "what's", "whats", "wats", "why", "how", "when", "where", "who", "which",
        "can", "could", "should", "would", "is", "are", "do", "does",
        "did", "will", "may", "tell me", "give me", "list", "explain", "define", "look up",
        "search", "find"
    )
    for candidate in (t, core):
        candidate_low = candidate.lower()
        if any(candidate_low.startswith(p + " ") or candidate_low == p for p in prefixes):
            return True
    return False


def _normalize_surface_anchor_label(anchor: str, working_memory: Any = None) -> str:
    raw = str(anchor or "").strip().lower()
    if not raw:
        return ""
    # Bind contraction fragments into their grammatical phrase before anchor
    # selection. A shard like "doesn" is not deleted from the utterance; it is
    # prevented from masquerading as a standalone concept.
    raw = re.sub(r"\bdoesn(?:['’]|\s+)?t\b", "does not", raw)
    raw = re.sub(r"\bdon(?:['’]|\s+)?t\b", "do not", raw)
    raw = re.sub(r"\bdidn(?:['’]|\s+)?t\b", "did not", raw)
    raw = re.sub(r"\bisn(?:['’]|\s+)?t\b", "is not", raw)
    raw = re.sub(r"\baren(?:['’]|\s+)?t\b", "are not", raw)
    raw = re.sub(r"\bwasn(?:['’]|\s+)?t\b", "was not", raw)
    raw = re.sub(r"\bweren(?:['’]|\s+)?t\b", "were not", raw)
    raw = re.sub(r"\bwon(?:['’]|\s+)?t\b", "will not", raw)
    raw = re.sub(r"\bwouldn(?:['’]|\s+)?t\b", "would not", raw)
    raw = re.sub(r"\bshouldn(?:['’]|\s+)?t\b", "should not", raw)
    raw = re.sub(r"\bcouldn(?:['’]|\s+)?t\b", "could not", raw)
    raw = re.sub(r"\bhaven(?:['’]|\s+)?t\b", "have not", raw)
    raw = re.sub(r"\bhasn(?:['’]|\s+)?t\b", "has not", raw)
    raw = re.sub(r"\bhadn(?:['’]|\s+)?t\b", "had not", raw)
    contraction_shards = {
        "don", "doesn", "didn", "isn", "aren", "wasn", "weren",
        "cant", "won", "wouldn", "shouldn", "couldn",
        "haven", "hasn", "hadn", "ain",
    }
    if working_memory is not None and hasattr(working_memory, "_normalize_mention"):
        try:
            normalized = str(working_memory._normalize_mention(raw) or "").strip().lower()
            if normalized in contraction_shards:
                return ""
            return normalized
        except Exception:
            pass
    normalized = " ".join(re.findall(r"[a-z0-9_\-]+", raw)).strip()
    if normalized in contraction_shards:
        return ""
    return normalized


def _bind_orphan_surface_predicate(text: str) -> str:
    """Attach predicate-only native fragments to their implied speaker/tense."""
    clean = re.sub(r"\s+", " ", str(text or "")).strip()
    if not clean:
        return ""
    low = clean.lower()
    if re.match(r"^(feeling|noticing|tracking|holding|carrying|hearing|seeing|watching)\b", low):
        clean = f"I am {clean}"
    elif re.match(r"^(trying|working|processing|listening|orienting)\b", low):
        clean = f"I am {clean}"
    if clean and not clean.endswith((".", "?", "!")):
        clean += "."
    return clean


