def _surface_text_is_articulated(text: str) -> bool:
    """True only when native output has become speakable surface language."""
    clean = re.sub(r"\s+", " ", str(text or "")).strip()
    if not clean:
        return False
    if ";" in clean:
        return False
    # Block JSON / code content — researcher results leaking as speech
    if "```" in clean or "proposed_action" in clean or '"file":' in clean:
        return False
    if re.search(r'\[\s*\{.*"file"', clean, re.DOTALL):
        return False
    clean_low = clean.lower()
    if any(p in clean_low for p in _INTERNAL_INSTRUCTION_PHRASES):
        return False
    if re.search(r"\b(?:don|doesn|didn|isn|aren|wasn|weren|won|wouldn|shouldn|couldn|haven|hasn|hadn|ain)\b", clean_low):
        return False
    if re.search(r"\d", clean) and re.search(r"\b(?:is|equals?)\b", clean_low):
        return True
    tokens = re.findall(r"[a-z']+", clean_low)
    if not tokens:
        return False
    if len(tokens) == 1 and tokens[0] not in {"yes", "no", "okay", "right"}:
        return False
    return True


def _constraint_emission_is_substantive(text: str, result: Any = None, input_frame: Any = None) -> bool:
    """True when constraint emission produced an answer, not a backchannel."""
    clean = re.sub(r"\s+", " ", str(text or "")).strip()
    if not _surface_text_is_articulated(clean):
        return False

    low = clean.lower().strip()
    backchannels = {
        "mm.", "mm", "mhm.", "mhm", "yeah.", "yeah", "mm, yeah.", "mm, yeah",
        "yeah, that tracks.", "yeah, that tracks", "right.", "right", "okay.", "okay"
    }
    if low in backchannels:
        return False
    if re.search(r"\b(?:the|a|an|any|that)\.$", low):
        return False

    act_name = ""
    try:
        act = getattr(result, "speech_act", None)
        act_name = str(getattr(act, "name", act) or "").upper()
    except Exception:
        act_name = ""

    is_question = bool(getattr(input_frame, "is_question", False))
    if act_name in {"ACKNOWLEDGMENT", "BACKCHANNEL"}:
        return False
    if is_question and act_name in {"AGREEMENT"}:
        return False

    tokens = re.findall(r"[a-z']+", low)
    if is_question and len(tokens) < 4 and act_name != "ASSERTION":
        return False
    return True


def _open_trailing_user_phrase(user_text: str) -> str:
    words = re.findall(r"[A-Za-z']+", str(user_text or "").strip())
    if not words:
        return ""
    low = [w.lower() for w in words]
    for width in (4, 3, 2):
        tail = low[-width:]
        if tail and tail[0] in {"how", "what", "why", "where", "when", "who"}:
            return " ".join(words[-width:])
    return ""


def _repair_unarticulated_surface_response(
    user_text: str,
    response_text: str,
    *,
    systems: Optional[Dict[str, Any]] = None,
    state: Any = None,
) -> str:
    """
    Bind stranded response tokens into a grammatical surface. This is not word
    deletion: user-language shards are rebound to nearby source words, while
    internal constraint tokens are expressed as the relation they encode.
    """
    raw = str(response_text or "").strip()
    if not raw:
        return raw
    raw_low = raw.lower()
    if any(p in raw_low for p in _INTERNAL_INSTRUCTION_PHRASES):
        return ""
    normalized = _bind_orphan_surface_predicate(raw)
    if _surface_text_is_articulated(normalized):
        return normalized
    if _surface_fragment_is_invalid(normalized, user_text=user_text):
        return ""

    user_low = str(user_text or "").lower()
    parts = [
        _bind_orphan_surface_predicate(p.strip())
        for p in re.split(r"[;,\n]+", raw)
        if p.strip()
    ]
    parts_low = [p.lower().strip(".!?") for p in parts]
    raw_tokens = re.findall(r"[a-z']+", raw.lower())
    has_context_need = (
        {"context", "continuity", "needed"}.issubset(set(parts_low))
        or {"context", "continuity", "needed"}.issubset(set(raw_tokens))
        or "context continuity needed" in " ".join(parts_low)
    )
    has_unbound_contraction = any(
        re.fullmatch(r"(?:don|doesn|didn|isn|aren|wasn|weren|won|wouldn|shouldn|couldn|haven|hasn|hadn|ain)", p)
        for p in parts_low
    ) or any(
        re.fullmatch(r"(?:don|doesn|didn|isn|aren|wasn|weren|won|wouldn|shouldn|couldn|haven|hasn|hadn|ain)", p)
        for p in raw_tokens
    )
    open_phrase = _open_trailing_user_phrase(user_text)

    if has_context_need and not str(user_text or "").strip():
        return normalized

    if ("doesn't answer" in user_low or "does not answer" in user_low or has_unbound_contraction) and has_context_need:
        # Generative context failure response
        from aurora_internal.aurora_language_state import IntentObject
        _f_intent = IntentObject(intent_type="inquiry", emotion_tone="reflective")
        _f_fragments = f"action; clarification; context; needed; {open_phrase or 'this'}"
        try:
            return systems['perception'].evo.sic._synthesize_fragments(_f_fragments, _f_intent)
        except Exception:
            return normalized

    if has_context_need:
        # Generative context failure response
        from aurora_internal.aurora_language_state import IntentObject
        _f_intent = IntentObject(intent_type="inquiry", emotion_tone="reflective")
        _f_fragments = f"action; context; missing; {open_phrase or 'understanding'}"
        try:
            return systems['perception'].evo.sic._synthesize_fragments(_f_fragments, _f_intent)
        except Exception:
            return normalized

    if parts:
        rebound = ". ".join(parts)
        rebound = _bind_orphan_surface_predicate(rebound)
        if _surface_text_is_articulated(rebound):
            return rebound
        if _surface_fragment_is_invalid(rebound, user_text=user_text):
            return ""

    return "" if _surface_fragment_is_invalid(normalized, user_text=user_text) else normalized


def _is_surface_meta_anchor_label(anchor: str, working_memory: Any = None) -> bool:
    normalized = _normalize_surface_anchor_label(anchor, working_memory=working_memory)
    if not normalized:
        return False
    if working_memory is not None and hasattr(working_memory, "_is_broad_surface_meta_anchor"):
        try:
            return bool(working_memory._is_broad_surface_meta_anchor(normalized))
        except Exception:
            pass
    words = [word for word in re.findall(r"[a-z]{3,}", normalized) if word]
    return len(words) == 1 and words[0] in set(getattr(WorkingMemory, "_SURFACE_META_ANCHORS", set()))


def _is_explicit_meaning_or_continuity_request(
    user_text: str,
    *,
    understood: Optional[Dict[str, Any]] = None,
    working_memory: Any = None,
) -> bool:
    if working_memory is not None and hasattr(working_memory, "_is_explicit_meaning_or_continuity_request"):
        try:
            return bool(working_memory._is_explicit_meaning_or_continuity_request(user_text, understood))
        except Exception:
            pass
    text_low = str(user_text or "").lower()
    understood = dict(understood or {})
    if str(understood.get("query_type", "") or "") == "definition":
        return True
    markers = tuple(getattr(WorkingMemory, "_EXPLICIT_MEANING_CONTINUITY_MARKERS", ()))
    return any(marker in text_low for marker in markers)


def _should_prefer_live_perspective(
    user_text: str,
    *,
    understood: Optional[Dict[str, Any]] = None,
    systems: Optional[Dict[str, Any]] = None,
    anchor: str = "",
) -> bool:
    understood = dict(understood or {})
    working_memory = (systems or {}).get("working_memory") if isinstance(systems, dict) else None
    if _is_explicit_meaning_or_continuity_request(
        user_text,
        understood=understood,
        working_memory=working_memory,
    ):
        return False

    text_low = str(user_text or "").lower()
    query_type = str(understood.get("query_type", "") or "").strip().lower()
    opinion_like = bool(
        understood.get("is_opinion") or
        understood.get("is_experiential") or
        query_type in {"opinion", "experience"} or
        any(
            phrase in text_low for phrase in (
                "what do you think", "how do you think", "what do you feel", "how do you feel",
                "your opinion", "your view", "your perspective", "your take",
                "to you", "for you", "in your view", "in your opinion",
                "from your perspective", "what does that mean to you",
                "what does this mean to you", "how do you see",
            )
        )
    )
    internal_state_request = _is_aurora_self_question(user_text) or _looks_like_inner_state_query(
        user_text, understood
    )
    if not (opinion_like or internal_state_request):
        return False

    normalized_anchor = _normalize_surface_anchor_label(anchor, working_memory=working_memory)
    if not normalized_anchor:
        normalized_anchor = _normalize_surface_anchor_label(
            str(understood.get("topic", "") or ""),
            working_memory=working_memory,
        )
    if _is_surface_meta_anchor_label(normalized_anchor, working_memory=working_memory):
        return True
    return query_type not in {"definition", "factual_entity", "factual_general", "weather_location"}


def _surface_recent_context_horizon(
    user_text: str,
    *,
    understood: Optional[Dict[str, Any]] = None,
    working_memory: Any = None,
) -> Tuple[int, str]:
    text = str(user_text or "").strip()
    if not text:
        return (0, "none")

    understood = dict(understood or {})
    text_low = text.lower()
    query_type = str(understood.get("query_type", "") or "").strip().lower()
    vague_referents = set(getattr(working_memory, "_VAGUE_REFERENTS", {"it", "this", "that", "these", "those", "they", "them"}))
    callback_markers = tuple(getattr(working_memory, "_REFERENT_CALLBACK_MARKERS", ()))
    readdress_markers = tuple(getattr(working_memory, "_SESSION_READDRESS_MARKERS", ()))

    if any(marker in text_low for marker in readdress_markers):
        return (3, "readdress")

    callback_like = bool(
        understood.get("is_callback") or
        understood.get("is_clarification") or
        any(marker in text_low for marker in callback_markers)
    )
    if callback_like:
        return (2, "callback")

    topic = str(understood.get("topic", "") or "").strip().lower()
    topic_words = {
        str(word or "").strip().lower()
        for word in list(understood.get("topic_words", []) or [])
        if str(word or "").strip()
    }
    referent_overlap = bool(topic and topic in vague_referents) or bool(topic_words & vague_referents)
    question_like = _looks_like_question(text)
    if question_like and referent_overlap:
        return (2, "callback")

    content_words = [word for word in re.findall(r"[a-z']+", text_low) if len(word) >= 3]
    if (
        not question_like and
        len(content_words) <= 7 and
        any(text_low.startswith(prefix) for prefix in ("and ", "but ", "so ", "then ", "also ", "right ", "yeah ", "yea ", "well "))
    ):
        return (1, "continuation")

    # Explicit recall/memory patterns always get recent context, regardless of query_type.
    _HORIZON_RECALL_TRIGGERS = (
        "what did i just tell you", "what did i tell you",
        "what did i just say", "what did i say",
        "i just told you", "i already told you",
        "you should know my", "don't you remember",
        "do you remember what i", "what's my name",
        "what is my name", "what was my name",
    )
    if any(trigger in text_low for trigger in _HORIZON_RECALL_TRIGGERS):
        return (3, "recall")

    if query_type in {"statement", "general", "experience", "opinion", "factual_entity", "factual_general", "definition"}:
        return (0, "present")

    return (0, "present")


def _inject_surface_recent_context(
    systems: Dict[str, Any],
    state: Any,
    user_text: str,
) -> None:
    if not isinstance(getattr(state, "pipeline_state", None), dict):
        return

    understood = dict(getattr(state, "parsed", {}) or {})
    working_memory = systems.get("working_memory")
    horizon, mode = _surface_recent_context_horizon(
        user_text,
        understood=understood,
        working_memory=working_memory,
    )
    state.pipeline_state["recent_context_mode"] = str(mode or "present")

    if horizon <= 0:
        state.pipeline_state["recent_context"] = ""
        state.pipeline_state["recent_context_turns"] = 0
        return

    buffer = list(systems.get("_session_turn_buffer") or [])
    if not buffer:
        state.pipeline_state["recent_context"] = ""
        state.pipeline_state["recent_context_turns"] = 0
        return

    lines: List[str] = []
    turns_used = 0
    for turn in buffer[-horizon:]:
        entry = dict(turn or {})
        user_line = str(entry.get("user", "") or "").strip()
        aurora_line = str(entry.get("aurora", "") or "").strip()
        if not user_line and not aurora_line:
            continue
        turns_used += 1
        if user_line:
            lines.append(f"User: {user_line[:180]}")
        if aurora_line:
            lines.append(f"Aurora: {aurora_line[:180]}")

    state.pipeline_state["recent_context"] = "\n".join(lines[:6]).strip()
    state.pipeline_state["recent_context_turns"] = int(turns_used)


