_MANIFOLD_ROOT = os.path.join(os.path.dirname(os.path.abspath(__file__)), "aurora_manifold_directory")
_MANIFOLD_INVENTORY: Dict[str, Dict[str, Dict[str, Dict[str, str]]]] = {}
_MANIFOLD_FAMILIES: List[str] = []
_MANIFOLD_DIMENSIONS: Tuple[str, ...] = ("POLARITY", "MAGNITUDE", "OPERATOR", "COST", "DIFFERENCE")

_AXIS_DOMAIN_NAMES: Dict[str, str] = {
    "X": "Existence",
    "T": "Temporal",
    "N": "Energetic",
    "B": "Boundary",
    "A": "Agency",
}

_DIAGONAL_FAMILY_BY_AXIS: Dict[str, str] = {
    "X": "Existential",
    "T": "Temporal",
    "N": "Energetic",
    "B": "Boundary",
    "A": "Agentive",
}

_ROLE_DIMENSION_MAP: Dict[str, str] = {
    "inquiry": "OPERATOR",
    "entity": "OPERATOR",
    "topic_word": "OPERATOR",
    "clarification": "OPERATOR",
    "hypothesis": "DIFFERENCE",
    "contrast": "DIFFERENCE",
    "concession": "DIFFERENCE",
    "callback": "DIFFERENCE",
    "opposition": "DIFFERENCE",
    "certainty": "POLARITY",
    "acknowledgment": "POLARITY",
    "opinion": "POLARITY",
    "experience": "MAGNITUDE",
    "emphasis": "MAGNITUDE",
    "addition": "MAGNITUDE",
    "minimization": "COST",
    "recency": "COST",
    "consequence": "COST",
    "similarity": "MAGNITUDE",
    "request": "MAGNITUDE",
    "accepting": "POLARITY",
    "uncertainty": "COST",
}

def _load_manifold_inventory() -> None:
    families: Set[str] = set()
    if not os.path.isdir(_MANIFOLD_ROOT):
        return
    for axis_letter in ("X", "T", "N", "B", "A"):
        dir_path = os.path.join(_MANIFOLD_ROOT, axis_letter)
        if not os.path.isdir(dir_path):
            continue
        for fname in os.listdir(dir_path):
            if not fname.endswith(".json"):
                continue
            try:
                with open(os.path.join(dir_path, fname), "r", encoding="utf-8") as fh:
                    data = json.load(fh)
            except Exception:
                continue
            target = str(data.get("nc_target", "") or "").strip()
            if not target:
                continue
            family = str(data.get("nc_name", "").split("_", 1)[0] or "")
            dimension = str(data.get("nc_dim", "") or "")
            summary = str(data.get("nc_semantic_summary", "") or "")
            name = str(data.get("nc_name", "") or "")
            families.add(family)
            _MANIFOLD_INVENTORY.setdefault(target, {}).setdefault(family, {})[dimension] = {
                "nc_name": name,
                "summary": summary,
            }
    _MANIFOLD_FAMILIES[:] = sorted(families)

_load_manifold_inventory()

@dataclass
class LawBinding:
    domain_letter: str
    domain_name: str
    family: str
    dimension: str
    score: float
    nc_name: str
    summary: str

    def to_dict(self) -> Dict[str, Any]:
        return {
            "domain_letter": self.domain_letter,
            "domain_name": self.domain_name,
            "family": self.family,
            "dimension": self.dimension,
            "score": round(self.score, 4),
            "nc_name": self.nc_name,
            "summary": self.summary,
        }

@dataclass
class NativeMeaningObject:
    meaning_id: str
    created_at: float
    semantic_roots: List[str]
    domain_scores: Dict[str, float]
    diagonal_anchor: str
    law_bindings: List[LawBinding]
    source_origin: str
    modality_origin: str = ""
    source_semantic_stage: str = ""
    sensory_lineage_tags: List[str] = field(default_factory=list)
    context_refs: List[str] = field(default_factory=list)
    memory_refs: List[str] = field(default_factory=list)
    axis_activation: Dict[str, float] = field(default_factory=dict)
    parsed_intent: Dict[str, Any] = field(default_factory=dict)
    ambiguity_map: Dict[str, Any] = field(default_factory=dict)
    # Per-layer profiles — explicit per-constraint expression surfaces
    existence_profile: Dict[str, Any] = field(default_factory=dict)   # X
    time_profile: Dict[str, Any] = field(default_factory=dict)        # T
    energy_profile: Dict[str, Any] = field(default_factory=dict)      # N
    boundary_profile: Dict[str, Any] = field(default_factory=dict)    # B
    agency_profile: Dict[str, Any] = field(default_factory=dict)      # A

    def to_dict(self) -> Dict[str, Any]:
        return {
            "meaning_id": self.meaning_id,
            "created_at": self.created_at,
            "semantic_roots": list(self.semantic_roots or []),
            "domain_scores": {k: round(v, 4) for k, v in self.domain_scores.items()},
            "diagonal_anchor": self.diagonal_anchor,
            "law_bindings": [binding.to_dict() for binding in self.law_bindings],
            "source_origin": self.source_origin,
            "modality_origin": self.modality_origin,
            "source_semantic_stage": self.source_semantic_stage,
            "sensory_lineage_tags": list(self.sensory_lineage_tags or []),
            "context_refs": list(self.context_refs or []),
            "memory_refs": list(self.memory_refs or []),
            "axis_activation": {k: round(v, 4) for k, v in self.axis_activation.items()},
            "parsed_intent": dict(self.parsed_intent or {}),
            "ambiguity_map": dict(self.ambiguity_map or {}),
            "existence_profile": dict(self.existence_profile or {}),
            "time_profile": dict(self.time_profile or {}),
            "energy_profile": dict(self.energy_profile or {}),
            "boundary_profile": dict(self.boundary_profile or {}),
            "agency_profile": dict(self.agency_profile or {}),
        }

_AXIS_PROFILE_STANCE: Dict[str, Dict[str, str]] = {
    "X": {"agency_resolution": "observing",  "boundary_resolution": "open",     "energy_resolution": "low",      "time_rendering_mode": "present",      "tone_signature": "grounding"},
    "T": {"agency_resolution": "tentative",  "boundary_resolution": "open",     "energy_resolution": "moderate", "time_rendering_mode": "sequential",   "tone_signature": "sequential"},
    "N": {"agency_resolution": "measured",   "boundary_resolution": "open",     "energy_resolution": "assertive","time_rendering_mode": "present",      "tone_signature": "measured"},
    "B": {"agency_resolution": "clarifying", "boundary_resolution": "framing",  "energy_resolution": "moderate", "time_rendering_mode": "present",      "tone_signature": "defining"},
    "A": {"agency_resolution": "committed",  "boundary_resolution": "owned",    "energy_resolution": "direct",   "time_rendering_mode": "present",      "tone_signature": "direct"},
}

def _build_layer_profile(axis_letter: str, activation: float, bindings: List["LawBinding"]) -> Dict[str, Any]:
    """Build a per-constraint expression profile from matching law bindings."""
    layer_bindings = [b for b in bindings if b.domain_letter == axis_letter]
    if not layer_bindings:
        return {}
    top = max(layer_bindings, key=lambda b: b.score)
    stance = _AXIS_PROFILE_STANCE.get(axis_letter, {})
    return {
        "activation": round(activation, 4),
        "dominant_family": top.family,
        "dominant_dimension": top.dimension,
        "top_nc": top.nc_name,
        "summary": top.summary[:120] if top.summary else "",
        **stance,
    }

def _dimension_scores(parsed: Dict[str, Any]) -> Dict[str, float]:
    scores: Dict[str, float] = {dim: 0.0 for dim in _MANIFOLD_DIMENSIONS}
    for role, _span in parsed.get("pragmatic_signals", []):
        dim = _ROLE_DIMENSION_MAP.get(str(role), "OPERATOR")
        scores[dim] += 1.0
    total = sum(scores.values()) or 1.0
    return {dim: (score / total) for dim, score in scores.items()}

def _merge_native_meaning_bundle(bundle: Any) -> Dict[str, Any]:
    items: List[Dict[str, Any]] = []
    if isinstance(bundle, dict):
        primary = bundle.get("primary")
        if isinstance(primary, dict):
            items.append(dict(primary))
        for key in ("sensory", "internal", "memory", "bundle"):
            value = bundle.get(key)
            if isinstance(value, dict):
                items.append(dict(value))
            elif isinstance(value, list):
                items.extend(dict(item) for item in value if isinstance(item, dict))
    elif isinstance(bundle, list):
        items.extend(dict(item) for item in bundle if isinstance(item, dict))
    elif isinstance(bundle, tuple):
        items.extend(dict(item) for item in bundle if isinstance(item, dict))
    else:
        return {}

    if not items:
        return {}

    merged = dict(items[0])
    merged["semantic_roots"] = []
    merged["context_refs"] = []
    merged["memory_refs"] = []
    merged["sensory_lineage_tags"] = []
    merged["law_bindings"] = []
    merged["domain_scores"] = {}
    merged["axis_activation"] = {}
    seen_laws: Set[Tuple[str, str, str, str]] = set()
    for item in items:
        for key in ("semantic_roots", "context_refs", "memory_refs", "sensory_lineage_tags"):
            merged.setdefault(key, [])
            merged[key].extend(str(v) for v in list(item.get(key, []) or []) if str(v).strip())
        for key in ("domain_scores", "axis_activation"):
            merged.setdefault(key, {})
            for axis, value in dict(item.get(key, {}) or {}).items():
                merged[key][str(axis)] = max(float(merged[key].get(str(axis), 0.0) or 0.0), float(value or 0.0))
        for binding in list(item.get("law_bindings", []) or []):
            if isinstance(binding, dict):
                law_key = (
                    str(binding.get("domain_letter", "") or ""),
                    str(binding.get("family", "") or ""),
                    str(binding.get("dimension", "") or ""),
                    str(binding.get("nc_name", "") or ""),
                )
                if law_key not in seen_laws:
                    seen_laws.add(law_key)
                    merged["law_bindings"].append(dict(binding))
        for key in ("diagonal_anchor", "source_origin", "modality_origin", "source_semantic_stage"):
            value = str(item.get(key, "") or "")
            if value and not merged.get(key):
                merged[key] = value
        for key, value in item.items():
            if key not in merged and value not in (None, "", [], {}):
                merged[key] = value

    for key in ("semantic_roots", "context_refs", "memory_refs", "sensory_lineage_tags"):
        merged[key] = list(dict.fromkeys(str(v) for v in merged.get(key, []) if str(v).strip()))
    merged["law_bindings"].sort(key=lambda item: float(item.get("score", 0.0) or 0.0), reverse=True)
    return merged

def _build_law_bindings(axis_activation: Dict[str, float], dimension_scores: Dict[str, float]) -> List[LawBinding]:
    bindings: List[LawBinding] = []
    for domain_letter in ("X", "T", "N", "B", "A"):
        domain_score = axis_activation.get(domain_letter, 0.0)
        if domain_score <= 0.0:
            continue
        families = _MANIFOLD_FAMILIES or list(_DIAGONAL_FAMILY_BY_AXIS.values())
        for family in families:
            domain_inventory = _MANIFOLD_INVENTORY.get(domain_letter, {})
            family_entries = domain_inventory.get(family, {})
            for dimension in _MANIFOLD_DIMENSIONS:
                entry = family_entries.get(dimension)
                if not entry:
                    continue
                score = domain_score * (dimension_scores.get(dimension, 0.05) + 0.1)
                if score <= 0:
                    continue
                binding = LawBinding(
                    domain_letter=domain_letter,
                    domain_name=_AXIS_DOMAIN_NAMES.get(domain_letter, ""),
                    family=family,
                    dimension=dimension,
                    score=score,
                    nc_name=entry["nc_name"],
                    summary=entry["summary"],
                )
                bindings.append(binding)
    bindings.sort(key=lambda item: item.score, reverse=True)
    return bindings[:25]

def _diagonal_anchor_for_axis(axis_letter: str) -> str:
    family = _DIAGONAL_FAMILY_BY_AXIS.get(axis_letter, "")
    target = _AXIS_DOMAIN_NAMES.get(axis_letter, "")
    if not family or not target:
        return ""
    return f"{family}_Operator_of_{target}"

def _build_native_meaning(
    text: str,
    parsed: Dict[str, Any],
    axis_activation: Dict[str, float],
    *,
    source_origin: str = "external_language",
    modality_origin: str = "language",
    source_semantic_stage: str = "processed_language",
    semantic_roots: Optional[List[str]] = None,
    sensory_lineage_tags: Optional[List[str]] = None,
    context_refs: Optional[List[str]] = None,
    memory_refs: Optional[List[str]] = None,
) -> NativeMeaningObject:
    dimension_scores = _dimension_scores(parsed)
    law_bindings = _build_law_bindings(axis_activation, dimension_scores)
    dominant_axis = max(axis_activation, key=axis_activation.get)
    diagonal = _diagonal_anchor_for_axis(dominant_axis)
    roots = list(semantic_roots or [])
    if not roots:
        roots = [
            str(item).strip()
            for item in list(parsed.get("topic_words", []) or [])[:8]
            if str(item).strip()
        ]
    ambiguity = {
        "low_axes": [ax for ax, v in axis_activation.items() if v < 0.15],
        "weak_dimensions": [dim for dim, v in dimension_scores.items() if v < 0.12],
    }
    return NativeMeaningObject(
        meaning_id=hashlib.md5(f"{text}{time.time()}".encode()).hexdigest(),
        created_at=time.time(),
        semantic_roots=roots,
        domain_scores=dict(axis_activation),
        diagonal_anchor=diagonal,
        law_bindings=law_bindings,
        source_origin=source_origin,
        modality_origin=modality_origin,
        source_semantic_stage=source_semantic_stage,
        sensory_lineage_tags=list(sensory_lineage_tags or []),
        context_refs=list(context_refs or []),
        memory_refs=list(memory_refs or []),
        axis_activation=dict(axis_activation),
        parsed_intent=dict(parsed),
        ambiguity_map=ambiguity,
        existence_profile=_build_layer_profile("X", axis_activation.get("X", 0.0), law_bindings),
        time_profile=_build_layer_profile("T", axis_activation.get("T", 0.0), law_bindings),
        energy_profile=_build_layer_profile("N", axis_activation.get("N", 0.0), law_bindings),
        boundary_profile=_build_layer_profile("B", axis_activation.get("B", 0.0), law_bindings),
        agency_profile=_build_layer_profile("A", axis_activation.get("A", 0.0), law_bindings),
    )

def _build_sensory_native_meaning(
    pipeline_state: Optional[Dict[str, Any]],
    axis_activation: Dict[str, float],
) -> Optional[NativeMeaningObject]:
    state = dict(pipeline_state or {})
    scene = dict(state.get("sensory_scene") or {})
    crystal = dict(state.get("sensory_crystal") or {})
    scene_desc = str(state.get("sensory_scene_desc") or "").strip()
    if not scene and not crystal and not scene_desc:
        return None

    visual_facets = dict(crystal.get("visual_facets", {}) or {})
    audio_facets = dict(crystal.get("audio_facets", {}) or {})
    roots: List[str] = []
    roots.extend(str(scene.get("scene_type", "") or "").split())
    roots.extend(list(scene.get("concepts", []) or []))
    roots.extend(list(visual_facets.keys())[:4])
    roots.extend(list(audio_facets.keys())[:4])
    roots.extend(re.findall(r"[a-z]{4,}", scene_desc.lower())[:8])
    roots = [root for root in (str(item).strip() for item in roots) if root]

    modality_parts: List[str] = []
    if visual_facets:
        modality_parts.append("visual")
    if audio_facets:
        modality_parts.append("auditory")
    if not modality_parts and scene_desc:
        modality_parts.append("multimodal")
    modality_origin = "_".join(modality_parts) if modality_parts else "sensory"

    parsed = {
        "topic_words": roots[:8],
        "claims": [scene_desc] if scene_desc else [],
        "pragmatic_signals": [],
    }
    lineage_tags = [
        f"scene:{scene.get('scene_type', '')}",
        f"visual:{','.join(list(visual_facets.keys())[:4])}" if visual_facets else "",
        f"audio:{','.join(list(audio_facets.keys())[:4])}" if audio_facets else "",
    ]
    lineage_tags = [tag for tag in lineage_tags if tag]
    context_refs = ["sensory_scene", "sensory_crystal", "surface_snapshot"]
    if scene_desc:
        context_refs.append(scene_desc[:120])
    return _build_native_meaning(
        scene_desc or "sensory context",
        parsed,
        axis_activation,
        source_origin="sensory_multimodal",
        modality_origin=modality_origin,
        source_semantic_stage="processed_sensory",
        semantic_roots=roots[:12],
        sensory_lineage_tags=lineage_tags,
        context_refs=context_refs,
        memory_refs=[],
    )


# ============================================================================
# CONSTRAINT FIELD BALANCER
# Tracks sustained axis dominance and generates rebalancing pressure.
#
# The 5 constraints behave as a coupled dynamic field, not 5 independent meters.
# When one axis is dominant for too long, the sustained imbalance IS the cost
# signal — it makes adjacent constraint pathways cheaper, encouraging drift
# toward unexplored regions of the state space.
#
# Timescale is axis-aware, derived from AXIS_TICK_PARTICIPATION:
#   X (surface): rebalances in ~4 exchanges   (decay=0.25)
#   T:           rebalances in ~12 exchanges  (decay=0.08)
#   N:           rebalances in ~40 exchanges  (decay=0.025)
#   B:           rebalances in ~125 exchanges (decay=0.008)
#   A (core):    rebalances in ~330 exchanges (decay=0.003)
#
# This prevents chaotic fast oscillation (no hard rule triggers) while still
# ensuring no single axis monopolizes the field for long stretches.
# ============================================================================

class ConstraintFieldBalancer:
    """
    Dynamic field balancer across the 5 constraint axes.

    Maintains a per-axis EMA of recent activation.  When the EMA shows
    sustained dominance on one axis, the field_gradient() method returns
    positive values for the starved axes — signaling that those constraint
    pathways are cheaper and should be explored.

    This feeds back into three layers:
      1. AxisProjector — starved axes get a boost in the orientation blend
      2. Genealogy — small relief events for starved axes lower their promotion cost
      3. LSV (via grammar engine) — nudges sentence structure toward balance
    """

    # Decay rates derived from AXIS_TICK_PARTICIPATION ratios.
    # Faster surface axes (X) track imbalance quickly; deep core (A) accumulates slowly.
    _DECAY: Dict[str, float] = {
        "X": 0.25,    # ~4 exchanges to equilibrate
        "T": 0.08,    # ~12 exchanges
        "N": 0.025,   # ~40 exchanges
        "B": 0.008,   # ~125 exchanges
        "A": 0.003,   # ~330 exchanges
    }

    # Genealogy ability IDs for each axis (what gets relieved when axis is starved)
    _STARVED_ABILITY: Dict[str, str] = {
        "X": "X:ADMISSIBILITY",
        "T": "T:ADVANCE_TICK",
        "N": "N:FLOW_CONTROL",
        "B": "B:INTERFACE_WEAKEN",
        "A": "A:OUTLET_PUSH",
    }

    def __init__(self):
        # Per-axis EMA of activation level (initialised to perfect balance)
        self._ema: Dict[str, float] = {a: 0.20 for a in ("X", "T", "N", "B", "A")}
        self._exchange_count: int = 0
        self._genealogy_inject_interval: int = 10   # inject to genealogy every N exchanges
        # Cached genealogy axis relief — updated each turn in update(), used by rebalanced_activation()
        self._relief_cache: Dict[str, float] = {a: 0.0 for a in ("X", "T", "N", "B", "A")}
        # Corpus-mode active decay multipliers (modified by set_corpus_mode())
        self._decay_active: Dict[str, float] = dict(self._DECAY)

    def update(self, activation: Dict[str, float], systems: dict):
        """
        Record this exchange's activation vector.
        Periodically injects gradient to genealogy when imbalance is sustained.
        """
        for ax, alpha in self._decay_active.items():
            current = activation.get(ax, 0.20)
            self._ema[ax] = (1.0 - alpha) * self._ema[ax] + alpha * current
        self._exchange_count += 1

        # Re-normalise EMA so it stays a probability distribution
        _s = sum(self._ema.values())
        if _s > 0:
            self._ema = {k: v / _s for k, v in self._ema.items()}

        # Periodically push gradient into genealogy to lower costs for starved axes
        if self._exchange_count % self._genealogy_inject_interval == 0:
            try:
                gen = systems.get("genealogy")
                if gen:
                    self._inject_to_genealogy(gen)
            except Exception:
                pass

        # Cache current genealogy axis relief for use by rebalanced_activation().
        # Axes actively building promoted links don't need gradient pushing — they're
        # developing at their own timescale.  Cache refreshes each turn so relief
        # signal stays current without requiring systems to be threaded everywhere.
        try:
            gen = systems.get("genealogy")
            if gen and hasattr(gen, "axis_relief_state"):
                self._relief_cache = gen.axis_relief_state()
        except Exception:
            pass

        # Nudge LSV via grammar engine / perception to rebalance expression structure
        try:
            grammar = systems.get("grammar_engine")
            if grammar and hasattr(grammar, "_genealogy") and grammar._genealogy is not None:
                # Feed the gradient into the LSV nudge already wired in perception
                perception = systems.get("perception")
                if perception and hasattr(perception, "evo"):
                    grad = self.field_gradient()
                    # Invert gradient sign for LSV nudge: starved axis = needs boosting
                    # Use the grammar engine's set_genealogy orientation as base,
                    # then blend in the field gradient
                    if hasattr(perception.evo, "nudge_lsv_from_axes"):
                        # Convert gradient to an orientation-like dict (>1.0 = compress/boost)
                        lsv_orient = {
                            ax: 1.0 + grad.get(ax, 0.0) * 2.0
                            for ax in ("X", "T", "N", "B", "A")
                        }
                        outlet = self._ema.get("A", 0.2) / 0.2   # relative to ideal
                        perception.evo.nudge_lsv_from_axes(lsv_orient, outlet)
        except Exception:
            pass

    def field_gradient(self) -> Dict[str, float]:
        """
        Return the rebalancing gradient vector.

        Positive value for axis X  → X is STARVED (below average activation)
        Negative value for axis X  → X is DOMINANT (above average activation)

        Magnitude is quadratic in the deviation so mild imbalance produces
        gentle pressure while sustained dominance produces strong pressure.
        """
        ideal = 0.20
        gradient: Dict[str, float] = {}
        for ax in ("X", "T", "N", "B", "A"):
            imbalance = self._ema[ax] - ideal
            # Quadratic cost, sign preserved
            gradient[ax] = round(-imbalance * abs(imbalance) * 25.0, 5)
        return gradient

    def _inject_to_genealogy(self, genealogy: Any):
        """
        Log small relief events for starved axes so their promotion costs drop.
        Only injects for axes genuinely below ideal (gradient > threshold).
        """
        import hashlib as _hl
        gradient = self.field_gradient()
        for ax, g in gradient.items():
            if g < 0.005:   # only inject for meaningfully starved axes
                continue
            ability = self._STARVED_ABILITY.get(ax)
            if not ability:
                continue
            try:
                pv_before = {a: (g * 0.015 if a == ax else 0.0)
                             for a in ("X", "T", "N", "B", "A")}
                pv_after = {a: 0.0 for a in ("X", "T", "N", "B", "A")}
                genealogy.observe(
                    pressure_before=pv_before,
                    trace=[{"ability": ability,
                            "cost": 0.0003, "source": "field_balance"}],
                    pressure_after=pv_after,
                    state_sig_before=_hl.md5(
                        f"bal_b_{ax}".encode()).hexdigest()[:8],
                    state_sig_after=_hl.md5(
                        f"bal_a_{ax}".encode()).hexdigest()[:8],
                    notes={"tag": "field_balance", "axis": ax,
                           "gradient": round(g, 4), "ema": round(self._ema[ax], 4)},
                    difference_snapshot={},
                )
            except Exception:
                pass

    def set_corpus_mode(self, enabled: bool) -> None:
        """
        Scale slow-axis decay rates so they equilibrate within a corpus pass.

        In real-time, B-axis equilibrates in ~125 exchanges and A-axis in ~330.
        In corpus mode (65k items), these are processed in seconds — both still
        converge, but the field balancer never gets to "feel" a sustained imbalance
        on slow axes because a single pass is equivalent to years of real-time.

        Corpus scaling (1/participation^0.25) compresses the 10000:1 ratio to ~10:1:
          X: 0.25  (unchanged — ~4 exchanges)
          T: 0.33  (was 0.08 — now equilibrates in ~3 exchanges instead of 12)
          N: 0.56  (was 0.025 — now ~1.8 exchanges instead of 40)
          B: 0.79  (was 0.008 — now ~1.3 exchanges instead of 125)
          A: 0.25  (was 0.003 — now ~4 exchanges instead of 330)

        This means all axes track current imbalance at approximately the same
        speed during corpus training, instead of slow axes lagging behind.
        """
        if enabled:
            # Corpus scale: 1 / participation^0.25 (log-compressed)
            # Capped at X's own decay so no axis goes faster than X tracks
            x_decay = self._DECAY["X"]
            from aurora_internal.constraint_genealogy import AXIS_TICK_PARTICIPATION as _ATP
            self._decay_active = {
                ax: min(x_decay, self._DECAY[ax] * (1.0 / max(1e-9, _ATP.get(ax, 1.0)) ** 0.25))
                for ax in ("X", "T", "N", "B", "A")
            }
        else:
            self._decay_active = dict(self._DECAY)

    def rebalanced_orientation(self, base_orientation: Dict[str, float]) -> Dict[str, float]:
        """
        Blend the base genealogy orientation with the field gradient.
        Starved axes get their orientation boosted (make them more attractive).
        Dominant axes get their orientation suppressed.
        """
        gradient = self.field_gradient()
        result: Dict[str, float] = {}
        for ax in ("X", "T", "N", "B", "A"):
            base = base_orientation.get(ax, 1.0)
            # gradient > 0 = starved = boost orientation (compress, make cheaper)
            # gradient < 0 = dominant = suppress orientation (expand, make costlier)
            result[ax] = max(0.3, base + gradient.get(ax, 0.0) * 0.5)
        return result

    def rebalanced_activation(self, raw: Dict[str, float]) -> Dict[str, float]:
        """
        Boost starved axes in a raw {X,T,N,B,A} activation vector and renormalize.
        Starved axes (gradient > 0) get a gentle additive boost; dominant axes are
        lightly suppressed.  The result stays a proper probability distribution.

        Gradient push is modulated by genealogy axis relief: axes with high relief
        (actively building promoted links) are already developing at their natural
        timescale — forcing them via field rebalancing would fight that rhythm.
        Relief = 1.0 → gradient factor scales from 0.3 to 0.15 (half push).
        Relief = 0.0 → full 0.3 gradient push (truly starved, needs the help).
        """
        gradient = self.field_gradient()
        relief = self._relief_cache
        result: Dict[str, float] = {}
        for ax in ("X", "T", "N", "B", "A"):
            grad_factor = 0.3 * (1.0 - relief.get(ax, 0.0) * 0.5)
            result[ax] = max(0.0, raw.get(ax, 0.2) + gradient.get(ax, 0.0) * grad_factor)
        total = sum(result.values()) or 1.0
        return {k: round(v / total, 4) for k, v in result.items()}

    def status(self) -> Dict[str, Any]:
        grad = self.field_gradient()
        dominant = max(self._ema, key=lambda k: self._ema[k])
        starved = min(self._ema, key=lambda k: self._ema[k])
        return {
            "ema":      {k: round(v, 4) for k, v in self._ema.items()},
            "gradient": {k: round(v, 4) for k, v in grad.items()},
            "exchanges": self._exchange_count,
            "dominant": dominant,
            "starved":  starved,
            "balance_score": round(1.0 - max(abs(v) for v in grad.values()), 3),
        }


_field_balancer = ConstraintFieldBalancer()


def _project_utterance_axes(text: str, systems: dict, parsed: Optional[Dict[str, Any]] = None) -> Dict[str, float]:
    """
    Parse text through UtteranceParser and project onto the 5 constraint axes.
    Blends live Subsurface and Sensory vitals into the initial perception.
    """
    try:
        from aurora_internal.aurora_utterance_parser import UtteranceParser as _UP
        _up = _UP()
        if parsed is None:
            parsed = _up.parse(text)
        
        # 1. Start with the raw textual projection
        projection = _axis_projector.project(parsed, systems)
        
        # 2. Blend the Subsurface DCE Convergence (Conscious Crest axis)
        # If the subsurface crest has a dominant axis, lean the surface
        # perception toward that axis (Closure Symmetry).
        _live_crest = dict(systems.get("_live_conscious_crest") or {})
        _crest_axis = str(_live_crest.get("axis", "") or "").upper()
        _crest_intensity = float(_live_crest.get("intensity", 0.0) or 0.0)
        if _crest_axis in ("X", "T", "N", "B", "A") and _crest_intensity >= 0.35:
            # Blend at 25% weight — the subsurface crest frames the surface
            _cur = float(projection.get(_crest_axis, 0.2))
            projection[_crest_axis] = (_cur * 0.75) + (_crest_intensity * 0.25)

        # 3. Blend live Sensory Vitals (Physical perturbation)
        _live_sensory = dict(systems.get("_live_sensory_state") or {})
        _sens_mat = float(_live_sensory.get("maturity", 0.0) or 0.0)
        if _sens_mat > 0.05:
            # Physical reality (sensory) acts as a grounding force
            _vis = float(_live_sensory.get("visual_intensity", 0.0) or 0.0)
            if _vis > 0.1:
                projection["X"] = min(1.0, float(projection.get("X", 0.2)) + _vis * 0.1)

        return projection
    except Exception:
        return {"X": 0.2, "T": 0.2, "N": 0.2, "B": 0.2, "A": 0.2}


def _looks_like_inner_state_query(text: str, parsed: Optional[dict] = None) -> bool:
    low = str(text or "").strip().lower()
    if not low:
        return False
    markers = (
        "how are you",
        "how do you feel",
        "what do you feel",
        "what do you think",
        "what are you thinking",
        "what do you want",
        "what's on your mind",
        "whats on your mind",
        "who are you",
        "what is your name",
        "what's your name",
        "whats your name",
        "do you know who i am",
        "what is my name",
        "what's my name",
        "whats my name",
    )
    if any(marker in low for marker in markers):
        return True
    parsed = dict(parsed or {})
    topic = str(parsed.get("topic", "") or "").strip().lower()
    if topic in {"you", "yourself", "your name", "my name", "who i am"}:
        return True
    topic_words = {str(w or "").strip().lower() for w in list(parsed.get("topic_words") or [])}
    return bool(topic_words & {"you", "yourself", "feel", "feeling", "think", "thinking", "want", "wanting", "name", "identity"})


def _classify_input_intent(text: str, *, _axis_activation: dict = None, _parsed: dict = None) -> str:
    """
    Derive communicative intent from field state -- no keyword prescriptions.

    Intent is inferred from:
      - axis_activation (dominant field signal from the upward chain)
      - UtteranceParser output (utterance_type, is_question, is_callback)
      - referent / claim signals passed in from the chain state

    Returns a label used downstream only for routing broad categories.
    The label is NOT a prescription -- it describes what the field state
    already determined, not what a keyword pattern fired on.
    """
    parsed   = dict(_parsed or {})
    axis     = dict(_axis_activation or {})
    dominant = max(axis, key=axis.get) if axis else "X"

    utype   = str(parsed.get("utterance_type", "") or "").lower()
    is_q    = bool(parsed.get("is_question") or str(text or "").strip().endswith("?"))
    is_cb   = bool(parsed.get("is_callback"))
    is_cl   = bool(parsed.get("is_clarification"))

    if not is_q and _extract_user_name(text):
        return "fact_assertion"

    # Imperative directive frame — grammatical signal from UtteranceParser.
    # A-axis (agency/will) + X-axis (instantiation) dominate when the user
    # issues a directed action command.  The pipeline routes to tool dispatch.
    if bool(parsed.get("is_imperative")):
        return "directive"

    # Explicit memory/recall patterns — must be checked before axis routing because
    # these are T-axis intent regardless of what the field activation reports.
    _text_low_cl = str(text or "").lower()
    _RECALL_TRIGGERS = (
        "what did i just tell you", "what did i tell you",
        "what did i just say", "what did i say",
        "i just told you", "i already told you",
        "you should know my", "you should remember",
        "don't you remember", "do you remember what i",
        "what's my name", "what is my name",
        "what did i say my name", "what was my name",
    )
    if any(trigger in _text_low_cl for trigger in _RECALL_TRIGGERS):
        return "recall_question"

    # A-axis dominant: self-directed / inner-field question
    if dominant == "A" and axis.get("A", 0.0) > 0.36 and _looks_like_inner_state_query(text, parsed):
        return "wellbeing_query"

    # T-axis dominant + callback/clarification: continuity / recall
    if dominant == "T" and (is_cb or is_cl):
        return "recall_question"

    # B-axis dominant + statement: user asserting a fact or boundary
    if dominant == "B" and utype == "statement" and not is_q:
        return "fact_assertion"

    # X-axis dominant + question: seeking information
    if dominant == "X" and is_q:
        return "general"

    # N-axis dominant: pressure / correction / cost signal
    if dominant == "N":
        return "followup_request"

    # Fallbacks from UtteranceParser alone
    if utype == "question" or is_q:
        return "general"
    if utype == "statement":
        return "statement"
    if is_cb:
        return "followup_request"

    return "general"

def _extract_user_name(text: str):
    """Extract a name from user fact assertions like 'My name is Sunni' or 'I'm Sunni'."""
    import re
    _skip = {
        'a', 'the', 'an', 'is', 'am', 'are', 'not', 'just', 'also', 'called', 'known',
        'here', 'fine', 'okay', 'good', 'sorry', 'ready', 'sure', 'trying', 'going',
        'that', 'this', 'your', 'her', 'him', 'them', 'their', 'our', 'its',
    }
    case_insensitive_patterns = [
        r'\bmy\s+name\s+is\s+([A-Za-z]+)\b',
        r'\bcall\s+me\s+([A-Za-z]+)\b',
        r'\byou\s+can\s+call\s+me\s+([A-Za-z]+)\b',
        r'\bi\s+go\s+by\s+([A-Za-z]+)\b',
        r'\bi\s+am\s+called\s+([A-Za-z]+)\b',
    ]
    for pat in case_insensitive_patterns:
        m = re.search(pat, text, re.IGNORECASE)
        if m:
            name = m.group(1)
            if name.lower() not in _skip:
                return name.capitalize()
    # Natural self-introduction: "I'm Sunni" / "I am Sunni"
    # Must NOT use IGNORECASE — the capital letter requirement distinguishes
    # proper nouns ("Sunni") from verbs ("asking", "going", "ready", etc.)
    m = re.search(r"(?:^|\s)[Ii](?:'m|m|\s+am)\s+([A-Z][a-z][A-Za-z'\-]{1,39})\b", text)
    if m:
        name = m.group(1)
        if name.lower() not in _skip:
            return name.capitalize()
    return None


_USER_NAME_PROMPT_MARKERS = (
    "what should i call you",
    "i don't have your name yet",
    "i dont have your name yet",
    "who am i talking to",
    "what is your name",
    "what's your name",
)


def _get_working_memory_value(working_memory: Any, key: str) -> Any:
    if isinstance(working_memory, dict):
        return working_memory.get(key)
    return getattr(working_memory, key, None)


def _get_working_memory_user_bucket(working_memory: Any, *, create: bool = False) -> Dict[str, Any]:
    if isinstance(working_memory, dict):
        stated_facts = working_memory.get("stated_facts")
        if not isinstance(stated_facts, dict):
            if not create:
                return {}
            stated_facts = {}
            working_memory["stated_facts"] = stated_facts
        bucket = stated_facts.get("user")
        if isinstance(bucket, dict):
            return bucket
        if create:
            bucket = {}
            stated_facts["user"] = bucket
            return bucket
        return {}

    stated_facts = getattr(working_memory, "stated_facts", None)
    if not isinstance(stated_facts, dict):
        if not create:
            return {}
        stated_facts = {}
        setattr(working_memory, "stated_facts", stated_facts)
    bucket = stated_facts.get("user")
    if isinstance(bucket, dict):
        return bucket
    if create:
        bucket = {}
        stated_facts["user"] = bucket
        return bucket
    return {}


def _last_aurora_response_text(systems: Dict[str, Any] | None) -> str:
    if not isinstance(systems, dict):
        return ""
    working_memory = systems.get("working_memory")
    if working_memory is None:
        return ""
    return str(_get_working_memory_value(working_memory, "last_aurora_response") or "").strip()


def _normalize_identity_followup_text(text: str, systems: Dict[str, Any] | None = None) -> str:
    raw = str(text or "").strip()
    if not raw or raw.endswith("?"):
        return raw
    if _extract_user_name(raw):
        return raw

    last_low = _last_aurora_response_text(systems).lower()
    if not any(marker in last_low for marker in _USER_NAME_PROMPT_MARKERS):
        return raw

    candidate = re.sub(
        r"^(?:it'?s|it\s+is|i'?m|i\s+am|name\s+is)\s+",
        "",
        raw,
        flags=re.IGNORECASE,
    ).strip(" \t\r\n.,!?;:'\"")
    if re.fullmatch(r"[A-Za-z][A-Za-z'\-]{1,40}", candidate or ""):
        return f"my name is {candidate.capitalize()}"
    return raw


def _persist_user_identity_name(
    name: str,
    systems: Dict[str, Any] | None,
    *,
    source_text: str = "",
) -> Dict[str, Any]:
    clean_name = str(name or "").strip().capitalize()
    if not clean_name or not isinstance(systems, dict):
        return {}

    # Guard: Do not learn own name as a user name
    core_identity = systems.get("core_identity")
    if core_identity and clean_name.lower() == str(getattr(core_identity, "self_name", "aurora")).lower():
        return {}

    result: Dict[str, Any] = {"name": clean_name}
    conversation_memory = systems.get("conversation_memory")
    working_memory = systems.get("working_memory")
    perception = systems.get("perception")

    if conversation_memory:
        try:
            conversation_memory.learn_fact(
                f"User's name is {clean_name}",
                source="direct_statement",
                confidence=1.0,
            )
        except Exception:
            pass
        try:
            conversation_memory.add_relationship_note(
                clean_name.lower(),
                f"Introduced themselves as {clean_name}",
            )
        except Exception:
            pass
        try:
            conversation_memory.instantiate_lineage_trace(
                anchor=clean_name.lower(),
                claim=f"User's name is {clean_name}",
                role_edges=[{
                    "subject": clean_name,
                    "relation": "user_name",
                    "object": "user",
                    "negated": False,
                }],
                pressure_snapshot=_capture_pressure_snapshot(systems),
                source="direct_statement",
                confidence=1.0,
                tick=int(time.time()),
            )
        except Exception:
            pass

    if working_memory is not None:
        stored = False
        if hasattr(working_memory, "note_user_identity_fact"):
            try:
                working_memory.note_user_identity_fact("name", clean_name, source="user")
                stored = True
            except Exception:
                stored = False
        if not stored:
            try:
                user_bucket = _get_working_memory_user_bucket(working_memory, create=True)
                user_bucket["name"] = clean_name
                user_bucket["identity_label"] = clean_name
                stored = True
            except Exception:
                stored = False
        if stored:
            result["working_memory"] = True

    guidance_result: Dict[str, Any] = {}
    if perception is not None and hasattr(perception, "guide_user_identity"):
        try:
            guidance_result = dict(
                perception.guide_user_identity(
                    clean_name,
                    source_text=source_text or f"my name is {clean_name}",
                ) or {}
            )
        except Exception:
            guidance_result = {}
    if guidance_result:
        existing = dict(systems.get("_latest_surface_guidance_result") or {})
        actions = [
            item for item in list(existing.get("actions") or [])
            if isinstance(item, dict)
        ]
        actions.append(guidance_result)
        systems["_latest_surface_guidance_result"] = {
            "source_text": source_text or f"my name is {clean_name}",
            "actions": actions,
            "applied": any(bool(item.get("applied")) for item in actions),
            "summary": "; ".join(
                f"{str(item.get('label', '') or '').strip()} -> "
                f"{', '.join(str(m) for m in list(item.get('modalities') or [])) or 'guided'}"
                for item in actions
                if str(item.get("label", "") or "").strip()
            ),
        }
        result["guidance"] = guidance_result

    systems["_active_user_identity_label"] = clean_name
    return result


def _render_user_name_grounding(
    systems: Dict[str, Any] | None,
    name: str,
    *,
    recognition: bool = False,
) -> str:
    clean_name = str(name or "").strip().capitalize()
    if not clean_name:
        return ""
    guidance = dict(systems.get("_latest_surface_guidance_result") or {}) if isinstance(systems, dict) else {}
    modalities: List[str] = []
    for item in list(guidance.get("actions") or []):
        if not isinstance(item, dict) or not item.get("applied"):
            continue
        for modality in list(item.get("modalities") or []):
            modality_text = str(modality or "").strip()
            if modality_text and modality_text not in modalities:
                modalities.append(modality_text)
    claim_parts = []
    if recognition:
        claim_parts.append(f"recognizing {clean_name}")
    claim_parts.append(f"{clean_name} is your name")
    claim_parts.append("anchored in this interaction")
    if modalities:
        claim_parts.append(f"{' and '.join(modalities)} presence aligned")
    if recognition:
        core_claim = f"I should call you {clean_name}"
    else:
        core_claim = f"your name is {clean_name}"
    rendered = _render_runtime_intent(
        systems,
        core_claim,
        emotion_tone='precise' if recognition else 'attentive',
        relationship_signal='neutral',
        certainty=0.94 if recognition else 0.92,
        supporting_concepts=[clean_name, 'name', 'user'],
    )
    return str(rendered or WorkingMemory._data_to_minimal_speech(core_claim, 'precise', 'neutral')).strip()


def _get_stored_user_name(conversation_memory, systems=None) -> str:
    """Retrieve the user's name from stored facts or working memory.

    NOTE: The creator's name is NOT the user's name — never fall through to it.
    """
    import re
    if isinstance(systems, dict):
        active_label = str(systems.get("_active_user_identity_label", "") or "").strip()
        if active_label:
            return active_label.capitalize()
    if conversation_memory:
        for fact in reversed(getattr(conversation_memory, 'learned_facts', [])):
            fact_text = fact.get("fact", "").lower()
            m = re.search(r"user(?:'s)?\s+name\s+is\s+(\w+)", fact_text)
            if m:
                return m.group(1).capitalize()
    if isinstance(systems, dict):
        wm = systems.get('working_memory')
        if wm is not None:
            try:
                user_bucket = _get_working_memory_user_bucket(wm, create=False)
                wm_name = str(
                    user_bucket.get('name', '') or user_bucket.get('identity_label', '') or ''
                ).strip()
                if wm_name:
                    return wm_name.capitalize()
            except Exception:
                pass
        sedi_results = _recall_semantic_sedimemory(
            systems,
            "my name is",
            axis_filter=("T", "B", "A"),
            max_results=10,
            min_score=0.25,
        )
        for item in list(sedi_results or []):
            content = dict(item.get("content", {}) or {})
            for value in content.values():
                if not isinstance(value, str) or not value.strip():
                    continue
                fact = _extract_user_owned_fact_from_text(value)
                if str(fact.get("field", "") or "") == "name":
                    return str(fact.get("value", "") or "").strip().capitalize()
        try:
            recent = list(getattr(wm, "recent_user_utterances", []) or [])
        except Exception:
            recent = []
        for item in recent:
            raw_text = str((item or {}).get("text", "") or "").strip()
            if not raw_text:
                continue
            identity = _extract_user_name(raw_text)
            if identity:
                return identity
            normalized = _normalize_identity_followup_text(raw_text, systems)
            identity = _extract_user_name(normalized)
            if identity:
                return identity
    return ""


def _observe_live_lineage_emergence(
    systems: Dict[str, Any],
    *,
    source: str = "runtime",
) -> List[Dict[str, Any]]:
    journal = systems.get("lineage_emergence_journal")
    if journal is None or not hasattr(journal, "observe_systems"):
        return []
    try:
        return list(journal.observe_systems(systems, source=source) or [])
    except Exception:
        return []


def _describe_live_lineage_emergence(
    systems: Dict[str, Any],
    *,
    limit: int = 3,
) -> str:
    journal = systems.get("lineage_emergence_journal")
    if journal is None or not hasattr(journal, "describe_recent"):
        return ""
    try:
        return str(journal.describe_recent(limit=limit) or "").strip()
    except Exception:
        return ""


def _interaction_status_path(systems: Dict[str, Any]) -> str:
    state_dir = str(systems.get("state_dir", "aurora_state") or "aurora_state")
    return os.path.join(state_dir, "interaction_status.json")


def _write_interaction_status(
    systems: Dict[str, Any],
    status: Dict[str, Any],
) -> None:
    try:
        from pathlib import Path as _Path
        from aurora_persistence_utils import atomic_write_json as _atomic_write_json
        _atomic_write_json(_Path(_interaction_status_path(systems)), dict(status or {}), indent=2, default=str)
    except Exception:
        pass


def _strategy_to_interaction_action(strategy: str) -> str:
    mapping = {
        "callback_grounding_repair": "clarify_referent",
        "internal_introspection_resolution": "route_to_self_introspection",
        "concept_cluster_binding": "bind_to_existing_oets_cluster",
        "boundary_preserving_answer": "surface_boundary",
        "ambiguity_reduction_then_response": "request_missing_context",
        "emotion_first_then_reasoning": "switch_to_fallback_expression",
    }
    return mapping.get(str(strategy or "").strip(), "defer_to_live_gradient")


def _summarize_interaction_route(route: Dict[str, Any]) -> Dict[str, Any]:
    route = dict(route or {})
    intake = dict(route.get("intake_signature") or {})
    selected = dict(route.get("selected_quasi") or {})
    node = selected.get("node")
    payload = dict(getattr(node, "payload", {}) or {}) if node is not None else {}
    execution = dict(route.get("execution_surface") or {})
    relic_bias = dict(route.get("relic_bias") or {})
    return {
        "selected": bool(selected),
        "quasi_id": str(getattr(node, "node_id", "") or ""),
        "input_signature": str(intake.get("input_signature") or ""),
        "interpretive_issue": str(intake.get("interpretive_issue") or ""),
        "processing_tier": str(intake.get("processing_tier") or ""),
        "interaction_archetype": str(payload.get("interaction_archetype") or execution.get("interaction_archetype") or ""),
        "primary_response_strategy": str(payload.get("primary_response_strategy") or execution.get("primary_response_strategy") or ""),
        "secondary_response_strategy": str(payload.get("secondary_response_strategy") or execution.get("secondary_response_strategy") or ""),
        "confidence": float(selected.get("confidence", payload.get("confidence", 0.0)) or 0.0),
        "match_score": float(selected.get("match_score", 0.0) or 0.0),
        "quasi_ready": bool(selected) and not bool(route.get("escalate", True)),
        "escalate": bool(route.get("escalate", True)),
        "reason": str(route.get("reason") or "novel_interaction_outside_indexed_archetypes"),
        "search_policy": str(execution.get("search_policy") or "allow"),
        "wake_processing_tiers": list(execution.get("wake_processing_tiers") or []),
        "failure_indicators": list(execution.get("failure_indicators") or []),
        "expected_effects": list(execution.get("expected_effects") or []),
        "relic_bias": relic_bias,
    }


def _record_interaction_lineage_event(
    systems: Dict[str, Any],
    *,
    event_id: str,
    kind: str,
    summary: str,
    route_summary: Optional[Dict[str, Any]] = None,
    extra: Optional[Dict[str, Any]] = None,
) -> None:
    journal = systems.get("lineage_emergence_journal")
    if journal is None or not hasattr(journal, "record_event"):
        return
    route_summary = dict(route_summary or {})
    extra = dict(extra or {})
    axis = str((systems.get("_last_pipeline_state") or {}).get("dominant_axis", "X") or "X").upper()
    event = {
        "timestamp": float(time.time()),
        "source": "interaction_processing",
        "kind": str(kind or "interaction_quasi"),
        "id": str(event_id or ""),
        "axis": axis if axis in {"X", "T", "N", "B", "A"} else "X",
        "tags": [
            "interaction",
            f"issue:{route_summary.get('interpretive_issue', '')}",
            f"archetype:{route_summary.get('interaction_archetype', '')}",
            f"strategy:{route_summary.get('primary_response_strategy', '')}",
        ],
        "summary": str(summary or "interaction lineage event"),
        "interaction_archetype": route_summary.get("interaction_archetype", ""),
        "primary_response_strategy": route_summary.get("primary_response_strategy", ""),
        "confidence": float(route_summary.get("confidence", 0.0) or 0.0),
        **extra,
    }
    try:
        journal.record_event(event)
    except Exception:
        pass


def _apply_interaction_quasi_route(
    systems: Dict[str, Any],
    user_text: str,
    pipeline_state: Optional[Dict[str, Any]] = None,
    *,
    session_id: str = "",
    turn_tick: int = 0,
    allow_search: bool = True,
) -> Dict[str, Any]:
    interaction_processing = systems.get("interaction_processing")
    if interaction_processing is None or not hasattr(interaction_processing, "route_interaction"):
        systems["_last_interaction_route"] = {}
        return {}
    try:
        route = interaction_processing.route_interaction(
            {
                "text": user_text,
                "session_id": session_id,
                "search_gate": "auto" if allow_search else "suppressed",
                "emotion_load": float((pipeline_state or {}).get("emotional_energy", 0.0) or 0.0),
                "primary_emotion": (pipeline_state or {}).get("primary_emotion", "neutral"),
                "intensity": (pipeline_state or {}).get("intensity", 0.5),
                "drive": (pipeline_state or {}).get("drive", "steady"),
                "passion": (pipeline_state or {}).get("passion", "observant"),
                "oets_cluster": str((pipeline_state or {}).get("resolved_referent_topic", "") or ""),
            },
            min_confidence=0.55,
        )
    except Exception:
        route = {}
    summary = _summarize_interaction_route(route)
    summary["session_id"] = str(session_id or systems.get("session_id") or "")
    summary["turn_tick"] = int(turn_tick or 0)
    systems["_last_interaction_route"] = summary
    if isinstance(pipeline_state, dict):
        pipeline_state["interaction_quasi"] = dict(summary)
        pipeline_state["interaction_archetype"] = str(summary.get("interaction_archetype", "") or "")
        pipeline_state["interaction_primary_strategy"] = str(summary.get("primary_response_strategy", "") or "")
        pipeline_state["interaction_secondary_strategy"] = str(summary.get("secondary_response_strategy", "") or "")
        pipeline_state["interaction_confidence"] = float(summary.get("confidence", 0.0) or 0.0)
        pipeline_state["interaction_quasi_ready"] = bool(summary.get("quasi_ready", False))
        pipeline_state["interaction_route_reason"] = str(summary.get("reason", "") or "")
        pipeline_state["interaction_wake_tiers"] = list(summary.get("wake_processing_tiers", []) or [])
        pipeline_state["interaction_failure_indicators"] = list(summary.get("failure_indicators", []) or [])
        pipeline_state["interaction_expected_effects"] = list(summary.get("expected_effects", []) or [])
        pipeline_state["interaction_search_policy"] = str(summary.get("search_policy", "allow") or "allow")
        if bool(summary.get("quasi_ready")) and str(summary.get("search_policy", "")) == "defer" and allow_search:
            pipeline_state["search_gate"] = "deferred_by_interaction_quasi"
    if (
        bool(summary.get("quasi_ready"))
        and float(summary.get("confidence", 0.0) or 0.0) >= 0.6
        and float(summary.get("match_score", 0.0) or 0.0) >= 0.55
    ):
        _record_interaction_lineage_event(
            systems,
            event_id=f"INTERACTION:ROUTE:{summary.get('session_id', 'session')}:{summary.get('turn_tick', 0)}",
            kind="interaction_quasi_route",
            summary=(
                f"Interaction quasi routed {summary.get('input_signature', 'turn')} via "
                f"{summary.get('primary_response_strategy', 'strategy')}"
            ),
            route_summary=summary,
            extra={"match_score": float(summary.get("match_score", 0.0) or 0.0)},
        )
    boot_status = dict(summary)
    boot_status["updated_at"] = float(time.time())
    boot_status["stage"] = "pre_route"
    _write_interaction_status(systems, boot_status)
    return summary


def _observe_interaction_runtime_turn(
    systems: Dict[str, Any],
    *,
    user_text: str,
    resp_A: Any,
    offered_lookup: bool = False,
    session_id: str = "",
    turn_tick: int = 0,
    source: str = "runtime_dialogue",
) -> Dict[str, Any]:
    interaction_processing = systems.get("interaction_processing")
    if interaction_processing is None or not hasattr(interaction_processing, "observe_interaction"):
        return {}
    pipeline_state = dict(systems.get("_last_pipeline_state") or {})
    route_summary = dict(systems.get("_last_interaction_route") or {})
    confidence = float(getattr(resp_A, "confidence", 0.0) or 0.0)
    response_source = str(getattr(resp_A, "src", "") or "")
    if confidence >= 0.82 and response_source in {"comprehension", "reasoning", "search", "identity"}:
        observed_effect = "resolved_fully"
    elif confidence >= 0.55:
        observed_effect = "resolved_partially"
    elif bool(offered_lookup):
        observed_effect = "pending_verification"
    else:
        observed_effect = "no_change_observed"
    wake_tiers = list(route_summary.get("wake_processing_tiers", []) or [])
    if len(set(wake_tiers)) > 1:
        distribution_context = "cross_stage__working_memory_to_expression"
    elif len(wake_tiers) == 1:
        distribution_context = "single_pipeline_stage__isolated"
    else:
        distribution_context = "multi_stage__same_turn"
    event = {
        "text": user_text,
        "session_id": str(session_id or systems.get("session_id") or ""),
        "turn_id": f"{session_id or 'session'}:{int(turn_tick or 0)}",
        "input_signature": str(route_summary.get("input_signature") or ""),
        "interpretive_issue": str(route_summary.get("interpretive_issue") or ""),
        "processing_tier": str(route_summary.get("processing_tier") or (wake_tiers[0] if wake_tiers else "")),
        "response_action": (
            _strategy_to_interaction_action(route_summary.get("primary_response_strategy", ""))
            if route_summary.get("primary_response_strategy") else ""
        ),
        "intended_effect": str((route_summary.get("expected_effects") or [""])[0] or ""),
        "observed_effect": observed_effect,
        "distribution_context": distribution_context,
        "search_gate": "forced_external" if offered_lookup else str(route_summary.get("search_policy") or "auto"),
        "emotion_load": float(pipeline_state.get("emotional_energy", 0.0) or 0.0),
        "oets_cluster": str(pipeline_state.get("resolved_referent_topic", "") or ""),
    }
    try:
        observed = interaction_processing.observe_interaction(
            event,
            tags=[
                "runtime",
                f"phase:{source}",
                f"response:{response_source or 'unknown'}",
                f"strategy:{route_summary.get('primary_response_strategy', '')}",
            ],
            auto_promote=True,
        )
    except Exception:
        observed = {}
    status = {}
    try:
        if hasattr(interaction_processing, "get_status"):
            status = dict(interaction_processing.get_status() or {})
    except Exception:
        status = {}
    base = dict(observed or {}).get("base") if isinstance(observed, dict) else None
    advance = dict(observed or {}).get("advance") if isinstance(observed, dict) else None
    promoted_quasi = dict(advance or {}).get("quasi") if isinstance(advance, dict) else None
    status.update({
        "updated_at": float(time.time()),
        "stage": "post_turn",
        "session_id": str(session_id or systems.get("session_id") or ""),
        "turn_tick": int(turn_tick or 0),
        "input_signature": str(route_summary.get("input_signature") or getattr(base, "get_facet", lambda *_: "")("input_signature") or event.get("input_signature") or ""),
        "interpretive_issue": str(route_summary.get("interpretive_issue") or getattr(base, "get_facet", lambda *_: "")("interpretive_issue") or event.get("interpretive_issue") or ""),
        "interaction_archetype": str(route_summary.get("interaction_archetype") or status.get("latest_archetype", "") or ""),
        "interaction_strategy": str(route_summary.get("primary_response_strategy") or status.get("latest_strategy", "") or ""),
        "interaction_confidence": float(route_summary.get("confidence", status.get("latest_confidence", 0.0)) or 0.0),
        "interaction_match_score": float(route_summary.get("match_score", 0.0) or 0.0),
        "interaction_route_reason": str(route_summary.get("reason") or ""),
        "interaction_quasi_ready": bool(route_summary.get("quasi_ready", False)),
        "interaction_observed_effect": observed_effect,
        "interaction_response_source": response_source,
        "interaction_search_policy": str(route_summary.get("search_policy") or event.get("search_gate") or "auto"),
        "interaction_wake_tiers": list(route_summary.get("wake_processing_tiers", []) or []),
        "interaction_quasi_id": str(route_summary.get("quasi_id") or ""),
        "interaction_base_id": str(getattr(base, "crystal_id", "") or ""),
        "interaction_promoted_quasi_id": str(getattr(promoted_quasi, "crystal_id", "") or ""),
    })
    systems["_last_interaction_status"] = status
    _write_interaction_status(systems, status)
    if promoted_quasi is not None:
        _record_interaction_lineage_event(
            systems,
            event_id=f"INTERACTION:QUASI:{getattr(promoted_quasi, 'crystal_id', '')}",
            kind="interaction_quasi",
            summary=(
                f"Interaction quasi promoted for {status.get('interpretive_issue', 'interaction')} "
                f"using {status.get('interaction_strategy', 'strategy')}"
            ),
            route_summary={
                "interaction_archetype": getattr(promoted_quasi, "get_facet", lambda *_: "")("interaction_archetype"),
                "primary_response_strategy": getattr(promoted_quasi, "get_facet", lambda *_: "")("primary_response_strategy"),
                "confidence": getattr(promoted_quasi, "get_facet", lambda *_: 0.0)("confidence"),
                "interpretive_issue": status.get("interpretive_issue", ""),
            },
            extra={"quasi_id": getattr(promoted_quasi, "crystal_id", "")},
        )
    return status


def _describe_pending_code_proposals(
    systems: Dict[str, Any],
    *,
    limit: int = 2,
) -> str:
    state_dir = str(systems.get("state_dir", "aurora_state") or "aurora_state")
    path = os.path.join(state_dir, "code_evolution_proposals.json")
    if not os.path.exists(path):
        return ""
    try:
        with open(path, "r", encoding="utf-8") as handle:
            payload = dict(json.load(handle) or {})
    except Exception:
        return ""
    proposals = [
        dict(rec or {})
        for rec in dict(payload.get("proposals", {}) or {}).values()
        if str(dict(rec or {}).get("status", "") or "") in {"pending_approval", "approved_pending_apply"}
    ]
    if not proposals:
        return ""
    proposals.sort(key=lambda rec: float(rec.get("created_at", 0.0) or 0.0), reverse=True)
    lines: List[str] = []
    for rec in proposals[:max(1, int(limit or 1))]:
        ctx = dict(rec.get("constraint_context", {}) or {})
        lines.append(
            f"I formed a pending code proposal `{rec.get('proposal_id', '')}`"
            f" on the {ctx.get('dominant_axis', 'X')} axis: {str(rec.get('summary', '') or '').strip()}"
        )
    return " ".join(lines).strip()


