    "about", "actually", "adapt", "adjust", "affect", "alongside", "and", "answer", "answers", "apply",
    "because", "before", "be", "believe", "carry", "change", "commit",
    "between", "both", "can", "could", "current", "currently", "do", "does",
    "during", "especially", "explicitly", "for", "from", "future", "have",
    "don", "doesn", "didn", "isn", "aren", "wasn", "weren", "won",
    "wouldn", "shouldn", "couldn", "haven", "hasn", "hadn", "ain",
    "how", "if", "in", "influence", "into", "interpret", "is", "it", "keep",
    "keeps", "being", "said", "fitting",
    "live", "closest", "implied", "let", "only", "reading",
    "maintain", "might", "more", "not", "of", "on", "opinion", "perspective",
    "prioritise", "prioritize", "priority", "preserve", "respond",
