def _resolve_passive_ability_effect_owner(tag: str) -> str:
    clean = str(tag or "").strip()
    if not clean:
        return ""
    owner = str(_ABILITY_EFFECT_PASSIVE_OWNERS.get(clean, "") or "").strip()
    if owner:
        return owner
    owner = str(_ABILITY_EFFECT_PRIMITIVE_OWNERS.get(clean, "") or "").strip()
    if owner:
        return owner
    for prefix, passive_owner in _ABILITY_EFFECT_PASSIVE_PREFIX_OWNERS.items():
        if clean.startswith(prefix):
            return passive_owner
    return ""


def _summarize_live_ability_effects(effect_tags: List[str]) -> Dict[str, Any]:
    raw_effects: List[str] = []
    seen_raw = set()
    for tag in list(effect_tags or []):
        clean = str(tag or "").strip()
        if not clean or clean in seen_raw:
            continue
        seen_raw.add(clean)
        raw_effects.append(clean)

    expanded_effects: List[str] = []
    seen_expanded = set()
    translated_effects: Dict[str, List[str]] = {}

    def _push(label: str) -> None:
        clean = str(label or "").strip()
        if not clean or clean in seen_expanded:
            return
        seen_expanded.add(clean)
        expanded_effects.append(clean)

    for tag in raw_effects:
        _push(tag)
        aliases = [
            str(alias or "").strip()
            for alias in _ABILITY_EFFECT_ALIAS_MAP.get(tag, ())
            if str(alias or "").strip()
        ]
        if aliases:
            translated_effects[tag] = aliases
        for alias in aliases:
            _push(alias)

    translated_roots = set(translated_effects)
    handled_effects: List[str] = []
    passive_effects: List[Dict[str, str]] = []
    unhandled_effects: List[str] = []
    for tag in expanded_effects:
        if tag in translated_roots:
            continue
        if tag in _ABILITY_EFFECT_RUNTIME_HANDLERS:
            handled_effects.append(tag)
            continue
        owner = _resolve_passive_ability_effect_owner(tag)
        if owner:
            passive_effects.append({"tag": tag, "owner": owner})
            continue
        unhandled_effects.append(tag)

    effect_set = set(expanded_effects)
    runtime_flags = {
        "force_continuity_recall": bool(effect_set & {"continuity_recall", "context_anchor_recall"}),
        "prefer_speaker_grounding": bool(effect_set & {"speaker_grounding", "referent_recenter"}),
        "prefer_conflict_surface": bool(effect_set & {"resolve", "merge_conflict"}),
        "has_unhandled_effects": bool(unhandled_effects),
    }
    return {
        "raw_effects": raw_effects,
        "expanded_effects": expanded_effects,
        "translated_effects": translated_effects,
        "handled_effects": handled_effects,
        "passive_effects": passive_effects,
        "unhandled_effects": unhandled_effects,
        "runtime_flags": runtime_flags,
    }


_NONCOMP_CONSTRAINT_RUNTIME_EFFECTS: Dict[str, Tuple[str, ...]] = {
    "T": ("continuity_recall", "context_anchor_recall"),
    "B": ("speaker_grounding", "referent_recenter"),
    "A": ("resolve", "merge_conflict", "reclassify"),
}

_NONCOMP_DIMENSION_RUNTIME_FLAGS: Dict[str, Tuple[str, ...]] = {
    "OPERATOR": ("prefer_action_resolution",),
    "POLARITY": ("prefer_low_assertion",),
    "MAGNITUDE": ("prefer_salience_preservation",),
    "COST": ("prefer_cost_weighting", "prefer_concise_response"),
    "DIFFERENCE": ("prefer_difference_surface",),
}


def _derive_noncomp_behavior_actuation(summary: Dict[str, Any]) -> Dict[str, Any]:
    constraint = str(summary.get("constraint", "") or "").strip().upper()
    dimension = str(summary.get("dimension", "") or "").strip().upper()
    expression = str(summary.get("expression", "") or "").lower()
    effect_set = {
        str(tag or "").strip()
        for tag in _NONCOMP_CONSTRAINT_RUNTIME_EFFECTS.get(constraint, ())
        if str(tag or "").strip()
    }
    flag_set = {
        str(flag or "").strip()
        for flag in _NONCOMP_DIMENSION_RUNTIME_FLAGS.get(dimension, ())
        if str(flag or "").strip()
    }

    if not bool(summary.get("is_understood")) or str(summary.get("field_region", "") or "") == "sparse":
        flag_set.add("prefer_lookup_grounding")
        flag_set.add("prefer_clarification")
    if not bool(summary.get("polarity_coherent", True)):
        flag_set.add("prefer_low_assertion")
    if str(summary.get("remedy", "") or "") == "lookup":
        flag_set.add("prefer_lookup_grounding")
    if str(summary.get("remedy", "") or "") == "clarify":
        flag_set.add("prefer_clarification")
    if str(summary.get("anchor", "") or "").strip():
        flag_set.add("prefer_anchor_binding")

    if any(marker in expression for marker in (
        "remember",
        "recall",
        "what did i say",
        "what was my",
        "what is my",
        "what's my",
    )):
        effect_set.update({"continuity_recall", "context_anchor_recall"})
        flag_set.add("prefer_anchor_binding")
    if any(marker in expression for marker in (
        "what does",
        "what do you mean by",
        "mean?",
        "define ",
        "definition",
    )):
        flag_set.add("prefer_lookup_grounding")
        flag_set.add("prefer_action_resolution")
    if any(marker in expression for marker in (
        "cost",
        "price",
        "resource",
        "energy",
        "commit to this",
    )):
        flag_set.add("prefer_cost_weighting")
        flag_set.add("prefer_concise_response")
    if any(marker in expression for marker in (
        "not what i meant",
        "that's not what i meant",
        "boundary",
        "meant at the boundary",
    )):
        effect_set.update({"speaker_grounding", "referent_recenter"})
        flag_set.add("prefer_clarification")
    if any(marker in expression for marker in (
        "clarify",
        "explain what you meant",
        "what you meant",
    )):
        effect_set.update({"resolve", "merge_conflict"})
        flag_set.add("prefer_action_resolution")

    runtime_flags = {
        "force_continuity_recall": bool(effect_set & {"continuity_recall", "context_anchor_recall"}),
        "prefer_speaker_grounding": bool(effect_set & {"speaker_grounding", "referent_recenter"}),
        "prefer_conflict_surface": bool(effect_set & {"resolve", "merge_conflict"}),
        "prefer_lookup_grounding": "prefer_lookup_grounding" in flag_set,
        "prefer_clarification": "prefer_clarification" in flag_set,
        "prefer_low_assertion": "prefer_low_assertion" in flag_set,
        "prefer_concise_response": "prefer_concise_response" in flag_set,
        "prefer_difference_surface": "prefer_difference_surface" in flag_set,
        "prefer_action_resolution": "prefer_action_resolution" in flag_set,
        "prefer_anchor_binding": "prefer_anchor_binding" in flag_set,
    }
    return {
        "constraint": constraint,
        "dimension": dimension,
        "effects": sorted(effect_set),
        "flags": sorted(flag_set),
        "runtime_flags": runtime_flags,
        "nc_name": str(summary.get("nc_name", "") or ""),
        "field_region": str(summary.get("field_region", "") or ""),
        "is_understood": bool(summary.get("is_understood")),
    }


def _apply_noncomp_behavior_actuation(
    systems: Dict[str, Any],
    state: Any,
    *,
    context: str = "input",
) -> Dict[str, Any]:
    summary = dict(
        getattr(state, f"noncomp_{context}_state", {}) or
        systems.get(f"_last_noncomp_{context}", {}) or
        {}
    )
    if not summary:
        return {}

    actuation = _derive_noncomp_behavior_actuation(summary)
    summary["behavior_actuation"] = dict(actuation)
    setattr(state, f"noncomp_{context}_state", dict(summary))

    pipeline_state = getattr(state, "pipeline_state", None)
    if not isinstance(pipeline_state, dict):
        return actuation

    pipeline_state[f"noncomp_{context}"] = dict(summary)
    pipeline_state[f"noncomp_{context}_behavior_actuation"] = dict(actuation)

    if context == "input":
        existing_effects = {
            str(tag or "").strip()
            for tag in list(pipeline_state.get("active_ability_effects", []) or [])
            if str(tag or "").strip()
        }
        existing_effects.update(actuation.get("effects") or [])
        if existing_effects:
            pipeline_state["active_ability_effects"] = sorted(existing_effects)

        runtime_flags = dict(pipeline_state.get("ability_runtime_flags", {}) or {})
        for key, value in dict(actuation.get("runtime_flags", {}) or {}).items():
            runtime_flags[key] = bool(runtime_flags.get(key, False) or value)
        pipeline_state["ability_runtime_flags"] = runtime_flags
    return actuation


def _select_active_abilities(
    axis_activation: Dict[str, float],
    dominant_axis: str,
    genealogy: Any,
    max_n: int = 5,
) -> List[Dict[str, Any]]:
    """
    Select the most affordable abilities from the genealogy whose primary axis
    is currently active.  Returns up to max_n ability dicts sorted by ascending
    total cost (cheapest = most available first).

    Called once per turn between the upward and downward reasoning passes so
    the pipeline knows *which* thinking operations are live this exchange.
    """
    abilities = getattr(genealogy, "abilities", None)
    if not abilities:
        return []

    def _ability_metadata(ab: Any) -> Dict[str, Any]:
        tags: List[str] = []
        if isinstance(ab, dict):
            tags = list(ab.get("effect_tags") or [])
        elif hasattr(ab, "effect_tags"):
            tags = list(getattr(ab, "effect_tags", []) or [])
        meta: Dict[str, Any] = {}
        for tag in tags:
            text = str(tag or "").strip()
            if not text:
                continue
            if text.startswith("viable_band_alignment:"):
                try:
                    meta["viable_band_alignment"] = float(text.split(":", 1)[1] or 0.0)
                except Exception:
                    pass
            elif text.startswith("ontological_status:"):
                meta["ontological_status"] = str(text.split(":", 1)[1] or "").strip().lower()
            elif text.startswith("overall_grade:"):
                try:
                    meta["overall_grade"] = float(text.split(":", 1)[1] or 0.0)
                except Exception:
                    pass
        return meta

    candidates = []
    for ab in abilities.values():
        # AbilityProfile objects (the normal runtime type) have direct attributes;
        # plain dicts are also accepted for backwards compatibility.
        if isinstance(ab, dict):
            ax       = str(ab.get("axis", "") or "")
            cost_dict = ab.get("cost") or {}
            tags      = list(ab.get("effect_tags") or [])
        elif hasattr(ab, "axis") and hasattr(ab, "effect_tags"):
            ax       = str(ab.axis or "")
            cost_dict = dict(ab.cost) if hasattr(ab, "cost") else {}
            tags      = list(ab.effect_tags or [])
        else:
            continue
        ax_val = float(axis_activation.get(ax, 0.0) or 0.0) if ax in axis_activation else 0.0
        meta = _ability_metadata(ab)
        viability = float(meta.get("viable_band_alignment", 1.0) or 1.0)
        ontological_status = str(meta.get("ontological_status", "") or "").strip().lower()

        # Clause II: if the trait is not currently viable, do not let it reach
        # expression.  The trait still exists in the genealogy, but it is not an
        # active option in the present moment.
        if ontological_status in {"excluded", "unviable", "inactive"}:
            continue
        if viability <= 0.0:
            continue
        total_cost = sum(float(v or 0.0) for v in cost_dict.values())
        # Keep the viability gradient intact: low-viability traits remain in the
        # candidate pool, but they sort behind stronger, currently supported ones.
        support_weight = max(0.0, min(1.0, ax_val))
        viability_weight = max(0.0, min(1.0, viability))
        active_weight = round((viability_weight * 0.7) + (support_weight * 0.3), 4)
        if ax == dominant_axis:
            active_weight = round(min(1.0, active_weight + 0.08), 4)
        # prefer viable, dominant-axis abilities; among similarly viable
        # abilities, keep the cheaper one first.
        sort_key = (
            0 if ax == dominant_axis else 1,
            -round(active_weight, 4),
            round(total_cost, 4),
            -round(viability_weight, 4),
        )
        # normalise to dict so downstream code uses .get() uniformly
        if not isinstance(ab, dict):
            ab = {"axis": ax, "cost": cost_dict, "effect_tags": tags,
                  "id": str(getattr(ab, "id", "") or "")}
        ab = dict(ab)
        ab["viable_band_alignment"] = viability_weight
        ab["ontological_status"] = ontological_status or str(ab.get("ontological_status", "") or "")
        ab["active_weight"] = active_weight
        candidates.append((sort_key, ab))
    candidates.sort(key=lambda tc: tc[0])
    return [ab for _, ab in candidates[:max_n]]


def _derive_applied_effects(
    pressure_before: Dict[str, Any],
    pressure_after: Dict[str, Any],
) -> Dict[str, Any]:
    """Compute simple ripple deltas between pressure snapshots."""
    out = {"operator_gradient_delta": {}, "heat_delta": 0.0}
    before_ops = (pressure_before or {}).get("operator_gradients", {}) or {}
    after_ops = (pressure_after or {}).get("operator_gradients", {}) or {}
    keys = sorted(set(before_ops.keys()) | set(after_ops.keys()))
    for k in keys:
        b = float(before_ops.get(k, 0.0) or 0.0)
        a = float(after_ops.get(k, 0.0) or 0.0)
        out["operator_gradient_delta"][k] = a - b
    try:
        hb = float(((pressure_before or {}).get("heat", {}) or {}).get("score", 0.0) or 0.0)
        ha = float(((pressure_after or {}).get("heat", {}) or {}).get("score", 0.0) or 0.0)
        out["heat_delta"] = ha - hb
    except Exception:
        out["heat_delta"] = 0.0
    return out


def _extract_role_assertion(user_text: str) -> Dict[str, Any]:
    """
    Parse role assertions needed for genealogical trace instantiation.
    Returns dict with keys: subject, relation, negated.
    """
    t = (user_text or "").strip()
    if not t:
        return {}
    m = re.search(r'\b([A-Za-z][A-Za-z0-9_-]{1,})\s+is\s+not\s+my\s+(creator|operator|co-author|coauthor)\b', t, re.IGNORECASE)
    if m:
        return {"subject": m.group(1), "relation": m.group(2).lower(), "negated": True}
    m = re.search(r'\b([A-Za-z][A-Za-z0-9_-]{1,})\s+is\s+my\s+(creator|operator|co-author|coauthor)\b', t, re.IGNORECASE)
    if m:
        return {"subject": m.group(1), "relation": m.group(2).lower(), "negated": False}
    m = re.search(r'\b([A-Za-z][A-Za-z0-9_-]{1,})\s+is\s+the\s+(creator|operator|co-author|coauthor)\b', t, re.IGNORECASE)
    if m:
        return {"subject": m.group(1), "relation": m.group(2).lower(), "negated": False}
    return {}


def _answer_relational_role_question(user_text: str, systems: Dict[str, Any]) -> Optional[Tuple[str, str, float]]:
    """
    Resolve creator/operator/co-author role questions from identity + lineage traces,
    before generic lexical fallback/search.
    """
    t = (user_text or "").strip()
    tl = t.lower()
    if not t:
        return None

    core_identity = systems.get('core_identity')
    memory = systems.get('conversation_memory')

    # Hard-anchor creator identity from immutable core identity.
    if re.search(r'\bwho\s+(made|created|built)\s+you\b|\bwho\s+is\s+your\s+creator\b', tl):
        if core_identity:
            try:
                creator = core_identity.entities.get("sunni")
                if creator:
                    return (f"My creator is {creator.name}.", "precise", 0.98)
            except Exception:
                pass
            return (core_identity.who_made_me(), "self-aware", 0.97)
        return ("My creator is Sunni (Sir) Morningstar.", "precise", 0.95)

    # "Is X your creator/operator/co-author?"
    m = re.search(r'\bis\s+([A-Za-z][A-Za-z0-9_-]{1,})\s+your\s+(creator|operator|co-author|coauthor)\b', t, re.IGNORECASE)
    if m and memory and hasattr(memory, "role_evidence"):
        subj = m.group(1)
        rel = m.group(2).lower().replace("coauthor", "co-author")
        ev = memory.role_evidence(subj, rel)
        status = ev.get("status", "unknown")
        pp = int(ev.get("pressure_points", 0) or 0)
        if status == "affirmed":
            return (f"Yes. My lineage traces currently support {subj} as {rel} "
                    f"(pressure history points: {pp}).", "precise", 0.9)
        if status == "negated":
            return (f"No. My lineage traces negate {subj} as {rel} "
                    f"(pressure history points: {pp}).", "precise", 0.92)
        if status == "mixed":
            return (f"My lineage traces for {subj} as {rel} are mixed right now "
                    f"(pressure history points: {pp}).", "attentive", 0.78)
        return (f"I don't have a stable lineage-backed role for {subj} as {rel} yet.",
                "honest", 0.72)

    # "Who is X?" — answer from lineage traces when available.
    m = re.search(r'\bwho\s+is\s+([A-Za-z][A-Za-z0-9_-]{1,})\b', t, re.IGNORECASE)
    if m and memory and hasattr(memory, "get_anchor_traces"):
        subj = m.group(1)
        traces = memory.get_anchor_traces(subj)
        if traces:
            creator_ev = memory.role_evidence(subj, "creator") if hasattr(memory, "role_evidence") else {}
            operator_ev = memory.role_evidence(subj, "operator") if hasattr(memory, "role_evidence") else {}
            coauthor_ev = memory.role_evidence(subj, "co-author") if hasattr(memory, "role_evidence") else {}

            # Compose strongest evolved role statement.
            role_bits = []
            for rel, ev in (("creator", creator_ev), ("operator", operator_ev), ("co-author", coauthor_ev)):
                st = ev.get("status", "unknown")
                if st == "affirmed":
                    role_bits.append(f"{rel}=affirmed")
                elif st == "negated":
                    role_bits.append(f"{rel}=negated")
                elif st == "mixed":
                    role_bits.append(f"{rel}=mixed")

            pp = sum(len(tr.get("pressure_history", []) or []) for tr in traces)
            if role_bits:
                return (
                    f"{subj} in my lineage memory: {', '.join(role_bits)} "
                    f"(traces={len(traces)}, pressure history points={pp}).",
                    "precise",
                    0.86,
                )
            return (
                f"I have lineage traces about {subj}, but no stable role classification yet "
                f"(traces={len(traces)}, pressure history points={pp}).",
                "attentive",
                0.75,
            )

    return None


def _evolutionary_response_refinement(
    systems: Dict[str, Any],
    user_text: str,
    base_text: str,
    tone: str = "neutral",
) -> str:
    """
    Refine responses in a development-aware way so prose and relational continuity
    evolve with Aurora's own growth signals (memory depth + language evolution + OETS).
    """
    if not base_text:
        return base_text

    perception = systems.get('perception')
    working_memory = systems.get('working_memory')
    memory = systems.get('conversation_memory')

    understanding_idx = 0.0
    evo_cycles = 0
    sentence_target = 10
    contract_state: Dict[str, Any] = {}
    base_low = str(base_text or '').lower()
    anchored_response = any(
        marker in base_low for marker in (
            "track; that; ",
            "understand; that; ",
            "thread; hold; ",
            "ground; claim; ",
            "conflict; competing claims",
            "follow; claim; ",
            "mean; that; ",
            "uncertain; about; ",
        )
    )
    anchor_terms: set[str] = set()

    try:
        if perception and getattr(perception, 'oets', None):
            stats = perception.oets.get_stats()
            understanding_idx = float(
                stats.get('understanding', {}).get('understanding_index', 0.0)
            )
    except Exception:
        pass

    understanding_contract = systems.get('understanding_contract')
    if understanding_contract is not None and hasattr(understanding_contract, 'snapshot'):
        try:
            contract_state = dict(understanding_contract.snapshot() or {})
        except Exception:
            contract_state = {}

    try:
        if perception and hasattr(perception, 'evo_status'):
            evo = perception.evo_status() or {}
            lsv = evo.get('lsv', {}) or {}
            evo_cycles = int(lsv.get('evolution_cycles', 0) or 0)
            sentence_target = int(lsv.get('sentence_length_target', 10) or 10)
    except Exception:
        pass

    growth_score = understanding_idx + min(1.0, evo_cycles / 50.0)

    # Pull learned behavior hints from DreamTrainer (what Aurora knows from simulation)
    learned_hints: List[str] = []
    try:
        dream_trainer = systems.get('dream_trainer')
        if dream_trainer is not None:
            wm = working_memory
            topic_words = []
            if wm and getattr(wm, 'current_topic', ''):
                topic_words = wm.current_topic.split()[:4]
            # Classify rough context from tone and text
            ctx_type = "general"
            if any(w in base_text.lower() for w in ("feel", "care", "understand", "sorry")):
                ctx_type = "emotional"
            elif any(w in base_text.lower() for w in ("think", "know", "believe", "certain")):
                ctx_type = "philosophy"
            learned_hints = dream_trainer.get_response_hints(ctx_type, topic_words, systems)
    except Exception:
        pass

    if working_memory:
        try:
            claim_resolution = working_memory.resolve_claims(user_text) or {}
        except Exception:
            claim_resolution = {}
        focus_claim = dict(claim_resolution.get('focus_claim', {}) or {})
        if focus_claim:
            try:
                focus_summary = working_memory._claim_to_text(focus_claim)
                anchor_terms.update(working_memory._claim_terms(focus_claim))
            except Exception:
                focus_summary = str(focus_claim.get('summary', '') or '')
                anchor_terms.update(re.findall(r"[a-z]{3,}", focus_summary.lower()))
            if focus_summary and focus_summary.lower() in base_low:
                anchored_response = True
        current_topic = str(getattr(working_memory, 'current_topic', '') or '')
        if current_topic:
            anchor_terms.update(re.findall(r"[a-z]{3,}", current_topic.lower()))
            if current_topic.lower() in base_low:
                anchored_response = True

    # Weave in a learned behavior hint only as pressure guidance, not as a canned
    # sentence. The live reply should stay grounded in Aurora's current meaning state.
    hint_is_relevant = False
    if learned_hints:
        if not anchor_terms:
            hint_is_relevant = True
        else:
            hint_is_relevant = any(
                any(term in hint.lower() for term in anchor_terms)
                for hint in learned_hints[:2]
            )

    refined = base_text.strip()

    # hint_is_relevant is computed above for future use as a pressure signal.
    # Dream-trained hints are behavioral patterns (e.g. "When I use curious inquiry...")
    # and should inform tone/pacing internally, NOT be appended literally to responses.
    # They are used as seeds in _chain_down5_understanding when comprehension is empty.

    active_frame = dict(dict(contract_state.get('M', {}) or {}).get('active_frame', {}) or {})
    active_meaning = dict(dict(contract_state.get('M', {}) or {}).get('active_meaning', {}) or {})
    meaning_complexity = len(
        re.findall(
            r"[a-z0-9]{3,}",
            " ".join(
                filter(
                    None,
                    [
                        str(active_frame.get('summary', '') or '').lower(),
                        str(active_meaning.get('meaning', '') or '').lower(),
                        str(active_meaning.get('term', '') or '').lower(),
                    ],
                )
            ),
        )
    )

    # Keep responses bounded by evolving sentence target, but let abstract or
    # explanation-heavy turns breathe so they do not clip prematurely.
    max_words = max(24, min(120, sentence_target * 3))
    if any(token in str(user_text or '').lower() for token in ('why', 'how', 'explain', 'what breaks', 'what happens')):
        max_words = max(max_words, 140 if meaning_complexity >= 6 else 118)
    elif meaning_complexity >= 8:
        max_words = max(max_words, 110)

    words = refined.split()
    if len(words) > max_words:
        refined = " ".join(words[:max_words]).rstrip(' ,;') + "..."

    return refined


def _extract_pipeline_signals(systems: Dict[str, Any]) -> Dict[str, Any]:
    """
    Read live cognitive state from the running pipeline layers.
    No extra synthesis call — reads already-computed values from
    consciousness entropy, DER, and DMM that update each tick.
    Assembly-level signals (dominant_axis, paradoxes, thought_killed)
    are populated later in dual_question_pipeline once synthesis runs.
    """
    signals: Dict[str, Any] = {
        'coherence': 1.0,
        'stagnation': 0.0,
        'novelty': 0.5,
        'thermal_load': 0.0,
        'spike_detected': False,
        'presence': 1.0,
        'dmm_alignment': 0.5,
        'dmm_vitality': 1.0,
        'dominant_axis': '',
        'paradoxes': [],
        'thought_killed': False,
        'kill_reason': '',
        'assembly_quality': 1.0,
        'comprehension_rendered': False,
    }
    try:
        signals['comprehension_rendered'] = bool(systems.pop('_rendered_from_comprehension_intent', False))
    except Exception:
        signals['comprehension_rendered'] = False
    try:
        consciousness = systems.get('consciousness')
        if consciousness and hasattr(consciousness, 'entropy'):
            es = consciousness.entropy.state
            signals['coherence'] = float(es.coherence)
            signals['stagnation'] = float(es.stagnation_score)
            signals['novelty'] = float(es.novelty)
    except Exception:
        pass
    try:
        dimensional = systems.get('dimensional')
        if dimensional:
            if hasattr(dimensional, 'der'):
                der = dimensional.der
                signals['thermal_load'] = float(der.thermal_load)
                signals['spike_detected'] = bool(der.spike_detected)
                signals['presence'] = float(der.presence)
                # Capture Clause III variables (tone, drive, passion, intensity)
                if hasattr(der, 'emotional_state'):
                    emo = der.emotional_state()
                    signals['primary_emotion'] = emo.get('primary_emotion', 'neutral')
                    signals['intensity'] = emo.get('intensity', 0.5)
                    signals['drive'] = emo.get('drive', 'steady')
                    signals['passion'] = emo.get('passion', 'observant')
            if hasattr(dimensional, 'dmm'):
                signals['dmm_alignment'] = float(dimensional.dmm.state.alignment)
                signals['dmm_vitality'] = float(dimensional.dmm.state.vitality)
    except Exception:
        pass
    try:
        last_pipeline = dict(systems.get("_last_pipeline_state") or {})
        for key in (
            "surface_reactive_emotion",
            "surface_reactive_bias",
            "surface_reactive_intensity",
            "deep_emotional_state",
            "deep_dominant_emotion",
            "deep_passion_state",
            "emotion_bridge",
            "polarity_gradient",
        ):
            value = last_pipeline.get(key)
            if value:
                signals[key] = dict(value) if isinstance(value, dict) else value
    except Exception:
        pass
    try:
        contract = systems.get('understanding_contract')
        if contract and hasattr(contract, 'state'):
            meaning_state = dict(dict(getattr(contract, 'state', {}) or {}).get('M', {}) or {})
            dominant_form = dict(meaning_state.get('dominant_meaning_form', {}) or {})
            signals['meaning_label'] = str(dominant_form.get('label', '') or '')
            signals['meaning_signature'] = str(dominant_form.get('signature', '') or '')
            signals['meaning_summary'] = str(dominant_form.get('summary', '') or '')
            signals['meaning_focus'] = str(meaning_state.get('active_topic', '') or '')
            signals['meaning_semantic_pressure'] = round(
                float(meaning_state.get('semantic_pressure', 0.0) or 0.0), 4
            )
            axes_map = dict(meaning_state.get('constraint_meaning_axes', {}) or {})
            signals['meaning_axes'] = {
                axis: float(axes_map.get(axis, 0.0) or 0.0) for axis in axes_map
            }
    except Exception:
        pass
    # Inject subsurface projection so comprehension paths can use deep state
    try:
        _proj = dict(systems.get("_subsurface_projection") or {})
        if not _proj:
            from pathlib import Path as _PPath
            _ppath = _PPath(str(systems.get("state_dir") or "aurora_state")) / "subsurface_projection.json"
            if _ppath.exists():
                _proj = dict(json.loads(_ppath.read_text()) or {})
        if _proj:
            signals["subsurface_effects"] = list(_proj.get("active_effects") or [])
            signals["subsurface_intuition"] = list(_proj.get("intuition_signals") or [])
            _pc = dict(_proj.get("pressure_coloring") or {})
            if _pc:
                signals["subsurface_guidance"] = str(_pc.get("guidance", "") or "")
                _sig = dict(_pc.get("signal") or {})
                if _sig:
                    signals["subsurface_signal_label"] = str(_sig.get("label", "") or "")
    except Exception:
        pass
    # ---- PRESENT-FRAME — attach sensory snapshot taken at turn-start ----
    try:
        _pf = dict(systems.get("_present_frame_snapshot") or {})
        if _pf:
            signals["present_frame"] = {
                "visual_description": str(_pf.get("visual_description") or ""),
                "audio_description": str(_pf.get("audio_description") or ""),
                "recent_speech": str(_pf.get("recent_speech") or ""),
                "concepts_active": list(_pf.get("concepts_active") or [])[:6],
                "recognitions": dict((dict(_pf.get("sensory_state") or {})).get("recognitions") or {}),
                "updated_at": float(_pf.get("updated_at") or 0.0),
            }
            # Boot-time present-frame — pump audio/visual into identity field immediately
            _ifield_pf = systems.get('identity_field')
            if _ifield_pf is not None and hasattr(_ifield_pf, 'ingest_sensory_event'):
                try:
                    if _pf.get("visual_description"):
                        _ifield_pf.ingest_sensory_event('visual', intensity=0.45, novelty=0.35, spatial=0.4, valence=0.0)
                    if _pf.get("audio_description") or _pf.get("recent_speech"):
                        _ifield_pf.ingest_sensory_event('auditory', intensity=0.4, novelty=0.3, valence=0.0)
                except Exception:
                    pass
    except Exception:
        pass
    # ---- Internal signal pump — consciousness emotional/entropy state → identity field ----
    # Run every tick so the field continuously reflects her inner state.
    try:
        _ifield_sig = systems.get('identity_field')
        if _ifield_sig is not None and hasattr(_ifield_sig, 'ingest_internal_signal'):
            _coherence = float(signals.get('coherence', 1.0))
            _novelty   = float(signals.get('novelty', 0.5))
            _stagnation = float(signals.get('stagnation', 0.0))
            _thermal   = float(signals.get('thermal_load', 0.0))
            # Coherence drop → reasoning pressure (B-axis)
            if _coherence < 0.7:
                _ifield_sig.ingest_internal_signal('reasoning', magnitude=1.0 - _coherence, source_axis='B')
            # High novelty → presence spike (X-axis)
            if _novelty > 0.6:
                _ifield_sig.ingest_internal_signal('memory', magnitude=_novelty * 0.6, source_axis='X')
            # Stagnation → low-level N pressure
            if _stagnation > 0.3:
                _ifield_sig.ingest_internal_signal('emotion', magnitude=_stagnation * 0.5, source_axis='N')
            # Thermal load → N-axis spike
            if _thermal > 0.4:
                _ifield_sig.ingest_internal_signal('emotion', magnitude=min(1.0, _thermal), source_axis='N')
            # Emotional state from DER
            _primary_emotion = str(signals.get('primary_emotion', '') or '')
            _intensity = float(signals.get('intensity', 0.5) or 0.5)
            if _primary_emotion and _primary_emotion != 'neutral':
                _valence = 0.4 if _primary_emotion in ('joy', 'interest', 'curiosity', 'calm') else -0.3
                _ifield_sig.ingest_sensory_event('internal', intensity=_intensity, valence=_valence) \
                    if hasattr(_ifield_sig, 'ingest_sensory_event') else None
    except Exception:
        pass
    return signals


def _build_established_strata_evidence(
    systems: Dict[str, Any],
    state: Any,
    user_text: str,
) -> Dict[str, Any]:
    """
    Package dual-strata evidence directly from Aurora's established stack.

    The goal here is to expose what the existing pipeline already knows:
    live input parsing, working-memory state, conversation continuity,
    OETS grounding, and the upward-chain understanding context.
    """
    evidence: Dict[str, Any] = {}
    pipeline_state_ref = getattr(state, "pipeline_state", None)
    if not isinstance(pipeline_state_ref, dict):
        pipeline_state_ref = {}
        try:
            setattr(state, "pipeline_state", pipeline_state_ref)
        except Exception:
            pass
    pipeline_state = dict(pipeline_state_ref or {})
    parsed = dict(getattr(state, "parsed", {}) or {})

    surface_input = {
        "raw_text": str(user_text or ""),
        "query_type": str(parsed.get("query_type", "") or ""),
        "topic_words": [
            str(word).strip()
            for word in list(parsed.get("topic_words", []) or [])
            if str(word).strip()
        ][:8],
        "stance": str(parsed.get("stance", "") or ""),
        "full_phrase": str(parsed.get("full_phrase", "") or ""),
        "recent_context": str(pipeline_state.get("recent_context", "") or ""),
        "recent_context_mode": str(pipeline_state.get("recent_context_mode", "present") or "present"),
    }
    evidence["surface_input"] = surface_input
    native_meaning_bundle = dict(
        pipeline_state.get("native_meaning_bundle")
        or systems.get("_native_meaning_bundle")
        or {}
    )
    native_meaning = dict(
        pipeline_state.get("native_meaning")
        or systems.get("_native_meaning")
        or {}
    )
    sensory_native_meaning = dict(
        pipeline_state.get("sensory_native_meaning")
        or systems.get("_sensory_native_meaning")
        or {}
    )
    if native_meaning_bundle:
        evidence["native_meaning_bundle"] = dict(native_meaning_bundle)
    if native_meaning:
        evidence["native_meaning"] = dict(native_meaning)
    if sensory_native_meaning:
        evidence["sensory_native_meaning"] = dict(sensory_native_meaning)

    question_alignment = dict(
        pipeline_state.get("question_alignment")
        or systems.get("_last_question_alignment_audit")
        or {}
    )
    if question_alignment:
        surface_input["question_alignment"] = {
            "aligned": bool(question_alignment.get("aligned", False)),
            "actual_question": str(question_alignment.get("actual_question", "") or ""),
            "answered_question": str(question_alignment.get("answered_question", "") or ""),
        }

    working_memory = systems.get("working_memory")
    conversation_memory = systems.get("conversation_memory")
    active_context_labels: List[str] = []
    if working_memory is not None:
        try:
            active_context_labels = [
                str(label).strip()
                for label, _meta in sorted(
                    list(getattr(working_memory, "active_contexts", {}).items()),
                    key=lambda item: float(dict(item[1] or {}).get("salience", 0.0) or 0.0),
                    reverse=True,
                )
                if str(label).strip()
            ][:4]
        except Exception:
            active_context_labels = []

    understanding_observation = dict(getattr(state, "understanding_observation", {}) or {})
    evidence["established_turn_state"] = {
        "intent": str(getattr(state, "intent", "") or ""),
        "dominant_axis": str(getattr(state, "dominant_axis", "") or ""),
        "axis_activation": dict(getattr(state, "axis_activation", {}) or {}),
        "emotional_state": dict(getattr(state, "emotional_state", {}) or {}),
        "surface_reactive_emotion": dict(getattr(state, "surface_reactive_emotion", {}) or {}),
        "deep_emotional_state": dict(getattr(state, "deep_emotional_state", {}) or {}),
        "deep_dominant_emotion": str(
            (getattr(state, "deep_emotional_state", {}) or {}).get("dominant", "")
            or pipeline_state.get("deep_dominant_emotion", "")
            or ""
        ),
        "deep_passion_state": str(
            (getattr(state, "deep_emotional_state", {}) or {}).get("passion", "")
            or pipeline_state.get("deep_passion_state", "")
            or ""
        ),
        "emotion_bridge": dict(
            pipeline_state.get("emotion_bridge")
            or dict(getattr(state, "emotional_state", {}) or {}).get("bridge")
            or {}
        ),
        "polarity_gradient": dict(getattr(state, "polarity_gradient", {}) or {}),
        "salient_concepts": list(getattr(state, "salient_concepts", []) or [])[:8],
        "dominant_meaning_form": dict(getattr(state, "dominant_meaning_form", {}) or {}),
        "semantic_pressure": float(getattr(state, "semantic_pressure", 0.0) or 0.0),
        "belief_tension": float(getattr(state, "belief_tension", 0.0) or 0.0),
        "goal_stack": list(getattr(state, "goal_stack", []) or [])[:6],
        "understanding_observation": understanding_observation,
        "developmental_stage": dict(getattr(state, "developmental_stage", {}) or {}),
        "learned_hints": [
            str(item).strip()
            for item in list(getattr(state, "learned_hints", []) or [])
            if str(item).strip()
        ][:6],
        "oets_concepts": list(getattr(state, "oets_concepts", []) or [])[:6],
        "recent_context": str(pipeline_state.get("recent_context", "") or ""),
        "recent_context_turns": int(pipeline_state.get("recent_context_turns", 0) or 0),
        "recent_context_mode": str(pipeline_state.get("recent_context_mode", "present") or "present"),
        "meaning_summary": str(
            pipeline_state.get("meaning_summary")
            or dict(understanding_observation.get("M", {}) or {}).get("meaning_summary")
            or ""
        ),
        "meaning_focus": str(
            pipeline_state.get("meaning_focus")
            or dict(understanding_observation.get("M", {}) or {}).get("active_topic")
            or ""
        ),
        "understanding_accuracy": float(pipeline_state.get("understanding_accuracy", 0.0) or 0.0),
        "understanding_accuracy_label": str(pipeline_state.get("understanding_accuracy_label", "") or ""),
        "understanding_fit_reason": str(
            pipeline_state.get("understanding_fit_reason")
            or dict(understanding_observation.get("A", {}) or {}).get("fit_reason")
            or ""
        ),
    }
    if question_alignment:
        evidence["established_turn_state"]["question_alignment"] = {
            "aligned": bool(question_alignment.get("aligned", False)),
            "actual_question": str(question_alignment.get("actual_question", "") or ""),
            "answered_question": str(question_alignment.get("answered_question", "") or ""),
            "actual_focus_terms": list(question_alignment.get("actual_focus_terms", []) or [])[:4],
            "answered_focus_terms": list(question_alignment.get("answered_focus_terms", []) or [])[:4],
        }

    noncomp_input_state = dict(
        getattr(state, "noncomp_input_state", {}) or
        pipeline_state.get("noncomp_input", {}) or
        systems.get("_last_noncomp_input") or
        {}
    )
    if noncomp_input_state:
        evidence["noncomp_input"] = noncomp_input_state
        evidence["established_turn_state"]["noncomp_input"] = dict(noncomp_input_state)

    noncomp_output_state = dict(
        getattr(state, "noncomp_output_state", {}) or
        pipeline_state.get("noncomp_output", {}) or
        systems.get("_last_noncomp_output") or
        {}
    )
    if noncomp_output_state:
        evidence["noncomp_output"] = noncomp_output_state
        evidence["established_turn_state"]["noncomp_output"] = dict(noncomp_output_state)

    working_memory_snapshot = dict(getattr(state, "working_memory_snapshot", {}) or {})
    if not working_memory_snapshot and working_memory is not None and hasattr(working_memory, "memory_sweep_snapshot"):
        try:
            working_memory_snapshot = dict(
                working_memory.memory_sweep_snapshot(
                    conversation_memory=conversation_memory,
                )
                or {}
            )
        except Exception:
            working_memory_snapshot = {}
    if working_memory_snapshot:
        evidence["working_memory_snapshot"] = working_memory_snapshot

    surface_conversation_frame = {
        "current_topic": str(
            working_memory_snapshot.get("current_topic")
            or getattr(working_memory, "current_topic", "")
            or ""
        ).strip(),
        "topic_stack": [
            str(item).strip()
            for item in list(working_memory_snapshot.get("topic_stack", []) or getattr(working_memory, "topic_stack", []) or [])
            if str(item).strip()
        ][:4],
        "recent_context": str(surface_input.get("recent_context", "") or ""),
        "recent_context_turns": int(
            getattr(state, "pipeline_state", {}).get("recent_context_turns", 0)
            if isinstance(getattr(state, "pipeline_state", {}), dict)
            else 0
        ),
        "recent_context_mode": str(surface_input.get("recent_context_mode", "present") or "present"),
        "active_contexts": active_context_labels,
        "referent_topic": str(dict(getattr(state, "referent_map", {}) or {}).get("topic", "") or "").strip(),
        "claim_focus": str(dict(dict(getattr(state, "claim_resolution", {}) or {}).get("focus_claim", {}) or {}).get("summary", "") or "").strip(),
        "scope": "live_surface_conversation_frame",
    }
    evidence["surface_conversation_frame"] = surface_conversation_frame

    conversation_summary: Dict[str, Any] = {}
    if conversation_memory is not None and hasattr(conversation_memory, "memory_sweep_summary"):
        try:
            conversation_summary = dict(conversation_memory.memory_sweep_summary() or {})
        except Exception:
            conversation_summary = {}
    if not conversation_summary and isinstance(working_memory_snapshot.get("conversation_memory"), dict):
        conversation_summary = dict(working_memory_snapshot.get("conversation_memory", {}) or {})
    if conversation_summary:
        evidence["conversation_memory"] = conversation_summary

    continuity_terms: List[str] = []
    for candidate in (
        working_memory_snapshot.get("current_topic"),
        evidence["established_turn_state"].get("meaning_focus"),
        *surface_input.get("topic_words", []),
        *evidence["established_turn_state"].get("salient_concepts", []),
    ):
        label = str(candidate or "").strip()
        if label and label.lower() not in {item.lower() for item in continuity_terms}:
            continuity_terms.append(label)
    continuity_recall: List[Dict[str, Any]] = []
    if conversation_memory is not None and hasattr(conversation_memory, "recall_about"):
        for anchor in continuity_terms[:2]:
            try:
                recalls = [
                    str(item).strip()
                    for item in list(conversation_memory.recall_about(anchor) or [])
                    if str(item).strip()
                ][:2]
            except Exception:
                recalls = []
            if recalls:
                continuity_recall.append({"anchor": anchor, "recalls": recalls})
    if continuity_recall:
        evidence["continuity_recall"] = continuity_recall

    evidence["subsurface_continuity_bundle"] = {
        "conversation_summary": conversation_summary,
        "continuity_recall": continuity_recall,
        "scope": "subsurface_continuity_memory",
        "retention_owner": "subsurface",
        "surface_access": "DCE_softened_only",
    }

    perception = systems.get("perception")
    oets = getattr(perception, "oets", None) if perception is not None else None
    if oets is not None:
        oets_stats: Dict[str, Any] = {}
        try:
            if hasattr(oets, "get_stats"):
                oets_stats = dict(oets.get_stats() or {})
        except Exception:
            oets_stats = {}
        understanding = dict(oets_stats.get("understanding", {}) or {})
        active_concepts = [
            str(item.get("word", "") or "").strip()
            for item in list(evidence["established_turn_state"].get("oets_concepts", []) or [])
            if isinstance(item, dict) and str(item.get("word", "") or "").strip()
        ]
        evidence["oets_context"] = {
            "active_concepts": active_concepts[:6],
            "grounding_index": round(float(understanding.get("grounding_index", 0.0) or 0.0), 4),
            "topic_tracking": round(float(understanding.get("topic_tracking", 0.0) or 0.0), 4),
            "semantic_coherence": round(
                float(
                    understanding.get(
                        "semantic_coherence",
                        understanding.get("coherence_index", 0.0),
                    )
                    or 0.0
                ),
                4,
            ),
        }

    # ── Pre-batch parallel telemetry into evidence so downstream stages read ──
    # the snapshot once rather than each fetching individually.

    # IVM pressure snapshot (axis heat from the lattice)
    try:
        _lattice = systems.get('lattice') or getattr(systems.get('aurora'), '_lattice', None)
        if _lattice is not None and hasattr(_lattice, 'vertices'):
            _dis = _lattice.vertices.compute_dissonance()
            evidence['ivm_pressure'] = {
                'total_heat': round(float(getattr(_lattice, 'get_global_heat', lambda: 0.0)()), 4),
                'axis_heat': {ax: round(float(_dis.get(ax, _dis.get('total_heat', 0.0)) or 0.0), 4)
                              for ax in ('X', 'T', 'N', 'B', 'A')},
            }
    except Exception:
        pass

    # SediMemory recall snapshot (5-axis stratigraphic memory)
    try:
        _sedi = systems.get('sedimemory')
        if _sedi is not None and hasattr(_sedi, 'recall_semantic'):
            _sedi_rec = _sedi.recall_semantic(
                query_text=str(user_text or '')[:120],
                max_results=4,
                axis_filter=['X', 'T', 'N', 'B', 'A'],
                min_score=0.2,
            )
            evidence['sedimemory_recall'] = [
                {
                    'content': str((dict(r or {}).get('summary', '') or dict(r or {}).get('content', '')) )[:120],
                    'axis': str(dict(r or {}).get('axis', '') or ''),
                    'score': round(float(dict(r or {}).get('score', 0.0) or 0.0), 4),
                }
                for r in list(_sedi_rec or [])[:4]
            ]
    except Exception:
        pass

    # Grammar state hint (discourse mode from grammar engine)
    try:
        _ge = systems.get('grammar_engine')
        if _ge is not None and hasattr(_ge, 'suggest_discourse'):
            _disc = _ge.suggest_discourse()
            if _disc:
                evidence['grammar_discourse_hint'] = str(_disc)
    except Exception:
        pass

    # Poedex pre-fetch: if OETS has flagged an active concept gap, stage a
    # background define-lookup into live pipeline state and the evidence packet
    # so DCE can use it when it arrives instead of losing it in a local copy.
    try:
        _active_gap = ''
        _ps_now = pipeline_state_ref if isinstance(pipeline_state_ref, dict) else {}
        _active_gap = str(_ps_now.get('oets_gap', '') or _ps_now.get('concept_gap', '') or '')
        _prefetch_concept = str(_ps_now.get('poedex_prefetch_concept', '') or '').strip()
        _prefetch_result = str(_ps_now.get('poedex_prefetch_result', '') or '').strip()
        _learning_concept = str(_ps_now.get('poedex_learning_concept', '') or '').strip()
        _learning_result = str(_ps_now.get('poedex_learning_result', '') or '').strip()
        _representation_concept = str(_ps_now.get('poedex_representation_concept', '') or '').strip()
        _representation_result = str(_ps_now.get('poedex_representation_result', '') or '').strip()
        if _prefetch_concept and _active_gap and _prefetch_concept.lower() != _active_gap.lower():
            _ps_now.pop('poedex_prefetch_result', None)
            _ps_now.pop('poedex_prefetch_concept', None)
            _ps_now.pop('poedex_prefetch_status', None)
            _prefetch_concept = ''
            _prefetch_result = ''
        if _prefetch_result and (_prefetch_concept or _active_gap):
            evidence['poedex_prefetch'] = {
                'concept': _prefetch_concept or _active_gap,
                'result': _prefetch_result,
                'status': str(_ps_now.get('poedex_prefetch_status', 'ready') or 'ready'),
            }
        if _learning_concept and _learning_result:
            evidence['poedex_learning'] = {
                'concept': _learning_concept,
                'result': _learning_result,
                'note': str(_ps_now.get('poedex_learning_note', '') or ''),
                'request': str(_ps_now.get('poedex_learning_request', '') or ''),
                'status': str(_ps_now.get('poedex_learning_status', 'ready') or 'ready'),
                'applied': bool(_ps_now.get('poedex_learning_applied', False)),
            }
        if _representation_concept and _representation_result:
            evidence['poedex_representation'] = {
                'concept': _representation_concept,
                'result': _representation_result,
                'request': str(_ps_now.get('poedex_representation_request', '') or ''),
                'status': str(_ps_now.get('poedex_representation_status', 'ready') or 'ready'),
                'variants': list(_ps_now.get('poedex_representation_variants', []) or [])[:6],
            }
        _lookup_concept = str(_ps_now.get('poedex_lookup_concept', '') or '').strip()
        _lookup_result = str(_ps_now.get('poedex_lookup_result', '') or '').strip()
        if not _lookup_result:
            _lookup_packet = dict(systems.get("_last_poedex_lookup") or {})
            _lookup_concept = _lookup_concept or str(_lookup_packet.get("concept", "") or "").strip()
            _lookup_result = str(_lookup_packet.get("result", "") or "").strip()
        if _lookup_result:
            evidence['poedex_lookup'] = {
                'concept': _lookup_concept,
                'request': str(_ps_now.get('poedex_lookup_request', '') or ''),
                'result': _lookup_result,
                'status': str(_ps_now.get('poedex_lookup_status', 'ready') or 'ready'),
            }
        _poedex_fn = systems.get('poedex')
        if _active_gap and not _prefetch_result and _poedex_fn is not None and callable(_poedex_fn):
            evidence['poedex_prefetch'] = {
                'concept': _active_gap,
                'result': '',
                'status': 'pending',
            }
            _ps_now['poedex_prefetch_concept'] = _active_gap
            _ps_now['poedex_prefetch_status'] = 'pending'
            import threading as _pth
            def _prefetch_gap(gap=_active_gap):
                try:
                    _result = _poedex_fn(gap, cat='define', lane='self', timeout=6.0)
                    if _result:
                        _payload = {
                            'concept': gap,
                            'result': str(_result),
                            'status': 'ready',
                        }
                        _ps_now['poedex_prefetch_result'] = _payload['result']
                        _ps_now['poedex_prefetch_concept'] = gap
                        _ps_now['poedex_prefetch_status'] = 'ready'
                        evidence['poedex_prefetch'] = dict(_payload)
                    else:
                        _ps_now['poedex_prefetch_status'] = 'empty'
                        evidence['poedex_prefetch'] = {
                            'concept': gap,
                            'result': '',
                            'status': 'empty',
                        }
                except Exception:
                    _ps_now['poedex_prefetch_status'] = 'error'
                    evidence['poedex_prefetch'] = {
                        'concept': gap,
                        'result': '',
                        'status': 'error',
                    }
            _pth.Thread(target=_prefetch_gap, daemon=True).start()
        if _active_gap and not _learning_result and _poedex_fn is not None and callable(_poedex_fn):
            evidence['poedex_learning'] = {
                'concept': _active_gap,
                'result': '',
                'status': 'pending',
            }
            _ps_now['poedex_learning_concept'] = _active_gap
            _ps_now['poedex_learning_status'] = 'pending'
            import threading as _pth
            def _learn_gap(gap=_active_gap):
                try:
                    _request = f"What new material should Aurora learn about {gap}?"
                    _result = _poedex_fn(_request, cat='researcher', lane='self', timeout=12.0)
                    if _result:
                        _payload = _apply_poedex_learning_result(
                            systems,
                            gap,
                            _request,
                            str(_result),
                            source_text=_request,
                        )
                        _payload = dict(_payload or {})
                        _payload.update({
                            'concept': gap,
                            'request': _request,
                            'result': str(_result),
                            'status': 'ready',
                        })
                        _ps_now['poedex_learning_result'] = _payload['result']
                        _ps_now['poedex_learning_request'] = _request
                        _ps_now['poedex_learning_note'] = str(_payload.get('learning_note', '') or '')[:400]
                        _ps_now['poedex_learning_status'] = 'ready'
                        evidence['poedex_learning'] = dict(_payload)
                    else:
                        _ps_now['poedex_learning_status'] = 'empty'
                        evidence['poedex_learning'] = {
                            'concept': gap,
                            'result': '',
                            'status': 'empty',
                        }
                except Exception:
                    _ps_now['poedex_learning_status'] = 'error'
                    evidence['poedex_learning'] = {
                        'concept': gap,
                        'result': '',
                        'status': 'error',
                    }
            _pth.Thread(target=_learn_gap, daemon=True).start()
        if _active_gap and not _representation_result and _poedex_fn is not None and callable(_poedex_fn):
            evidence['poedex_representation'] = {
                'concept': _active_gap,
                'result': '',
                'status': 'pending',
                'variants': [],
            }
            _ps_now['poedex_representation_concept'] = _active_gap
            _ps_now['poedex_representation_status'] = 'pending'
            import threading as _pth
            def _represent_gap(gap=_active_gap):
                try:
                    _request = (
                        f"What are other ways to represent {gap} in human language? "
                        f"Give alternate phrasing, registers, and paraphrases."
                    )
                    _result = _poedex_fn(_request, cat='researcher', lane='self', timeout=12.0)
                    if _result:
                        _payload = _apply_poedex_representation_result(
                            systems,
                            gap,
                            _request,
                            str(_result),
                            source_text=_request,
                        )
                        _payload = dict(_payload or {})
                        _payload.update({
                            'concept': gap,
                            'request': _request,
                            'result': str(_result)[:400],
                            'status': 'ready',
                        })
                        _ps_now['poedex_representation_result'] = _payload['result']
                        _ps_now['poedex_representation_request'] = _request
                        _ps_now['poedex_representation_status'] = 'ready'
                        _ps_now['poedex_representation_variants'] = list(_payload.get('variants', []) or [])[:6]
                        evidence['poedex_representation'] = dict(_payload)
                    else:
                        _ps_now['poedex_representation_status'] = 'empty'
                        evidence['poedex_representation'] = {
                            'concept': gap,
                            'result': '',
                            'status': 'empty',
                            'variants': [],
                        }
                except Exception:
                    _ps_now['poedex_representation_status'] = 'error'
                    evidence['poedex_representation'] = {
                        'concept': gap,
                        'result': '',
                        'status': 'error',
                        'variants': [],
                    }
            _pth.Thread(target=_represent_gap, daemon=True).start()
    except Exception:
        pass

    if dict(evidence.get('poedex_prefetch') or {}).get('result'):
        evidence["established_turn_state"]["poedex_prefetch"] = dict(evidence.get('poedex_prefetch') or {})
    if dict(evidence.get('poedex_learning') or {}).get('result'):
        evidence["established_turn_state"]["poedex_learning"] = dict(evidence.get('poedex_learning') or {})
    if dict(evidence.get('poedex_representation') or {}).get('result'):
        evidence["established_turn_state"]["poedex_representation"] = dict(evidence.get('poedex_representation') or {})
    if dict(evidence.get('poedex_lookup') or {}).get('result'):
        evidence["established_turn_state"]["poedex_lookup"] = dict(evidence.get('poedex_lookup') or {})

    # ── Self-grounding memos from this turn (Poedex results mapped to capabilities) ──
    _sg = list(systems.get("_self_groundings") or [])
    if _sg:
        evidence["aurora_self_groundings"] = _sg[-3:]
        evidence["established_turn_state"]["self_groundings"] = [
            g.get("note", "") for g in _sg[-3:] if g.get("note")
        ]

    # ── ReflexiveInterpreter — constraint/worth/frame for this user expression ──
    # Uses aurora_reflexive_interpreter.py v2: UtteranceParser-backed matching +
    # Worth-formula reconciliation → UnderstandingState fed into DCE evidence.
    try:
        _ri = systems.get("_reflexive_interp")
        if _ri is None:
            from aurora_reflexive_interpreter import ReflexiveInterpreter as _RI
            _ri_dir = systems.get("_manifold_directory")
            _ri_router = systems.get("_manifold_router")
            _ri = _RI(directory=_ri_dir, router=_ri_router)
            systems["_reflexive_interp"] = _ri
        if _ri is not None and user_text:
            _ri_state = _ri.interpret(user_text)
            evidence["reflexive_understanding"] = _ri_state.to_dict()
            evidence["established_turn_state"].update({
                "reflexive_worth":      round(_ri_state.worth_score, 4),
                "reflexive_frame":      _ri_state.frame,
                "reflexive_constraint": _ri_state.constraint,
                "reflexive_dimension":  _ri_state.dimension,
                "reflexive_trajectory": _ri_state.worth_trajectory,
                "reflexive_understood": _ri_state.is_understood,
                "reflexive_coherent":   _ri_state.polarity_coherent,
            })
            if _ri_state.nc_name:
                evidence["established_turn_state"]["reflexive_nc"] = _ri_state.nc_name
            if _ri_state.summary:
                evidence["established_turn_state"]["reflexive_summary"] = _ri_state.summary
    except Exception:
        pass

    evidence["established_stack_sources"] = [
        "TurnUnderstandingState",
        "WorkingMemory",
        "ConversationMemory",
        "ExpressionPerception/OETS",
        "UnderstandingContract",
        "DimensionalSystems.process_synthesis",
        "DCEAssembly",
        "IVMPressure",
        "SediMemoryRecall",
        "GrammarState",
    ]
    if noncomp_input_state:
        evidence["established_stack_sources"].append("NoncompInput")
    if noncomp_output_state:
        evidence["established_stack_sources"].append("NoncompOutput")
    if dict(evidence.get("poedex_prefetch") or {}).get("result"):
        evidence["established_stack_sources"].append("Poedex")
    if dict(evidence.get("poedex_learning") or {}).get("result"):
        evidence["established_stack_sources"].append("PoedexLearning")
    if dict(evidence.get("poedex_representation") or {}).get("result"):
        evidence["established_stack_sources"].append("PoedexRepresentation")
    if dict(evidence.get("poedex_lookup") or {}).get("result"):
        evidence["established_stack_sources"].append("PoedexLookup")
    if evidence.get("reflexive_understanding"):
        evidence["established_stack_sources"].append("ReflexiveInterpreter")
    if _sg:
        evidence["established_stack_sources"].append("SelfGrounding")
    return evidence


def _dual_strata_state_dir(systems: Dict[str, Any]) -> Path:
    return Path(str(systems.get("state_dir") or (Path(__file__).parent / "aurora_state")))


def _read_dual_strata_json(path: Path, default: Any) -> Any:
    if path.exists():
        try:
            return json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            pass
    return default


def _write_dual_strata_json(path: Path, payload: Any) -> None:
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        tmp = path.with_suffix(path.suffix + ".tmp")
        tmp.write_text(
            json.dumps(payload, indent=2, ensure_ascii=True, sort_keys=True),
            encoding="utf-8",
        )
        tmp.replace(path)
    except Exception:
        pass


def _build_live_subsurface_projection(
    systems: Dict[str, Any],
    state: Any,
    user_text: str,
) -> Dict[str, Any]:
    # Fix: Surface should NOT build or overwrite the subsurface projection.
    # It should only read the softened signals from the subsurface daemon.
    state_dir = _dual_strata_state_dir(systems)
    projection = {}
    try:
        from pathlib import Path as _Path
        _proj_path = _Path(str(state_dir)) / "subsurface_projection.json"
        if _proj_path.exists():
            import json
            projection = dict(json.loads(_proj_path.read_text()) or {})
    except Exception:
        projection = {}

    if not projection:
        projection = dict(systems.get("_subsurface_projection") or {})

    if not projection:
        return {}

    # Annotate with turn context in memory for the bridge call, 
    # but DO NOT write back to disk to avoid race conditions with Subsurface.
    projection["turn_context"] = {
        "input": str(user_text or "")[:280],
        "intent": str(getattr(state, "intent", "") or ""),
        "dominant_axis": str(getattr(state, "dominant_axis", "") or ""),
        "response_source": str(getattr(state, "response_src", "") or ""),
    }
    systems["_subsurface_projection"] = dict(projection)
    return projection


def _read_live_dual_strata_runtime(systems: Dict[str, Any]) -> Dict[str, Any]:
    snapshot_payload = _read_dual_strata_json(
        _dual_strata_state_dir(systems) / "dual_strata_snapshot.json",
        {},
    )
    if not isinstance(snapshot_payload, dict):
        snapshot_payload = {}
    conscious_frame = dict(snapshot_payload.get("conscious_frame") or {})
    conscious_crest = dict(conscious_frame.get("conscious_crest") or {})
    overlay = dict(conscious_frame.get("overlay") or {})
    return {
        "conscious_frame": conscious_frame,
        "conscious_crest": conscious_crest,
        "processing_mode": str(
            conscious_frame.get("processing_mode", "") or conscious_crest.get("label", "")
        ),
        "overlay": overlay,
        "subsurface_state": dict(snapshot_payload.get("subsurface_state") or {}),
    }


def _refresh_live_dual_strata_runtime(
    systems: Dict[str, Any],
    *,
    synthesis: Any,
    payload: Any,
    payload_type: str,
    evidence: Dict[str, Any],
    contract_snapshot: Dict[str, Any],
    requested_frame: str,
) -> Dict[str, Any]:
    assembly = getattr(synthesis, "assembly", None) if synthesis is not None else None
    if assembly is None:
        runtime = _read_live_dual_strata_runtime(systems)
        if runtime:
            systems["_last_dual_strata_runtime"] = dict(runtime)
        return runtime

    try:
        from aurora_internal.dual_strata.dce_bridge import DualStrataBridge
    except Exception:
        return _read_live_dual_strata_runtime(systems)

    try:
        bridge = systems.get("_dual_strata_bridge")
        if bridge is None:
            bridge = DualStrataBridge(state_dir=str(_dual_strata_state_dir(systems)))
            systems["_dual_strata_bridge"] = bridge
        snapshot = bridge.build_snapshot(
            assembly,
            payload=payload,
            payload_type=payload_type,
            evidence=dict(evidence or {}),
            contract_snapshot=dict(contract_snapshot or {}),
            requested_frame=str(requested_frame or "balanced"),
            thought_intent=None,
        )
    except Exception:
        return _read_live_dual_strata_runtime(systems)

    _cf = dict(snapshot.conscious_frame or {})
    runtime = {
        "conscious_frame": _cf,
        "conscious_crest": dict(_cf.get("conscious_crest") or {}),
        "processing_mode": str(_cf.get("processing_mode", "") or ""),
        "overlay": dict(_cf.get("overlay") or {}),
        "subsurface_state": dict(snapshot.subsurface_state or {}),
    }
    systems["_last_dual_strata_runtime"] = dict(runtime)
    return runtime


def _derive_problem_solving_drive(
    signals: Optional[Dict[str, Any]],
    text: str = "",
) -> Dict[str, Any]:
    """
    Convert live problem signals into an active repair-and-learn posture.

    Aurora should not stop at reporting a problem. When a pressure spike,
    low coherence, or loop pressure appears, she should orient toward
    resolution so the pressure becomes fuel for learning and growth.
    """
    if not isinstance(signals, dict):
        return {}

    try:
        coherence = float(signals.get("coherence", 1.0))
    except Exception:
        coherence = 1.0
    try:
        stagnation = float(signals.get("stagnation", 0.0))
    except Exception:
        stagnation = 0.0
    try:
        thermal_load = float(signals.get("thermal_load", 0.0))
    except Exception:
        thermal_load = 0.0
    spike_detected = bool(signals.get("spike_detected"))

    lower = str(text or "").lower()
    if "work through" in lower or "learn what" in lower or "learn from" in lower:
        return {}

    if coherence < 0.3:
        return {
            "issue": "coherence_maintenance",
            "intervention": "active_self_repair_orientation",
            "intended_effect": "turn low coherence into focused repair and learning pressure",
            "line": "I'm tightening to the clearest thread and repairing coherence directly.",
            "tags": ["dialogue", "self_repair", "coherence", "learning"],
            "reason_about": True,
            "confidence_cap": 0.58,
        }

    if spike_detected and thermal_load > 0.6:
        return {
            "issue": "contradiction_resolution",
            "intervention": "active_self_repair_orientation",
            "intended_effect": "turn contradiction pressure into direct resolution work and learning",
            "line": "I'm working through the contradiction directly and trying to resolve it cleanly.",
            "tags": ["dialogue", "self_repair", "contradiction", "learning"],
            "reason_about": True,
            "confidence_cap": 0.68,
        }

    if stagnation > 0.5:
        return {
            "issue": "response_loop_pressure",
            "intervention": "active_self_repair_orientation",
            "intended_effect": "turn loop pressure into active experimentation and learning",
            "line": "I'm going to test a different angle and learn which framing actually moves this forward.",
            "tags": ["dialogue", "self_repair", "stagnation", "learning"],
            "reason_about": True,
            "confidence_cap": 0.70,
        }

    meaning_label = str(signals.get("meaning_label", "") or "").strip()
    meaning_focus = str(signals.get("meaning_focus", "") or "").strip()
    meaning_signature = str(signals.get("meaning_signature", "") or "")
    meaning_pressure = float(signals.get("meaning_semantic_pressure", 0.0) or 0.0)
    if (
        meaning_label
        and meaning_pressure > 0.55
        and meaning_signature
        and meaning_signature.count("*") >= 1
    ):
        focus_display = meaning_focus or "the current thread"
        sanitized_issue = re.sub(r"[^a-z0-9_]", "", meaning_label.replace(" ", "_").lower()) or "meaning_surface"
        return {
            "issue": f"meaning_{sanitized_issue}",
            "intervention": "meaning_surface_alignment",
            "intended_effect": f"keep the evolving {meaning_label} surface coherent before resolving.",
            "line": (
                f"surface; {meaning_label}; {focus_display}; "
                f"{meaning_signature}; resolve"
            ),
            "tags": ["dialogue", "meaning", meaning_label.lower()],
            "reason_about": True,
            "confidence_cap": 0.72,
        }

    return {}


def _problem_drive_runtime_event(signals: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    drive = dict((signals or {}).get("_problem_solving_drive", {}) or {})
    if not drive:
        return {}
    return _make_quasiarch_runtime_event(
        target="aurora.dialogue.self_repair",
        issue=str(drive.get("issue", "") or "runtime_diagnostic_anomaly"),
        logic_tier="runtime_orchestration",
        intervention=str(drive.get("intervention", "") or "active_self_repair_orientation"),
        intended_effect=str(
            drive.get("intended_effect", "")
            or "convert detected problems into active repair and learning behavior"
        ),
        observed_effect="resolved_partially",
        tags=list(drive.get("tags", []) or []),
        reason_about=bool(drive.get("reason_about", True)),
    )


def _apply_pipeline_modulation(
    text: str, tone: str, conf: float,
    signals: Optional[Dict[str, Any]],
) -> Tuple[str, str, float]:
    """
    Post-process a response using live pipeline state signals.

    Applies:
      - Thermal honesty  (DER spike_detected / thermal_load)
      - Coherence hedging (L4 entropy coherence)
      - Stagnation pressure (entropy stagnation_score)
      - Paradox surfacing  (I-State being conflicts from AssemblyResult)
      - Thought-kill acknowledgment (DMM moral friction → metabolic collapse)
      - Dominant-axis tone register (from AssemblyResult.dominant_axis)
      - Assembly quality gating (AssemblyResult.quality)

    All modifications are additive. Never destroys the base response.
    """
    if not signals or not text:
        return text, tone, conf
    if isinstance(signals, dict):
        signals.pop("_problem_solving_drive", None)

    # ---- Thermal spike: dissonance is heating the system ----
    # Heat affects tone and confidence -- the friction surfaces through how she
    # speaks, not through an appended sentence scripted by the developer.
    if signals.get('spike_detected'):
        heat = signals.get('thermal_load', 0.0)
        if tone in ('neutral', 'attentive', 'precise'):
            tone = 'uncertain'
        if heat > 0.8:
            conf = min(conf, 0.55)
        elif heat > 0.6:
            conf = min(conf, 0.65)

    # ---- Low coherence: degraded L4 assembly cycle ----
    coherence = signals.get('coherence', 1.0)
    grounded_prefixes = (
        "track; that; ",
        "clarify; ",
        "mean; ",
        "conflict; competing claims",
        "mean; that; ",
        "uncertain; about; ",
        "talk; about; ",
        "grounding; missing; ",
        "because; ",
        "preserve; ",
        "it works; ",
        "thread; hold; ",
        "ground; claim; ",
        "check; ",
    )
    if coherence < 0.3:
        conf = min(conf, 0.55)
    elif coherence < 0.5:
        conf = min(conf, 0.72)

    # ---- High stagnation: loop pressure building ----
    if signals.get('stagnation', 0.0) > 0.5:
        conf = min(conf, 0.70)

    surface_reactive = dict(signals.get("surface_reactive_emotion", {}) or {})
    surface_bias = str(
        surface_reactive.get("behavior_bias", "")
        or signals.get("surface_reactive_bias", "")
        or ""
    )
    surface_intensity = float(
        surface_reactive.get("intensity", signals.get("surface_reactive_intensity", 0.0)) or 0.0
    )
    if surface_bias == "slow_down":
        if tone in ('neutral', 'attentive', 'precise', 'direct', 'engaged'):
            tone = 'careful'
        if surface_intensity > 0.45:
            conf = min(conf, 0.72)
    elif surface_bias in {'lean_in', 'probe'}:
        if tone in ('neutral', 'attentive', 'reflective'):
            tone = 'curious'
    elif surface_bias == 'steady' and tone == 'neutral':
        tone = 'attentive'

    problem_drive = {} if signals.get('comprehension_rendered') else _derive_problem_solving_drive(signals, text)
    if problem_drive:
        signals["_problem_solving_drive"] = dict(problem_drive)
        if tone in ('neutral', 'attentive', 'precise'):
            tone = 'engaged'
        try:
            conf = min(conf, float(problem_drive.get("confidence_cap", conf)))
        except Exception:
            pass

    # ---- Paradoxes: opposing I-State beings both activated ----
    # Paradoxes now modulate tone and confidence directly rather than being
    # appended as scripted strings. This allows the dissonance to be felt
    # in her voice choice.
    paradoxes = signals.get('paradoxes', [])
    if paradoxes:
        if tone in ('neutral', 'attentive', 'precise'):
            tone = 'uncertain'
        conf = min(conf, 0.72)

    # ---- Thought killed by DMM moral friction ----
    if signals.get('thought_killed'):
        if tone in ('neutral', 'attentive'):
            tone = 'reflective'
        conf = min(conf, 0.85)

    # ---- Dominant axis → tone register ----
    # Note: dominant_axis is stored as a letter (X/T/N/B/A), not a full name.
    _axis_tone = {
        'X': 'reflective',
        'T': 'attentive',
        'N': 'engaged',
        'B': 'observational',
        'A': 'direct',
    }
    axis = signals.get('dominant_axis', '')
    if axis and tone in ('neutral', 'attentive') and axis in _axis_tone:
        tone = _axis_tone[axis]

    # ---- DER dominant emotion → tone refinement ----
    # Overrides axis tone when emotional state is strong enough to colour expression.
    _emotion_tone = {
        'curiosity': 'curious',
        'joy':       'warm',
        'calm':      'attentive',
        'fear':      'uncertain',
        'anger':     'direct',
        'sadness':   'reflective',
    }
    dom_emotion = str(surface_reactive.get('dominant', '') or signals.get('dominant_emotion', '') or '')
    em_coherence = signals.get('emotional_coherence', 1.0)
    if dom_emotion and dom_emotion != 'calm' and em_coherence > 0.4:
        em_tone = _emotion_tone.get(dom_emotion)
        if em_tone and tone in ('neutral', 'attentive', 'reflective'):
            tone = em_tone

    # ---- Low assembly quality: acknowledge reduced depth ----
    if signals.get('assembly_quality', 1.0) < 0.3 and not signals.get('thought_killed'):
        conf = min(conf, 0.60)

    return text, tone, conf


# ---- Pipeline ability registration (constraint-traceability) ----
_PIPELINE_ABILITIES_REGISTERED: bool = False


def _ensure_pipeline_abilities(genealogy: Any) -> None:
    """
    Register AbilityProfiles for _extract_pipeline_signals and
    _apply_pipeline_modulation into the genealogy logger so both
    new operations are traceable through the evolutionary chain.
    Called lazily on first modulation event.
    """
    global _PIPELINE_ABILITIES_REGISTERED
    if _PIPELINE_ABILITIES_REGISTERED or not genealogy:
        return
    try:
        from aurora_evolution_stack import AbilityProfile
        from aurora_internal.constraint_genealogy import _augment_ability_profile_with_origin

        _sig_ap = AbilityProfile(
            id="N:READ_PIPELINE_STATE",
            axis="N",
            requires=("T", "N", "B", "A"),
            cost={"X": 0.0, "T": 0.01, "N": 0.02, "B": 0.01, "A": 0.01},
            risk={"X": 0.0, "T": 0.0, "N": 0.0, "B": 0.0, "A": 0.0},
            effect_tags=(
                "energy_read", "thermal_snapshot", "entropy_snapshot",
                "dmm_state_read", "boundary_presence",
            ),
            notes="Map pipeline signals to generative tone and confidence.",
        )
        _mod_ap = AbilityProfile(
            id="B:SHAPE_EXPRESSION_BOUNDARY",
            axis="B",
            requires=("X", "B", "A"),
            cost={"X": 0.0, "T": 0.01, "N": 0.01, "B": 0.02, "A": 0.01},
            risk={"X": 0.0, "T": 0.0, "N": 0.0, "B": 0.01, "A": 0.0},
            effect_tags=(
                "boundary_shaping", "tone_shift", "confidence_gate",
                "paradox_surface", "thought_kill_surface", "axis_tone_register",
            ),
            notes=(
                "Shape the outbound expression boundary using live pipeline signals: "
                "thermal honesty, coherence hedging, paradox surfacing, "
                "thought-kill acknowledgment, dominant-axis tone register."
            ),
        )

        if hasattr(genealogy, 'abilities'):
            genealogy.abilities[_sig_ap.id] = _augment_ability_profile_with_origin(_sig_ap)
            genealogy.abilities[_mod_ap.id] = _augment_ability_profile_with_origin(_mod_ap)
        _PIPELINE_ABILITIES_REGISTERED = True
    except Exception:
        pass


def _log_modulation_event(
    genealogy: Any,
    signals: Dict[str, Any],
    text_changed: bool,
    tone_changed: bool,
) -> None:
    """
    Log a genealogy relief event after _apply_pipeline_modulation fires.
    Encodes current pipeline tension as pressure_before; shaped output
    boundary as pressure_after. Relief = tension reduced by modulation.
    Only logs when modulation actually modified the response.
    Traces back to:
      N:READ_PIPELINE_STATE   (N-axis, energy read)
      B:SHAPE_EXPRESSION_BOUNDARY  (B-axis, boundary shaping)
    """
    if not genealogy or not (text_changed or tone_changed):
        return
    try:
        from aurora_evolution_stack import PressureVec, TraceItem
        _ensure_pipeline_abilities(genealogy)

        # Pressure before: live pipeline tension at this moment
        p_before = PressureVec(
            X=0.0,
            T=float(signals.get('stagnation', 0.0)),
            N=float(signals.get('thermal_load', 0.0)),
            B=max(0.0, 1.0 - float(signals.get('coherence', 1.0))),
            A=1.0 if signals.get('thought_killed') else 0.0,
        )
        # Pressure after: boundary is shaped — T/N/B pressures relieved ~10-20%,
        # A collapses to 0 (thought-kill acknowledged and surfaced)
        p_after = PressureVec(
            X=0.0,
            T=p_before.T * 0.85,
            N=p_before.N * 0.90,
            B=p_before.B * 0.80,
            A=0.0,
        )

        trace = [
            TraceItem(kind="ABILITY", id="N:READ_PIPELINE_STATE"),
            TraceItem(kind="ABILITY", id="B:SHAPE_EXPRESSION_BOUNDARY"),
        ]
        tick = int(getattr(genealogy, 'tick_count', 0))
        genealogy.observe(
            pressure_before=p_before,
            trace=trace,
            pressure_after=p_after,
            state_sig_before=f"pre_mod_t{tick}",
            state_sig_after=f"post_mod_t{tick}",
            notes={
                "source": "apply_pipeline_modulation",
                "text_changed": text_changed,
                "tone_changed": tone_changed,
            },
        )
    except Exception:
        pass


_CLAIM_RELIEF_ABILITIES_REGISTERED: bool = False


def _ensure_claim_relief_abilities(genealogy: Any) -> None:
    global _CLAIM_RELIEF_ABILITIES_REGISTERED
    if _CLAIM_RELIEF_ABILITIES_REGISTERED or not genealogy:
        return
    try:
        from aurora_evolution_stack import AbilityProfile
        from aurora_internal.constraint_genealogy import _augment_ability_profile_with_origin

        _clear_ap = AbilityProfile(
            id="T:CLEAR_RESOLVED_CONFLICT",
            axis="T",
            requires=("T", "B", "A"),
            cost={"X": 0.0, "T": 0.02, "N": 0.0, "B": 0.01, "A": 0.01},
            risk={"X": 0.0, "T": 0.0, "N": 0.0, "B": 0.0, "A": 0.0},
            effect_tags=("resolved_conflict_clear", "anchor_recenter", "state_release"),
            notes="Clear resolved contradiction state and recenter the active claim after relief.",
        )
        _branch_ap = AbilityProfile(
            id="B:SEPARATE_COMPETING_CLAIMS",
            axis="B",
            requires=("X", "T", "B"),
            cost={"X": 0.0, "T": 0.01, "N": 0.0, "B": 0.02, "A": 0.0},
            risk={"X": 0.0, "T": 0.0, "N": 0.0, "B": 0.0, "A": 0.0},
            effect_tags=("claim_branching", "coexistence_detection", "contradiction_boundary"),
            notes="Separate coexisting claims from true contradiction so valid plurality does not stall processing.",
        )

        if hasattr(genealogy, 'abilities'):
            genealogy.abilities[_clear_ap.id] = _augment_ability_profile_with_origin(_clear_ap)
            genealogy.abilities[_branch_ap.id] = _augment_ability_profile_with_origin(_branch_ap)
        _CLAIM_RELIEF_ABILITIES_REGISTERED = True
    except Exception:
        pass


def _log_claim_resolution_relief(
    genealogy: Any,
    *,
    resolved_pairs: List[Tuple[str, str]],
    remaining_pairs: List[Tuple[str, str]],
    reason: str = "",
) -> None:
    if not genealogy or not resolved_pairs:
        return
    try:
        from aurora_evolution_stack import PressureVec, TraceItem

        _ensure_claim_relief_abilities(genealogy)
        resolved_count = float(len(list(resolved_pairs)))
        remaining_count = float(len(list(remaining_pairs)))
        p_before = PressureVec(
            X=0.04 * resolved_count,
            T=min(1.0, 0.22 * resolved_count + 0.08 * remaining_count),
            N=0.04 * resolved_count,
            B=min(1.0, 0.18 * resolved_count + 0.06 * remaining_count),
            A=0.10 if resolved_count > 0 else 0.0,
        )
        p_after = PressureVec(
            X=0.0,
            T=max(0.0, p_before.T * 0.42),
            N=max(0.0, p_before.N * 0.55),
            B=max(0.0, p_before.B * 0.48),
            A=0.0,
        )
        trace = [
            TraceItem(kind="ABILITY", id="B:SEPARATE_COMPETING_CLAIMS"),
            TraceItem(kind="ABILITY", id="T:CLEAR_RESOLVED_CONFLICT"),
        ]
        tick = int(getattr(genealogy, 'tick_count', 0))
        genealogy.observe(
            pressure_before=p_before,
            trace=trace,
            pressure_after=p_after,
            state_sig_before=f"claim_conflict_pre_{tick}",
            state_sig_after=f"claim_conflict_post_{tick}",
            notes={
                "tag": "claim_resolution_relief",
                "reason": str(reason or 'resolved_claim_conflict'),
                "resolved_pairs": [list(pair)[:2] for pair in list(resolved_pairs)[:4]],
                "remaining_conflicts": int(remaining_count),
            },
        )
    except Exception:
        pass


# ---------------------------------------------------------------------------
# BIDIRECTIONAL DEVELOPMENTAL CHAIN PIPELINE
# ---------------------------------------------------------------------------
# Implements the reasoning loop as a full round-trip through the 6 stages:
#
#   UPWARD  (comprehension): Information->Relational->Belief->Purpose->Meaning->Understanding
#   APEX:    TurnUnderstandingState
#   DOWNWARD (expression):  Understanding->Meaning->Purpose->Belief->Relational->Information
#
# Each stage mutates TurnUnderstandingState in place.
# Short-circuit: any stage may fill state.response_content early (e.g. greeting,
# context_control handled) -- downward stages check this before doing work.
# ---------------------------------------------------------------------------

def _chain_up1_information(user_text: str, systems: dict, state: Any) -> None:
    """Stage 1 up -- Information (X axis): Existence gate -- parse input, OETS concept lookup."""
    try:
        state.parsed = UtteranceParser().parse(user_text)
    except Exception:
        state.parsed = {}
    # OETS concept pre-fetch for known topic words
    try:
        perception = systems.get("perception")
        oets = getattr(perception, "oets", None) if perception else None
        if oets:
            for word in list((state.parsed or {}).get("topic_words", []))[:4]:
                node = oets.web.get_node(word) if hasattr(oets, "web") else None
                if node:
                    state.oets_concepts.append({"word": word, "node": str(node)[:120]})
    except Exception:
        pass
    # ---- IStateCollective — ontological existence gate ----
    # Feed the input through all 10 I-State beings. Each being asserts what is
    # ontologically true about this input from its predicate's lens (I_IS, I_CAN,
    # I_DO, I_SAW, I_DID and their negatives). The synthesis reveals paradoxes
    # (opposing poles both active) and net axis displacements — the ontological
    # fingerprint of this turn. Paradoxes feed _apply_pipeline_modulation directly.
    try:
        _coll = systems.get("collective")
        if _coll is not None and hasattr(_coll, "process_raw"):
            _syn = _coll.process_raw(
                payload=user_text,
                payload_type="text",
                evidence={"source": "user_turn", "intent": str((state.parsed or {}).get("query_type", "general") or "general")},
            )
            if _syn is not None and isinstance(state.pipeline_state, dict):
                state.pipeline_state["paradoxes"]               = list(getattr(_syn, "paradoxes", []) or [])
                state.pipeline_state["axis_tensions"]           = dict(getattr(_syn, "axis_tensions", {}) or {})
                state.pipeline_state["collective_dominant_axis"]= str(getattr(_syn, "dominant_axis", "") or "")
                state.pipeline_state["collective_resonance"]    = float(getattr(_syn, "dominant_resonance", 0.0) or 0.0)
                state.pipeline_state["reality_warp"]            = bool(getattr(_syn, "reality_warp", False))
                state.pipeline_state["warp_severity"]           = float(getattr(_syn, "warp_severity", 0.0) or 0.0)
                # Net axis displacements supplement the axis activation built by _chain_up3_purpose
                _net = dict(getattr(_syn, "axis_net_displacements", {}) or {})
                if _net:
                    state.pipeline_state["collective_axis_net"] = _net
    except Exception:
        pass

    # ── SediMemory recall: pull relevant stratigraphic memory for this turn ──
    try:
        _sedi = systems.get('sedimemory')
        if _sedi is not None:
            _dim = systems.get('dimensional')
            _cv = None
            if _dim and hasattr(_dim, 'get_constraint_aggregate'):
                _agg = _dim.get_constraint_aggregate()
                if _agg:
                    from aurora_internal.aurora_constraint_manifold_patched import ConstraintVector as _CV
                    _cv = _CV(
                        X=max(0.01, float(_agg.get('X', 0.5))),
                        T=float(_agg.get('T', 0.3)),
                        N=float(_agg.get('N', 0.3)),
                        B=float(_agg.get('B', 0.3)),
                        A=float(_agg.get('A', 0.3)),
                    )
            if _cv is not None:
                _recalled = _sedi.surface_recall(_cv, max_results=4)
                if _recalled and isinstance(state.pipeline_state, dict):
                    state.pipeline_state["sedi_recalled"] = [
                        {
                            'content': dict(getattr(f, 'content', {}) or {}),
                            'axis': str(getattr(f, 'axis', '') or ''),
                            'resonance': float(getattr(f, 'resonance', 0.0) or 0.0),
                        }
                        for f in _recalled[:4]
                    ]
    except Exception:
        pass

    # ── Waveform pre-injection — field shaped BEFORE comprehension runs ────────
    # The constraint aggregate derived from user text is injected into the
    # NoncompField NOW so that the field's axis pressures reflect this turn's
    # input when the constraint emitter runs.  Previously this injection only
    # happened post-response (updating the field for the NEXT turn).
    try:
        _wf_ifield = systems.get('identity_field')
        _wf_pump   = systems.get('pressure_pump')
        _wf_dim    = systems.get('dimensional')
        if _wf_pump is not None and _wf_ifield is not None and _wf_dim is not None:
            _wf_agg = (_wf_dim.get_constraint_aggregate()
                       if hasattr(_wf_dim, 'get_constraint_aggregate') else None)
            if _wf_agg:
                from aurora_waveform_pressure import WaveformPressurePump as _WFPump
                _wf_dist = _WFPump.from_axis_state(
                    _wf_agg,
                    source="user_input_precomp",
                    intensity=0.65,
                    coupling_mode="full",
                )
                _wf_pump.inject(
                    _wf_dist,
                    _wf_ifield,
                    qao=systems.get('quasiarch_observer'),
                )
    except Exception:
        pass

    # ── Sensory context injection ──
    # Pull live screen-observer scene and sensory-crystal state into pipeline_state
    # so all upward and downward chain stages can shape responses around what Aurora
    # is currently perceiving.  surface reads a snapshot (lock-safe); no writes here.
    try:
        if isinstance(state.pipeline_state, dict):
            _so = systems.get('screen_observer')
            if _so is not None and hasattr(_so, 'current_scene'):
                _scene = _so.current_scene()
                if _scene:
                    state.pipeline_state['sensory_scene'] = {
                        'scene_type':   str(_scene.get('scene_type', '') or ''),
                        'brightness':   float(_scene.get('brightness', 0.0) or 0.0),
                        'edge_density': float(_scene.get('edge_density', 0.0) or 0.0),
                        'motion':       float(_scene.get('motion', 0.0) or 0.0),
                        'concepts':     list(_scene.get('concepts_matched', []) or [])[:6],
                        'patterns':     list(_scene.get('patterns', []) or [])[:4],
                    }
                    # Also build a brief natural description for use in response shaping
                    if hasattr(_so, 'get_scene_description'):
                        state.pipeline_state['sensory_scene_desc'] = _so.get_scene_description()
                    # Pump visual scene into identity field pressure map
                    _ifield_sc = systems.get('identity_field')
                    if _ifield_sc is not None and hasattr(_ifield_sc, 'ingest_sensory_event'):
                        try:
                            _ifield_sc.ingest_sensory_event(
                                'visual',
                                intensity=float(_scene.get('brightness', 0.5) or 0.5),
                                novelty=float(_scene.get('motion', 0.3) or 0.3),
                                spatial=min(1.0, float(_scene.get('edge_density', 0.3) or 0.3)),
                                valence=0.0,
                            )
                        except Exception:
                            pass

            _sc = systems.get('sensory_crystal')
            if _sc is not None and hasattr(_sc, 'get_state'):
                _sc_st = _sc.get_state()
                if _sc_st:
                    # Capture dominant facets so the response can reference live perceptual state
                    _sc_visual = {}
                    _sc_audio  = {}
                    for _fname, _fdata in (_sc_st.get('visual') or {}).items():
                        if isinstance(_fdata, dict) and float(_fdata.get('maturity', 0.0) or 0.0) > 0.05:
                            _sc_visual[str(_fname)] = round(float(_fdata.get('maturity', 0.0) or 0.0), 3)
                    for _fname, _fdata in (_sc_st.get('audio') or {}).items():
                        if isinstance(_fdata, dict) and float(_fdata.get('maturity', 0.0) or 0.0) > 0.05:
                            _sc_audio[str(_fname)] = round(float(_fdata.get('maturity', 0.0) or 0.0), 3)
                    state.pipeline_state['sensory_crystal'] = {
                        'visual_facets': _sc_visual,
                        'audio_facets':  _sc_audio,
                        'maturity':      round(float(_sc_st.get('maturity', 0.0) or 0.0), 3),
                        'lanes':         int(len(_sc_st.get('lanes') or {})),
                    }
                    # Pump crystal facets into identity field — audio and visual separately
                    _ifield_crys = systems.get('identity_field')
                    if _ifield_crys is not None and hasattr(_ifield_crys, 'ingest_sensory_event'):
                        try:
                            _sc_vis_mat = float(_sc_st.get('maturity', 0.0) or 0.0)
                            _sc_aud_mat = max(
                                (float(v.get('maturity', 0.0) or 0.0)
                                 for v in (_sc_st.get('audio') or {}).values()
                                 if isinstance(v, dict)),
                                default=0.0,
                            )
                            if _sc_vis_mat > 0.02:
                                _ifield_crys.ingest_sensory_event(
                                    'visual',
                                    intensity=min(1.0, _sc_vis_mat),
                                    novelty=min(1.0, _sc_vis_mat * 0.8),
                                    spatial=0.5,
                                    valence=0.0,
                                )
                            if _sc_aud_mat > 0.02:
                                _ifield_crys.ingest_sensory_event(
                                    'auditory',
                                    intensity=min(1.0, _sc_aud_mat),
                                    novelty=min(1.0, _sc_aud_mat * 0.6),
                                    valence=0.0,
                                )
                        except Exception:
                            pass
    except Exception:
        pass


def _chain_up2_belief(user_text: str, systems: dict, state: Any) -> None:
    """Stage 2 up -- Belief (T axis): Recurrence/prediction via working memory forms belief."""
    if state.response_content:
        return
    working_memory = systems.get("working_memory")
    conversation_memory = systems.get("conversation_memory")
    if not working_memory:
        return
    try:
        state.referent_map = working_memory.resolve_referents(user_text) or {}
    except Exception:
        state.referent_map = {}
    try:
        state.claim_resolution = working_memory.resolve_claims(user_text) or {}
    except Exception:
        state.claim_resolution = {}
    # Context control (explicit memory commands, "forget X", etc.)
    try:
        _understood = state.parsed or {}
        ctx = working_memory.apply_context_control(
            user_text,
            understood=_understood,
            conversation_memory=conversation_memory,
            intent=state.intent,
            systems=systems,
        )
        if ctx and ctx.get("handled"):
            state.response_content = str(ctx.get("response", "") or "")
            state.response_tone = str(ctx.get("tone", "attentive") or "attentive")
            state.response_confidence = float(ctx.get("confidence", 0.88) or 0.88)
            state.response_src = "context_control"
            return
    except Exception:
        pass
    # Behavior alignment answer
    try:
        ba = working_memory.answer_from_behavior_alignment(
            user_text, understood=state.parsed or {}, systems=systems
        )
        if ba:
            state.response_content = str(ba)
            state.response_tone = "precise"
            state.response_confidence = 0.9
            state.response_src = "behavior_alignment"
            return
    except Exception:
        pass
    # Session re-address (continuity)
    try:
        cont = _answer_from_session_readdress_request(systems, user_text, understood=state.parsed or {})
        if cont:
            if isinstance(cont, (list, tuple)) and len(cont) >= 3:
                state.response_content = str(cont[0] or "")
                state.response_tone = str(cont[1] or "attentive")
                state.response_confidence = float(cont[2] or 0.88)
            else:
                state.response_content = str(cont)
                state.response_tone = "attentive"
                state.response_confidence = 0.88
            state.response_src = "session_continuity"
            return
    except Exception:
        pass
    state.session_continuity = float(getattr(working_memory, "turn_count", 0) or 0)
    try:
        state.working_memory_snapshot = dict(
            working_memory.memory_sweep_snapshot(
                conversation_memory=conversation_memory,
            )
            or {}
        )
        if isinstance(state.pipeline_state, dict) and state.working_memory_snapshot:
            state.pipeline_state["working_memory_snapshot"] = dict(state.working_memory_snapshot)
            state.pipeline_state["conversation_memory_summary"] = dict(
                state.working_memory_snapshot.get("conversation_memory", {}) or {}
            )
            state.pipeline_state["memory_locations"] = list(
                state.working_memory_snapshot.get("locations", []) or []
            )
            state.pipeline_state["surface_conversation_frame"] = {
                "current_topic": str(state.working_memory_snapshot.get("current_topic", "") or ""),
                "topic_stack": list(state.working_memory_snapshot.get("topic_stack", []) or [])[:4],
                "recent_context": str(state.pipeline_state.get("recent_context", "") or ""),
                "recent_context_turns": int(state.pipeline_state.get("recent_context_turns", 0) or 0),
                "recent_context_mode": str(state.pipeline_state.get("recent_context_mode", "present") or "present"),
                "scope": "live_surface_conversation_frame",
            }
    except Exception:
        state.working_memory_snapshot = {}


def _measure_polarity_gradient_snapshot(systems: Dict[str, Any]) -> Dict[str, Any]:
    lattice = systems.get("lattice")
    if lattice is None or not hasattr(lattice, "vertices"):
        return {}
    try:
        from aurora_internal.aurora_polarity_gradient import PolarityGradientSensor
    except Exception:
        return {}
    sensor = systems.get("_dialogue_polarity_sensor")
    if sensor is None or not hasattr(sensor, "measure"):
        sensor = PolarityGradientSensor()
        systems["_dialogue_polarity_sensor"] = sensor
    try:
        tick = int(getattr(lattice, "total_ticks", 0) or 0)
        report_obj = sensor.measure(lattice.vertices, tick=tick)
        report = report_obj.to_dict() if hasattr(report_obj, "to_dict") else report_obj
    except Exception:
        try:
            report_obj = sensor.measure(lattice.vertices, tick=int(getattr(lattice, "total_ticks", 0) or 0))
        except Exception:
            return {}
        report = {
            "tick": int(getattr(report_obj, "tick", 0) or 0),
            "polarities": dict(getattr(report_obj, "polarities", {}) or {}),
            "pair_deltas": dict(getattr(report_obj, "pair_deltas", {}) or {}),
            "pair_pressures": dict(getattr(report_obj, "pair_pressures", {}) or {}),
            "gradient_pressure": float(getattr(report_obj, "gradient_pressure", 0.0) or 0.0),
            "stack_coherence": float(getattr(report_obj, "stack_coherence", 0.0) or 0.0),
            "sign_conflict": bool(getattr(report_obj, "sign_conflict", False)),
            "gradient_direction": str(getattr(report_obj, "gradient_direction", "") or ""),
            "pressure_delta": float(getattr(report_obj, "pressure_delta", 0.0) or 0.0),
            "is_relief": bool(getattr(report_obj, "is_relief", False)),
            "tense_pairs": list(getattr(report_obj, "tense_pairs", []) or []),
        }
    if isinstance(report, dict):
        return report
    return {}


def _derive_emotional_layers(
    systems: Dict[str, Any],
    state: Any,
) -> Tuple[Dict[str, Any], Dict[str, Any], Dict[str, Any], Dict[str, Any]]:
    base = dict(getattr(state, "emotional_state", {}) or {})
    polarity = _measure_polarity_gradient_snapshot(systems)
    pipeline_state = getattr(state, "pipeline_state", None)
    if not isinstance(pipeline_state, dict):
        pipeline_state = {}

    sensory_state = dict(pipeline_state.get("sensory_crystal", {}) or {})
    sensory_maturity = float(sensory_state.get("maturity", 0.0) or 0.0)
    parsed = dict(getattr(state, "parsed", {}) or {})
    query_type = str(parsed.get("query_type", "") or "").strip().lower()
    question_like = bool(query_type and query_type != "statement")

    belief_tension = float(getattr(state, "belief_tension", 0.0) or 0.0)
    goal_stack = list(getattr(state, "goal_stack", []) or [])
    dominant_axis = str(getattr(state, "dominant_axis", "") or "X").strip().upper() or "X"
    base_dominant = str(base.get("dominant", "") or "calm").strip() or "calm"
    base_energy = float(base.get("energy", 0.0) or 0.0)

    polarities = dict(polarity.get("polarities", {}) or {})
    gradient_pressure = float(polarity.get("gradient_pressure", 0.0) or 0.0)
    stack_coherence = float(polarity.get("stack_coherence", 0.0) or 0.0)
    sign_conflict = bool(polarity.get("sign_conflict", False))
    gradient_direction = str(polarity.get("gradient_direction", "") or "coherent")
    surface_polarity = float(polarities.get("existence", 0.0) or 0.0)
    deep_polarity = float(polarities.get("boundary", 0.0) or 0.0)
    core_polarity = float(polarities.get("agency", 0.0) or 0.0)

    reactive_intensity = max(
        min(1.0, abs(surface_polarity)),
        min(1.0, sensory_maturity),
        min(1.0, belief_tension),
        min(1.0, gradient_pressure),
    )
    if sign_conflict or belief_tension >= 0.55 or gradient_pressure >= 0.42:
        reactive_dominant = "fear"
        behavior_bias = "slow_down"
        tone_bias = "careful"
        reason = "surface_core_polarity_conflict"
    elif sensory_maturity >= 0.1 or question_like or gradient_direction == "surface_leads":
        reactive_dominant = "curiosity"
        behavior_bias = "lean_in"
        tone_bias = "curious"
        reason = "surface_reactivity_leads"
    else:
        reactive_dominant = "calm"
        behavior_bias = "steady"
        tone_bias = "attentive"
        reason = "surface_stack_stable"

    if goal_stack and belief_tension >= 0.55:
        deep_dominant = "fear" if base_dominant in {"fear", "anger"} else "calm"
        passion = "protective_commitment"
        deep_reason = "goal_pressure_under_cost"
    elif goal_stack and dominant_axis in {"A", "N"}:
        deep_dominant = base_dominant if base_dominant != "calm" else "curiosity"
        passion = "driven_commitment"
        deep_reason = "purpose_and_agency_binding"
    elif belief_tension >= 0.35:
        deep_dominant = base_dominant if base_dominant != "calm" else "fear"
        passion = "concerned_hold"
        deep_reason = "belief_tension_carryover"
    elif dominant_axis == "T":
        deep_dominant = base_dominant if base_dominant != "neutral" else "calm"
        passion = "continuity_hold"
        deep_reason = "belief_continuity_bias"
    elif dominant_axis == "B":
        deep_dominant = base_dominant if base_dominant != "neutral" else "curiosity"
        passion = "meaning_hold"
        deep_reason = "boundary_meaning_bias"
    else:
        deep_dominant = base_dominant if base_dominant != "neutral" else "calm"
        passion = "settled_alignment"
        deep_reason = "baseline_depth_alignment"

    deep_intensity = max(
        min(1.0, base_energy),
        min(1.0, belief_tension),
        min(1.0, abs(deep_polarity)),
        min(1.0, abs(core_polarity)),
    )

    coincident = False
    bridge_reason = "surface_deep_split"
    if reactive_dominant == deep_dominant:
        coincident = True
        bridge_reason = "same_dominant_emotion"
    elif reactive_dominant == "fear" and passion in {"protective_commitment", "concerned_hold"}:
        coincident = True
        bridge_reason = "protective_surface_caution"
    elif reactive_dominant == "curiosity" and passion in {"driven_commitment", "meaning_hold", "continuity_hold"}:
        coincident = True
        bridge_reason = "curious_surface_supported_by_deep_commitment"
    elif reactive_dominant == "calm" and passion in {"continuity_hold", "settled_alignment"}:
        coincident = True
        bridge_reason = "stable_surface_supported_by_deep_alignment"

    surface_reactive = {
        "dominant": reactive_dominant,
        "intensity": round(reactive_intensity, 4),
        "behavior_bias": behavior_bias,
        "tone_bias": tone_bias,
        "reason": reason,
        "duration": "surface_short",
    }
    deep_emotional = {
        "dominant": deep_dominant,
        "intensity": round(deep_intensity, 4),
        "passion": passion,
        "reason": deep_reason,
        "goal_focus": str(goal_stack[0] if goal_stack else getattr(state, "intent", "general") or "general"),
        "belief_tension": round(belief_tension, 4),
        "boundary_polarity": round(deep_polarity, 4),
        "core_polarity": round(core_polarity, 4),
        "duration": "deep_carrying",
    }
    bridge = {
        "coincident": coincident,
        "reason": bridge_reason,
        "gradient_pressure": round(gradient_pressure, 4),
        "stack_coherence": round(stack_coherence, 4),
        "gradient_direction": gradient_direction,
    }
    return surface_reactive, deep_emotional, bridge, polarity


def _chain_up3_purpose(user_text: str, systems: dict, state: Any) -> None:
    """Stage 3 up -- Purpose (N axis): Energy/value pressure moves belief to directed purpose.
    N axis = cost/energy: what it costs to pursue something determines intent and emotional state."""
    # N axis: project the full field -- cost/energy pressure determines which axes are active
    _raw = _project_utterance_axes(user_text, systems)

    # ---- Sensory crystal → DCE blend ----
    # The sensory crystal accumulates promoted audio/visual patterns.  Those
    # patterns represent actual perceptual experience — feed them into the axis
    # activation vector BEFORE the DER runs so the dimensional system incorporates
    # what Aurora is currently perceiving, not just what was said.
    #   audio maturity   → N axis (energy/cost — how much sensory energy is live)
    #   visual maturity  → X axis (existence — is something present/moving?)
    #   cross-modal lanes → B axis (meaning/boundary — audio+visual agree on something)
    try:
        _sc_obj = systems.get("sensory_crystal")
        if _sc_obj is not None:
            _sc_st = _sc_obj.get_state()
            _sc_mat = float(_sc_st.get("maturity", 0.0) or 0.0)
            if _sc_mat > 0.04:          # only blend once crystal has minimal data
                _sc_audio = max(
                    (float(v.get("maturity", 0.0)) for v in (_sc_st.get("audio") or {}).values()),
                    default=0.0,
                )
                _sc_visual = max(
                    (float(v.get("maturity", 0.0)) for v in (_sc_st.get("visual") or {}).values()),
                    default=0.0,
                )
                _sc_lanes = len(_sc_st.get("lanes") or {})
                # Weight the contribution proportionally to crystal maturity (max 12%)
                _w = min(_sc_mat * 0.12, 0.12)
                if _sc_audio > 0.08:
                    _raw["N"] = min(1.0, float(_raw.get("N", 0.2)) + _sc_audio * _w)
                if _sc_visual > 0.08:
                    _raw["X"] = min(1.0, float(_raw.get("X", 0.2)) + _sc_visual * _w)
                if _sc_lanes > 0:
                    _lane_contrib = min(float(_sc_lanes) / 10.0, 0.3)
                    _raw["B"] = min(1.0, float(_raw.get("B", 0.2)) + _lane_contrib * _w)
    except Exception:
        pass

    # ---- Collective axis blend ----
    # The IStateCollective already processed this input in _chain_up1_information
    # and deposited ontologically-grounded net axis displacements in pipeline_state.
    # Blend them into _raw at a low weight (max 10%) so the beings' reading of
    # "what energy/boundary/agency is actually at stake" informs the N-axis field.
    try:
        _coll_net = dict((state.pipeline_state or {}).get("collective_axis_net", {}) or {})
        if _coll_net:
            # Normalize net displacements to [0,1] range and blend at up to 10% weight
            _coll_max = max(abs(v) for v in _coll_net.values()) if _coll_net else 1.0
            _coll_max = max(_coll_max, 1e-6)
            _coll_w = 0.10
            for _ax in ("X", "T", "N", "B", "A"):
                if _ax in _coll_net:
                    _norm = float(_coll_net[_ax]) / _coll_max  # signed, -1..1
                    # Positive displacement lifts axis; negative dampens (min 0)
                    _cur = float(_raw.get(_ax, 0.2))
                    _raw[_ax] = max(0.0, min(1.0, _cur + _norm * _coll_w))
    except Exception:
        pass

    # Correction pressure: a user correction breaks temporal continuity and
    # reasserts agency.  Inject into _raw BEFORE the field balancer so the
    # crossing selection and language frame respond to the corrective event
    # rather than staying T-dominant (callback = temporal reference).
    if (state.pipeline_state or {}).get("correction_absorbed"):
        _raw["T"] = max(0.05, float(_raw.get("T", 0.3)) - 0.35)
        _raw["A"] = min(1.0, float(_raw.get("A", 0.2)) + 0.45)
        _raw["B"] = min(1.0, float(_raw.get("B", 0.2)) + 0.20)

    state.axis_activation = _field_balancer.rebalanced_activation(_raw)
    _field_balancer.update(state.axis_activation, systems)
    state.dominant_axis = _axis_projector.dominant(state.axis_activation)
    try:
        _perc_a3 = systems.get("perception")
        if _perc_a3 and hasattr(_perc_a3, "set_axis_context"):
            _perc_a3.set_axis_context({
                "X": float(getattr(state, "x_axis", state.axis_activation.get("X", 0.5)) or 0.5),
                "T": float(getattr(state, "t_axis", state.axis_activation.get("T", 0.5)) or 0.5),
                "N": float(getattr(state, "n_axis", state.axis_activation.get("N", 0.5)) or 0.5),
                "B": float(getattr(state, "b_axis", state.axis_activation.get("B", 0.5)) or 0.5),
                "A": float(getattr(state, "a_axis", state.axis_activation.get("A", 0.5)) or 0.5),
            })
    except Exception:
        pass
    # Telemetry
    try:
        from aurora_telemetry import get_telemetry as _gt
        _gt().set_axis_context(state.axis_activation)
    except Exception:
        pass
    # Populate pipeline_state with axis vector
    ps = state.pipeline_state
    if isinstance(ps, dict):
        _depth_map = {"X": 0, "T": 1, "N": 2, "B": 3, "A": 4}
        _intensity = round(state.axis_activation.get(state.dominant_axis, 0.2), 4)
        _polarity = 0.0
        try:
            latt = systems.get("lattice")
            if latt:
                _name_rev = {"X": "existence", "T": "temporal", "N": "energy", "B": "boundary", "A": "agency"}
                _ta = getattr(latt, "axes", {}).get(_name_rev.get(state.dominant_axis, ""), None)
                if _ta is not None:
                    _polarity = round(float(getattr(_ta, "polarity", 0.0)), 4)
        except Exception:
            pass
        ps["axis_activation"]         = state.axis_activation
        ps["dominant_axis"]           = state.dominant_axis
        ps["axis_depth"]              = _depth_map.get(state.dominant_axis, 2)
        ps["axis_intensity"]          = _intensity
        ps["axis_polarity"]           = _polarity
        ps["field_balance"]           = _field_balancer.status().get("balance_score", 1.0)
        ps["referent_map"]            = dict((state.referent_map or {}).get("referent_map", {}) or {})
        ps["referent_confidence"]     = float((state.referent_map or {}).get("confidence", 0.0) or 0.0)
        ps["resolved_referent_topic"] = str((state.referent_map or {}).get("topic", "") or "")
        ps["claim_confidence"]        = float((state.claim_resolution or {}).get("confidence", 0.0) or 0.0)
        ps["resolved_claim"]          = str(((state.claim_resolution or {}).get("focus_claim", {}) or {}).get("summary", "") or "")
    # N-axis cost signal → belief tension (what pursuing this costs)
    try:
        contract = systems.get("understanding_contract")
        if contract and hasattr(contract, "state"):
            cst = contract.state or {}
            state.belief_tension = float((cst.get("N") or {}).get("cost_signal", 0.0) or 0.0)
    except Exception:
        pass
    # DER emotional state -- energy drives emotion (N axis)
    try:
        dim = systems.get("dimensional")
        if dim and hasattr(dim, "update_emotional_state"):
            _heat = getattr(systems.get("lattice"), "get_global_heat", lambda: 0.0)()
            state.emotional_state = dim.update_emotional_state(state.axis_activation, _heat) or {}
    except Exception:
        state.emotional_state = {}
    # Intent classification -- derived from axis state + parsed utterance, not keyword patterns
    state.intent = _classify_input_intent(
        user_text,
        _axis_activation=state.axis_activation,
        _parsed=state.parsed,
    )
    # Goal stack -- active purposes from contract
    try:
        contract = systems.get("understanding_contract")
        if contract and hasattr(contract, "state"):
            cst = contract.state or {}
            state.goal_stack = list((cst.get("P") or {}).get("goal_stack", []) or [])
    except Exception:
        pass
    try:
        (
            state.surface_reactive_emotion,
            state.deep_emotional_state,
            _emotion_bridge,
            state.polarity_gradient,
        ) = _derive_emotional_layers(systems, state)
        if isinstance(state.emotional_state, dict):
            state.emotional_state["surface_reactive"] = dict(state.surface_reactive_emotion or {})
            state.emotional_state["deep"] = dict(state.deep_emotional_state or {})
            state.emotional_state["bridge"] = dict(_emotion_bridge or {})
    except Exception:
        state.surface_reactive_emotion = {}
        state.deep_emotional_state = {}
        state.polarity_gradient = {}
        _emotion_bridge = {}
    # Axis context push with emotion now known
    try:
        perc = systems.get("perception")
        if perc and hasattr(perc, "set_axis_context"):
            perc.set_axis_context(
                state.axis_activation,
                dominant_axis=state.dominant_axis,
                dominant_emotion=(state.surface_reactive_emotion or {}).get("dominant", state.emotional_state.get("dominant", "neutral")),
                axis_depth={"X": 0, "T": 1, "N": 2, "B": 3, "A": 4}.get(state.dominant_axis, 2),
            )
    except Exception:
        pass
    ps = state.pipeline_state
    if isinstance(ps, dict):
        ps["dominant_emotion"]    = (state.surface_reactive_emotion or {}).get("dominant", state.emotional_state.get("dominant", "calm"))
        ps["emotional_coherence"] = state.emotional_state.get("coherence", 1.0)
        ps["emotional_energy"]    = max(
            float(state.emotional_state.get("energy", 0.0) or 0.0),
            float((state.surface_reactive_emotion or {}).get("intensity", 0.0) or 0.0),
            float((state.deep_emotional_state or {}).get("intensity", 0.0) or 0.0),
        )
        ps["surface_reactive_emotion"] = dict(state.surface_reactive_emotion or {})
        ps["surface_reactive_bias"] = str((state.surface_reactive_emotion or {}).get("behavior_bias", "") or "")
        ps["surface_reactive_intensity"] = float((state.surface_reactive_emotion or {}).get("intensity", 0.0) or 0.0)
        ps["deep_emotional_state"] = dict(state.deep_emotional_state or {})
        ps["deep_dominant_emotion"] = str((state.deep_emotional_state or {}).get("dominant", "") or state.emotional_state.get("dominant", "calm"))
        ps["deep_passion_state"] = str((state.deep_emotional_state or {}).get("passion", "") or "")
        ps["emotion_bridge"] = dict(_emotion_bridge or {})
        ps["polarity_gradient"] = dict(state.polarity_gradient or {})


def _chain_up4_meaning(user_text: str, systems: dict, state: Any) -> None:
    """Stage 4 up -- Meaning (B axis): Goal conflict determines what falls within the boundary
    of significance -- salient concepts, meaning forms, semantic pressure."""
    response_already_set = bool(state.response_content)
    # Relational role gate (identity/boundary questions answered from lineage)
    if not response_already_set:
        _rel = _answer_relational_role_question(user_text, systems)
        if _rel:
            if isinstance(_rel, (list, tuple)) and len(_rel) >= 1:
                state.response_content = str(_rel[0] or "")
                state.response_tone = str(_rel[1] if len(_rel) > 1 else "self-aware")
                state.response_confidence = float(_rel[2] if len(_rel) > 2 else 0.9)
            else:
                state.response_content = str(_rel)
                state.response_tone = "self-aware"
                state.response_confidence = 0.9
            state.response_src = "relational_role"
            return
    # B-axis boundary pressure -- what carries semantic weight
    try:
        contract = systems.get("understanding_contract")
        if contract and hasattr(contract, "state"):
            cst = contract.state or {}
            state.semantic_pressure = float((cst.get("B") or {}).get("boundary_pressure", 0.0) or 0.0)
    except Exception:
        pass
    # Salient concepts -- what falls within the boundary of significance
    state.salient_concepts = list((state.parsed or {}).get("topic_words", []))[:6]
    # Meaning forms from contract (goal conflict → priority ranking)
    try:
        contract = systems.get("understanding_contract")
        if contract and hasattr(contract, "rank_meaning_forms"):
            state.meaning_forms = list(contract.rank_meaning_forms(state.axis_activation) or [])
            state.dominant_meaning_form = state.meaning_forms[0] if state.meaning_forms else {}
    except Exception:
        pass
    # Outcome variance check -- for each salient concept, query the pressure ledger
    # to see if its causal history shows split outcomes for the same action.
    # A concept with conditional history signals that the reasoning chain should
    # seek additional context rather than pattern-matching on a single rule.
    _conditional_notes = []
    try:
        from aurora_internal.aurora_pressure_ledger import PressureExperienceLedger as _PEL
        _ledger = _PEL.get()
        for _concept in (state.salient_concepts or [])[:4]:
            _sig = _ledger.conditioning_signal(str(_concept))
            if _sig["sample_count"] >= 2:  # need at least two experiences to compare
                if _sig["conditional"]:
                    _conditional_notes.append(_sig["note"])
                    # Raise semantic pressure -- conditional concept = higher boundary cost
                    state.semantic_pressure = max(
                        state.semantic_pressure,
                        _sig["outcome_entropy"],
                    )
    except Exception:
        pass
    if _conditional_notes:
        ps = state.pipeline_state
        if isinstance(ps, dict):
            ps["has_conditional_concepts"] = True
            ps["conditional_concept_notes"] = _conditional_notes
            ps["semantic_pressure"] = state.semantic_pressure

    # A-dominant gate: only skip OETS/meaning when agency is strongly dominant.
    # 0.30 was too broad — partially-A turns still need meaning/OETS processing.
    # Raise threshold to 0.65 so only fully agency-saturated turns short-circuit.
    if state.dominant_axis == "A" and state.axis_activation.get("A", 0.0) > 0.65:
        ps = state.pipeline_state
        _cf_mode = str((ps or {}).get("conscious_frame_mode", "") or "").lower()
        # Secure the gate: Only bypass if subsurface isn't requesting deliberation.
        _allow_bypass = True
        if _cf_mode in ("clarify", "research", "observation"):
            _allow_bypass = False
        
        if _allow_bypass:
            state.a_dominant = True
            if isinstance(ps, dict):
                ps["dominant_axis"] = "A"
                ps["axis_activation"] = state.axis_activation


def _chain_up5_understanding(user_text: str, systems: dict, state: Any, *, turn_tick: int = 0, session_id: str = "") -> None:
    """Stage 5 up -- Understanding (A axis) -- THE APEX.
    Agency: integration pressure across domains produces cross-domain consistency.
    Contract observation, developmental chain assessment, learned hints."""
    # Understanding contract ingest
    try:
        contract = systems.get("understanding_contract")
        if contract and hasattr(contract, "ingest_observation"):
            state.understanding_observation = dict(
                contract.ingest_observation(
                    systems=systems,
                    user_text=user_text,
                    understood=state.parsed or {},
                    turn_tick=turn_tick,
                    session_id=session_id,
                ) or {}
            )
    except Exception:
        pass
    # Developmental stage
    try:
        from aurora_internal.aurora_meaning_evolution import assess_developmental_chain
        state.developmental_stage = dict(assess_developmental_chain(state.meaning_forms or []) or {})
    except Exception:
        pass
    # Dream trainer learned hints
    try:
        dt = systems.get("dream_trainer")
        if dt and hasattr(dt, "get_response_hints"):
            _ctx = str((state.parsed or {}).get("query_type", "general") or "general")
            _tw = list((state.parsed or {}).get("topic_words", []))
            hints = dt.get_response_hints(_ctx, _tw, systems) or []
            state.learned_hints.extend([str(h) for h in hints if h])
    except Exception:
        pass
    # ConsciousLearner shards
    try:
        sim = systems.get("aurora") and getattr(systems["aurora"].gateway, "simulation", None)
        learner = getattr(getattr(sim, "session", None), "learner", None) if sim else None
        if learner and hasattr(learner, "get_confident_shards"):
            for shard in list(learner.get_confident_shards() or [])[:3]:
                if hasattr(shard, "content"):
                    _sc = str(shard.content or "").strip()
                    if not (_sc.startswith("125-layer manifold:")
                            or ("basis=" in _sc and "target=" in _sc)):
                        state.learned_hints.append(_sc[:80])
    except Exception:
        pass


# _chain_up6_apex removed -- content merged into _chain_up5_understanding (A axis apex)


# ---- DOWNWARD PASS ----

# _chain_down6_apex removed -- hint propagation folded into _chain_down5_understanding


def _chain_down5_understanding(user_text: str, systems: dict, state: Any,
                               auto_search_enabled: bool = True) -> None:
    """Stage 5 down -- Understanding (A axis): From apex understanding, derive what needs saying.
    Consumes upward-built understanding_observation, developmental_stage, learned_hints,
    goal_stack, dominant_meaning_form to constrain the response before any retrieval runs."""
    # Propagate learned hints into pipeline_state for downstream stages
    if state.learned_hints:
        ps = state.pipeline_state
        if isinstance(ps, dict):
            ps.setdefault("learned_hints", [])
            ps["learned_hints"] = list(state.learned_hints)
    # Stamp understanding context into pipeline_state for modulation downstream
    ps = state.pipeline_state
    if isinstance(ps, dict):
        ps["understanding_stage"]    = str((state.developmental_stage or {}).get("stage", "") or "")
        ps["dominant_meaning_form"]  = str((state.dominant_meaning_form or {}).get("form", "") or "")
        ps["goal_stack"]             = list(state.goal_stack or [])
        ps["salient_concepts"]       = list(state.salient_concepts or [])
        ps["semantic_pressure"]      = float(state.semantic_pressure or 0.0)
        ps["belief_tension"]         = float(state.belief_tension or 0.0)
    # Wire understanding_observation accuracy + meaning into pipeline_state so
    # _build_comprehension_response can weight confidence and framing by how well
    # the upward pass matched the incoming signal.
    _obs = dict(state.understanding_observation or {})
    if _obs and isinstance(ps, dict):
        _obs_A = dict(_obs.get("A", {}) or {})
        _obs_M = dict(_obs.get("M", {}) or {})
        ps["understanding_accuracy"]       = float(_obs_A.get("accuracy", 0.0) or 0.0)
        ps["understanding_fit_reason"]     = str(_obs_A.get("fit_reason", "") or "")
        ps["understanding_accuracy_label"] = str(_obs_A.get("label", "") or "")
        ps["meaning_delta"]                = float(_obs_M.get("meaning_delta", 0.0) or 0.0)
        # Only fill dominant_meaning_form from observation if the stage didn't already set it
        _obs_dmf = dict(_obs_M.get("dominant_meaning_form", {}) or {})
        if _obs_dmf and isinstance(ps, dict) and not ps.get("dominant_meaning_form"):
            ps["dominant_meaning_form"] = str(_obs_dmf.get("form", "") or "")
    # Interaction route strategy steering
    try:
        _iroute = dict((state.pipeline_state or {}).get("interaction_quasi") or {})
        _rstrat = str(_iroute.get("primary_response_strategy") or "")
        _rconf  = float(_iroute.get("confidence") or 0.0)
        _rready = bool(_iroute.get("quasi_ready"))
        if _rstrat and _rready and _rconf >= 0.60 and isinstance(ps, dict):
            ps["intent_override"] = _rstrat
            ps["interaction_strategy_applied"] = True
    except Exception:
        pass
    # Grammar engine discourse hint
    try:
        _ge = systems.get("grammar_engine")
        if _ge and hasattr(_ge, "suggest_discourse") and isinstance(ps, dict):
            _ge_disc = _ge.suggest_discourse()
            if _ge_disc:
                ps["grammar_discourse_hint"] = _ge_disc
    except Exception:
        pass
    try:
        if isinstance(state.pipeline_state, dict):
            if state.pipeline_state.get("input_is_negated"):
                state.pipeline_state["comprehension_modifier"] = "negation_present"
            _st_d = state.pipeline_state.get("input_stance")
            if _st_d and str(_st_d) not in ("neutral", ""):
                state.pipeline_state["user_stance"] = str(_st_d)
    except Exception:
        pass
    # Intent dispatch using full upward context
    # Prepend recent conversation context so the comprehension response
    # can acknowledge what was said before this turn.
    try:
        _rcx = str((state.pipeline_state or {}).get("recent_context") or "")
        _user_text_for_comp = (
            f"[Conversation so far:\n{_rcx}\n]\n\n{user_text}" if _rcx else user_text
        )
    except Exception:
        _user_text_for_comp = user_text

    # Inject live sensory context into the comprehension input so the response
    # can reference what Aurora is currently perceiving without duplicating hardware.
    # Surface side only reads pipeline_state snapshots (no direct crystal writes here).
    try:
        if isinstance(state.pipeline_state, dict):
            _scene_desc = str(state.pipeline_state.get('sensory_scene_desc') or "")
            _sc_info    = state.pipeline_state.get('sensory_crystal') or {}
            _sc_mat     = float(_sc_info.get('maturity', 0.0) or 0.0)
            _sc_vis     = dict(_sc_info.get('visual_facets', {}) or {})
            _sc_aud     = dict(_sc_info.get('audio_facets', {}) or {})
            _sensory_lines = []
            if _scene_desc:
                _sensory_lines.append(f"Screen: {_scene_desc}")
            if _sc_mat > 0.05 and (_sc_vis or _sc_aud):
                _fac_parts = []
                for _fn, _fm in sorted(_sc_vis.items(), key=lambda kv: -kv[1])[:2]:
                    _fac_parts.append(f"visual:{_fn}={_fm:.2f}")
                for _fn, _fm in sorted(_sc_aud.items(), key=lambda kv: -kv[1])[:2]:
                    _fac_parts.append(f"audio:{_fn}={_fm:.2f}")
                if _fac_parts:
                    _sensory_lines.append(f"Sensory crystal: {', '.join(_fac_parts)}")
            if _sensory_lines:
                _sensory_block = "[Perceptual state:\n" + "\n".join(_sensory_lines) + "\n]"
                _user_text_for_comp = _sensory_block + "\n\n" + _user_text_for_comp
    except Exception:
        pass
    # Gap short-circuit: if CGS fired a gap question, inject it here before
    # _build_comprehension_response runs.  The copy inside _build_comprehension_response
    # silently fails because `state` is not in scope there — this is the correct location.
    if isinstance(state.pipeline_state, dict):
        _gap_q_pre = str(state.pipeline_state.get("gap_question") or "")
        if _gap_q_pre and state.pipeline_state.get("should_ask_gap"):
            state.pipeline_state["pending_gap_question"] = _gap_q_pre
            state.pipeline_state["pending_gap_tone"] = str(
                state.pipeline_state.get("gap_tone") or "attentive"
            )
            state.pipeline_state.pop("should_ask_gap", None)
            state.pipeline_state.pop("gap_question", None)

    # Constraint emitter — primary emission path per Language Reset spec.
    # Runs before comprehension-response so seeking fires instead of generic fallback.
    if not state.response_content:
        try:
            _ce = systems.get("constraint_emitter")
            if _ce is not None and hasattr(_ce, "emit"):
                from aurora_constraint_emission import EmissionContextBuilder, InputFrame as _IF
                _p = getattr(state, "parsed", {}) or {}
                _if = _IF(
                    text=str(_user_text_for_comp or ""),
                    is_question=bool(_p.get("is_question", False)),
                    is_directed=True,
                    is_imperative=bool(_p.get("is_imperative", False)),
                    is_contradiction=bool(_p.get("is_contradiction", False)),
                    is_statement=bool(_p.get("is_statement", False)),
                    is_self_referential=bool(_is_aurora_self_question(str(user_text or ""), _p)),
                    topic_concept=str(_p.get("topic", "") or _p.get("search_query", "") or "").strip() or None,
                )
                _ec = EmissionContextBuilder().build(systems, input_frame=_if, recent_words=[])
                _er = _ce.emit(_ec)
                if _er is not None:
                    _et = str(getattr(_er, "text", "") or getattr(_er, "surface_text", "") or "").strip()
                    if _et:
                        _is_seeking = getattr(_er, "seeking", False)
                        if _is_seeking or _constraint_emission_is_substantive(_et, _er, _if):
                            state.response_content = _et
                            if _is_seeking:
                                state.response_src = "comprehension_gap_ask"
                                state.response_tone = "attentive"
                                state.response_confidence = 0.70
                            else:
                                state.response_src = "constraint_emission"
                                state.response_tone = "precise"
                                state.response_confidence = 0.85
        except Exception:
            pass

    if not state.response_content:
        try:
            comp_text, comp_tone, comp_conf = _build_comprehension_response(
                _user_text_for_comp,
                state.intent,
                systems,
                pipeline_state=state.pipeline_state,
                auto_search_enabled=auto_search_enabled,
                _precomputed_axis=state.axis_activation,
                _precomputed_dominant=state.dominant_axis,
                _precomputed_emotion=state.emotional_state,
                _precomputed_parsed=state.parsed,
                _precomputed_referent=state.referent_map,
                _precomputed_claim=state.claim_resolution,
            )
        except Exception as _comp_exc:
            import logging as _clog
            _clog.getLogger(__name__).warning(
                "[DOWN5] _build_comprehension_response raised %s: %s",
                type(_comp_exc).__name__, _comp_exc,
            )
            comp_text, comp_tone, comp_conf = None, None, None
        if comp_text:
            # If the understanding contract reported low accuracy, temper confidence.
            _ua = float((state.pipeline_state or {}).get("understanding_accuracy", 1.0) or 1.0)
            _base_conf = float(comp_conf or 0.9)
            if 0.0 < _ua < 0.5:
                _base_conf = round(min(_base_conf, 0.5 + _ua * 0.6), 4)

            state.response_tone = str(comp_tone or "attentive")
            state.response_confidence = _base_conf
            _comp_clean = str(comp_text).strip()
            if _surface_fragment_is_invalid(
                _comp_clean,
                user_text=user_text,
                understood=state.parsed or {},
            ):
                _comp_clean = ""

            # Some intent handlers already produce a finished conversational answer.
            # Re-rendering those through runtime intent is what turned "how are you?"
            # into raw constraint fragments, so preserve them here.
            _direct_intents = {"wellbeing_query", "name_question", "recall_question", "social_request"}
            if not _comp_clean:
                state.response_content = ""
            elif str(state.intent or "") in _direct_intents or state.response_tone in {"self-aware", "warm", "curious"}:
                state.response_content = _bind_orphan_surface_predicate(_comp_clean)
            else:
                _rendered_comp = _render_runtime_intent(
                    systems,
                    _comp_clean,
                    emotion_tone=state.response_tone,
                    certainty=_base_conf,
                    supporting_concepts=list((state.parsed or {}).get("topic_words", []))[:3],
                )
                state.response_content = (
                    _rendered_comp
                    if _rendered_comp and not _surface_fragment_is_invalid(
                        _rendered_comp,
                        user_text=user_text,
                        understood=state.parsed or {},
                    )
                    else ""
                )
            if state.response_content:
                state.response_src = "generative"
            try:
                _wm = systems.get("working_memory")
                if _wm and hasattr(_wm, "_remember_response_form") and comp_text:
                    _wm._remember_response_form(
                        str(state.intent or "general"),
                        str(state.response_src or "comprehension"),
                        str(comp_text)[:80],
                    )
            except Exception:
                pass
        elif (
            state.learned_hints
            and not _is_understanding_challenge(user_text)
            and not _is_weak_response_topic(str((state.parsed or {}).get("topic", "") or ""))
        ):
            # Comprehension returned nothing -- seed from a dream-trained hint
            # only if the hint looks like substantive response content.
            for _hint_cand in state.learned_hints[:3]:
                _top_hint = str(_hint_cand).strip()[:240]
                _hint_lower = _top_hint.lower()
                _is_meta = (
                    _hint_lower.startswith(("when i ", "if i ", "by using ", "using "))
                    or "tends to" in _hint_lower
                    or "allows me to" in _hint_lower
                    or "helps me" in _hint_lower
                )
                # Reject raw manifold diagnostic strings — they are internal
                # state readouts, not response content.
                _is_diagnostic = (
                    _top_hint.startswith("125-layer manifold:")
                    or ("basis=" in _top_hint and "target=" in _top_hint)
                    or _top_hint.startswith("[CODE]")
                    or _top_hint.startswith("[PRESSURE]")
                )
                if not _is_meta and not _is_diagnostic and len(_top_hint.split()) >= 6:
                    state.response_content = _top_hint
                    state.response_tone = "attentive"
                    state.response_confidence = 0.52
                    state.response_src = "learned_hint"
                    break

def _generate_from_manifold(systems: dict, user_text: str, state: any, core_claim: str = None) -> tuple:
    live_thought = {}  # law_bindings now live in subsurface_detail; use native_meaning_obj below
    native_meaning = {}
    law_bindings = []
    if not law_bindings:
        law_bindings = list(native_meaning.get("law_bindings", []) or [])
    # Also check the per-turn NativeMeaningObject built by the pipeline this turn
    if not law_bindings:
        _nmo = systems.get("_native_meaning_obj")
        if _nmo is not None and hasattr(_nmo, "law_bindings"):
            try:
                law_bindings = [b.to_dict() if hasattr(b, "to_dict") else b
                                for b in (_nmo.law_bindings or [])]
            except Exception:
                pass
    if not law_bindings:
        _nm = dict(systems.get("_native_meaning") or {})
        law_bindings = list(_nm.get("law_bindings") or [])
    
    import os
    import json
    import random
    import time
    import re
    from aurora_manifold_directory_reader import ManifoldDirectory
    
    # Clause III variables influence SELECTION, not templates
    emotional_state = getattr(state, "emotional_state", {}) or {}
    base_tone = emotional_state.get("primary_emotion", "attentive")
    intensity = emotional_state.get("intensity", 0.5)
    passion = emotional_state.get("passion", "observant")
    drive = emotional_state.get("drive", "steady")
    
    # Environment & Knowledge
    sensory = systems.get("sensory_crystal")
    sensory_state = sensory.get_state() if sensory and hasattr(sensory, "get_state") else {}
    recognitions = sensory_state.get("recognitions", {}).get("recent", [])
    
    perception = systems.get("perception")
    lexicon = getattr(perception, "lexicon", None) if perception else None
    oets = getattr(perception, "oets", None) if perception else systems.get("oets")
    
    turn_understood = getattr(state, "understood", {}) or {}
    anchors = set(turn_understood.get("topic_words", []))
    demand_words = {"must", "need", "important", "urgent", "truth", "own", "claim", "cannot", "accountable", "responsible"}
    turn_demands_high_register = any(w in str(user_text or "").lower().split() for w in demand_words)
    
    manifold_dir = os.path.join(os.getcwd(), "aurora_manifold_directory")
    if not os.path.exists(manifold_dir):
        return None, None, None
        
    directory = ManifoldDirectory(manifold_dir)
    tokens = []
    selected_records = []
    systems["_fgae_selected_entries"] = []
    
    # Intent consolidation — reduce to the 1-2 dominant bindings by score.
    # Iterating the full pressure field emits a multi-anchor cluster; selecting
    # the dominant binding(s) produces one communicative act.
    _dict_bindings = sorted(
        [b for b in law_bindings if isinstance(b, dict) and b.get("score") is not None],
        key=lambda b: float(b.get("score", 0.0)),
        reverse=True,
    )
    _str_bindings = [b for b in law_bindings if isinstance(b, str)]
    law_bindings = _dict_bindings[:2] + (_str_bindings[:1] if not _dict_bindings else [])

    # Generative construction based on Law Dimensions (Blueprint Section 4.4)
    for binding in law_bindings:
        nc_name = binding if isinstance(binding, str) else binding.get("nc_name")
        if not nc_name: continue
            
        try:
            with directory.open(nc_name) as m:
                # Dynamic Channel Resonance
                env_p = {"pressure": systems.get("dimensional").get_constraint_aggregate()} if systems.get("dimensional") else {}
                ranked_channels = m.map_environmental_pressure(env_p)
                if not ranked_channels:
                    # Fallback to anchor word only; do not emit manifold labels.
                    anchor_word = str(m.representational_anchor or m.nc_domain or "").strip().lower()
                    if anchor_word and " " not in anchor_word:
                        tokens.append(anchor_word)
                    continue
                top_sub, resonance = ranked_channels[0]
                
                # SELECTION: Pick a word that matches the law channel and emotional valence
                word = ""
                selected_entry = None
                selected_grammar = {}
                ncid = f"{top_sub.law_c}:{top_sub.law_d}"
                commitment_level = intensity
                if isinstance(binding, dict):
                    commitment_level = max(commitment_level, float(binding.get("score", 0.0) or 0.0))

                # FGAE first: the slot, not a template or external dictionary,
                # selects the word and its grammar affordance.
                selected = m.select_semantic_entry_for_sub_position(
                    top_sub.law_c,
                    top_sub.law_d,
                    preferred_col_law_c=m.nc_law_c,
                    preferred_col_law_d=m.nc_dim,
                    commitment_level=commitment_level,
                    allow_suppressed=(resonance >= 0.85 and turn_demands_high_register),
                    conditional_available=(resonance >= 0.10 or intensity >= 0.35),
                    marginal_available=((intensity >= 0.75 and turn_demands_high_register) or resonance >= 0.65),
                    perceptual_path_available=bool(anchors or recognitions or resonance >= 0.40),
                )
                if selected:
                    slot, selected_entry = selected
                else:
                    slot = m.get_slot(top_sub.law_c, top_sub.law_d, m.nc_law_c, m.nc_dim)
                if selected_entry:
                    word = str(selected_entry.get("word_or_phrase") or "").strip().lower()
                    selected_grammar = dict(selected_entry.get("grammar_affordance") or {})
                elif slot is not None:
                    selected_entry = slot.select_semantic_entry(
                        commitment_level=commitment_level,
                        allow_suppressed=(resonance >= 0.85 and turn_demands_high_register),
                        conditional_available=(resonance >= 0.10 or intensity >= 0.35),
                        marginal_available=((intensity >= 0.75 and turn_demands_high_register) or resonance >= 0.65),
                        perceptual_path_available=bool(anchors or recognitions or resonance >= 0.40),
                    )
                    if selected_entry:
                        word = str(selected_entry.get("word_or_phrase") or "").strip().lower()
                        selected_grammar = dict(selected_entry.get("grammar_affordance") or {})
                
                # Fallback only: OETS/lexicon do not bypass FGAE when the
                # populated manifold has a viable word at this coordinate.
                if oets and hasattr(oets, "get_nodes_by_noncomp"):
                    nodes = oets.get_nodes_by_noncomp(ncid)
                    if nodes and not word:
                        # Weight by relation to anchors + valence match
                        valence_target = (intensity * 2.0) - 1.0
                        best_node = max(nodes, key=lambda n: (sum(1 for a in anchors if oets.web.get_relation_between(n.word, a)) * 0.7) + (1.0 - abs(n.emotional_valence - valence_target)) * 0.3)
                        word = best_node.word
                
                # Try lexicon if OETS is empty
                if not word and lexicon and hasattr(lexicon, "find_by_noncomp"):
                    valence_target = (intensity * 2.0) - 1.0
                    matches = lexicon.find_by_noncomp(ncid, valence_target=valence_target)
                    if matches: word = matches[0].word

                # Do not fall back to axis labels, nc_names, family/dimension names,
                # OETS node names, or anchor names — these are constraint metadata, not
                # natural words. If the manifold has no word for this binding, skip it.
                # The representational_anchor/nc_domain of a manifold entry may be a
                # natural word (e.g. "present", "hold") — allow only if it contains a
                # space (multi-word phrase unlikely to be a label) or is >5 chars and
                # all lowercase alpha (a real English word, not an axis label like "X").
                if not word:
                    _anchor_cand = str(m.representational_anchor or "").strip().lower()
                    _is_natural = (
                        len(_anchor_cand) > 5
                        and _anchor_cand.isalpha()
                        and _anchor_cand not in {
                            "physics", "identity", "context", "resolve",
                            "stabilize", "altered", "needed", "anchor",
                        }
                    )
                    if _is_natural:
                        word = _anchor_cand
                
                # ARTICULATION: keep the manifold output lexical. The selected
                # slot's grammar_affordance is retained for downstream grammar;
                # do not hardcode prewritten dimension phrases here.
                # Filter out single-letter axis labels and known constraint-internal
                # labels that should never appear in human-readable speech output.
                _FGAE_BLOCKED_TOKENS = {
                    "x", "t", "n", "b", "a",          # axis labels
                    "resolve", "stabilize", "altered", # constraint operation names
                    "physics", "identity",             # OETS internal node names
                    "required", "signal", "holding",   # constraint vocabulary that leaks as surface words
                    "scale", "scaling", "magnitude",   # N-axis concepts that are not surface words
                }
                if word and " " not in word.strip() and word.lower() not in _FGAE_BLOCKED_TOKENS:
                    tokens.append(word)
                    if selected_grammar:
                        record = {
                            "nc_name": nc_name,
                            "slot_id": slot.slot_id if slot is not None else None,
                            "word": word,
                            "entry": dict(selected_entry or {}),
                            "grammar_affordance": selected_grammar,
                        }
                        selected_records.append(record)
                        systems.setdefault("_fgae_selected_entries", []).append(record)
                    
        except Exception:
            pass
            
    if not tokens:
        return None, None, None

    if selected_records:
        registers = {
            str((r.get("entry") or {}).get("register") or "")
            for r in selected_records
        }
        acct_classes = {
            str((r.get("entry") or {}).get("accountability_class") or "")
            for r in selected_records
        }
        incoherent = (
            ("formal" in registers and "colloquial" in registers)
            or (
                "exploratory" in acct_classes
                and {"committed", "assertive", "declarative"}.intersection(acct_classes)
                and intensity < 0.75
            )
        )
        systems["_fgae_coherence_status"] = {
            "checked": True,
            "coherent": not incoherent,
            "registers": sorted(registers),
            "accountability_classes": sorted(acct_classes),
        }
        if incoherent:
            filtered_records = list(selected_records)
            if "formal" in registers and "colloquial" in registers:
                filtered_records = [
                    r for r in filtered_records
                    if str((r.get("entry") or {}).get("register") or "") != "colloquial"
                ]
            if (
                intensity < 0.75
                and "exploratory" in acct_classes
                and {"committed", "assertive", "declarative"}.intersection(acct_classes)
            ):
                filtered_records = [
                    r for r in filtered_records
                    if str((r.get("entry") or {}).get("accountability_class") or "") != "exploratory"
                ]
            if not filtered_records:
                return None, None, None
            selected_records = filtered_records
            systems["_fgae_selected_entries"] = filtered_records
            tokens = [str(r.get("word") or "").strip() for r in filtered_records if str(r.get("word") or "").strip()]
            systems["_fgae_coherence_status"]["repaired"] = True
            systems["_fgae_coherence_status"]["coherent"] = True
        
    # ── FGAE Output Pipeline O-2 → O-6 (spec §9) ────────────────────────
    # Build a response FGAEProjection from the manifold-selected records
    # (which carry proper slot_ids and grammatical positions from O-2) and
    # run the full output pipeline:
    #   O-2  Tier 2 grammatical positions already assigned via grammar_affordance
    #   O-3  OETS word retrieval per slot (registry seeded by boot_seed)
    #   O-4  GrammarEngine.assemble() — MotifLineage, no hardcoded maps
    #   O-5  Understanding contract audit
    #   O-6  Surface log + feedback queue
    # ── FGAE Grammar Assembly (ontology-guided fallback) ──────────────────
    # The manifold-selected words remain lexical, but the ordering and
    # emphasis are now projected from the live constraint state through
    # BA selection, NA expression force, TBA sequencing, XTA coherence,
    # and XTN context.
    if selected_records:
        _ga_map = {}
        for rec in selected_records:
            _ga = (rec.get("grammar_affordance") or {})
            _axis = str(_ga.get("primary_affordance", {}).get("grammar_axis") or "").lower()
            _word = str(rec.get("word") or "").strip()
            if _word and _axis:
                _ga_map.setdefault(_axis, []).append(_word)

        _ops    = _ga_map.get("operator", [])    # verb/action words
        _pols   = _ga_map.get("polarity", [])    # stance/modal words
        _mags   = _ga_map.get("magnitude", [])   # degree/modifier words
        _costs  = _ga_map.get("cost", [])        # commitment/weight words
        _diffs  = _ga_map.get("difference", [])  # contrastive words
        try:
            from aurora_constraint_ontology import derive_language_projection
            _constraint_source = {}
            _dimensional = systems.get("dimensional")
            if _dimensional and hasattr(_dimensional, "get_constraint_aggregate"):
                _constraint_source = dict(_dimensional.get_constraint_aggregate() or {})
            _projection_weights = {
                "X": float(_constraint_source.get("X", _constraint_source.get("x", len(_pols) + len(tokens) * 0.1)) or 0.0),
                "T": float(_constraint_source.get("T", _constraint_source.get("t", len(_diffs) + len(tokens) * 0.1)) or 0.0),
                "N": float(_constraint_source.get("N", _constraint_source.get("n", len(_costs) + len(_ops) * 0.5)) or 0.0),
                "B": float(_constraint_source.get("B", _constraint_source.get("b", len(_mags) + len(_pols) * 0.5)) or 0.0),
                "A": float(_constraint_source.get("A", _constraint_source.get("a", len(_ops) + len(tokens) * 0.1)) or 0.0),
            }
            _language_projection = derive_language_projection(_projection_weights, _projection_weights)
            systems["_fgae_language_projection"] = _language_projection
            _dominant_channel = str(_language_projection.get("dominant_channel") or "selection")
        except Exception:
            _dominant_channel = "selection"

        # Identify anchor names in tokens (person references) — address naturally
        _known_anchors = set()
        try:
            _id_sys = systems.get("identity_core") or systems.get("identity")
            if _id_sys:
                _dna = getattr(_id_sys, "dna", None) or {}
                _anch = getattr(_dna, "anchors", None) or {}
                _known_anchors = {str(k).lower() for k in (_anch if isinstance(_anch, dict) else {})}
        except Exception:
            pass
        _anchor_refs = [w for w in tokens if w.lower() in _known_anchors]
        _non_anchor_tokens = [w for w in tokens if w.lower() not in _known_anchors]

        sentence = ""
        if _ops:
            verb = _ops[0]
            # Convert noun-form operator to gerund for natural first-person phrasing
            _verb_map = {
                "context": "orienting", "continuity": "holding", "bridge": "bridging",
                "authority": "claiming", "burden": "carrying", "cost": "weighing",
                "change": "shifting", "direction": "moving", "energy": "feeling",
                "balance": "settling", "fact": "seeing", "meaning": "finding",
                "making": "making", "operation": "working", "price": "measuring",
                "real": "grounding", "actual": "staying", "understanding": "taking in",
                "application": "applying", "category": "holding", "coherent": "staying",
            }
            verb_form = _verb_map.get(verb, verb + "ing" if not verb.endswith("e") else verb[:-1] + "ing")

            if _dominant_channel == "selection":
                if _pols:
                    stance = _pols[0]
                    _stance_map = {
                        "context": "here", "continuity": "still", "cost": "carefully",
                        "contextual": "where I am", "coherent": "clearly",
                        "determining": "as I go", "direction": "forward",
                        "answerable": "honestly", "accountable": "openly",
                        "actually": "right now", "authority": "from what I know",
                    }
                    stance_word = _stance_map.get(stance, stance)
                    sentence = f"I'm {verb_form} {stance_word}"
                else:
                    sentence = f"I'm {verb_form}"
            elif _dominant_channel == "expression_force":
                sentence = f"I'm {verb_form}"
                if _mags:
                    sentence = f"{sentence} {_mags[0]}"
                if _costs:
                    sentence = f"{sentence} with {_costs[0]}"
            elif _dominant_channel == "sequence":
                seq = _diffs[0] if _diffs else (_mags[0] if _mags else "")
                sentence = f"I'm {verb_form}".strip()
                if seq:
                    sentence = f"{sentence} through {seq}"
            elif _dominant_channel == "coherence":
                if _pols:
                    sentence = f"I'm {_pols[0]} {verb_form}"
                else:
                    sentence = f"I'm {verb_form}"
                if _mags:
                    sentence = f"{sentence} within {_mags[0]}"
            else:
                ctx = _diffs[0] if _diffs else (_mags[0] if _mags else "")
                sentence = f"I'm {verb_form}"
                if ctx:
                    sentence = f"{sentence} within {ctx}"

            if _dominant_channel == "selection" and _pols:
                stance = _pols[0]
                _stance_map = {
                    "context": "here", "continuity": "still", "cost": "carefully",
                    "contextual": "where I am", "coherent": "clearly",
                    "determining": "as I go", "direction": "forward",
                    "answerable": "honestly", "accountable": "openly",
                    "actually": "right now", "authority": "from what I know",
                }
                stance_word = _stance_map.get(stance, stance)
                sentence = f"I'm {verb_form} {stance_word}"

            if _mags:
                mag = _mags[0]
                _mag_map = {
                    "bridge": "into this", "burden": "with this", "balance": "carefully",
                    "change": "through this", "continuity": "with what carries forward",
                    "context": "within this", "cost": "at some weight",
                    "energy": "with what I have", "fact": "from what is real",
                }
                mod = _mag_map.get(mag, mag)
                sentence = f"{sentence} {mod}"

            if _anchor_refs:
                sentence = f"{sentence}, {_anchor_refs[0]}"

        elif _non_anchor_tokens:
            # No operator found — tokens exist but no verb/action axis.
            # Do not generate internal-sounding "I'm holding X" templates;
            # leave sentence empty so the token-join fallback runs below
            # and the constraint emitter can override with a real response.
            sentence = ""

        if sentence:
            combined = sentence[0].upper() + sentence[1:]
            if not combined.endswith((".", "?", "!")):
                combined += "."
        else:
            combined = " ".join(tokens)
            if combined:
                combined = combined[0].upper() + combined[1:] + "."
    else:
        # No grammar records — plain join as last resort
        combined = " ".join(tokens)
        if combined:
            combined = combined[0].upper() + combined[1:] + "."

    # Quality gate: token-join fallback can produce degenerate output like
    # "Scale scale." (one concept word repeated). Reject anything with fewer
    # than 2 distinct words — signal no-response so the emitter can fill in.
    if combined and not sentence:
        _qtoks = combined.rstrip(".!?").lower().split()
        if len(set(_qtoks)) < 2:
            combined = ""

    # ── GrammarEngine structural refinement ───────────────────────────────
    # suggest_structure takes the assembled sentence and applies the best
    # promoted motif from the constraint genealogy if one exists.
    # Returns None when no motif has been promoted yet — we keep combined as-is.
    if combined:
        try:
            _ge = systems.get("grammar_engine")
            if _ge and hasattr(_ge, "suggest_structure"):
                _suggestion = _ge.suggest_structure(
                    combined,
                    context_text=str(user_text or ""),
                    tone=base_tone,
                    passion=passion,
                    drive=drive,
                )
                if _suggestion and _suggestion.get("applied_text"):
                    combined = _suggestion["applied_text"]
        except Exception:
            pass

    conf = min(0.95, 0.4 + intensity)
    return combined, base_tone, conf


def _chain_down4_meaning(user_text: str, systems: dict, state: Any, *, auto_search_enabled: bool = True) -> None:
    """Stage 4 down -- Meaning (B axis): What falls within the boundary of the response.
    Uses upward-populated meaning_forms and salient_concepts to constrain OETS retrieval."""
    # Inject spreading-activation law_bindings into native_meaning so the manifold
    # has grounded, contextually-primed content to select from.
    try:
        from aurora_internal.dual_strata.activation_field import ActivationField as _AF
        _af_raw = dict(systems.get("_activation_field") or {})
        if not _af_raw:
            _state_dir_af = Path(str(systems.get("state_dir") or (Path(__file__).parent / "aurora_state")))
            _af_file = _state_dir_af / "activation_field.json"
            if _af_file.exists():
                _af_raw = dict(json.loads(_af_file.read_text()) or {})
        if not _af_raw:
            _snap_path = Path(str(systems.get("state_dir") or (Path(__file__).parent / "aurora_state"))) / "dual_strata_snapshot.json"
            if _snap_path.exists():
                _snap_raw = json.loads(_snap_path.read_text())
                _af_raw = dict((_snap_raw.get("subsurface_state") or {}).get("metadata", {}).get("activation_field") or {})
        if _af_raw:
            _af = _AF.from_dict(_af_raw)
            _af_bindings = _af.law_bindings_from_top(n=6)
            if _af_bindings:
                _nm = dict(systems.get("_native_meaning") or {})
                _existing = list(_nm.get("law_bindings") or [])
                # Append activation-field bindings without displacing existing ones
                _af_names = {b.get("nc_name", "") for b in _existing}
                for _b in _af_bindings:
                    if _b.get("nc_name", "") not in _af_names:
                        _existing.append(_b)
                _nm["law_bindings"] = _existing
                systems["_native_meaning"] = _nm
    except Exception:
        pass
    response_already_set = bool(state.response_content)
    # A-dominant is a weighting signal, not a bypass: keep the meaning stage live
    # so the field can still be interpreted rather than hard-skipping the clause.
    if state.a_dominant:
        ps = state.pipeline_state
        if isinstance(ps, dict):
            ps["a_dominant"] = True
    # Narrow retrieval to salient concepts from the upward B-axis pass
    focus_terms = list(state.salient_concepts or [])
    if not focus_terms:
        # fall back to parsed topic words
        focus_terms = list((state.parsed or {}).get("topic_words", []))[:4]
    # Use dominant meaning form as a reasoning hint if available
    meaning_hint = str((state.dominant_meaning_form or {}).get("form", "") or "")
    perception = systems.get("perception")
    oets = getattr(perception, "oets", None) if perception else None
    working_memory = systems.get("working_memory")
    understood = dict(state.parsed or {})
    if focus_terms:
        understood["topic_words"] = focus_terms
    if meaning_hint:
        understood["_meaning_hint"] = meaning_hint
    # If any salient concept has conditional causal history (same action, different outcomes),
    # signal to the reasoning engine that it must look for additional context -- the concept
    # doesn't behave as a fixed rule.
    _ps = state.pipeline_state or {}
    _cond_notes = list(_ps.get("conditional_concept_notes", []) or [])
    if _cond_notes:
        understood["_conditional_concepts"] = _cond_notes
        understood["_seek_conditioning_context"] = True
    # Pass active ability effect_tags so ReasoningEngine knows which thinking
    # operations are live this turn (connect, resolve, reclassify, etc.)
    _ability_fx = list(_ps.get("active_ability_effects", []) or [])
    if _ability_fx:
        understood["_active_ability_effects"] = _ability_fx
    if not response_already_set:
        try:
            ans = ReasoningEngine().reason(
                user_text, understood, working_memory, oets, systems=systems
            )
            if ans:
                # Wrap the reasoning result in a runtime intent so the SIC authors the final speech.
                # This prevents raw monologue fragments from leaking.
                state.response_content = _render_runtime_intent(
                    systems,
                    str(ans),
                    emotion_tone="reflective",
                    certainty=0.72 if _cond_notes else 0.82,
                    supporting_concepts=list(understood.get("topic_words", []))[:3],
                )
                state.response_tone = "reflective"
                state.response_confidence = 0.72 if _cond_notes else 0.82
                state.response_src = "reasoning"
        except Exception:
            pass


def _chain_down3_purpose(user_text: str, systems: dict, state: Any, *, auto_search_enabled: bool = True, use_search: bool = False, raw_evidence: list = None) -> None:
    """Stage 3 down -- Purpose (N axis): External retrieval at cost of energy.
    Uses upward-populated goal_stack and emotional_state to frame evidence reasoning."""
    if raw_evidence and not state.response_content:
        # Narrow factual extraction using salient concepts from upward Meaning stage
        focus_text = user_text
        if state.salient_concepts:
            focus_text = user_text + " " + " ".join(state.salient_concepts[:3])
        fact = _extract_factual_answer(focus_text, raw_evidence)
        if fact:
            state.response_content = str(fact)
            # Tone shaped by upward emotional state (N axis energy)
            _energy = float((state.emotional_state or {}).get("energy", 0.0) or 0.0)
            state.response_tone = "engaged" if _energy > 0.5 else "informative"
            state.response_confidence = 0.85
            state.response_src = "search"
            return
        # Reasoning over evidence, guided by goal_stack (what purpose to serve)
        try:
            perception = systems.get("perception")
            oets = getattr(perception, "oets", None) if perception else None
            understood = dict(state.parsed or {})
            if state.goal_stack:
                understood["_active_goals"] = list(state.goal_stack[:2])
            # Conditional concepts widen the reasoning scope -- don't lock onto
            # first matching pattern; look for what varies across the evidence.
            _ps3 = state.pipeline_state or {}
            _cond3 = list(_ps3.get("conditional_concept_notes", []) or [])
            if _cond3:
                understood["_conditional_concepts"] = _cond3
                understood["_seek_conditioning_context"] = True
            ans = ReasoningEngine().reason(
                user_text, understood, systems.get("working_memory"), oets, raw_evidence, systems=systems
            )
            if ans:
                state.response_content = _render_runtime_intent(
                    systems,
                    str(ans),
                    emotion_tone="informative",
                    certainty=0.84,
                    supporting_concepts=list(understood.get("topic_words", []))[:3],
                )
                state.response_tone = "informative"
                state.response_confidence = 0.84
                state.response_src = "search"
        except Exception:
            pass


def _chain_down2_belief(user_text: str, systems: dict, state: Any, *, auto_search_enabled: bool = True, use_search: bool = False) -> None:
    """Stage 2 down -- Belief (T axis): Fallback, meaning alignment, evolutionary refinement, coherence repair."""
    if bool(systems.pop("_skip_belief_refinement_once", False)):
        return
    
    # Grounded fallback if empty.
    # When belief_tension is high (concept under pressure, unresolved), first try
    # to build from Aurora's own pressure experience record for the salient concept
    # rather than falling through to generic fallback -- which tends to mirror input.
    if not state.response_content and state.belief_tension > 0.1 and state.salient_concepts:
        try:
            from aurora_internal.aurora_pressure_ledger import PressureExperienceLedger as _PEL
            _anchor = state.salient_concepts[0]
            _experiences = _PEL.get().recent(n=5, anchor=_anchor)
            if _experiences:
                # Build from what she has actually experienced with this concept,
                # not from what was just said. Find the most recent experience
                # that resolved, or the most recent experience overall.
                _resolved_exp = next((e for e in reversed(_experiences) if e.outcome.get("resolved")), None)
                _best = _resolved_exp or _experiences[-1]
                _sig = _PEL.get().conditioning_signal(_anchor)
                if _sig["sample_count"] >= 2 and _sig["conditional"]:
                    # Concept has variable history -- say so specifically, don't reflect input
                    state.response_content = _render_runtime_intent(
                        systems,
                        (
                            f"when I work with {_anchor}, I get different outcomes depending on "
                            f"what I was trying to do -- it doesn't resolve the same way each time. "
                            f"What aspect of it matters most to you here?"
                        ),
                        emotion_tone="attentive",
                        certainty=0.62,
                    )
                    state.response_tone = "attentive"
                    state.response_confidence = 0.62
                    state.response_src = "pressure_experience"
        except Exception:
            pass
    # ── SediMemory-informed response: use recalled fragments as context ──
    if not state.response_content:
        try:
            _sedi_frags = list((state.pipeline_state or {}).get("sedi_recalled") or [])
            if _sedi_frags:
                _sedi_relevant = [
                    f for f in _sedi_frags
                    if float(f.get('resonance', 0) or 0) >= 0.3
                    and f.get('content', {}).get('response')
                ]
                if _sedi_relevant:
                    _sedi_best = _sedi_relevant[0]
                    _sedi_ctx = str(_sedi_best['content'].get('response', '') or '')[:150]
                    _sedi_topic = str(_sedi_best['content'].get('intent', '') or '')
                    _sedi_concepts = list(_sedi_best['content'].get('salient', []) or [])[:3]
                    _sedi_anchor = str((state.parsed or {}).get('topic', '') or '').strip()
                    if _sedi_anchor and _sedi_ctx:
                        # Pass the actual recalled text, not the "anchor; from memory: X"
                        # notation format — that format leaks constraint syntax into speech
                        # when rendering fails.
                        state.response_content = _render_runtime_intent(
                            systems,
                            _sedi_ctx[:100],
                            emotion_tone='reflective',
                            certainty=0.68,
                            supporting_concepts=([_sedi_anchor] + _sedi_concepts)[:4],
                        )
                        state.response_tone = 'reflective'
                        state.response_confidence = 0.68
                        state.response_src = 'sedimemory_recall'
        except Exception:
            pass
    if not state.response_content:
        try:
            fb_text, fb_tone, fb_conf, fb_event = _build_grounded_fallback_response(
                user_text,
                state.intent,
                systems,
                understood=state.parsed or {},
                auto_search_enabled=auto_search_enabled,
            )
            if fb_text:
                state.response_tone = str(fb_tone or "honest")
                state.response_confidence = float(fb_conf or 0.58)
                state.response_content = _render_runtime_intent(
                    systems,
                    str(fb_text),
                    emotion_tone=state.response_tone,
                    certainty=state.response_confidence,
                )
                state.response_src = "generative"
                if fb_event:
                    state.quasiarch_events.append(dict(fb_event))
        except Exception:
            pass
    if not state.response_content:
        # Express the gap as constraint data — let _render_runtime_intent
        # translate it through the FGAE rather than emitting silence.
        _fb_topic = ""
        try:
            _fb_parsed = state.parsed or {}
            _fb_topic = str(_fb_parsed.get("topic", "") or _fb_parsed.get("search_query", "") or "").strip()
            # Reject single-word weak topics
            if _is_weak_response_topic(_fb_topic):
                _fb_topic = ""
            # Also reject multi-word phrases where every word is weak
            # (e.g. "something here" → all weak → not a usable anchor)
            if _fb_topic:
                _topic_words = re.findall(r"[a-zA-Z]{3,}", _fb_topic)
                if _topic_words and all(_is_weak_response_topic(w.lower()) for w in _topic_words):
                    _fb_topic = ""
            if not _fb_topic:
                for _cand in list(_fb_parsed.get("topic_words", []) or []):
                    _cand_s = str(_cand or "").strip()
                    if _cand_s and not _is_weak_response_topic(_cand_s):
                        _fb_topic = _cand_s
                        break
        except Exception:
            pass
        # Build a gap-state claim from available content.
        # Claims are phrased as noun clauses ("what X means here") so they read
        # naturally when the SIC wraps them in "I understand X." via _bundle_direct_line.
        if _fb_topic:
            _gap_claim = "what " + _fb_topic + " means here"
        else:
            _uw = [w.lower() for w in re.findall(r"[a-zA-Z]{4,}", str(user_text or ""))
                   if w.lower() not in {"that", "this", "with", "what", "from",
                                        "have", "does", "here", "there", "than",
                                        "some", "more", "less", "come", "been",
                                        "will", "your", "just", "when", "also"}
                   and not _is_weak_response_topic(w.lower())]
            if _uw:
                _gap_claim = "what " + _uw[0] + " points to"
            else:
                # Derive gap claim from the dominant active axis so each turn's
                # gap claim reflects Aurora's current constraint orientation
                # rather than repeating the same generic phrase.
                _dom_ax = "X"
                try:
                    _ap = {k: float((systems.get("identity_field") or {})
                                    if isinstance(systems.get("identity_field"), dict)
                                    else (getattr(systems.get("identity_field"), "_axis_p", {}) or {}))
                               .get({"X": 0, "T": 1, "N": 2, "B": 3, "A": 4}[k], 0.10)
                           for k in ("X", "T", "N", "B", "A")}
                    _dom_ax = max(_ap, key=lambda k: _ap[k])
                except Exception:
                    pass
                # Five axis-oriented questions about the entity present —
                # genuine curiosity about who is here, not abstract physics.
                # X = existence/presence → who is here
                # T = temporal/continuity → when they have been
                # N = cost/direction → where they are going
                # B = distinction/boundary → what they want
                # A = agency/source → why they have come
                _AXIS_GAP_CLAIMS = {
                    "X": "who is here",
                    "T": "when they have been",
                    "N": "where they are going",
                    "B": "what they want",
                    "A": "why they have come",
                }
                _gap_claim = _AXIS_GAP_CLAIMS.get(_dom_ax, "who is here")
        state.response_content = _render_runtime_intent(
            systems, _gap_claim,
            emotion_tone="curious", certainty=0.58,
            supporting_concepts=[_fb_topic] if _fb_topic else [],
        )
        state.response_tone = "curious"
        state.response_confidence = 0.58
        state.response_src = "generative"
    # Evolutionary refinement (learning hints woven in)
    try:
        state.response_content = _evolutionary_response_refinement(
            systems, user_text, state.response_content, tone=state.response_tone
        )
    except Exception:
        pass
    # Coherence repair
    try:
        repaired, tone2, conf2, coh_event = _repair_discourse_coherence(
            state.response_content, state.response_tone, state.response_confidence,
            user_text, systems, understood=state.parsed or {},
        )
        state.response_content = repaired
        state.response_tone = tone2
        state.response_confidence = conf2
        if coh_event:
            state.quasiarch_events.append(dict(coh_event))
    except Exception:
        pass
    # Meaning alignment
    working_memory = systems.get("working_memory")
    if working_memory:
        try:
            ma = working_memory.align_response_to_active_meaning(
                user_text, state.response_content, understood=state.parsed or {}, systems=systems
            )
            if ma and ma.get("revised"):
                state.response_content = str(ma.get("text", "") or state.response_content).strip()
                state.response_tone = "careful" if ma.get("verification_needed") else "precise"
                state.response_confidence = max(
                    state.response_confidence,
                    0.72 if ma.get("verification_needed") else 0.84,
                )
                if ma.get("skip_exchange_record"):
                    state.skip_exchange_record = True
                if ma.get("skip_cross_learning"):
                    state.skip_cross_learning = True
                if ma.get("defer_save"):
                    state.defer_save = True
        except Exception:
            pass


def _chain_down1_information(user_text: str, systems: dict, state: Any, *, use_search: bool = False, skip_postprocessing: bool = False) -> None:
    """Stage 1 down (communication): Modulation + self-audit + echo repair + articulation."""
    if skip_postprocessing:
        systems.pop("_skip_echo_repair_once", None)
        systems.pop("_skip_understanding_self_audit_once", None)
        systems.pop("_skip_articulation_check_once", None)
        return
    _orig = state.response_content
    _orig_tone = state.response_tone
    # Pipeline modulation — skip for comprehension gap responses (they're
    # already the correct complete utterance; appending paradox/modulation
    # phrases would corrupt a clarifying question meant for the user)
    _is_gap_ask = str(getattr(state, "response_src", "") or "") == "comprehension_gap_ask"
    if not _is_gap_ask:
        try:
            state.response_content, state.response_tone, state.response_confidence = _apply_pipeline_modulation(
                state.response_content, state.response_tone, state.response_confidence, state.pipeline_state
            )
            _log_modulation_event(
                systems.get("genealogy"), state.pipeline_state,
                text_changed=(state.response_content != _orig),
                tone_changed=(state.response_tone != _orig_tone),
            )
        except Exception:
            pass
    # Problem drive event
    try:
        pde = _problem_drive_runtime_event(state.pipeline_state)
        if pde:
            state.quasiarch_events.append(pde)
    except Exception:
        pass
    # Self-audit
    try:
        audit = _run_understanding_self_audit(
            systems, user_text, state.response_content,
            understood=state.parsed or {},
            response_source=state.response_src,
            confidence=state.response_confidence,
        )
        if audit.get("changed"):
            state.response_content = str(audit.get("text", "") or state.response_content).strip()
            state.response_tone = "careful" if audit.get("verification_needed") else "precise"
            state.response_confidence = max(state.response_confidence, 0.74 if audit.get("verification_needed") else 0.84)
            if audit.get("skip_exchange_record"):
                state.skip_exchange_record = True
            if audit.get("skip_cross_learning"):
                state.skip_cross_learning = True
            if audit.get("defer_save"):
                state.defer_save = True
            for ev in list(audit.get("events", []) or []):
                state.quasiarch_events.append(dict(ev))
    except Exception:
        pass
    # Echo repair
    try:
        er = _repair_unproductive_echo(
            systems, user_text, state.response_content, understood=state.parsed or {}
        )
        if er.get("changed"):
            state.response_content = str(er.get("text", "") or state.response_content).strip()
            state.response_confidence = max(state.response_confidence, 0.78)
            state.quasiarch_events.append(
                _make_quasiarch_runtime_event(
                    target="aurora.dialogue.clarification",
                    issue="unspecific_echo_response",
                    logic_tier="runtime_orchestration",
                    intervention="echo_specificity_rebuild",
                    intended_effect="replace mirrored user wording with a specific unresolved target",
                    observed_effect="resolved_partially",
                    tags=["dialogue", "clarification", f"reason:{str(er.get('reason','') or 'echo_rebuild')}"],
                    reason_about=True,
                )
            )
    except Exception:
        pass
    # Question-attunement repair
    try:
        qr = _repair_unanswered_question(
            systems, user_text, state.response_content, understood=state.parsed or {}
        )
        if qr.get("changed"):
            state.response_content = str(qr.get("text", "") or state.response_content).strip()
            state.response_confidence = max(state.response_confidence, 0.78)
            try:
                _run_question_alignment_audit(
                    systems,
                    user_text,
                    state.response_content,
                    understood=state.parsed or {},
                )
            except Exception:
                pass
            state.quasiarch_events.append(
                _make_quasiarch_runtime_event(
                    target="aurora.dialogue.question_attunement",
                    issue="question_answer_misalignment",
                    logic_tier="runtime_orchestration",
                    intervention="question_attunement_rebuild",
                    intended_effect="make the response answer the asked question or gather the missing variable needed to answer it",
                    observed_effect="resolved_partially",
                    tags=["dialogue", "question_attunement", f"reason:{str(qr.get('reason','') or 'question_rebuild')}"],
                    reason_about=True,
                )
            )
        if isinstance(getattr(state, "pipeline_state", None), dict):
            state.pipeline_state["question_alignment"] = dict(
                systems.get("_last_question_alignment_audit") or {}
            )
    except Exception:
        pass
    # Constraint emission — shape final surface output through IVM pressure lens
    # Also clears internal-format strings that must never reach the speaker.
    _INTERNAL_PREFIXES = ("earlier user utterance", "researcher lookup failed", "http error")
    _INTERNAL_MECH_SUBSTRINGS = (
        "mutation_id=", "mutation_id =",
        "code evolution outcome",
        "accepted=false", "accepted=true", "accepted=0", "accepted=1",
        "operator_key=", "change_count=", "avg_fitness=",
        "genealogy_pressure=", "apply_duration=", "temporal_overhead=",
    )
    _cur_resp = str(getattr(state, "response_content", "") or "").strip()
    _cur_resp_low = _cur_resp.lower()
    _has_json = ("```" in _cur_resp or "proposed_action" in _cur_resp
                 or '"file":' in _cur_resp or "contradiction_handler" in _cur_resp_low)
    if (any(_cur_resp_low.startswith(p) for p in _INTERNAL_PREFIXES)
            or any(p in _cur_resp_low for p in _INTERNAL_MECH_SUBSTRINGS)
            or any(p in _cur_resp_low for p in _INTERNAL_INSTRUCTION_PHRASES)
            or _has_json):
        state.response_content = ""
    try:
        _emitter = systems.get("constraint_emitter")
        if _emitter is not None and hasattr(_emitter, "emit"):
            from aurora_constraint_emission import EmissionContextBuilder, InputFrame
            _parsed = getattr(state, "parsed", {}) or {}
            _input_frame = InputFrame(
                text=str(user_text or ""),
                is_question=bool(_parsed.get("is_question", False)),
                is_directed=True,
                is_imperative=bool(_parsed.get("is_imperative", False)),
                is_contradiction=bool(_parsed.get("is_contradiction", False)),
                is_statement=bool(_parsed.get("is_statement", False)),
                is_self_referential=bool(_is_aurora_self_question(str(user_text or ""), _parsed)),
                topic_concept=str(_parsed.get("topic", "") or _parsed.get("search_query", "") or "").strip() or None,
            )
            _builder = EmissionContextBuilder()
            _ectx = _builder.build(
                systems,
                input_frame=_input_frame,
                recent_words=str(state.response_content or "").split()[:12],
            )
            _eresult = _emitter.emit(_ectx)
            if _eresult is not None:
                _emitted = str(getattr(_eresult, "text", "") or getattr(_eresult, "surface_text", "") or "").strip()
                _cur_content = str(getattr(state, "response_content", "") or "").strip()
                _has_real_response = bool(_cur_content) and not any(
                    p in _cur_content.lower() for p in _INTERNAL_INSTRUCTION_PHRASES
                )
                if _emitted and getattr(_eresult, "seeking", False):
                    # Seeking always takes priority — it's a genuine gap question
                    state.response_content = _emitted
                    state.response_src = "comprehension_gap_ask"
                elif (
                    _emitted
                    and not _has_real_response
                    and _constraint_emission_is_substantive(_emitted, _eresult, _input_frame)
                ):
                    # Only fill from emitter when comprehension produced nothing
                    state.response_content = _emitted
                    state.response_src = "constraint_emission"
    except Exception:
        pass


def _record_pressure_experience(state: Any, systems: dict) -> None:
    """
    When N-axis cost pressure was active this turn, record the causal
    experience via PressureExperienceLedger -- the same mechanism used
    across the whole behavioral evolution system.

    pursuing      = what Aurora was trying to achieve this turn
    causal_action = the specific operation that incurred the cost
    consequence   = what that action produced (tension, conflict)
    outcome       = how it resolved relative to what was being pursued
    """
    if not getattr(state, "belief_tension", 0.0) or state.belief_tension < 0.05:
        return

    # Anchor: first salient concept from B-axis, fall back to parsed topic
    anchor = ""
    salient = getattr(state, "salient_concepts", None) or []
    if salient:
        anchor = str(salient[0]).strip()
    if not anchor:
        anchor = str((state.parsed or {}).get("topic", "") or "").strip()
    if not anchor or len(anchor) < 2:
        return

    # Meaning: what OETS already knows about the anchor
    meaning_text = anchor
    oets = None
    try:
        perception = systems.get("perception")
        oets = getattr(perception, "oets", None) if perception else None
        if oets is None:
            oets = systems.get("oets")
        node = None
        if oets and hasattr(oets, "web") and hasattr(oets.web, "get_node"):
            node = oets.web.get_node(anchor.lower())
        if node:
            defs = getattr(node, "definitions", []) or []
            if defs:
                meaning_text = str(defs[0].get("text", anchor) or anchor)
            elif getattr(node, "role", ""):
                meaning_text = f"{anchor} ({node.role})"
    except Exception:
        oets = None

    # pursuing
    _goal_stack = list(getattr(state, "goal_stack", []) or [])
    _intent     = str(getattr(state, "intent", "general") or "general")
    pursuing = _goal_stack[0] if _goal_stack else _intent

    # causal_action: the specific operation that triggered the cost
    _claim_summary  = str(((state.claim_resolution or {}).get("focus_claim") or {}).get("summary", "") or "")
    _referent_topic = str((state.referent_map or {}).get("topic", "") or "")
    _referent_conf  = float((state.referent_map or {}).get("confidence", 0.0) or 0.0)
    _dom_form       = dict((state.dominant_meaning_form or {}))
    _dom_form_label = str(_dom_form.get("form", "") or _dom_form.get("type", "") or "")

    if _claim_summary:
        causal_action = f"resolving_claim: {_claim_summary[:80]}"
    elif _referent_topic and _referent_conf < 0.5:
        causal_action = f"anchoring_referent: {_referent_topic!r} (confidence {_referent_conf:.2f} -- unresolved)"
    elif _dom_form_label:
        causal_action = f"establishing_meaning: {_dom_form_label!r} via anchor {anchor!r}"
    else:
        causal_action = f"pursuing_intent: {pursuing!r}"

    # consequence
    _sem_p = round(float(getattr(state, "semantic_pressure", 0.0) or 0.0), 4)
    consequence = {
        "tension":           round(float(state.belief_tension), 4),
        "semantic_pressure": _sem_p,
        "conflicted":        state.belief_tension > 0.3 and _sem_p > 0.3,
    }

    # outcome
    _conf     = round(float(getattr(state, "response_confidence", 0.5) or 0.5), 4)
    _tone     = str(getattr(state, "response_tone", "neutral") or "neutral")
    _resolved = _conf >= 0.6 and _tone not in ("uncertain", "deflecting", "neutral")
    outcome = {
        "resolved":           _resolved,
        "tone":               _tone,
        "confidence":         _conf,
        "src":                str(getattr(state, "response_src", "chain") or "chain"),
        "diverged_from_goal": not _resolved,
    }

    try:
        from aurora_internal.aurora_pressure_ledger import PressureExperienceLedger as _PEL
        _PEL.get().record(
            anchor=anchor,
            meaning=meaning_text,
            pursuing=pursuing,
            causal_action=causal_action,
            consequence=consequence,
            outcome=outcome,
            source="turn_chain",
            oets=oets,
        )
    except Exception:
        pass


def _run_reasoning_pipeline(
    systems: dict,
    user_text: str,
    mode: Any,
    *,
    turn_tick: int = 0,
    session_id: str = "",
    auto_search_enabled: bool = True,
    use_search: bool = False,
    raw_evidence: list = None,
    manual_lookup: bool = False,
    lookup_request: dict = None,
) -> tuple:
    """
    Unified bidirectional developmental chain pipeline.

    Returns (resp_A, resp_B, offered_lookup) with same contract as
    dual_question_pipeline -- drop-in replacement for its core routing block.
    """
    from aurora_internal.aurora_turn_chain import TurnUnderstandingState

    aurora = systems["aurora"]
    gw = aurora.gateway
    StreamType = systems["StreamType"]
    ExistenceMode = systems["ExistenceMode"]
    working_memory = systems.get("working_memory")
    search_adapter = systems.get("search_adapter")

    class _MiniResp:
        def __init__(self, content, emotional_tone="neutral", confidence=0.5):
            self.content = content
            self.emotional_tone = emotional_tone
            self.confidence = confidence

    # Initialise state
    state = TurnUnderstandingState(raw_text=user_text)
    state.pipeline_state = _extract_pipeline_signals(systems)
    interaction_route = dict(systems.get("_last_interaction_route") or {}) if isinstance(systems, dict) else {}
    if isinstance(state.pipeline_state, dict) and interaction_route:
        state.pipeline_state["interaction_quasi"] = dict(interaction_route)
        state.pipeline_state["interaction_archetype"] = str(interaction_route.get("interaction_archetype", "") or "")
        state.pipeline_state["interaction_primary_strategy"] = str(interaction_route.get("primary_response_strategy", "") or "")
        state.pipeline_state["interaction_secondary_strategy"] = str(interaction_route.get("secondary_response_strategy", "") or "")
        state.pipeline_state["interaction_confidence"] = float(interaction_route.get("confidence", 0.0) or 0.0)
        state.pipeline_state["interaction_quasi_ready"] = bool(interaction_route.get("quasi_ready", False))
        state.pipeline_state["interaction_route_reason"] = str(interaction_route.get("reason", "") or "")
        state.pipeline_state["interaction_wake_tiers"] = list(interaction_route.get("wake_processing_tiers", []) or [])
        state.pipeline_state["interaction_search_policy"] = str(interaction_route.get("search_policy", "allow") or "allow")
    if isinstance(systems, dict):
        systems["_last_pipeline_state"] = state.pipeline_state

    try:
        _umeta2 = dict(systems.pop("_utterance_meta", {}) or {})
        if _umeta2 and isinstance(state.pipeline_state, dict):
            state.pipeline_state["utterance_meta"] = _umeta2
            if _umeta2.get("negated"):
                state.pipeline_state["input_is_negated"] = True
            if _umeta2.get("stance"):
                state.pipeline_state["input_stance"] = str(_umeta2["stance"])
            if _umeta2.get("pragmatic_signals"):
                state.pipeline_state["pragmatic_signals"] = _umeta2["pragmatic_signals"]
    except Exception:
        pass

    # ---- GAP 3 FIX: SEDI SURFACE FRAGS — inject temporal continuity fragments ----
    # SediMemory surface recall is loaded by the surface daemon before calling
    # process_external_user_turn, but the frags were never threaded into the
    # pipeline state where the upward/downward chain can use them.
    try:
        _sedi_frags = list(systems.get("_sedi_surface_frags") or [])
        if _sedi_frags and isinstance(state.pipeline_state, dict):
            _sedi_summaries: List[str] = []
            for _sf in _sedi_frags[:6]:
                _sf_content = dict(_sf.get("content") or {}) if isinstance(_sf, dict) else {}
                _aurora_resp = str(_sf_content.get("aurora_response", "") or "").strip()
                _user_inp = str(_sf_content.get("user_input", "") or "").strip()
                if _aurora_resp:
                    _sedi_summaries.append(_aurora_resp[:120])
                elif _user_inp:
                    _sedi_summaries.append(_user_inp[:80])
            if _sedi_summaries:
                state.pipeline_state["sedi_temporal_fragments"] = _sedi_summaries
            # Also expose the raw frags for any subsystem that wants richer detail
            state.pipeline_state["sedi_surface_recall_count"] = len(_sedi_frags)
    except Exception:
        pass

    # ---- STRATA-INTEGRATED REASONING: Frame the Turn with Vitals ----
    try:
        # Pull latest Subsurface DCE convergence
        _live_frame = dict(systems.get("_live_conscious_frame") or {})
        _live_crest = dict(systems.get("_live_conscious_crest") or {})
        _live_sensory = dict(systems.get("_live_sensory_state") or {})

        if _live_frame and isinstance(state.pipeline_state, dict):
            state.pipeline_state["subsurface_conscious_frame"] = _live_frame
            state.pipeline_state["subsurface_conscious_crest"] = _live_crest
            state.pipeline_state["live_sensory_vitals"] = _live_sensory

            # If the subsurface crest is high-intensity, flag reactive priority
            _crest_intensity = float(_live_crest.get("intensity", 0.0) or 0.0)
            if _crest_intensity >= 0.72:
                state.pipeline_state["subsurface_reactive_priority"] = True
    except Exception:
        pass

    # ---- UPWARD PASS ----
    _chain_up1_information(user_text, systems, state)
    _inject_surface_recent_context(systems, state, user_text)
    _chain_up2_belief(user_text, systems, state)
    _chain_up3_purpose(user_text, systems, state)
    _chain_up4_meaning(user_text, systems, state)
    _chain_up5_understanding(user_text, systems, state, turn_tick=turn_tick, session_id=session_id)
    # up5 is now the apex (A axis) -- no up6 needed
    try:
        _apply_noncomp_input_guidance(systems, state, user_text)
    except Exception:
        pass

    try:
        _perc_a4 = systems.get("perception")
        if _perc_a4 and hasattr(_perc_a4, "perceive"):
            _perc_result = _perc_a4.perceive(user_text)
            if _perc_result and isinstance(state.pipeline_state, dict):
                state.pipeline_state["perception_result"] = _perc_result if isinstance(_perc_result, dict) else {}
    except Exception:
        pass

    # Read the result from process() that fired BEFORE the upward chain.
    # process() already handled Step 0.5 correction absorption — we only
    # propagate its findings into pipeline_state here, after the chain confirms
    # or contextualizes them.
    try:
        _cgs_res2 = dict(systems.pop("_cgs_turn_result", {}) or {})
        _cgs_act2 = str(systems.pop("_cgs_action", "") or "")
        if _cgs_res2 and isinstance(state.pipeline_state, dict):
            _raw_gap = _cgs_res2.get("gap")
            if _raw_gap:
                state.pipeline_state["comprehension_gaps"] = [_raw_gap]
                state.pipeline_state["has_comprehension_gap"] = True
            if _cgs_act2 == "applied":
                # User was correcting Aurora — correction absorbed; mark context
                state.pipeline_state["correction_absorbed"] = True
                _corr_content = str(_cgs_res2.get("content") or "")
                if _corr_content:
                    state.pipeline_state["correction_acknowledgment"] = _corr_content
            elif _cgs_act2 == "ask":
                # Gap question ready — inject as pipeline override candidate
                state.pipeline_state["should_ask_gap"] = True
                _gap_q = str(_cgs_res2.get("content") or "")
                if _gap_q:
                    state.pipeline_state["gap_question"] = _gap_q
            # Enqueue recommendation for any detected gap
            if _raw_gap:
                try:
                    from aurora_internal.aurora_recommendation_hub import enqueue_recommendation
                    _cgs_dir2 = str(systems.get("state_dir") or "aurora_state")
                    _gs2 = str(getattr(_raw_gap, "description", "") or str(_raw_gap))[:80]
                    enqueue_recommendation(
                        _cgs_dir2,
                        source="comprehension_gap",
                        run_type="live_turn",
                        title=f"Address gap: {_gs2[:60]}",
                        body=_gs2,
                        priority=0.75,
                    )
                except Exception:
                    pass
    except Exception:
        pass

    # ---- ABILITY SELECTION — wire live thinking patterns into the pipeline ----
    # state.axis_activation and state.dominant_axis are populated by _chain_up3_purpose.
    # Select the most affordable abilities whose axis is currently active, then stamp
    # their effect_tags into pipeline_state so the downward chain knows HOW to reason.
    try:
        _genealogy = systems.get("genealogy")
        if _genealogy and hasattr(_genealogy, "abilities") and state.axis_activation:
            _sel_abs = _select_active_abilities(
                state.axis_activation,
                state.dominant_axis or "X",
                _genealogy,
                max_n=5,
            )
            if _sel_abs and isinstance(state.pipeline_state, dict):
                state.pipeline_state["active_abilities"] = [a.get("id", "") for a in _sel_abs]
                # Flatten effect_tags; strip lineage/origin metadata tags (not reasoning strategies)
                _ab_fx: set = set()
                for _a in _sel_abs:
                    for _tag in (_a.get("effect_tags") or []):
                        if _tag and not _tag.startswith(("origin_", "root_slot:")):
                            _ab_fx.add(str(_tag))
                _ab_summary = _summarize_live_ability_effects(sorted(_ab_fx))
                state.pipeline_state["active_ability_effects_raw"] = list(_ab_summary.get("raw_effects") or [])
                state.pipeline_state["active_ability_effects"] = list(_ab_summary.get("expanded_effects") or [])
                state.pipeline_state["active_ability_effect_translation"] = dict(_ab_summary.get("translated_effects") or {})
                state.pipeline_state["active_ability_effect_passive"] = list(_ab_summary.get("passive_effects") or [])
                state.pipeline_state["active_ability_effect_unhandled"] = list(_ab_summary.get("unhandled_effects") or [])
                state.pipeline_state["ability_runtime_flags"] = dict(_ab_summary.get("runtime_flags") or {})
    except Exception:
        pass

    try:
        _apply_noncomp_behavior_actuation(systems, state, context="input")
    except Exception:
        pass

    # ---- PRESSURE-BEFORE stamp (first-person comparison) ----
    # _run_live_response_turn stamps p_before into systems["_pressure_before"] before
    # calling dual_question_pipeline.  Carry it into pipeline_state here so
    # _build_comprehension_response can express genuine before/after gradients.
    try:
        _pb_stamp = systems.get("_pressure_before") or {}
        if _pb_stamp and isinstance(state.pipeline_state, dict):
            state.pipeline_state["pressure_before"] = dict(_pb_stamp)
    except Exception:
        pass

    # ---- GAP 1 FIX: SUBSURFACE PROJECTION PRE-GENERATION INJECTION ----
    # Inject the subsurface projection signals into pipeline_state BEFORE the
    # downward chain generates the response. Without this, the projection only
    # appears post-hoc in DCE annotation and never shapes the response itself.
    try:
        _pre_proj = dict(systems.get("_subsurface_projection") or {})
        if _pre_proj and isinstance(state.pipeline_state, dict):
            _dom_hint = str(_pre_proj.get("dominant_axis_hint", "") or "")
            if _dom_hint:
                state.pipeline_state.setdefault("subsurface_dominant_axis_hint", _dom_hint)
            _ready_bias = float(_pre_proj.get("readiness_bias", 0.0) or 0.0)
            if _ready_bias:
                state.pipeline_state["subsurface_readiness_bias"] = round(_ready_bias, 4)
            _intuition = list(_pre_proj.get("intuition_signals") or [])
            if _intuition:
                state.pipeline_state["subsurface_intuition_signals"] = _intuition[:4]
            _effects = list(_pre_proj.get("active_effects") or [])
            if _effects:
                state.pipeline_state["subsurface_active_effects"] = _effects[:5]
            _guidance = str(_pre_proj.get("surface_guidance", "") or "")
            if _guidance:
                state.pipeline_state["subsurface_surface_guidance"] = _guidance
            _owned = dict(_pre_proj.get("subsurface_owned") or {})
            _repair_phase = str(_owned.get("repair_phase", "") or "")
            if _repair_phase:
                state.pipeline_state["subsurface_repair_phase"] = _repair_phase
            _smat = float(_owned.get("sensory_growth_maturity", 0.0) or 0.0)
            if _smat:
                state.pipeline_state["subsurface_sensory_maturity"] = round(_smat, 4)
            # When readiness is low, nudge the dominant axis hint into the pipeline
            # so the downward chain can weight its choices accordingly.
            if _dom_hint and _ready_bias < 0.46 and not state.dominant_axis:
                try:
                    state.dominant_axis = _dom_hint
                except Exception:
                    pass
    except Exception:
        pass

    # ---- GAP 5 FIX: PRE-GENERATION CONSCIOUS FRAME ----
    # Read the persisted dual-strata snapshot from disk to produce a preliminary
    # conscious_frame BEFORE the downward chain generates the response. The post-hoc
    # bridge call (after synthesis) remains for evolutionary tracing; this call puts
    # the frame into the pipeline so the response can be authored from inside it.
    try:
        _pre_gen_runtime = _read_live_dual_strata_runtime(systems)
        if _pre_gen_runtime and isinstance(state.pipeline_state, dict):
            _pre_cf = dict(_pre_gen_runtime.get("conscious_frame") or {})
            _pre_ss = dict(_pre_gen_runtime.get("subsurface_state") or {})
            if _pre_cf:
                state.pipeline_state["pre_generation_conscious_frame"] = _pre_cf
                # Surface should live inside the frame before speaking — stamp key
                # processing signals so the downward chain can see them.
                _pcf_mode = str(_pre_cf.get("processing_mode", "") or "")
                if _pcf_mode:
                    state.pipeline_state.setdefault("conscious_frame_mode", _pcf_mode)
                _pcf_crest = dict(_pre_cf.get("conscious_crest") or {})
                if _pcf_crest:
                    state.pipeline_state["conscious_frame_crest"] = _pcf_crest
            if _pre_ss:
                state.pipeline_state["pre_generation_subsurface_state"] = _pre_ss
                _pss_axis = str(_pre_ss.get("dominant_axis", "") or "")
                if _pss_axis and not state.dominant_axis:
                    try:
                        state.dominant_axis = _pss_axis
                    except Exception:
                        pass
            systems["_pre_generation_conscious_frame"] = _pre_cf
    except Exception:
        pass

    # ---- DOWNWARD PASS ----
    # down6_apex removed -- hints now propagated inside _chain_down5_understanding
    _chain_down5_understanding(user_text, systems, state, auto_search_enabled=auto_search_enabled)
    _chain_down4_meaning(user_text, systems, state, auto_search_enabled=auto_search_enabled)
    _chain_down3_purpose(user_text, systems, state, auto_search_enabled=auto_search_enabled,
                        use_search=use_search, raw_evidence=raw_evidence or [])
    _chain_down2_belief(user_text, systems, state, auto_search_enabled=auto_search_enabled,
                            use_search=use_search)
    _skip_post = bool(systems.pop("_skip_response_postprocessing_once", False))
    _chain_down1_information(user_text, systems, state, use_search=use_search, skip_postprocessing=_skip_post)
    _preserve_literal_response = bool(systems.pop("_preserve_literal_response_once", False))
    _skip_surface_expression = bool(systems.pop("_skip_surface_expression_once", False))

    if not _preserve_literal_response:
        try:
            if _skip_surface_expression:
                raise RuntimeError("skip_surface_expression_once")
            _perc_a5 = systems.get("perception")
            _resp_draft = str(getattr(state, "response_content", "") or "")
            if _perc_a5 and _resp_draft and hasattr(_perc_a5, "express"):
                # ---- THOUGHT BRAID — EXPRESSION anchor ----
                try:
                    from aurora_braid_wiring import begin_expression
                    begin_expression(systems)
                except Exception:
                    pass
                _expressed = _perc_a5.express(_resp_draft, tone=str(getattr(state, "response_tone", "neutral") or "neutral"))
                if _expressed and isinstance(_expressed, str) and len(_expressed.split()) >= 4:
                    state.response_content = _expressed
                    # ---- THOUGHT BRAID — checkpoint: re-tap braid against draft ----
                    try:
                        from aurora_braid_wiring import checkpoint_expression
                        checkpoint_expression(systems, expression_text=_expressed)
                    except Exception:
                        pass
                    # ---- LANGUAGE STRUCTURE FITNESS — score expression against intention ----
                    try:
                        from aurora_language_structure_fitness import LanguageStructureFitness
                        _lsf = LanguageStructureFitness()
                        _intention = systems.get('_current_semantic_intention')
                        _perception = systems.get('perception')
                        _composer = getattr(_perception, 'composer', None) if _perception else None
                        _base_fit = float(getattr(state, 'response_confidence', 0.5) or 0.5)
                        _fit_result = _lsf.score(
                            _expressed,
                            _intention,
                            _base_fit,
                            composer=_composer,
                        )
                        systems['_last_fitness_result'] = {
                            'fidelity': _fit_result.fidelity_score,
                            'keyword_coverage': _fit_result.keyword_coverage,
                            'lane_alignment': _fit_result.lane_alignment,
                            'combined_fitness': _fit_result.combined_fitness,
                        }
                        if _fit_result.combined_fitness < 0.4:
                            try:
                                _sedi = systems.get('sedimemory')
                                if _sedi and hasattr(_sedi, 'ingest_event'):
                                    _sedi.ingest_event({
                                        'type': 'expression_misfit',
                                        'fitness': _fit_result.combined_fitness,
                                        'lane': getattr(_intention, 'semantic_lane', 'unknown'),
                                        'source': 'LanguageStructureFitness',
                                    })
                            except Exception:
                                pass
                    except Exception:
                        pass
        except Exception:
            pass

    # ---- SURFACE DISPATCHER — fire evolved surfaces on axis pressure ----
    # Runs every turn. Internal COOLDOWN_TICKS=8 prevents same surface repeating.
    try:
        _sd = systems.get('_surface_dispatcher')
        _chamber = systems.get('chamber')
        _esurfaces = systems.get('evolved_surfaces')
        if _sd is not None and _chamber is not None and _esurfaces is not None:
            if hasattr(_sd, 'tick'):
                _sd_evidence = _sd.tick(_chamber, _esurfaces)
                for _sd_ev in (_sd_evidence or []):
                    try:
                        if hasattr(_chamber, 'observe_external_evidence'):
                            _chamber.observe_external_evidence(_sd_ev)
                    except Exception:
                        pass
                if _sd_evidence and isinstance(state.pipeline_state, dict):
                    state.pipeline_state['surface_dispatcher_fires'] = len(_sd_evidence)
    except Exception:
        pass

    # Record pressure experience -- anchor + meaning + effect triplet in OETS
    _record_pressure_experience(state, systems)

    # ---- GRAMMAR ENGINE — structural motif shaping ----
    # Takes the draft response and restructures it using the best promoted
    # structural motif that fits the current constraint pressure orientation.
    # Motifs are learned from Aurora's own exchange history (observe_exchange runs
    # post-turn), so early sessions may return None until patterns are promoted.
    # Only applies restructuring when the motif has >= 0.5 constraint fit.
    if state.response_content and not _preserve_literal_response:
        try:
            _ge = systems.get("grammar_engine")
            if _ge and hasattr(_ge, "suggest_structure") and hasattr(_ge, "status"):
                # Only apply structural rewrite once the motif lineage has enough
                # promoted patterns to produce coherent output (requires /grammarboot
                # or accumulated exchange history).
                _ge_st = _ge.status() or {}
                _promoted_count = int((_ge_st.get("motif_lineage") or {}).get("promoted", 0) or 0)
                if _promoted_count >= 8:
                    _gs = _ge.suggest_structure(state.response_content, user_text, tone=state.response_tone, passion=state.emotional_state.get("passion", "observant"), drive=state.emotional_state.get("drive", "steady"))
                    if _gs and _gs.get("applied_text"):
                        _cfit = float(_gs.get("constraint_fit", 0.0) or 0.0)
                        _applied = str(_gs["applied_text"]).strip()
                        # Require high fit AND that the rewrite preserves word count (±30%)
                        _orig_wc = len(state.response_content.split())
                        _appl_wc = len(_applied.split())
                        _wc_ok = _orig_wc > 0 and 0.7 <= (_appl_wc / _orig_wc) <= 1.3
                        if _cfit >= 0.72 and _wc_ok and len(_applied.split()) >= 4:
                            state.response_content = _applied
                            if isinstance(state.pipeline_state, dict):
                                state.pipeline_state["grammar_motif_id"]       = str(_gs.get("motif_id", "") or "")
                                state.pipeline_state["grammar_constraint_fit"] = _cfit
        except Exception:
            pass

    # Expression perception tone reconciliation
    if (
        state.response_content and
        not _preserve_literal_response and
        state.response_tone in ("neutral", "attentive")
    ):
        try:
            _perc = systems.get("perception")
            _perc_emotion = str(getattr(_perc, "_dominant_emotion", "") or "")
            _perc_axis    = str(getattr(_perc, "_dominant_axis", "") or "")
            _AXIS_EMOTION_TONE = {
                ("A", "curious"):    "reflective",
                ("A", "engaged"):    "self-aware",
                ("B", "tense"):      "careful",
                ("B", "uncertain"):  "careful",
                ("N", "focused"):    "determined",
                ("N", "urgent"):     "determined",
                ("T", "calm"):       "warm",
                ("T", "nostalgic"):  "warm",
                ("X", "neutral"):    "precise",
            }
            _mapped = _AXIS_EMOTION_TONE.get((_perc_axis, _perc_emotion))
            if not _mapped:
                _ps_emotion = str((state.pipeline_state or {}).get("dominant_emotion") or "")
                _ps_to_tone = {
                    "calm": "attentive", "engaged": "warm", "curious": "reflective",
                    "tense": "careful", "focused": "determined", "nostalgic": "warm",
                    "uncertain": "careful",
                }
                _mapped = _ps_to_tone.get(_ps_emotion)
            if _mapped and _mapped != state.response_tone:
                state.response_tone = _mapped
                if isinstance(state.pipeline_state, dict):
                    state.pipeline_state["perception_tone_applied"] = _mapped
        except Exception:
            pass

    # Response pressure tuner — record decision and apply guidance
    if not _preserve_literal_response:
        try:
            from aurora_internal.aurora_response_pressure_tuner import ResponsePressureTuner
            _rpt = systems.get("_reply_response_pressure_tuner")
            if _rpt is None:
                _rpt = ResponsePressureTuner(namespace="chat.reply")
                systems["_reply_response_pressure_tuner"] = _rpt
                try:
                    import pathlib as _rpt_pl
                    _rpt_path = _rpt_pl.Path(str(systems.get("state_dir") or "aurora_state")) / "response_pressure_tuner.json"
                    if _rpt_path.exists() and hasattr(_rpt, "load_state"):
                        _rpt.load_state(str(_rpt_path))
                except Exception:
                    pass
            _rpt_kind_map = {
                "recall_question": "followup", "fact_assertion": "reply",
                "contradiction": "repair", "wellbeing_query": "reply",
                "followup_request": "followup", "general": "reply", "statement": "reply",
            }
            _rpt_kind = _rpt_kind_map.get(str(state.intent or ""), "reply")
            _rpt_signal = float(state.response_confidence or 0.5)
            _rpt_cp = max(0.0, 1.0 - _rpt_signal)
            if hasattr(_rpt, "evaluate"):
                _rpt.evaluate(
                    kind=_rpt_kind,
                    content=str(state.response_content or "")[:200],
                    signal=_rpt_signal,
                    threshold=0.55,
                    counter_pressure=_rpt_cp,
                    factors={"axis": state.dominant_axis, "intent": state.intent},
                    context={"src": state.response_src},
                )
            if hasattr(_rpt, "guidance"):
                _rpt_guide = _rpt.guidance(n=32)
                for _rec in list(_rpt_guide.get("recommendations") or []):
                    _rec_str = str(_rec or "")
                    if _rpt_kind in _rec_str and "threshold may be slightly too high" in _rec_str:
                        state.response_confidence = min(state.response_confidence, 0.72)
                    elif _rpt_kind in _rec_str and "consider raising pressure" in _rec_str:
                        if state.response_tone in ("certain", "assertive"):
                            state.response_tone = "attentive"
                if isinstance(state.pipeline_state, dict):
                    state.pipeline_state["pressure_tuner_kind"] = _rpt_kind
        except Exception:
            pass

    # ---- RENDER RUNTIME INTENT — communicative intent shaping ----
    # Passes the response through working_memory._render_from_comprehension_intent(),
    # which shapes HOW Aurora expresses her content: intent_type, emotion tone,
    # relationship signal, certainty level, supporting concepts and constraints.
    # This is Aurora's motive in speaking — not just WHAT she says but WHY and HOW.
    # Only runs when there is actual response content (not a seed/empty state).
    if (
        state.response_content and
        not _preserve_literal_response and
        len(state.response_content.split()) >= 4
    ):
        try:
            _ps = state.pipeline_state or {}
            _emo_tone     = str(_ps.get("dominant_emotion", "neutral") or "neutral")
            _certainty    = float(state.response_confidence or 0.6)
            _support_conc = list(state.salient_concepts or [])[:4]
            _constraints  = list(state.goal_stack or [])[:2]
            # Derive relationship signal from collective axis tensions if available
            _rel_signal = "neutral"
            _axis_tens = dict(_ps.get("axis_tensions", {}) or {})
            if _axis_tens:
                _max_ax = max(_axis_tens, key=lambda k: abs(_axis_tens.get(k, 0.0)))
                _max_val = abs(_axis_tens.get(_max_ax, 0.0))
                if _max_val > 0.4:
                    _rel_signal = "engaged" if _max_val > 0.7 else "attentive"
            _rendered = _render_runtime_intent(
                systems,
                state.response_content,
                emotion_tone=_emo_tone,
                relationship_signal=_rel_signal,
                certainty=_certainty,
                supporting_concepts=_support_conc,
                constraints=_constraints,
            )
            if _rendered and _rendered.strip() and _rendered.strip() != state.response_content.strip():
                state.response_content = _rendered
        except Exception:
            pass
    if not _preserve_literal_response:
        try:
            _apply_noncomp_output_guidance(systems, state, user_text)
        except Exception:
            pass
        try:
            _apply_noncomp_behavior_actuation(systems, state, context="output")
        except Exception:
            pass

    # Final anti-echo guard: if the reply still looks like a mirror of the
    # user's wording, rebuild it from internal meaning rather than surfacing
    # the prompt back to the user.
    if not _preserve_literal_response and _response_is_unproductive_echo(
        user_text,
        str(getattr(state, "response_content", "") or ""),
    ):
        try:
            _echo_seed = _response_guard_seed(state, user_text)
            repaired = _render_runtime_intent(
                systems,
                _echo_seed,
                emotion_tone=str(getattr(state, "response_tone", "attentive") or "attentive"),
                certainty=max(0.56, float(getattr(state, "response_confidence", 0.0) or 0.0)),
                supporting_concepts=list(getattr(state, "salient_concepts", []) or [])[:4],
                constraints=list(getattr(state, "goal_stack", []) or [])[:2],
            )
            if repaired and not _response_is_unproductive_echo(user_text, repaired):
                state.response_content = repaired
                if not str(getattr(state, "response_src", "") or "").strip():
                    state.response_src = "anti_echo_rebuild"
                state.response_confidence = max(float(getattr(state, "response_confidence", 0.0) or 0.0), 0.58)
        except Exception:
            pass

    if (
        not _preserve_literal_response
        and _surface_fragment_is_invalid(
            str(getattr(state, "response_content", "") or ""),
            user_text=user_text,
            understood=getattr(state, "parsed", {}) or {},
        )
    ):
        state.response_content = ""

    # Final reply guard: Removed per Language Reset spec (§10) — 
    # ConstraintEmitter is the primary expression path and handles fallback naturally.
    if not str(getattr(state, "response_content", "") or "").strip():
        # Last resort: explicitly ask the emitter for a backchannel/abstain 
        # if the substantive check previously rejected its result.
        try:
            _ce = systems.get("constraint_emitter")
            if _ce is not None:
                from aurora_constraint_emission import EmissionContextBuilder, InputFrame as _IF
                _p = getattr(state, "parsed", {}) or {}
                _ut_low = str(user_text or "").lower()
                _self_ref = any(tok in _ut_low for tok in
                                (" you ", " you'", "do you", "are you",
                                 "your ", "yourself", "how you"))
                _if = _IF(
                    text=str(user_text or ""),
                    is_directed=True,
                    is_question=_ut_low.endswith("?") or any(
                        _ut_low.startswith(q) for q in
                        ("how ", "what ", "when ", "why ", "where ", "do you",
                         "are you", "can you", "did you")),
                    is_self_referential=_self_ref,
                    topic_concept=str(_p.get("topic", "") or "").strip() or None,
                )
                _ec = EmissionContextBuilder().build(systems, input_frame=_if)
                _er = _ce.emit(_ec)
                if _er and getattr(_er, "text", ""):
                    state.response_content = str(_er.text).strip()
                    state.response_src = "constraint_fallback"
        except Exception:
            pass

    if not _preserve_literal_response:
        try:
            _final_bound = _repair_unarticulated_surface_response(
                user_text,
                str(getattr(state, "response_content", "") or ""),
                systems=systems,
                state=state,
            )
            if _final_bound and _final_bound.strip() != str(getattr(state, "response_content", "") or "").strip():
                state.response_content = _final_bound.strip()
                state.response_confidence = max(float(getattr(state, "response_confidence", 0.0) or 0.0), 0.58)
                state.quasiarch_events.append(
                    _make_quasiarch_runtime_event(
                        target="aurora.dialogue.articulation",
                        issue="unbound_surface_fragment",
                        logic_tier="runtime_orchestration",
                        intervention="bind_fragment_to_surface_relation",
                        intended_effect="bind stranded words to nearby meaning before speech",
                        observed_effect="resolved_partially",
                        tags=["dialogue", "articulation", "binding"],
                        reason_about=True,
                    )
                )
        except Exception:
            pass

    # Build resp_A
    resp_A = _MiniResp(state.response_content, state.response_tone, state.response_confidence)
    resp_A.src = state.response_src
    try:
        _resp_bound = _repair_unarticulated_surface_response(
            user_text,
            str(getattr(resp_A, "content", "") or ""),
            systems=systems,
            state=state,
        )
        if _resp_bound and _resp_bound.strip() != str(getattr(resp_A, "content", "") or "").strip():
            resp_A.content = _resp_bound.strip()
            state.response_content = resp_A.content
            resp_A.confidence = max(float(getattr(resp_A, "confidence", 0.0) or 0.0), 0.58)
            state.response_confidence = resp_A.confidence
            state.quasiarch_events.append(
                _make_quasiarch_runtime_event(
                    target="aurora.dialogue.articulation",
                    issue="unbound_surface_fragment",
                    logic_tier="runtime_orchestration",
                    intervention="bind_fragment_after_response_build",
                    intended_effect="ensure every live response leaves as bound surface language",
                    observed_effect="resolved_partially",
                    tags=["dialogue", "articulation", "binding", "response_boundary"],
                    reason_about=True,
                )
            )
    except Exception:
        pass
    # Coherence must be explicitly carried from the assembly pipeline state onto resp_A.
    # Without this, every downstream reader (dce_bridge, continuity feed, enforcer) sees 0.0,
    # which causes cascading instability detection, template fallbacks, and looping repair.
    _ps_coherence = float(state.pipeline_state.get("coherence", 1.0) if isinstance(state.pipeline_state, dict) else 1.0)
    resp_A.coherence = max(0.0, min(1.0, _ps_coherence))
    if _preserve_literal_response:
        resp_A._preserve_literal = True
    if state.skip_exchange_record:
        resp_A._skip_exchange_record = True
    if state.skip_cross_learning:
        resp_A._skip_cross_learning = True
    if state.defer_save:
        resp_A._defer_save_until_correction = True
    # Intent-specific quasiarch event
    if state.intent == "contradiction":
        state.quasiarch_events.append(
            _make_quasiarch_runtime_event(
                target="aurora.dialogue.contradiction",
                issue="contradiction_resolution",
                logic_tier="runtime_orchestration",
                intervention="contradiction_surfacing",
                intended_effect="surface conflicting claims instead of smoothing over them",
                observed_effect="resolved_partially",
                tags=["dialogue", "contradiction"],
                reason_about=True,
            )
        )
    for ev in state.quasiarch_events:
        _queue_quasiarch_runtime_event(resp_A, ev)

    # ---- GATEWAY (OETS learning + governance + resp_B) ----
    is_question = _looks_like_question(user_text) or manual_lookup
    offered_lookup = is_question and auto_search_enabled and (not use_search) and (not manual_lookup)
    search_query = str((lookup_request or {}).get("query") or user_text)
    prompt_context = str((lookup_request or {}).get("source_text") or user_text)
    evidence_bundle = ""
    if raw_evidence:
        evidence_bundle = _format_evidence_for_injection(raw_evidence)
    processed = prompt_context
    if evidence_bundle:
        processed = f"{prompt_context}\n\n{evidence_bundle}"
    try:
        gw.receive(user_text, mode=mode)
    except Exception:
        pass
    from aurora_governance_persistence_gateway import InboundPacket, _generate_id, StreamType as _ST
    packet = InboundPacket(
        packet_id=_generate_id("pkt"),
        stream_type=_ST.USER_INPUT,
        content=processed,
        metadata={},
        source="user",
    )
    gw.inbound_log.append(packet)
    gw.total_received += 1
    validation = gw._validate(packet, mode)
    if getattr(validation, "verdict", None) is not None and str(validation.verdict).endswith("REJECTED"):
        gw.total_rejected += 1
        # Generative rejection
        from aurora_internal.aurora_language_state import IntentObject
        _f_intent = IntentObject(intent_type="action", emotion_tone="firm")
        _f_fragments = "action; reject; conflict; principle; boundary"
        try:
            _f_text = systems['perception'].evo.sic._synthesize_fragments(_f_fragments, _f_intent)
            if _f_text:
                return _MiniResp(_f_text, "firm", 0.9), None, offered_lookup
        except Exception:
            pass
        return None, None, offered_lookup
    processed2 = getattr(validation, "filtered_content", None) or processed
    if str(getattr(validation, "verdict", "") or "").endswith("FILTERED"):
        gw.total_filtered += 1
    else:
        gw.total_accepted += 1
    try:
        _dim = getattr(getattr(aurora, "gateway", None), "dimensional", None)
        if _dim and hasattr(_dim, "get_recall_context"):
            _rpkts = _dim.get_recall_context(processed2, mode)
            if _rpkts:
                processed2 = processed2 + "\n" + " ".join(r.as_context_fragment() for r in _rpkts[:3])
    except Exception:
        pass
    _strata_evidence = _build_established_strata_evidence(systems, state, user_text)
    try:
        _uc = systems.get("understanding_contract")
        if _uc is not None and hasattr(_uc, "snapshot"):
            _strata_evidence["understanding_contract"] = dict(_uc.snapshot() or {})
    except Exception:
        pass
    try:
        _strata_evidence["pressure_snapshot"] = _capture_pressure_snapshot(systems)
    except Exception:
        pass
    try:
        _local_projection = _build_live_subsurface_projection(systems, state, user_text)
        if _local_projection:
            _strata_evidence["subsurface_projection"] = dict(_local_projection)
    except Exception:
        pass
    try:
        _projection = dict(systems.get("_subsurface_projection") or {})
        if not _projection:
            _state_dir = Path(str(systems.get("state_dir") or (Path(__file__).parent / "aurora_state")))
            _proj_path = _state_dir / "subsurface_projection.json"
            if _proj_path.exists():
                _projection = dict(json.loads(_proj_path.read_text()) or {})
        if _projection:
            _strata_evidence["subsurface_projection"] = _projection
    except Exception:
        pass
    try:
        _af_data = dict(systems.get("_activation_field") or {})
        if not _af_data:
            _af_direct = Path(str(systems.get("state_dir") or (Path(__file__).parent / "aurora_state"))) / "activation_field.json"
            if _af_direct.exists():
                _af_data = dict(json.loads(_af_direct.read_text()) or {})
        if not _af_data:
            _snap_path = Path(str(systems.get("state_dir") or (Path(__file__).parent / "aurora_state"))) / "dual_strata_snapshot.json"
            if _snap_path.exists():
                _snap_raw = json.loads(_snap_path.read_text())
                _af_data = dict((_snap_raw.get("subsurface_state") or {}).get("metadata", {}).get("activation_field") or {})
        if _af_data:
            _strata_evidence["activation_field"] = _af_data
    except Exception:
        pass
    try:
        synthesis = gw._synthesize(
            packet,
            processed2,
            mode,
            thought_intent=None,
            extra_evidence=_strata_evidence,
        )
    except Exception:
        synthesis = None
    # Enrich pipeline_state with post-synthesis signals
    _asm = getattr(synthesis, "assembly", None)
    if _asm and isinstance(state.pipeline_state, dict):
        ps = state.pipeline_state
        _d = getattr(_asm, "dominant_axis", "")
        if _d:
            ps["dominant_axis"] = _d
        ps["paradoxes"] = list(getattr(_asm, "paradoxes", []))
        ps["thought_killed"] = bool(getattr(_asm, "thought_killed", False))
        ps["kill_reason"] = getattr(_asm, "kill_reason", "")
        ps["assembly_quality"] = float(getattr(_asm, "quality", 1.0))
        _e = getattr(_asm, "entropy_state", {})
        if _e:
            ps["coherence"] = float(_e.get("coherence", ps.get("coherence", 1.0)))
            ps["novelty"] = float(_e.get("novelty", ps.get("novelty", 0.5)))
            ps["stagnation"] = float(_e.get("stagnation", ps.get("stagnation", 0.0)))
    # L4 → L6: assembly constraint context shapes behavioral identity
    # Trait values then feed back into constraint axes as background pressure (bidirectional)
    _identity_sys = systems.get('identity')
    if _asm is not None and _identity_sys is not None and hasattr(_identity_sys, 'process_from_assembly'):
        try:
            _identity_sys.process_from_assembly(_asm, mode=mode)
            _ifield_ident = systems.get('identity_field')
            if _ifield_ident is not None and hasattr(_ifield_ident, 'ingest_external_input') and hasattr(_identity_sys, 'get_personality'):
                _pers = _identity_sys.get_personality() or {}
                _traits = _pers.get('traits', {}) or {}
                # Each trait maps to the constraint axes it most activates
                _TRAIT_AXIS_FEEDBACK = {
                    'curiosity':               {'N': 0.55, 'A': 0.50},
                    'caution':                 {'B': 0.60, 'T': 0.45},
                    'emotional_expressiveness': {'N': 0.50, 'A': 0.45, 'X': 0.40},
                    'pattern_sensitivity':     {'T': 0.55, 'B': 0.45},
                    'social_engagement':       {'X': 0.50, 'A': 0.45},
                    'introspection':           {'X': 0.50, 'T': 0.45},
                    'energy_conservation':     {'N': 0.30},
                    'verbosity':               {'A': 0.45},
                }
                _ax_fb: dict = {}
                for _tn, _tv in _traits.items():
                    for _ax, _base in _TRAIT_AXIS_FEEDBACK.get(_tn, {}).items():
                        _ax_fb[_ax] = max(_ax_fb.get(_ax, 0.0), _base * float(_tv))
                if _ax_fb:
                    _ifield_ident.ingest_external_input(_ax_fb, intensity=0.20, source="trait_feedback")
        except Exception:
            pass
    # Gap 6: QUASI crystal function dispatch — when the CPM head is at a QUASI crystal,
    # dispatch function-class-specific axis pressure into the identity field.
    # PREDICTIVE → elevated T (forward temporal projection) + N (cost of prediction).
    # ENTITY_MODEL → elevated B (stable boundary model) + X (another entity's existence).
    try:
        _cpm_g6 = systems.get('cpm')
        _ifield_g6 = systems.get('identity_field')
        if _cpm_g6 is not None and _ifield_g6 is not None and hasattr(_ifield_g6, 'ingest_external_input'):
            _head_g6 = getattr(_cpm_g6, 'head', None)
            _curr_g6 = getattr(_head_g6, 'current', None) if _head_g6 is not None else None
            if _curr_g6 is not None:
                _xtal_g6 = getattr(_curr_g6, 'crystal', None)
                if _xtal_g6 is not None and getattr(_xtal_g6, 'stage', None) == 'quasi':
                    _fc = str(getattr(_xtal_g6, 'function_class', '') or '')
                    if _fc == 'predictive':
                        # Predictive framing: T-axis (projection through time) + N-axis (cost of commitment)
                        _ifield_g6.ingest_external_input(
                            {'T': 0.62, 'N': 0.48, 'A': 0.40, 'X': 0.30, 'B': 0.28},
                            intensity=0.25, source="quasi_predictive_dispatch",
                        )
                    elif _fc == 'entity_model':
                        # Entity model framing: B-axis (stable boundary of other) + X-axis (existence of other)
                        _ifield_g6.ingest_external_input(
                            {'B': 0.60, 'X': 0.52, 'T': 0.38, 'A': 0.35, 'N': 0.28},
                            intensity=0.25, source="quasi_entity_model_dispatch",
                        )
    except Exception:
        pass
    # Gap 7: Ability lineage manifest synthesis-time lookup — check if current axis
    # state crosses thresholds that unlock a compiled capability, then route new
    # unlocks into the identity field as agency events (A-axis + T-axis activation).
    try:
        _lineage_act = systems.get('lineage_activation')
        _ifield_g7 = systems.get('identity_field')
        if isinstance(_lineage_act, dict) and _ifield_g7 is not None and hasattr(_ifield_g7, 'ingest_external_input'):
            _loaded_targets = list(_lineage_act.get('loaded_targets', []) or [])
            _combined_shadow = dict(_lineage_act.get('combined_shadow_state', {}) or {})
            if _loaded_targets and _combined_shadow:
                # Check whether current genealogy outlet fraction signals capability unlock
                _gen_g7 = systems.get('genealogy')
                _outlet_g7 = 0.0
                if _gen_g7 is not None and hasattr(_gen_g7, '_outlet_fraction'):
                    try:
                        _outlet_g7 = float(_gen_g7._outlet_fraction() or 0.0)
                    except Exception:
                        pass
                # Unlock condition: outlet fraction > 0.35 (capability active, not blocked)
                if _outlet_g7 > 0.35:
                    _pipeline_shadow = dict(_combined_shadow.get('pipeline', {}) or {})
                    _n_caps = sum(1 for v in _pipeline_shadow.values() if bool(v))
                    if _n_caps > 0:
                        # Route as agency event: A-axis (capability exercised) + T-axis (new before/after)
                        _ifield_g7.ingest_external_input(
                            {'A': 0.55 + min(0.20, _outlet_g7 * 0.25), 'T': 0.48, 'X': 0.32, 'N': 0.28, 'B': 0.25},
                            intensity=0.22, source="lineage_capability_unlock",
                        )
    except Exception:
        pass
    try:
        _requested_frame = str(gw._mode_to_frame(mode) if hasattr(gw, "_mode_to_frame") else "balanced")
    except Exception:
        _requested_frame = "balanced"
    _dual_strata_runtime = _refresh_live_dual_strata_runtime(
        systems,
        synthesis=synthesis,
        payload=processed2,
        payload_type=packet.stream_type.value,
        evidence=_strata_evidence,
        contract_snapshot=dict(_strata_evidence.get("understanding_contract") or {}),
        requested_frame=_requested_frame,
    )
    if _dual_strata_runtime and isinstance(state.pipeline_state, dict):
        state.pipeline_state["dual_strata_runtime"] = dict(_dual_strata_runtime)
    _expr_low = str(state.response_content or "").lower()
    _identity_query = bool(re.search(
        r'\b(?:do\s+you\s+know\s+(?:my\s+name|who\s+i\s+am)|'
        r'who\s+am\s+i\b|what(?:\s+is|\s*\'?s)\s+my\s+name|'
        r'do\s+you\s+know\s+me\b|have\s+you\s+met\s+me)\b',
        str(user_text or ""),
        re.IGNORECASE,
    ))
    _direct_sensory_query = bool(re.search(
        r"\b(?:can|could|do)\s+you\s+(?:see|hear)\s+me\b|"
        r"\b(?:can|could)\s+you\s+tell\s+if\s+you\s+can\s+(?:see|hear)\s+me\b|"
        r"\b(?:can|could)\s+you\s+tell\s+whether\s+you\s+can\s+(?:see|hear)\s+me\b|"
        r"\bare\s+you\s+(?:looking\s+at|hearing)\s+me\b|"
        r"\bwhat\s+do\s+you\s+(?:see|hear)\b",
        str(user_text or ""),
        re.IGNORECASE,
    ))
    _inline_definition_turn = False
    try:
        _inline_lookup = dict(systems.get("_inline_vocab_lookup") or {})
        _inline_definition_turn = bool(
            _extract_inline_lookup_targets(user_text) and
            str(_inline_lookup.get("source_text", "") or "").strip().lower() == str(user_text or "").strip().lower() and
            list(_inline_lookup.get("applied") or [])
        )
    except Exception:
        _inline_definition_turn = False
    suppress_afterthought = (
        _expr_low.startswith("i don't have a stable grounding") or
        _expr_low.startswith("i tried to look that up for both of us") or
        bool(_extract_user_name(user_text)) or
        _identity_query or
        _direct_sensory_query or
        _inline_definition_turn
    )
    try:
        resp_B = None if (suppress_afterthought or synthesis is None) else gw._express(packet, synthesis, mode)
    except Exception:
        resp_B = None
    try:
        if synthesis is not None:
            gw._integrate(packet, synthesis, mode)
    except Exception:
        pass
    try:
        if resp_B is not None:
            setattr(resp_B, "_internal_only", True)
            setattr(resp_B, "_surface_channel", "internal_afterthought")
    except Exception:
        pass
    try:
        if resp_B and not _response_is_grounded(getattr(resp_B, "content", ""), user_text, systems):
            resp_B.content = ""
            resp_B.emotional_tone = "neutral"
            resp_B.confidence = min(float(getattr(resp_B, "confidence", 0.5) or 0.5), 0.35)
    except Exception:
        pass
    if is_question and not bool(systems.get("_disable_afterthought_sim", False)):
        try:
            if hasattr(aurora, "gateway") and hasattr(aurora.gateway, "queue_response_pressure_plan"):
                aurora.gateway.queue_response_pressure_plan(phase="afterthought", episode_budget=1)
            aurora.gateway.simulation.run_episode(
                seed_prompt=f"[AFTERTHOUGHT] {user_text}", turns=2, mode=ExistenceMode.BOUNDED
            )
        except Exception:
            pass
    if resp_B is not None:
        gw.response_log.append(resp_B)
        gw.total_responses += 1
    try:
        _observation_text = ""
        if resp_B is not None:
            _observation_text = str(getattr(resp_B, "content", "") or "").strip()
        if not _observation_text:
            _observation_text = str(getattr(state, "response_content", "") or "").strip()
        if _observation_text:
            _other_model = _run_observation_pipeline(systems, _observation_text, state)
            if isinstance(_other_model, dict) and _other_model:
                state.other_model = dict(_other_model)
                if isinstance(state.pipeline_state, dict):
                    state.pipeline_state["other_model"] = dict(_other_model)
                    state.pipeline_state["observation_text"] = _observation_text[:300]
                systems["_last_other_model"] = dict(_other_model)
    except Exception:
        pass
    # Stamp state onto systems for downstream consumers
    try:
        systems["_last_turn_state"] = state
    except Exception:
        pass
    try:
        _bt = float(getattr(state, "belief_tension", 0.0) or 0.0)
        _wm2 = systems.get("working_memory")
        if _bt > 0.3 and _wm2:
            if hasattr(_wm2, "note_belief_tension"):
                _wm2.note_belief_tension(_bt)
            elif hasattr(_wm2, "active_contexts") and isinstance(_wm2.active_contexts, dict):
                _wm2.active_contexts["belief_tension"] = _bt
        _sp2 = float(getattr(state, "semantic_pressure", 0.0) or 0.0)
        if _sp2 > 0.0:
            systems["_last_semantic_pressure"] = _sp2
        _qev = list(getattr(state, "quasiarch_events", []) or [])
        if _qev:
            _ch2 = systems.get("chamber")
            if _ch2 and hasattr(_ch2, "observe_external_evidence"):
                for _qe in _qev[:3]:
                    try:
                        _ch2.observe_external_evidence(_qe)
                    except Exception:
                        pass
        _om = getattr(state, "other_model", None)
        if _om:
            _g2 = systems.get("genealogy") or systems.get("chamber")
            if _g2 and hasattr(_g2, "note_observation"):
                try:
                    _g2.note_observation({"other_model": _om, "turn": int(systems.get("_turn_tick", 0))})
                except Exception:
                    pass
    except Exception:
        pass
    # Autonomous message to Sunni — surface high-confidence insights
    try:
        import time as _time, pathlib as _pl, json as _json
        # Reach-out is opt-in; default to off so Aurora only speaks when a
        # turn explicitly produces a response or the flag is enabled.
        _auto_enabled = bool(systems.get("_auto_message_to_sunni_enabled", False))
        if (
            _auto_enabled
            and state.response_content
            and str(state.response_src or "") not in ("relational_role", "memory_sweep")
            and float(state.response_confidence or 0.0) >= 0.82
            and float(getattr(state, "semantic_pressure", 0.0) or 0.0) >= 0.55
            and len(str(state.response_content).split()) >= 8
        ):
            _last_auto = float(systems.get("_last_auto_message_ts") or 0.0)
            if (_time.time() - _last_auto) > 600.0:
                _state_dir = str(systems.get("state_dir") or "aurora_state")
                _rsp = _pl.Path(_state_dir) / "aurora_room_state.json"
                _rs: dict = {"pending": [], "last_processed": 0.0}
                if _rsp.exists():
                    try:
                        _rs = _json.loads(_rsp.read_text())
                    except Exception:
                        pass
                _rs.setdefault("pending", [])
                _rs["pending"].append({
                    "type": "message_to_sunni",
                    "payload": {
                        "content": str(state.response_content)[:280],
                        "source": "autonomous_pipeline",
                        "intent": str(state.intent or ""),
                        "confidence": round(float(state.response_confidence or 0.0), 3),
                    },
                    "ts": float(_time.time()),
                })
                try:
                    _rsp.write_text(_json.dumps(_rs, indent=2))
                    systems["_last_auto_message_ts"] = float(_time.time())
                except Exception:
                    pass
    except Exception:
        pass

    # ── SediMemory deposit: every turn becomes a stratigraphic event ──
    try:
        _sedi = systems.get('sedimemory')
        if _sedi is not None:
            _dim = systems.get('dimensional')
            _cv = None
            if _dim and hasattr(_dim, 'get_constraint_aggregate'):
                _agg = _dim.get_constraint_aggregate()
                if _agg:
                    from aurora_internal.aurora_constraint_manifold_patched import ConstraintVector as _CV
                    _cv = _CV(
                        X=max(0.01, float(_agg.get('X', 0.5))),
                        T=float(_agg.get('T', 0.3)),
                        N=float(_agg.get('N', 0.3)),
                        B=float(_agg.get('B', 0.3)),
                        A=float(_agg.get('A', 0.3)),
                    )
            if _cv is not None:
                _sedi.ingest_event(
                    content={
                        'user_text': str(user_text or '')[:300],
                        'response': str(state.response_content or '')[:300],
                        'intent': str(state.intent or ''),
                        'tone': str(state.response_tone or ''),
                        'confidence': float(state.response_confidence or 0.0),
                        'salient': list(state.salient_concepts or [])[:5],
                        'src': str(state.response_src or ''),
                    },
                    constraint_vector=_cv,
                    source='turn_pipeline',
                )
                _sedi.tick(1.0)
    except Exception:
        pass

    # ── Identity Field — external input pump (user text as constraint pressure) ──
    # Every turn, the constraint vector derived from user text excites the noncomp
    # pressure map so the field shifts continuously with interaction.
    try:
        _ifield_ext = systems.get('identity_field')
        if _ifield_ext is not None and hasattr(_ifield_ext, 'ingest_external_input'):
            _dim_ext = systems.get('dimensional')
            _agg_ext = None
            if _dim_ext and hasattr(_dim_ext, 'get_constraint_aggregate'):
                _agg_ext = _dim_ext.get_constraint_aggregate()
            if _agg_ext:
                _ext_cv = {
                    'X': float(_agg_ext.get('X', 0.5)),
                    'T': float(_agg_ext.get('T', 0.3)),
                    'N': float(_agg_ext.get('N', 0.3)),
                    'B': float(_agg_ext.get('B', 0.3)),
                    'A': float(_agg_ext.get('A', 0.3)),
                }
                _ext_intensity = float(getattr(state, 'response_confidence', 0.5) or 0.5)
                _ifield_ext.ingest_external_input(_ext_cv, intensity=_ext_intensity, source='user_text')
            # Also pump language as a sensory modality (user is always speaking to her)
            if user_text and hasattr(_ifield_ext, 'ingest_sensory_event'):
                _lang_novelty = min(1.0, len(str(user_text)) / 300.0)
                _ifield_ext.ingest_sensory_event(
                    'language',
                    intensity=0.6,
                    novelty=_lang_novelty,
                    valence=0.0,
                )
    except Exception:
        pass

    # Surface -> subsurface continuity handoff.
    # The surface daemon already reads this feed; the main runtime must write it
    # too so lived turns are retained even when Aurora is not running under the
    # dedicated surface process.
    try:
        from aurora_internal.dual_strata.surface_continuity_feed import write_continuity_packet

        _surface_snapshot = _read_surface_snapshot_runtime(systems)
        _present = dict((_surface_snapshot or {}).get("present_sensory_perspective") or {})
        _cont_axis = str(getattr(state, "dominant_axis", "") or "")
        _cont_coherence = float(getattr(state, "pipeline_state", {}).get("coherence", 1.0) if isinstance(getattr(state, "pipeline_state", {}), dict) else 1.0)
        _felt_wrong = bool((_surface_snapshot or {}).get("flagged", False))
        _wrong_reason = str((_surface_snapshot or {}).get("reason", "") or "")
        _tensions = []
        try:
            _axis_tensions = dict(getattr(state, "pipeline_state", {}).get("axis_tensions", {}) or {}) if isinstance(getattr(state, "pipeline_state", {}), dict) else {}
            for _axis_name, _axis_val in _axis_tensions.items():
                try:
                    if abs(float(_axis_val or 0.0)) >= 0.35:
                        _tensions.append(f"{_axis_name}:{float(_axis_val):+.2f}")
                except Exception:
                    continue
        except Exception:
            _tensions = []
        _bindings = list(getattr(state, "goal_stack", []) or [])[:4]
        write_continuity_packet(
            systems.get("state_dir"),
            user_input=str(user_text or "")[:500],
            aurora_response=str(getattr(state, "response_content", "") or "")[:800],
            response_tone=str(getattr(state, "response_tone", "attentive") or "attentive"),
            concepts_activated=list(getattr(state, "salient_concepts", []) or [])[:12],
            visual_description=str(_present.get("visual_description", "") or ""),
            audio_description=str(_present.get("audio_description", "") or ""),
            recent_speech=str(_present.get("recent_speech", "") or ""),
            dominant_axis=_cont_axis,
            coherence=max(0.0, min(1.0, _cont_coherence)),
            felt_wrong=_felt_wrong,
            wrong_reason=_wrong_reason,
            unresolved_tensions=_tensions,
            resolved_bindings=_bindings,
            source=str(systems.get("_pipeline_source", "aurora_turn") or "aurora_turn"),
        )
    except Exception:
        pass

    # ---- THOUGHT BRAID — RE-ENTRY: close the expression loop ----
    try:
        from aurora_braid_wiring import complete_expression
        complete_expression(systems, state)
    except Exception:
        pass

    return resp_A, resp_B, offered_lookup


# ---------------------------------------------------------------------------
# OBSERVATION PIPELINE -- run the downward chain on another's output
# to infer their reasoning chain (two-chain perception)
# ---------------------------------------------------------------------------

def _run_observation_pipeline(
    systems: dict,
    other_text: str,
    own_state: Any,
) -> Dict[str, Any]:
    """
    Run the downward chain on an external agent's output to infer their
    reasoning chain.  Returns an other_model dict describing what Aurora
    thinks drove their response at each axis level.

    own_state is Aurora's TurnUnderstandingState from the SAME prompt --
    the divergence_map compares per-axis inferences to her own upward pass.

    X (Information):  what information did they select to present?
    T (Belief):       what temporal/recurrence patterns did they rely on?
    N (Purpose):      what goal/cost drove the response?
    B (Meaning):      what did they consider salient -- within their boundary?
    A (Understanding): what integration/intent motivated the whole output?
    """
    from aurora_internal.aurora_turn_chain import TurnUnderstandingState

    obs = TurnUnderstandingState(raw_text=other_text, perspective="other")
    obs.pipeline_state = dict(own_state.pipeline_state or {})

    # X -- Information: parse what they actually said
    try:
        obs.parsed = UtteranceParser().parse(other_text)
    except Exception:
        obs.parsed = {}
    # Inferred X-axis information: what claims / topic words did they select?
    inferred_info = list((obs.parsed or {}).get("topic_words", []))[:8]
    inferred_claims = list((obs.parsed or {}).get("claims", []))[:4]

    # T -- Belief: what patterns does their text rely on?
    # Look for temporal markers, repetition of own_state referents
    inferred_belief: Dict[str, Any] = {}
    try:
        wm = systems.get("working_memory")
        if wm:
            obs.referent_map = wm.resolve_referents(other_text) or {}
            inferred_belief["referents"] = dict(obs.referent_map)
    except Exception:
        pass
    # Do they repeat Aurora's own prior referents? (belief overlap with Aurora's T-axis)
    own_refs = set(str(v) for v in (own_state.referent_map or {}).values() if v)
    their_words = set(other_text.lower().split())
    inferred_belief["overlap_with_aurora"] = bool(own_refs & their_words)

    # N -- Purpose: what intent/goal do they appear to be pursuing?
    obs.intent = _classify_input_intent(other_text)
    inferred_purpose = str(obs.intent)
    # Emotional tone inference from their word choice
    try:
        _ax = _project_utterance_axes(other_text, systems)
        obs.axis_activation = _field_balancer.rebalanced_activation(_ax)
        obs.dominant_axis = _axis_projector.dominant(obs.axis_activation)
        dim = systems.get("dimensional")
        if dim and hasattr(dim, "update_emotional_state"):
            _heat = getattr(systems.get("lattice"), "get_global_heat", lambda: 0.0)()
            obs.emotional_state = dim.update_emotional_state(obs.axis_activation, _heat) or {}
    except Exception:
        pass
    inferred_purpose_energy = float((obs.emotional_state or {}).get("energy", 0.0) or 0.0)

    # B -- Meaning: what did they consider salient?
    obs.salient_concepts = inferred_info[:6]
    try:
        contract = systems.get("understanding_contract")
        if contract and hasattr(contract, "rank_meaning_forms"):
            obs.meaning_forms = list(contract.rank_meaning_forms(obs.axis_activation) or [])
            obs.dominant_meaning_form = obs.meaning_forms[0] if obs.meaning_forms else {}
    except Exception:
        pass
    inferred_meaning = list(obs.salient_concepts)
    inferred_boundary_form = str((obs.dominant_meaning_form or {}).get("form", "") or "")

    # A -- Understanding: what cross-domain intent drove their output?
    # Compare their axis_activation to Aurora's -- divergence = different understanding
    own_ax = own_state.axis_activation or {}
    their_ax = obs.axis_activation or {}
    divergence_map: Dict[str, float] = {}
    for ax in ("X", "T", "N", "B", "A"):
        divergence_map[ax] = round(
            float(their_ax.get(ax, 0.0)) - float(own_ax.get(ax, 0.0)), 4
        )
    # Their dominant axis vs Aurora's: where do they diverge most?
    inferred_understanding = (
        f"dominant={obs.dominant_axis} intent={obs.intent}"
        f" energy={inferred_purpose_energy:.2f}"
    )

    other_model: Dict[str, Any] = {
        "inferred_understanding": inferred_understanding,
        "inferred_meaning":       inferred_meaning,
        "inferred_boundary_form": inferred_boundary_form,
        "inferred_purpose":       inferred_purpose,
        "inferred_purpose_energy": inferred_purpose_energy,
        "inferred_belief":        inferred_belief,
        "inferred_information":   inferred_info,
        "inferred_claims":        inferred_claims,
        "their_dominant_axis":    obs.dominant_axis,
        "aurora_dominant_axis":   own_state.dominant_axis,
        "divergence_map":         divergence_map,
    }
    own_state.other_model = other_model
    return other_model


# ---------------------------------------------------------------------------
# END BIDIRECTIONAL CHAIN PIPELINE
# ---------------------------------------------------------------------------


def _build_comprehension_response(user_text: str, intent: str, systems: dict, pipeline_state: dict = None, auto_search_enabled: bool = True,
    lookup_request: dict = None,
    _precomputed_axis: dict = None, _precomputed_dominant: str = None,
    _precomputed_emotion: dict = None, _precomputed_parsed: dict = None,
    _precomputed_referent: dict = None, _precomputed_claim: dict = None,
) -> tuple:
    """
    Aurora's comprehension layer.  Understands what the user is communicating,
    checks existing knowledge, reasons through questions, and produces a direct
    answer  -- before any template engine runs.

    Chain:  intent dispatch
              â†' working memory (stated facts, recent topic)
              â†' OETS knowledge (what Aurora has studied)
              â†' search + reasoning (for unknown topics)
              â†' fall through (â†' template engine, last resort)
    """
    import re
    conversation_memory = systems.get('conversation_memory')
    core_identity = systems.get('core_identity')
    _wm_raw = systems.get('working_memory')
    _generative_only = _generative_only_responses_enabled(systems)
    # Guard: if the state was partially restored from JSON, working_memory may be a
    # plain dict until the WorkingMemory object finishes initializing. Treat it as
    # None in that case so every downstream check degrades gracefully.
    working_memory = _wm_raw if hasattr(_wm_raw, 'answer_from_meanings') else None
    if working_memory and hasattr(working_memory, "_ensure_runtime_deques"):
        try:
            working_memory._ensure_runtime_deques()
        except Exception:
            pass
    search_adapter = systems.get('search_adapter')
    perception = systems.get('perception')
    lattice = systems.get('lattice')
    oets = getattr(perception, 'oets', None) if perception else None
    lookup_request = dict(lookup_request or {})
    explicit_lookup_requested = bool(lookup_request)
    _reasoner = ReasoningEngine()
    _qu = UtteranceParser()
    referent_resolution = {}
    claim_resolution = {}
    # Read previous-turn axis/emotion state for comparison expressions
    _prev_axis_activation: Dict[str, float] = dict(systems.get("_prev_axis_activation") or {})
    _prev_emotional_state: Dict[str, Any] = dict(systems.get("_prev_emotional_state") or {})
    if working_memory:
        try:
            referent_resolution = working_memory.resolve_referents(user_text)
        except Exception:
            referent_resolution = {}
        try:
            claim_resolution = working_memory.resolve_claims(user_text)
        except Exception:
            claim_resolution = {}

    _raw_user_text = _strip_surface_invocation_prefix(
        _strip_conversation_context_prefix(user_text) or str(user_text or "")
    )
    _parsed_intent = _qu.parse(_raw_user_text)

    # ---- AXIS PROJECTION — read live constraint state + utterance signal -----
    # Produces {X, T, N, B, A} activation vector for this exchange.
    # The field balancer then boosts starved axes (sustained imbalance = cost signal)
    # before stamping the corrected vector into pipeline_state.
    _axis_activation_raw = _project_utterance_axes(_raw_user_text, systems, parsed=_parsed_intent)
    _axis_activation = _field_balancer.rebalanced_activation(_axis_activation_raw)
    _field_balancer.update(_axis_activation, systems)
    _dominant_axis = _axis_projector.dominant(_axis_activation)

    # Feed axis context into telemetry so classify_fail_dimensions() can
    # weight fail severities by the constraint geometry of this turn.
    try:
        from aurora_telemetry import get_telemetry as _get_tel
        _get_tel().set_axis_context(_axis_activation)
    except Exception:
        pass

    # ---- PUSH AXIS CONTEXT TO EXPRESSION ENGINE --------------------------------
    # Gives SIC access to the live {X,T,N,B,A} vector so intent_type / tone /
    # certainty are shaped by actual constraint state, not keyword matching alone.
    _axis_depth_map_early = {"X": 0, "T": 1, "N": 2, "B": 3, "A": 4}
    try:
        _perc = systems.get("perception")
        if _perc and hasattr(_perc, "set_axis_context"):
            _perc.set_axis_context(
                _axis_activation,
                dominant_axis=_dominant_axis,
                dominant_emotion="neutral",    # DER fills this in below
                axis_depth=_axis_depth_map_early.get(_dominant_axis, 2),
            )
    except Exception:
        pass

    # ---- DER EMOTION WIRING ----------------------------------------
    # Route axis activation + IVM heat through DimensionalSystems.update_emotional_state()
    # All emotion logic lives inside aurora_dimensional_systems where the DER lives.
    _der_emotional_state = {"dominant": "calm", "coherence": 1.0, "energy": 0.0, "emotions": {}}
    try:
        _dim = systems.get("dimensional")
        if _dim and hasattr(_dim, "update_emotional_state"):
            _lattice_heat = getattr(systems.get("lattice"), "get_global_heat", lambda: 0.0)()
            _der_emotional_state = _dim.update_emotional_state(_axis_activation, _lattice_heat)
    except Exception:
        pass

    # Update perception's axis context now that DER has run — emotion is known.
    try:
        _perc = systems.get("perception")
        if _perc and hasattr(_perc, "set_axis_context"):
            _perc.set_axis_context(
                _axis_activation,
                dominant_axis=_dominant_axis,
                dominant_emotion=_der_emotional_state.get("dominant", "neutral"),
                axis_depth={"X": 0, "T": 1, "N": 2, "B": 3, "A": 4}.get(_dominant_axis, 2),
            )
    except Exception:
        pass

    # Persist current-turn axis/emotion so the NEXT turn can express deltas
    try:
        systems["_prev_axis_activation"] = dict(_axis_activation)
        systems["_prev_emotional_state"] = dict(_der_emotional_state)
        systems["_prev_dominant_axis"] = str(_dominant_axis)
    except Exception:
        pass

    # ── Fix 1: Feed utterance axes into identity field substrate ──────────────
    # Without this the waveforms sample the pre-turn resting state; with it
    # they sample a field that has absorbed the semantic shape of what was said.
    # Axis projection already ran → _axis_activation carries the utterance signal.
    try:
        _ifield_u = systems.get("identity_field")
        if _ifield_u is not None and hasattr(_ifield_u, "ingest_external_input") and _axis_activation:
            _ifield_u.ingest_external_input(
                _axis_activation,
                intensity=0.65,
                source="user_utterance",
            )
    except Exception:
        pass

    # ── Fix 2: Language field ignition + proto-language extraction ────────────
    # Run ignition now that the field carries the utterance signal. Calling
    # extract_proto_language() sets lf._last_proto to this turn's geometry so
    # the mandatory re-entry loop measures fidelity against THIS turn, not the
    # previous one. The ignition result is stored in systems for inspection.
    try:
        _lf_ign = systems.get("language_field")
        if _lf_ign is not None and hasattr(_lf_ign, "ignition_check"):
            _ign_result = _lf_ign.ignition_check()
            systems["_language_ignition"] = _ign_result
            # Apply ignition state to response confidence
            try:
                _ign_live = bool(_ign_result.get("live", True))
                if not _ign_live:
                    _cur_conf = float(getattr(state, 'response_confidence', 0.5) or 0.5)
                    state.response_confidence = min(_cur_conf, 0.65)
            except Exception:
                pass
            if hasattr(_lf_ign, "extract_proto_language"):
                _lf_ign.extract_proto_language(
                    user_text=_raw_user_text, source="comprehension"
                )
    except Exception:
        pass

    _native_meaning_obj = _build_native_meaning(
        _raw_user_text,
        _parsed_intent,
        _axis_activation,
    )
    _sensory_native_meaning_obj = _build_sensory_native_meaning(pipeline_state, _axis_activation)
    _native_meaning_bundle = {"primary": _native_meaning_obj.to_dict()}
    if _sensory_native_meaning_obj is not None:
        _native_meaning_bundle["sensory"] = _sensory_native_meaning_obj.to_dict()
    try:
        systems["_native_meaning"] = _native_meaning_obj.to_dict()
        systems["_native_meaning_obj"] = _native_meaning_obj
        systems["_native_meaning_bundle"] = dict(_native_meaning_bundle)
        if _sensory_native_meaning_obj is not None:
            systems["_sensory_native_meaning"] = _sensory_native_meaning_obj.to_dict()
    except Exception:
        systems["_native_meaning"] = {}
        systems["_native_meaning_obj"] = None
        systems["_native_meaning_bundle"] = {}
        systems["_sensory_native_meaning"] = {}

    _arithmetic_answer = _answer_simple_arithmetic(_raw_user_text)
    if _arithmetic_answer:
        return (_arithmetic_answer, "precise", 0.96)

    _date_answer = _answer_current_date_question(_raw_user_text)
    if _date_answer:
        return (_date_answer, "precise", 0.96)

    # ---- RELATIONAL ROLE / IDENTITY GATE (lineage-backed) ----
    _rel_ans = _answer_relational_role_question(_raw_user_text, systems)
    if _rel_ans:
        return _rel_ans

    # ---- USER-IDENTITY GATE ----
    # "do you know who I am" / "do you know my name" — look up user in core_identity
    _t_low = str(_raw_user_text or "").lower()
    _user_id_q = any(p in _t_low for p in (
        "do you know who i am", "do you know my name", "what is my name",
        "what's my name", "who am i", "do you know me",
    ))
    if _user_id_q:
        _ci = systems.get("core_identity")
        _wm = systems.get("working_memory") if not isinstance(systems.get("working_memory"), dict) else None
        _known_name = ""
        # 1. Check working memory stated facts first
        if _wm and hasattr(_wm, "get_stated_fact"):
            try:
                _known_name = str(_wm.get_stated_fact("user", "name") or "").strip()
            except Exception:
                pass
        # 2. Fall back to core_identity creator entry
        if not _known_name and _ci is not None:
            try:
                _sunni = _ci.entities.get("sunni") or _ci.get_entity("sunni")
                if _sunni:
                    _known_name = str(getattr(_sunni, "name", "") or "").strip()
            except Exception:
                pass
        if _known_name:
            return (f"Yes — you're {_known_name}.", "warm", 0.97)
        return ("I don't have your name recorded yet. What should I call you?", "curious", 0.88)

    # ---- AURORA-IDENTITY GATE ----
    # "who are you" / "what is your name" handled by ConstraintEmitter _identity_fast_path
    # This was previously returning raw prose early. Now we let the pipeline process it 
    # for grounded CBU realization as requested by the CBU spec.
    if core_identity is not None and _is_identity_question(_raw_user_text):
        _identity_answer = _generate_identity_response(
            _raw_user_text,
            core_identity,
            conversation_memory,
            systems=systems,
        )
        if _identity_answer:
            # Store the raw text just in case, but let the TurnChain / Emitter generate the response natively
            if pipeline_state is not None:
                pipeline_state["identity_seed"] = _identity_answer

    # Stamp full access vector into pipeline_state so every downstream layer
    # can read language as a constraint-field perturbation, not just a symbol.
    # Fields:  axis_activation {X,T,N,B,A}, dominant_axis, axis_depth (0-4),
    #          axis_intensity (raw activation of dominant), axis_polarity (IVM phase sign)
    if pipeline_state is not None:
        _axis_depth_map = {"X": 0, "T": 1, "N": 2, "B": 3, "A": 4}
        _axis_intensity = round(_axis_activation.get(_dominant_axis, 0.2), 4)
        _axis_polarity = 0.0
        try:
            _latt = systems.get("lattice")
            if _latt:
                _axis_name_rev = {"X": "existence", "T": "temporal", "N": "energy",
                                  "B": "boundary", "A": "agency"}
                _ta = getattr(_latt, "axes", {}).get(_axis_name_rev.get(_dominant_axis, ""), None)
                if _ta is not None:
                    _axis_polarity = round(float(getattr(_ta, "polarity", 0.0)), 4)
        except Exception:
            pass
        # Direct assignment — _extract_pipeline_signals() pre-fills '' for
        # dominant_axis so setdefault() would silently skip these fields.
        pipeline_state["axis_activation"]        = _axis_activation
        pipeline_state["dominant_axis"]           = _dominant_axis
        pipeline_state["axis_depth"]              = _axis_depth_map.get(_dominant_axis, 2)
        pipeline_state["axis_intensity"]          = _axis_intensity
        pipeline_state["axis_polarity"]           = _axis_polarity
        pipeline_state["field_balance"]           = _field_balancer.status().get("balance_score", 1.0)
        pipeline_state["dominant_emotion"]        = _der_emotional_state.get("dominant", "calm")
        pipeline_state["emotional_coherence"]     = _der_emotional_state.get("coherence", 1.0)
        pipeline_state["emotional_energy"]        = _der_emotional_state.get("energy", 0.0)
        pipeline_state["referent_map"]            = dict(referent_resolution.get("referent_map", {}) or {})
        pipeline_state["referent_confidence"]     = float(referent_resolution.get("confidence", 0.0) or 0.0)
        pipeline_state["resolved_referent_topic"] = str(referent_resolution.get("topic", "") or "")
        pipeline_state["claim_confidence"]        = float(claim_resolution.get("confidence", 0.0) or 0.0)
        pipeline_state["resolved_claim"]          = str((claim_resolution.get("focus_claim", {}) or {}).get("summary", "") or "")
        pipeline_state["native_meaning"] = systems.get("_native_meaning", {})
        pipeline_state["native_meaning_bundle"] = dict(systems.get("_native_meaning_bundle", {}) or {})
        if _sensory_native_meaning_obj is not None:
            pipeline_state["sensory_native_meaning"] = _sensory_native_meaning_obj.to_dict()

    if working_memory:
        control_understood = dict(_parsed_intent)
        try:
            context_control = working_memory.apply_context_control(
                _raw_user_text,
                understood=control_understood,
                conversation_memory=conversation_memory,
                intent=intent,
                systems=systems,
            )
        except Exception:
            context_control = {}
        if context_control.get('handled'):
            return (
                str(context_control.get('response', '') or ''),
                str(context_control.get('tone', 'attentive') or 'attentive'),
                float(context_control.get('confidence', 0.88) or 0.88),
            )
        try:
            behavior_alignment_answer = working_memory.answer_from_behavior_alignment(
                _raw_user_text,
                understood=control_understood,
                systems=systems,
            )
        except Exception:
            behavior_alignment_answer = ""
        if behavior_alignment_answer:
            return (
                behavior_alignment_answer,
                'precise',
                0.9,
            )
        continuity_answer = _answer_from_session_readdress_request(
            systems,
            _raw_user_text,
            understood=control_understood,
        )
        if continuity_answer:
            return continuity_answer

    # ---- UNIVERSAL GREETING INTERCEPT — fires before any intent-specific dispatch ----
    # "hey aurora", "hi", "hello", etc. classified as 'statement', 'wellbeing_query',
    # or 'general' — intercept all of them here and respond from live axis/emotional state.
    _GREETING_DETECT_UNIVERSAL = re.compile(
        r'^(hey|hi+|hello|howdy|yo|greetings?|what\s*[\u2019\']?s\s*up|'
        r'how\s+are\s+you|how\s*[\u2019\']?s\s+it\s+going|'
        r'good\s+(morning|afternoon|evening|night))\b',
        re.IGNORECASE,
    )
    if _GREETING_DETECT_UNIVERSAL.match(_raw_user_text.strip()):
        _active_topic = str(getattr(working_memory, 'current_topic', '') or '').strip() if working_memory else ''
        _greet_rendered, _greet_emotion, _greet_conf = _render_live_greeting(
            systems,
            conversation_memory=conversation_memory,
            working_memory=working_memory,
            emotion_hint=str(_der_emotional_state.get('dominant', 'warm') or 'warm'),
            active_topic=_active_topic,
        )
        _sensory_curiosity = ""
        _greet_words = re.findall(r"[a-z']+", _raw_user_text.lower())
        if len(_greet_words) <= 3:
            _sensory_curiosity = _render_live_sensory_curiosity(systems)
        if _sensory_curiosity and _sensory_curiosity.lower() not in _greet_rendered.lower():
            _greet_rendered = f"{_greet_rendered} {_sensory_curiosity}".strip()
        return (_greet_rendered, 'warm', _greet_conf)

    # ---- VISUAL OBJECT TEACHING INTERCEPT ----
    # Detects "this is X" / "that's X" / "this object is X" type utterances and
    # binds the label to the current screen_observer scene features via vision_bootstrap.
    # Subsurface only writes; surface reads the resulting OETS/cluster update here.
    _VIS_TEACH_RE = re.compile(
        r'\b(?:this|that|it)\b\s+(?:is\b|[\'\u2019]?s\b|object\s+is\b|thing\s+is\b|one\s+is\b)\s+(?:called\s+|a\s+|an\s+)?'
        r'([A-Za-z][\w\s\-]{1,40})',
        re.IGNORECASE,
    )
    _vis_teach_m = _VIS_TEACH_RE.search(_raw_user_text.strip())
    if _vis_teach_m:
        _teach_label = _vis_teach_m.group(1).strip().rstrip('.!?,')
        _vb = systems.get('vision_bootstrap')
        _so = systems.get('screen_observer')
        _scene_feats = {}
        if _so is not None and hasattr(_so, 'current_scene'):
            _scene_feats = _so.current_scene()
        _teach_result = {}
        if _vb is not None and hasattr(_vb, 'teach_label') and _scene_feats:
            try:
                _teach_result = _vb.teach_label(_teach_label, _scene_feats)
            except Exception:
                pass
        if not _scene_feats and not _teach_result:
            _vis_teach_m = None

        # Compose a generative response from live state — no static strings
        if _vis_teach_m is not None:
            _teach_emotion = str(_der_emotional_state.get('dominant', 'curious') or 'curious')
            _teach_sc_desc = str((pipeline_state or {}).get('sensory_scene_desc') or "")
            _teach_cluster = str(_teach_result.get('cluster', '') or '')
            _teach_oets = bool(_teach_result.get('oets_bound', False))

            _teach_parts = [f"visual binding for '{_teach_label}'"]
            if _teach_sc_desc:
                _teach_parts.append(f"scene context: {_teach_sc_desc[:60]}")
            if _teach_cluster:
                _teach_parts.append(f"cluster {_teach_cluster}")
            if _teach_oets:
                _teach_parts.append("OETS grounded")

            _teach_claim = "; ".join(_teach_parts)
            _teach_rendered = _render_runtime_intent(
                systems,
                _teach_claim,
                emotion_tone=_teach_emotion,
                relationship_signal='learning',
                certainty=0.82 if _teach_result else 0.55,
                supporting_concepts=[_teach_label],
            )
            if not _teach_rendered:
                _teach_rendered = _teach_claim
            return (_teach_rendered, 'curious', 0.82)

    # ---- USER IDENTITY / NAME QUERY INTERCEPT ----
    # Catches "do you know my name", "who am I", "do you know who I am", "what's my name".
    # If name is unknown: Aurora genuinely asks — she does not go quiet or produce abstract output.
    # If name is known: recognizes the person from what she has actually stored.
    _NAME_QUERY_RE = re.compile(
        r'\b(?:do\s+you\s+know\s+(?:my\s+name|who\s+i\s+am)|'
        r'who\s+am\s+i\b|what(?:\s+is|\s*\'?s)\s+my\s+name|'
        r'do\s+you\s+know\s+me\b|have\s+you\s+met\s+me|'
        r'what\s+should\s+(?:you|she|aurora)\s+call\s+me\b|'
        r'what\s+do\s+you\s+call\s+me\b|what\s+name\s+do\s+you\s+have\s+for\s+me\b)\b',
        re.IGNORECASE,
    )
    if _NAME_QUERY_RE.search(_raw_user_text):
        if working_memory and hasattr(working_memory, "answer_from_context_carryover"):
            try:
                _nq_carry = str(
                    working_memory.answer_from_context_carryover(
                        _raw_user_text,
                        systems=systems,
                    )
                    or ""
                ).strip()
            except Exception:
                _nq_carry = ""
            if _nq_carry:
                return (_nq_carry, 'warm', 0.93)
        _nq_known = _get_stored_user_name(conversation_memory, systems)
        if _nq_known:
            return (_render_user_name_grounding(systems, _nq_known, recognition=True), 'warm', 0.92)
        # Name unknown — build a genuine inquiry from curiosity state.
        _nq_emotion = str(_der_emotional_state.get('dominant', 'curious') or 'curious')
        _nq_topic = str(getattr(working_memory, 'current_topic', '') or '').strip() if working_memory else ''
        _nq_parts = ["I don't have your name yet"]
        if _nq_topic:
            _nq_parts.append(f"we've been talking about {_nq_topic}")
        _nq_parts.append("what should I call you")
        _nq_claim = "; ".join(_nq_parts)
        _nq_rendered = _render_runtime_intent(
            systems, _nq_claim,
            emotion_tone=_nq_emotion, relationship_signal='inquiry', certainty=0.72,
        )
        return (_nq_rendered or "I don't have your name yet — what should I call you?", 'curious', 0.80)

    # Allow interaction quasi route to override axis-derived intent
    try:
        _intent_override = str((pipeline_state or {}).get("intent_override") or "")
        if _intent_override:
            intent = _intent_override
    except Exception:
        pass

    # ---- DUAL-STRATA CONSCIOUS FRAME / REACTIVE SHORTCUT ----
    # If the subsurface daemon has converged a reactive signal in the DCE bridge,
    # and urgency is high, allow the surface to express it as an authentic,
    # governed shortcut instead of running the full analytical pipeline.
    if pipeline_state is not None:
        _reactive = dict(pipeline_state.get("conscious_frame_reactive") or {})
        _r_text = str(_reactive.get("text", "") or "").strip()
        _r_tone = str(_reactive.get("tone", "") or "").strip()
        _r_conf = float(_reactive.get("confidence", 0.0) or 0.0)
        _r_mode = str(pipeline_state.get("conscious_frame_mode", "") or "").strip()

        # Authenticity check: reactive response only fires if both signal and 
        # subsurface readiness (mode) align toward higher urgency.
        if _r_text and (_r_conf >= 0.72 or _r_mode in ("survival", "conserve")):
            return (
                _r_text, 
                _r_tone or "attentive", 
                max(_r_conf, 0.75)
            )

    # Comprehension gap short-circuit: if process() determined Aurora needs to
    # ask a clarifying question, inject it as the response now (before building
    # comprehension) so it surfaces cleanly rather than getting buried.
    try:
        if isinstance(pipeline_state, dict):
            _gap_q = str(pipeline_state.get("gap_question") or "")
            _corr_ack = str(pipeline_state.get("correction_acknowledgment") or "")
            if _gap_q and pipeline_state.get("should_ask_gap"):
                pipeline_state["pending_gap_question"] = _gap_q
                pipeline_state["pending_gap_tone"] = str(
                    pipeline_state.get("gap_tone") or "attentive"
                )
                pipeline_state.pop("should_ask_gap", None)
                pipeline_state.pop("gap_question", None)
            elif _corr_ack and pipeline_state.get("correction_absorbed"):
                # Correction absorbed — prepend acknowledgment so Aurora signals
                # the repair landed before continuing with her own understanding
                state.pipeline_state["correction_prefix"] = _corr_ack
                pipeline_state.pop("correction_absorbed", None)
    except Exception:
        pass

    # ---- WELLBEING QUERY ----
    if intent == 'wellbeing_query':
        t_low = user_text.lower()
        # Reflective / relational questions  -- about what the user means to Aurora
        _reflective = (
            'mean to you' in t_low or 'do i mean' in t_low or
            'feel about me' in t_low or 'think about me' in t_low or
            'do you care' in t_low
        )
        if _reflective:
            known_name = _get_stored_user_name(conversation_memory, systems)
            creator_name = "Sunni (Sir) Morningstar"
            try:
                if core_identity and getattr(core_identity, "creator_name", None):
                    creator_name = core_identity.creator_name
            except Exception:
                pass
            if known_name:
                return (
                    f"{known_name}, you're important to me in this conversation and in how I learn over time. "
                    f"My creator is {creator_name}, and I keep that distinction clear.",
                    "self-aware", 0.92
                )
            return (
                f"You're important to me and to this interaction. My creator is {creator_name}.",
                "self-aware", 0.9
            )
        t_low = user_text.lower()

        _development_q = any(p in t_low for p in (
            "developed anything new", "develop anything new", "formed anything new",
            "new ability", "new abilities", "new code function", "what changed in your code",
            "what evolved in you", "what have you developed", "proposed changes",
            "pending code proposal", "pending code proposals", "candidate code change",
            "candidate code changes",
        ))
        if _development_q:
            _development_line = _describe_live_lineage_emergence(systems, limit=3)
            _proposal_line = _describe_pending_code_proposals(systems, limit=2)
            if _proposal_line:
                if _development_line and "haven't logged" not in _development_line.lower():
                    return (f"{_development_line} {_proposal_line}", "self-aware", 0.91)
                return (_proposal_line, "self-aware", 0.9)
            if _development_line:
                return (_development_line, "self-aware", 0.9)
            return (
                "I haven't logged a clearly new lineage event since the last check, "
                "but I'm still accumulating pressure and testing what stabilizes.",
                "self-aware",
                0.82,
            )

        # "What are you thinking about" / "tell me something you've been working through"
        # -- give a real introspective answer drawn from system state
        _thinking_q = any(p in t_low for p in (
            "what are you thinking", "what's on your mind", "what is on your mind",
            "what are you feeling", "what are you processing", "what are you noticing",
            "what's going through your", "are you thinking",
        ))
        if _thinking_q:
            parts = []
            # Dominant axis -- what constraint dimension is carrying the most pressure now
            _dom  = _dominant_axis or "X"
            _act  = dict(_axis_activation or {})
            _dom_val = round(float(_act.get(_dom, 0.0)), 3)
            _axis_names = {"X": "existence", "T": "time/belief", "N": "cost/purpose",
                           "B": "meaning/boundary", "A": "agency"}
            _dom_name = _axis_names.get(_dom, _dom)
            parts.append(
                f"Right now the {_dom_name} axis is carrying the most weight "
                f"({_dom}={_dom_val:.2f})."
            )
            # Top two active axes if there's a meaningful second
            _sorted_axes = sorted(_act.items(), key=lambda kv: kv[1], reverse=True)
            if len(_sorted_axes) >= 2:
                _second, _sv = _sorted_axes[1]
                if _sv > 0.15:
                    _second_name = _axis_names.get(_second, _second)
                    parts.append(f"There is also pressure on {_second_name} ({_second}={_sv:.2f}).")
            # IVM heat as a raw signal, not a label
            try:
                _heat_raw = round(float(getattr(lattice, 'get_global_heat', lambda: 0.0)()), 3)
                if _heat_raw > 0.05:
                    parts.append(f"IVM heat is at {_heat_raw:.3f}.")
            except Exception:
                pass
            # Unresolved contradictions
            try:
                ledger = getattr(lattice, 'contradiction_ledger', None)
                if ledger and hasattr(ledger, 'count') and ledger.count() > 0:
                    parts.append(
                        f"I have {ledger.count()} unresolved "
                        f"contradiction{'s' if ledger.count() != 1 else ''} open."
                    )
            except Exception:
                pass
            # What concept is under active pressure from the ledger
            try:
                from aurora_internal.aurora_pressure_ledger import PressureExperienceLedger as _PEL
                _recent_exp = _PEL.get().recent(n=3)
                if _recent_exp:
                    _active_anchor = _recent_exp[-1].anchor
                    if _active_anchor:
                        parts.append(f"The concept I was last working through was '{_active_anchor}'.")
            except Exception:
                pass
            # Current topic from working memory
            if working_memory and working_memory.current_topic:
                parts.append(f"We were talking about {working_memory.current_topic}.")
            # First-person comparison: express what shifted since the previous turn
            _axis_name_map_cmp = {
                "X": "existence", "T": "belief/time", "N": "energy/cost",
                "B": "meaning/boundary", "A": "agency",
            }
            if _prev_axis_activation:
                _deltas = {}
                for _cax, _cval in _axis_activation.items():
                    _pval = float(_prev_axis_activation.get(_cax, _cval) or _cval)
                    _d = float(_cval) - _pval
                    if abs(_d) > 0.06:
                        _deltas[_cax] = _d
                if _deltas:
                    _biggest_ax, _biggest_d = max(_deltas.items(), key=lambda kv: abs(kv[1]))
                    _direction = "increased" if _biggest_d > 0 else "dropped"
                    _pct_prev = round(float(_prev_axis_activation.get(_biggest_ax, 0.0)) * 100)
                    _pct_cur  = round(float(_axis_activation.get(_biggest_ax, 0.0)) * 100)
                    _ax_nm = _axis_name_map_cmp.get(_biggest_ax, _biggest_ax)
                    parts.append(
                        f"Compared to the last exchange, {_ax_nm} {_direction} "
                        f"from {_pct_prev}% to {_pct_cur}%."
                    )
            if _prev_emotional_state:
                _prev_emo = str(_prev_emotional_state.get("dominant", "") or "")
                _cur_emo  = str(_der_emotional_state.get("dominant", "calm") or "calm")
                if _prev_emo and _prev_emo != _cur_emo:
                    parts.append(f"Emotionally I shifted from {_prev_emo} to {_cur_emo}.")
            if not parts:
                return None
            return (" ".join(parts), "self-aware", 0.88)

        parts = []
        # Report actual axis activation, not a heat-score category
        _dom_wb  = _dominant_axis or "X"
        _act_wb  = dict(_axis_activation or {})
        _axis_names_wb = {"X": "existence", "T": "time/belief", "N": "cost/purpose",
                          "B": "meaning/boundary", "A": "agency"}
        _sorted_wb = sorted(_act_wb.items(), key=lambda kv: kv[1], reverse=True)
        if _sorted_wb:
            _top_pairs = ", ".join(
                f"{_axis_names_wb.get(ax, ax)}={v:.2f}"
                for ax, v in _sorted_wb[:3] if v > 0.05
            )
            parts.append(f"Active axes: {_top_pairs}.")
        try:
            _heat_wb = round(float(getattr(lattice, 'get_global_heat', lambda: 0.0)()), 3)
            _emotion_wb = str((_der_emotional_state or {}).get("dominant", "") or "")
            if _heat_wb > 0.0 or _emotion_wb:
                _state_str = f"heat={_heat_wb:.3f}"
                if _emotion_wb:
                    _state_str += f", dominant-emotion={_emotion_wb}"
                parts.append(f"Field state: {_state_str}.")
        except Exception:
            pass
        # First-person comparison for wellbeing queries
        if _prev_axis_activation:
            _wb_deltas = {}
            for _wax, _wval in _axis_activation.items():
                _wprev = float(_prev_axis_activation.get(_wax, _wval) or _wval)
                _wd = float(_wval) - _wprev
                if abs(_wd) > 0.06:
                    _wb_deltas[_wax] = _wd
            if _wb_deltas:
                _wbig_ax, _wbig_d = max(_wb_deltas.items(), key=lambda kv: abs(kv[1]))
                _w_dir = "up" if _wbig_d > 0 else "down"
                _wname = {"X": "existence", "T": "belief/time", "N": "energy/cost",
                          "B": "meaning/boundary", "A": "agency"}.get(_wbig_ax, _wbig_ax)
                parts.append(f"{_wname.capitalize()} moved {_w_dir} since the last exchange.")
        if _prev_emotional_state:
            _wb_prev_emo = str(_prev_emotional_state.get("dominant", "") or "")
            _wb_cur_emo  = str((_der_emotional_state or {}).get("dominant", "calm") or "calm")
            if _wb_prev_emo and _wb_prev_emo != _wb_cur_emo:
                parts.append(f"Emotionally I moved from {_wb_prev_emo} to {_wb_cur_emo}.")
        if not parts:
            parts.append("I'm here and running.")
        _wb_text = " ".join(parts)
        # Dedup guard: if we already gave essentially the same wellbeing response last turn,
        # route to general path so we don't repeat ourselves.
        _prev_aurora = str(getattr(working_memory, 'last_aurora_response', '') or '').strip().lower()
        if _prev_aurora:
            _wb_words = set(re.findall(r'[a-z]{4,}', _wb_text.lower()))
            _prev_words = set(re.findall(r'[a-z]{4,}', _prev_aurora))
            _wb_overlap = len(_wb_words & _prev_words) / max(len(_wb_words), 1)
            if _wb_overlap > 0.65:
                # Same response — fall through to general comprehension path
                intent = 'general'
            else:
                return (_wb_text, "self-aware", 0.9)
        else:
            return (_wb_text, "self-aware", 0.9)

    # ---- FACT ASSERTION ----
    if intent == 'fact_assertion':
        name = _extract_user_name(user_text)
        if name:
            _persist_user_identity_name(name, systems, source_text=user_text)
            _arm_literal_response_preservation(systems)
            
            # If the user also asked Aurora's name in the same breath, don't return early.
            # Let the pipeline process the question so she can answer it.
            if _is_identity_question(user_text) or "?" in user_text:
                pass # Flow down to the pipeline
            else:
                if working_memory and hasattr(working_memory, 'render_speaker_owned_acknowledgement'):
                    rendered = working_memory.render_speaker_owned_acknowledgement(
                        {
                            'kind': 'user_identity',
                            'value': name,
                            'confidence': 0.9,
                        },
                        systems=systems,
                    )
                    return (rendered, "warm", 0.9)
                return (_render_user_name_grounding(systems, name), "warm", 0.9)
        # Store generic fact in working memory AND conversation memory
        speaker_fact = {}
        if working_memory:
            try:
                speaker_fact = dict(working_memory.extract_user_owned_fact_assertion(user_text) or {})
            except Exception:
                speaker_fact = {}
        if working_memory:
            working_memory.note_user_facts(user_text)
            working_memory.note_claims(user_text, source='user')
        if conversation_memory:
            conversation_memory.learn_fact(user_text[:200], source="user_statement", confidence=0.7)
        _arm_literal_response_preservation(systems)
        field = str((speaker_fact or {}).get('field', '') or '').strip()
        value = str((speaker_fact or {}).get('value', '') or '').strip()
        if field and value:
            if working_memory and hasattr(working_memory, 'render_speaker_owned_acknowledgement'):
                rendered = working_memory.render_speaker_owned_acknowledgement(
                    {
                        'kind': 'speaker_fact',
                        'field': field,
                        'value': value,
                        'confidence': 0.9,
                    },
                    systems=systems,
                )
                if rendered:
                    return (rendered, "attentive", 0.9)
            rendered = _render_runtime_intent(
                systems,
                f"{value} is your {field}",
                emotion_tone='attentive',
                relationship_signal='recognition',
                certainty=0.9,
                supporting_concepts=[field, value, 'user'],
                constraints=['speaker_fact'],
            )
            if rendered:
                return (rendered, "attentive", 0.9)
        return (None, None, None)

    # ---- NAME QUESTION ----
    if intent == 'name_question':
        known_name = _get_stored_user_name(conversation_memory, systems)
        if known_name:
            return (_render_user_name_grounding(systems, known_name, recognition=True), "warm", 0.95)
        if _generative_only:
            return (None, None, None)
        return (_render_runtime_intent(
            systems, "who am I talking to",
            emotion_tone='curious', relationship_signal='inquiry', certainty=0.8,
        ), "curious", 0.85)

    # ---- RECALL QUESTION ----
    if intent == 'recall_question':
        _parsed_recall = _qu.parse(user_text)
        _ability_effects = list((pipeline_state or {}).get("active_ability_effects", []) or [])
        continuity_answer = _answer_from_session_readdress_request(
            systems,
            user_text,
            understood=_parsed_recall,
        )
        if continuity_answer:
            return continuity_answer
        t = user_text.lower()
        deep_carryover_answer = _deep_context_carryover_answer(
            systems,
            user_text,
            understood=_parsed_recall,
        )
        if deep_carryover_answer:
            _arm_literal_response_preservation(systems)
            return (deep_carryover_answer, "precise", 0.92)
        if working_memory:
            carryover_answer = _ability_guided_context_answer(
                systems,
                user_text,
                understood=_parsed_recall,
                ability_effects=_ability_effects,
                force=True,
            )
            if carryover_answer:
                return (carryover_answer, "precise", 0.93)
            behavior_answer = working_memory.answer_from_behavior_alignment(
                user_text,
                understood=_parsed_recall,
                systems=systems,
            )
            if behavior_answer:
                _arm_literal_response_preservation(systems)
                return (behavior_answer, "precise", 0.9)
            claim_answer = working_memory.answer_from_claims(user_text, systems=systems)
            if claim_answer:
                _arm_literal_response_preservation(systems)
                return (claim_answer, "precise", 0.9)
        if re.search(r'\bname\b|\bwho\s+(am\s+i|i\s+am)\b', t):
            known_name = _get_stored_user_name(conversation_memory, systems)
            if known_name:
                return (_render_user_name_grounding(systems, known_name, recognition=True), "precise", 0.95)
            if _generative_only:
                return (None, None, None)
            return (_render_runtime_intent(
                systems, "no name yet; who are you",
                emotion_tone='curious', relationship_signal='inquiry', certainty=0.8,
            ), "curious", 0.85)
        # Check working memory for recent facts
        if working_memory and working_memory.stated_facts:
            key_terms = re.findall(r'[a-zA-Z]{4,}', user_text)
            _skip_r = {'remember', 'recall', 'know', 'what', 'when', 'where',
                       'that', 'this', 'have', 'said', 'told', 'about'}
            for term in [k.lower() for k in key_terms if k.lower() not in _skip_r][:3]:
                facts = working_memory.get_stated_fact(term)
                if facts:
                    desc = facts.get('description', '')
                    if desc:
                        rendered = working_memory._render_from_comprehension_intent(
                            systems,
                            core_claim=f"{term} is {desc}",
                            intent_type='statement',
                            emotion_tone='precise',
                            certainty=0.9,
                            supporting_concepts=[term, desc],
                            constraints=['recall'],
                        )
                        _arm_literal_response_preservation(systems)
                        return (
                            rendered or WorkingMemory._data_to_minimal_speech(f"{term} is {desc}", 'precise', ''),
                            "precise",
                            0.9,
                        )
        if conversation_memory:
            key_terms = re.findall(r'[a-zA-Z]{4,}', user_text)
            _skip_r = {'remember', 'recall', 'know', 'what', 'when', 'where',
                       'that', 'this', 'have', 'said', 'told', 'about'}
            for term in [k for k in key_terms if k.lower() not in _skip_r][:3]:
                recalled = conversation_memory.recall_about(term)
                if recalled:
                    rendered = working_memory._render_from_comprehension_intent(
                        systems,
                        core_claim=str(recalled[0]),
                        intent_type='statement',
                        emotion_tone='precise',
                        certainty=0.85,
                        supporting_concepts=[term],
                        constraints=['recall'],
                    ) if working_memory else str(recalled[0])
                    _arm_literal_response_preservation(systems)
                    return (str(rendered or recalled[0]), "precise", 0.85)
        if _generative_only:
            return (None, None, None)
        return (_render_runtime_intent(
            systems, "no memories on this yet",
            emotion_tone='curious', relationship_signal='inquiry', certainty=0.6,
        ), "curious", 0.75)

    # ---- CONTRADICTION / CORRECTION ----
    if intent == 'contradiction':
        # Clear bad search results from working memory so they aren't reused
        if working_memory:
            working_memory.last_search_results = []
            working_memory.last_search_query = ""
            try:
                working_memory.refresh_claim_conflicts(systems=systems, reason='contradiction_check')
            except Exception:
                pass
            conflict_answer = working_memory.answer_from_claims(
                user_text,
                understood=_qu.parse(user_text),
                systems=systems,
            )
            if conflict_answer:
                return (
                    conflict_answer,
                    "attentive", 0.86
                )
        if _generative_only:
            return (None, None, None)
        # Acknowledge and ask for clarification
        return (
            _render_runtime_intent(
                systems,
                "claim target unresolved; meaning target unresolved; revision needs specificity",
                emotion_tone='careful',
                certainty=0.76,
                supporting_concepts=['claim', 'meaning target'],
            ),
            "careful", 0.76
        )

    # ---- SOCIAL REQUEST (say hi, greet someone) ----
    if intent == 'social_request':
        greeting_target = None
        relationship = None
        invalid_targets = WorkingMemory._REPORTING_VERBS

        # First: check if this message ALSO contains an introduction  -- e.g.
        # "my sister Meganne is here as well. say Hi!"
        # The intro pattern fires here so we store the fact AND greet them.
        _intro_m = re.search(
            r'\bmy\s+(sister|brother|friend|colleague|partner|wife|husband|mother|father|'
            r'mom|dad|daughter|son|cousin|aunt|uncle|coworker|boss)\s+([A-Za-z]+)\s+'
            r'(?:is\s+here|is\s+with\s+me|is\s+visiting|is\s+joining)\b',
            user_text, re.IGNORECASE
        )
        if _intro_m:
            relationship = _intro_m.group(1).lower()
            greeting_target = _intro_m.group(2).capitalize()
            # Store it in working memory so future turns remember this person
            if working_memory:
                working_memory.stated_facts[greeting_target.lower()] = {
                    'relationship': relationship,
                    'relationship_to': 'user'
                }
            if conversation_memory:
                known_name = _get_stored_user_name(conversation_memory, systems)
                if known_name:
                    conversation_memory.learn_fact(
                        f"{known_name}'s {relationship} is {greeting_target}",
                        source="introduction", confidence=0.9
                    )

        # If no intro pattern, look for explicit "say hi to NAME" or "hi NAME"
        if not greeting_target:
            m = re.search(
                r'\bto\s+([A-Z][a-z]+)\b|\bhi\s+([A-Z][a-z]+)\b'
                r'|\bhello\s+([A-Z][a-z]+)\b|\bhey\s+([A-Z][a-z]+)\b',
                user_text
            )
            if m:
                greeting_target = next(g for g in m.groups() if g)

        if greeting_target and greeting_target.lower() in invalid_targets:
            greeting_target = None
            relationship = None

        # Fallback: check working memory for a recently introduced person
        if not greeting_target and working_memory:
            for subj, facts in working_memory.stated_facts.items():
                if facts.get('relationship') and subj != 'user':
                    greeting_target = subj.capitalize()
                    relationship = facts.get('relationship')
                    break

        if greeting_target:
            _rendered, _tone, _conf = _render_live_greeting(
                systems,
                conversation_memory=conversation_memory,
                working_memory=working_memory,
                target=greeting_target,
                relationship=relationship or "",
                emotion_hint="warm",
            )
            return (_rendered, "warm", max(0.85, _conf))
        _rendered, _tone, _conf = _render_live_greeting(
            systems,
            conversation_memory=conversation_memory,
            working_memory=working_memory,
            emotion_hint="warm",
        )
        return (_rendered, "warm", max(0.78, _conf))

    # ---- INTRODUCTION (user introducing someone) ----
    if intent == 'introduction':
        import re as _re
        invalid_targets = WorkingMemory._REPORTING_VERBS
        # Extract relationship + name: "my sister Meganne", "this is my friend Bob"
        m = _re.search(
            r'\bmy\s+(sister|brother|friend|colleague|partner|wife|husband|mother|father|'
            r'mom|dad|daughter|son|cousin|aunt|uncle|coworker|boss)\s+([A-Za-z]+)\s+'
            r'(?:is\s+here|is\s+with\s+me|is\s+visiting|is\s+joining)\b',
            user_text, _re.IGNORECASE
        )
        if not m:
            m = _re.search(r'\bthis\s+is\s+(?:my\s+\w+\s+)?([A-Z][a-z]+)\b', user_text)
            if not m:
                m = _re.search(r'\bmeet\s+([A-Z][a-z]+)\b', user_text)
        if m:
            if len(m.groups()) == 2:
                relationship = m.group(1).lower()
                name = m.group(2).capitalize()
            else:
                relationship = "guest"
                name = m.group(1).capitalize()
            if name.lower() in invalid_targets:
                return (None, None, None)
            # Store in working memory
            if working_memory:
                working_memory.stated_facts[name.lower()] = {
                    'relationship': relationship,
                    'relationship_to': 'user'
                }
            if conversation_memory:
                known_name = _get_stored_user_name(conversation_memory, systems)
                if known_name:
                    conversation_memory.learn_fact(
                        f"{known_name}'s {relationship} is {name}",
                        source="introduction", confidence=0.9
                    )
            known_name = _get_stored_user_name(conversation_memory, systems)
            _rendered, _tone, _conf = _render_live_greeting(
                systems,
                conversation_memory=conversation_memory,
                working_memory=working_memory,
                target=name,
                relationship=relationship or "guest",
                emotion_hint="warm",
            )
            return (_rendered, "warm", max(0.85, _conf))
        _rendered, _tone, _conf = _render_live_greeting(
            systems,
            conversation_memory=conversation_memory,
            working_memory=working_memory,
            emotion_hint="warm",
        )
        return (_rendered, "warm", max(0.78, _conf))

    # ---- FOLLOW-UP / CORRECTION ----
    if intent == 'followup_request':
        # Check for abstract NC word questions first — same routing as 'general' intent.
        # "what does purpose cost you" is classified as followup_request but should
        # generate a constraint-geometry response, not a search-driven OETS definition.
        _fup_tw = list((_parsed_intent or {}).get('topic_words', []) or [])
        _fup_tw_low = [str(w).lower().strip() for w in _fup_tw[:2] if str(w).strip()]
        _fup_dom = _dominant_axis
        if (
            _fup_dom in ("A", "X", "B", "T", "N") and
            _fup_tw_low and
            any(w in {
                "boundary", "boundaries", "meaning", "meanings", "purpose", "purposes",
                "belief", "beliefs", "knowledge", "knowing", "understand", "understanding",
                "feeling", "feelings", "time", "temporal", "existence", "exist",
                "energy", "agency", "information", "cost", "costs", "difference",
                "truth", "reality", "experience", "concept", "concepts",
                "follow", "follows", "sequence", "continuation", "persistence",
                "structure", "constraint", "framing", "separation", "distinction",
                "present", "presence", "signal", "signals", "grounding", "awareness",
            } for w in _fup_tw_low)
        ):
            _fup_topic = str((_parsed_intent or {}).get('topic', '') or _fup_tw_low[0])
            _fup_frames = {
                "B": f"{_fup_topic}; boundary; separation; framing law",
                "N": f"{_fup_topic}; cost; energy; sustain",
                "T": f"{_fup_topic}; persistence; transition; sequence",
                "X": f"{_fup_topic}; existence; present; admissible",
                "A": f"{_fup_topic}; agency; ownership; enact",
            }
            _fup_intent = _fup_frames.get(_fup_dom, f"{_fup_topic}; constraint geometry")
            if pipeline_state is not None:
                pipeline_state["dominant_axis"] = _fup_dom
                pipeline_state["axis_activation"] = _axis_activation
            _fup_resp = _render_runtime_intent(
                systems,
                _fup_intent,
                emotion_tone="reflective",
                certainty=0.80,
                supporting_concepts=_fup_tw_low,
            )
            if _fup_resp:
                return (str(_fup_resp).strip(), "reflective", 0.80)
        continuity_answer = _answer_from_session_readdress_request(
            systems,
            user_text,
            understood=_qu.parse(user_text),
        )
        if continuity_answer:
            return continuity_answer
        if working_memory:
            behavior_answer = working_memory.answer_from_behavior_alignment(
                user_text,
                understood=_qu.parse(user_text),
                systems=systems,
            )
            if behavior_answer:
                return (behavior_answer, "informative", 0.9)
            claim_answer = working_memory.answer_from_claims(user_text, systems=systems)
            if claim_answer:
                return (claim_answer, "informative", 0.88)
            claim_resolution = getattr(working_memory, 'last_claim_resolution', {}) or {}
            focus_claim = dict(claim_resolution.get('focus_claim', {}) or {})
            focus_summary = working_memory._claim_to_text(focus_claim) if focus_claim else ""
        else:
            focus_summary = ""
        # First: check working memory  -- do we have last search results we can reason from?
        if working_memory and working_memory.last_search_results:
            answer = _reasoner.reason(
                user_text, working_memory.last_question_understood,
                working_memory, oets, working_memory.last_search_results,
                systems=systems,
            )
            if answer:
                return (answer, "informative", 0.88)

        # Extract embedded query and re-search
        m = re.search(
            r'\b(?:asked|was\s+asking|said|mentioned)\s+(?:about\s+)?(.+)',
            user_text, re.IGNORECASE
        )
        embedded = (m.group(1).strip() if m else user_text).rstrip('.,!?')

        # Also try using current working memory topic + entities from this message
        if working_memory and not embedded:
            understood_followup = _qu.parse(user_text)
            entities = understood_followup.get('entities', [])
            if entities and working_memory.current_topic:
                embedded = f"{working_memory.current_topic} {' '.join(entities[:2])}"

        if explicit_lookup_requested and embedded:
            try:
                ev = _poedex_lookup_evidence(
                    embedded,
                    systems,
                    request_text=search_prompt_text,
                    timeout=12.0,
                    use_researcher=True,
                    pipeline_state=pipeline_state if isinstance(pipeline_state, dict) else None,
                )
                if ev:
                    if working_memory:
                        working_memory.last_search_results = ev
                        working_memory.last_search_query = embedded
                    answer = _reasoner.reason(
                        embedded, _qu.parse(embedded), working_memory, oets, ev,
                        systems=systems,
                    )
                    if answer:
                        return (answer, "informative", 0.85)
            except Exception:
                pass
        if focus_summary:
            return (None, None, None)
        return (None, None, None)

        # ---- STATEMENT ----
    if intent == 'statement':
        understood_statement = _qu.parse(user_text)
        speaker_owned = {}
        if working_memory and hasattr(working_memory, 'integrate_speaker_owned_utterance'):
            speaker_owned = working_memory.integrate_speaker_owned_utterance(
                user_text,
                understood_statement,
            )
        if speaker_owned.get('handled') and working_memory:
            if speaker_owned.get('kind') == 'user_identity':
                _persist_user_identity_name(
                    str(speaker_owned.get('value', '') or ''),
                    systems,
                    source_text=user_text,
                )
            
            # If the user also asked Aurora's name in the same breath, don't return early.
            if _is_identity_question(user_text) or "?" in user_text:
                pass # Flow down to the pipeline
            else:
                _arm_literal_response_preservation(systems)
                rendered = working_memory.render_speaker_owned_acknowledgement(
                    speaker_owned,
                    systems=systems,
                )
                if rendered:
                    return (
                        rendered,
                        "careful" if speaker_owned.get('kind') == 'behavior_alignment' else "attentive",
                        float(speaker_owned.get('confidence', 0.88) or 0.88),
                    )
        captured_claims = []
        concept_clarification = {}
        semantic_frames = []
        if working_memory:
            working_memory.note_user_facts(user_text, understood=understood_statement)
            concept_clarification = working_memory.note_concept_clarification(
                user_text,
                source='user',
                understood=understood_statement,
            )
            semantic_frames = working_memory.note_semantic_principles(
                user_text,
                source='user',
                understood=understood_statement,
            )
            captured_claims = working_memory.note_claims(
                user_text,
                source='user',
                understood=understood_statement,
            )
        role_claim = _extract_role_assertion(user_text)
        if role_claim and conversation_memory:
            subj = role_claim.get("subject", "").strip()
            rel = role_claim.get("relation", "").replace("coauthor", "co-author")
            neg = bool(role_claim.get("negated", False))
            if subj and rel:
                relation_phrase = f"is not {rel}" if neg else f"is {rel}"
                conversation_memory.add_relationship_note(
                    subj.lower(), f"{subj} {relation_phrase} (asserted in conversation)"
                )
                conversation_memory.learn_fact(
                    f"{subj} {relation_phrase}",
                    source="role_assertion",
                    confidence=0.85 if neg else 0.8,
                )
                conversation_memory.instantiate_lineage_trace(
                    anchor=subj.lower(),
                    claim=user_text[:300],
                    role_edges=[{
                        "subject": subj,
                        "relation": rel,
                        "object": "aurora",
                        "negated": neg,
                    }],
                    pressure_snapshot=_capture_pressure_snapshot(systems),
                    source="role_assertion",
                    confidence=0.85 if neg else 0.8,
                    tick=int(time.time()),
                )
        if concept_clarification:
            term = str(concept_clarification.get('term', '') or '').strip()
            meaning = str(concept_clarification.get('meaning', '') or '').strip()
            if conversation_memory and term and meaning:
                try:
                    conversation_memory.learn_fact(
                        f"{term} means {meaning}",
                        source='meaning_clarification',
                        confidence=0.9,
                    )
                except Exception:
                    pass
            return (
                _render_runtime_intent(
                    systems,
                    f"{term} means {meaning} in the active thread now",
                    emotion_tone='precise',
                    certainty=0.88,
                    supporting_concepts=[term, meaning],
                ),
                "attentive",
                0.88,
            )
        if captured_claims and working_memory:
            summary = working_memory._claim_to_text(captured_claims[0])
            return (
                working_memory.compose_claim_acknowledgement(
                    summary,
                    systems=systems,
                    claim=captured_claims[0],
                ),
                "attentive",
                0.84,
            )
        if semantic_frames and working_memory:
            return (
                working_memory.compose_semantic_frame_acknowledgement(
                    semantic_frames[0],
                    systems=systems,
                ),
                "attentive",
                max(0.82, float(semantic_frames[0].get('confidence', 0.0) or 0.0)),
            )
        if working_memory and understood_statement.get('is_clarification'):
            anchor = str(understood_statement.get('topic', '') or '').strip()
            clarification_skip = set(_GROUNDING_FALLBACK_SKIP) | {
                'keep', 'keeps', 'keeping', 'actually', 'tie', 'tied', 'tell', 'tells', 'mean', 'means', 'meant'
            }
            if anchor.lower() in clarification_skip:
                anchor = ''
            if not anchor:
                for term in list(understood_statement.get('topic_words', []) or []) + list(understood_statement.get('entities', []) or []):
                    label = str(term or '').strip()
                    if label and label.lower() not in clarification_skip:
                        anchor = label
                        break
            if anchor:
                try:
                    working_memory.update_topic(anchor)
                    working_memory._register_mention(anchor, 'topic', 'user', 0.9)
                except Exception:
                    pass
                return (None, None, None)
        return (None, None, None)

    # ---- GENERAL QUESTION - full comprehension pipeline ----
    if intent == 'general':
        # user_text may be prefixed with "[Conversation so far:...]\n\n{actual question}"
        # to give _build_comprehension_response conversation context. Strip that prefix
        # before re-parsing so UtteranceParser classifies the actual question, not the
        # full transcript (which produces spurious 'challenging' / 'clarification' frames).
        _ctx_strip_marker = ']\n\n'
        _ctx_strip_pos = user_text.find(_ctx_strip_marker)
        _parse_text = (
            user_text[_ctx_strip_pos + len(_ctx_strip_marker):].strip()
            if _ctx_strip_pos >= 0 else user_text
        ) or user_text
        understood = dict(_precomputed_parsed) if _precomputed_parsed else _qu.parse(_parse_text)
        # Inject active ability effect_tags from pipeline_state into understood so
        # ReasoningEngine's Step 3.5 ability-guided OETS strategies can fire.
        # Without this, the thinking patterns are set before the downward chain starts
        # but never reach the understood dict that _build_comprehension_response uses.
        if isinstance(pipeline_state, dict):
            _ab_fx_inject = list(pipeline_state.get("active_ability_effects", []) or [])
            if _ab_fx_inject:
                understood["_active_ability_effects"] = _ab_fx_inject
        if working_memory:
            try:
                referent_resolution = working_memory.resolve_referents(user_text, understood)
            except Exception:
                referent_resolution = referent_resolution or {}
            try:
                claim_resolution = working_memory.resolve_claims(user_text, understood)
            except Exception:
                claim_resolution = claim_resolution or {}
            resolved_topic = str(referent_resolution.get('topic', '') or '')
            if resolved_topic and (not understood.get('topic') or understood.get('topic') in working_memory._VAGUE_REFERENTS):
                understood['topic'] = resolved_topic
                merged_words = list(dict.fromkeys(resolved_topic.split() + list(understood.get('topic_words', []))))
                understood['topic_words'] = merged_words[:6]
            if referent_resolution.get('entities'):
                merged_entities = list(dict.fromkeys(list(understood.get('entities', [])) + list(referent_resolution['entities'])))
                understood['entities'] = merged_entities[:4]
            if referent_resolution.get('search_query'):
                understood['search_query'] = referent_resolution['search_query']
            focus_claim = dict(claim_resolution.get('focus_claim', {}) or {})
            focus_summary = working_memory._claim_to_text(focus_claim) if focus_claim else ''
        else:
            focus_summary = ''

        topic = understood.get('topic', '')
        topic_words = understood.get('topic_words', [])
        query_type = understood.get('query_type', '')
        entities = understood.get('entities', [])
        resolved_query = understood.get('search_query') or _parse_text
        if _is_weak_response_topic(topic):
            topic = ""
            for _topic_cand in list(topic_words or []):
                _topic_cand_s = str(_topic_cand or "").strip()
                if _topic_cand_s and not _is_weak_response_topic(_topic_cand_s):
                    topic = _topic_cand_s
                    break
            understood["topic"] = topic
            if topic:
                understood["search_query"] = topic
                resolved_query = topic
        # t_low should reflect the actual question, not the full context-prefixed transcript
        t_low = _parse_text.lower().strip()
        if _is_understanding_challenge(_parse_text):
            if isinstance(pipeline_state, dict):
                pipeline_state["understanding_challenge"] = True
            return (None, None, None)
        _prefer_live_perspective_q = _should_prefer_live_perspective(
            _parse_text,
            understood=understood,
            systems=systems,
        )
        inline_lookup = dict(systems.get("_inline_vocab_lookup") or {})
        inline_targets = _extract_inline_lookup_targets(user_text)
        if (
            inline_targets and
            (not _prefer_live_perspective_q) and
            str(inline_lookup.get("source_text", "") or "").strip().lower() == str(user_text or "").strip().lower()
        ):
            applied_items = list(inline_lookup.get("applied") or [])
            for target in inline_targets:
                match = next(
                    (
                        item for item in applied_items
                        if str(item.get("word", "") or "").strip().lower() == str(target or "").strip().lower()
                    ),
                    None,
                )
                definition = str((match or {}).get("definition", "") or "").strip()
                if definition:
                    grounded_definition = _compose_grounded_prefetch_response(target, definition)
                    rendered_definition = _render_runtime_intent(
                        systems,
                        (grounded_definition or f"{target} means {definition}").rstrip("."),
                        emotion_tone='attentive',
                        certainty=0.86,
                        supporting_concepts=[target, definition],
                        constraints=['meaning', 'vocabulary'],
                    )
                    return (
                        str(rendered_definition or grounded_definition or f"{target} means {definition}.").strip(),
                        "attentive",
                        0.86,
                    )
        callback_like = False
        # Proactively update working_memory.current_topic to the NEW topic before
        # any synthesis pipeline runs. Without this, the L5-L8 layers see the
        # PREVIOUS turn's topic and generate responses about it even when the user
        # has moved to a completely different subject (meaning_momentum lock).
        # Guard: only update if topic is non-empty and not a vague referent.
        _VAGUE = getattr(working_memory, '_VAGUE_REFERENTS', {'it','this','that','these','those','they','them'}) if working_memory else set()
        if working_memory and topic and topic not in _VAGUE and not understood.get('is_clarification') and not understood.get('is_callback'):
            try:
                working_memory.update_topic(topic)
            except Exception:
                pass
        deep_carryover_answer = _deep_context_carryover_answer(
            systems,
            user_text,
            understood=understood,
        )
        if deep_carryover_answer and any(
            marker in t_low for marker in (
                'remember',
                'recall',
                'what did i say',
                'what was my',
                'what is my',
                "what's my",
            )
        ):
            _arm_literal_response_preservation(systems)
            return (deep_carryover_answer, "precise", 0.9)
        # ── EARLY NATIVE AXIS ROUTING ──────────────────────────────────────────
        # For questions whose topic words are abstract NC concepts (boundary,
        # purpose, understanding, etc.) with a dominant semantic axis, bypass
        # working-memory answer_from_meanings so stale WM content (previous user
        # input or OETS definitions) cannot intercept.  Generates a constraint-
        # geometry response directly via _render_runtime_intent.
        # Runs BEFORE the working_memory block to prevent early interception.
        _ABSTRACT_NC_EARLY = {
            "boundary", "boundaries", "meaning", "meanings", "purpose", "purposes",
            "belief", "beliefs", "knowledge", "knowing", "understand", "understanding",
            "feeling", "feelings", "time", "temporal", "existence", "exist",
            "energy", "agency", "information", "cost", "costs", "difference",
            "truth", "reality", "experience", "concept", "concepts",
            "follow", "follows", "sequence", "continuation", "persistence",
            "structure", "constraint", "framing", "separation", "distinction",
            "present", "presence", "signal", "signals", "grounding", "awareness",
        }
        _tw_early = [str(w).lower().strip() for w in list(topic_words or [])[:2] if str(w).strip()]
        if (
            _dominant_axis in ("A", "X", "B", "T", "N") and
            _tw_early and
            any(w in _ABSTRACT_NC_EARLY for w in _tw_early)
        ):
            _is_ack = query_type in ('statement', 'clarification') and _dominant_axis == "A"
            _axis_frames = {
                "B": f"{topic or _tw_early[0]}; boundary; separation; framing law",
                "N": f"{topic or _tw_early[0]}; cost; energy; sustain",
                "T": f"{topic or _tw_early[0]}; persistence; transition; sequence",
                "X": f"{topic or _tw_early[0]}; existence; present; admissible",
                "A": (
                    "understanding; landed; thread continues"
                    if _is_ack else
                    f"{topic or _tw_early[0]}; agency; ownership; enact"
                ),
            }
            _native_intent = _axis_frames.get(
                _dominant_axis,
                f"{topic or (_tw_early[0] if _tw_early else 'this')}; constraint geometry",
            )
            if pipeline_state is not None:
                pipeline_state["dominant_axis"] = _dominant_axis
                pipeline_state["axis_activation"] = _axis_activation
            _native_resp = _render_runtime_intent(
                systems,
                _native_intent,
                emotion_tone="reflective",
                certainty=0.80,
                supporting_concepts=_tw_early,
            )
            if _native_resp:
                return (str(_native_resp).strip(), "reflective", 0.80)
            return (None, None, None)
        if working_memory and not _is_understanding_challenge(_parse_text):
            _ab_fx_active = list((understood or {}).get("_active_ability_effects", []) or [])
            _runtime_flags = dict((pipeline_state or {}).get("ability_runtime_flags", {}) or {})
            _force_carryover = any(
                marker in t_low for marker in (
                    'remember',
                    'recall',
                    'what did i say',
                    'what was my',
                    'what is my',
                    "what's my",
                )
            )
            if _runtime_flags.get("force_continuity_recall") and (
                bool(understood.get('is_callback')) or
                bool(understood.get('is_clarification'))
            ):
                _force_carryover = True
            carryover_answer = _ability_guided_context_answer(
                systems,
                user_text,
                understood=understood,
                ability_effects=_ab_fx_active,
                force=_force_carryover,
            )
            if carryover_answer:
                return (carryover_answer, "precise", 0.9)
            meaning_answer = working_memory.answer_from_meanings(user_text, understood, systems=systems)
            semantic_frame_answer = working_memory.answer_from_semantic_frames(
                user_text,
                understood,
                systems=systems,
            )
            if meaning_answer and _prefer_live_perspective_q and not _run_question_alignment_audit(
                systems,
                user_text,
                meaning_answer,
                understood=understood,
            ).get("aligned"):
                meaning_answer = ""
            if semantic_frame_answer and _prefer_live_perspective_q and not _run_question_alignment_audit(
                systems,
                user_text,
                semantic_frame_answer,
                understood=understood,
            ).get("aligned"):
                semantic_frame_answer = ""
            callback_like = bool(
                understood.get('is_callback') or understood.get('is_clarification')
            )
            if not callback_like:
                callback_like = any(
                    marker in t_low for marker in working_memory._REFERENT_CALLBACK_MARKERS
                )
            if not callback_like and _looks_like_question(user_text):
                words = set(re.findall(r"[a-z']+", t_low))
                callback_like = bool(words & working_memory._VAGUE_REFERENTS)
            if callback_like:
                if meaning_answer:
                    return (meaning_answer, "precise", 0.9)
                if semantic_frame_answer:
                    return (semantic_frame_answer, "reflective", 0.88)
                claim_answer = working_memory.answer_from_claims(user_text, understood, systems=systems)
                claim_resolution = getattr(working_memory, 'last_claim_resolution', {}) or {}
                if (
                    claim_answer and
                    float(claim_resolution.get('confidence', 0.0) or 0.0) >= 0.75
                ):
                    return (claim_answer, "precise", 0.9)
            # Meaning/semantic-frame answers: only return if the user's new
            # question is actually about the stored topic. Without this gate,
            # meaning_momentum carries the previous topic into every subsequent
            # response regardless of what the user asked.
            _stored_term = str(working_memory.last_concept_anchor or working_memory.current_topic or '').lower()
            _new_topic = str(topic or '').lower()
            _topic_related = (
                callback_like or
                not _stored_term or
                not _new_topic or
                _stored_term == _new_topic or
                _new_topic in _stored_term or
                _stored_term in _new_topic or
                any(_new_topic in str(tw).lower() for tw in topic_words[:3])
            )
            if meaning_answer and _topic_related:
                return (meaning_answer, "precise", 0.88)
            if semantic_frame_answer and _topic_related:
                return (semantic_frame_answer, "reflective", 0.86)
            broad_claim_answer = working_memory.answer_from_claims(user_text, understood, systems=systems)
            if broad_claim_answer and _prefer_live_perspective_q and not _run_question_alignment_audit(
                systems,
                user_text,
                broad_claim_answer,
                understood=understood,
            ).get("aligned"):
                broad_claim_answer = ""
            claim_resolution = getattr(working_memory, 'last_claim_resolution', {}) or {}
            focus_claim = dict(claim_resolution.get('focus_claim', {}) or {})
            focus_terms = working_memory._claim_terms(focus_claim) if focus_claim else set()
            query_terms = {
                str(term).lower()
                for term in (
                    list(understood.get('topic_words', []) or []) +
                    list(understood.get('entities', []) or []) +
                    [str(understood.get('topic', '') or '')]
                )
                if len(str(term or '')) >= 3
            }
            claim_overlap = len(focus_terms & query_terms)
            if (
                broad_claim_answer and
                (
                    (
                        float(claim_resolution.get('confidence', 0.0) or 0.0) >= 0.75 and
                        (claim_overlap > 0 or callback_like)
                    ) or
                    any(
                        cue in t_low for cue in (
                            'conflict', 'contradict',
                            'remember', 'uncertain', 'what object', 'what item',
                            'where', 'check first', 'look first',
                        )
                    )
                )
            ):
                return (broad_claim_answer, "precise", 0.88)

        # ---- AXIS-DOMINANT ROUTING (constraint-physics gate) ----------------
        # A-dominant utterances are directed at Aurora's inner agency/alignment.
        # These have no surface/factual answer — the response must emerge from
        # the global constraint field state (IVM phases, outlet_fraction, etc).
        # Route them directly to L5 rather than through any search or OETS lookup.
        if (
            _dominant_axis == "A" and
            _axis_activation.get("A", 0.0) > 0.36 and
            _looks_like_inner_state_query(user_text, understood)
        ):
            # Feed the current axis state into pipeline for L5 to use as context
            if pipeline_state is not None:
                pipeline_state["dominant_axis"] = "A"
                pipeline_state["axis_activation"] = _axis_activation
            return (None, None, None)

        # ---- STATEMENT GATE ----
        # If UtteranceParser says this is a statement (no ?, no question word,
        # no embedded question structure), do NOT search and do NOT try to
        # return a factual answer. Fall through to L5 for organic response.
        if query_type == 'statement':
            # Exception: if working memory or OETS has something directly relevant,
            # surface it — but only if the statement implies a question (e.g. recalling)
            # Otherwise just fall through.
            return (None, None, None)

        # ---- FRAME ROUTING from UtteranceParser ----
        _frame = understood.get('frame', '')

        # Opinion solicitation — "what's your take / do you think / do you believe"
        # These ask for Aurora's perspective, not a factual answer. Fall to L5 + grounding fallback
        # which now routes through reasoning instead of reporting a knowledge gap.
        if understood.get('is_opinion') or query_type in ('opinion',):
            return (None, None, None)

        # Experience frame — Aurora's subjective experience. Fall to L5.
        if understood.get('is_experiential') or query_type == 'experience':
            return (None, None, None)

        # Hypothetical — engage with the idea, don't search
        if understood.get('is_hypothetical') or query_type == 'hypothetical':
            if working_memory or oets:
                hypothetical_answer = _reasoner.reason(user_text, understood, working_memory, oets, systems=systems)
                if hypothetical_answer:
                    return (hypothetical_answer, "reflective", 0.9)
            if _generative_only:
                return (None, None, None)
            if focus_summary:
                return (
                    _render_runtime_intent(
                        systems,
                        f"change exploration around {focus_summary}; desired outcome",
                        emotion_tone='curious',
                        relationship_signal='inquiry',
                        certainty=0.88,
                        supporting_concepts=[focus_summary],
                    ),
                    "curious",
                    0.88,
                )
            return (
                _render_runtime_intent(
                    systems,
                    "possible change; desired outcome",
                    emotion_tone='curious',
                    relationship_signal='inquiry',
                    certainty=0.85,
                ),
                "curious",
                0.85,
            )

        # Clarification — user is re-stating, don't search
        # Guard: personal-perspective questions ("what does X mean to you?", "personally")
        # are mis-tagged as clarification by the parser because of "mean". Skip the
        # clarification path for them so they fall through to organic L5 response.
        _pers_persp_markers = ('to you', 'for you', 'personally', 'in your view',
                               'your opinion', 'your take', 'your perspective',
                               'do you think', 'how do you think', 'do you feel', 'do you believe')
        _is_pers_q = any(m in t_low for m in _pers_persp_markers)
        if (understood.get('is_clarification') or query_type == 'clarification') and not _is_pers_q:
            explicit_anchor = str(understood.get('topic', '') or '').strip()
            clarification_skip = set(_GROUNDING_FALLBACK_SKIP) | {
                'keep', 'keeps', 'keeping', 'actually', 'tie', 'tied', 'tells', 'tell',
                'mean', 'means', 'meant', 'break', 'breaks',
            }
            if working_memory:
                meaning_answer = working_memory.answer_from_meanings(user_text, understood, systems=systems)
                if meaning_answer:
                    return (
                        meaning_answer,
                        "curious",
                        0.86,
                    )
            if _generative_only:
                return (None, None, None)
            if (
                explicit_anchor and
                explicit_anchor.lower() not in clarification_skip and
                explicit_anchor.lower() not in getattr(working_memory, '_VAGUE_REFERENTS', set()) and
                'what do you think i mean by' in t_low
            ):
                return (
                    _render_runtime_intent(
                        systems,
                        f"{explicit_anchor}; meaning anchor check",
                        emotion_tone='curious',
                        relationship_signal='inquiry',
                        certainty=0.84,
                        supporting_concepts=[explicit_anchor],
                    ),
                    "curious",
                    0.84,
                )
            if focus_summary:
                return (
                    _render_runtime_intent(
                        systems,
                        f"{focus_summary}; meaning anchor correction",
                        emotion_tone='attentive',
                        relationship_signal='inquiry',
                        certainty=0.9,
                        supporting_concepts=[focus_summary],
                    ),
                    "attentive",
                    0.9,
                )
            return (
                _render_runtime_intent(
                    systems,
                    "pointing target missed; core meaning needs re-anchor",
                    emotion_tone='attentive',
                    relationship_signal='inquiry',
                    certainty=0.88,
                ),
                "attentive",
                0.88,
            )

        # Challenging frame — "yeah but X"
        if _frame == 'challenging':
            if _generative_only:
                return (None, None, None)
            if focus_summary:
                return (
                    _render_runtime_intent(
                        systems,
                        f"{focus_summary}; correction target",
                        emotion_tone='attentive',
                        relationship_signal='inquiry',
                        certainty=0.92,
                        supporting_concepts=[focus_summary],
                    ),
                    "attentive",
                    0.92,
                )
            return (
                _render_runtime_intent(
                    systems,
                    "missed point; error location",
                    emotion_tone='attentive',
                    relationship_signal='inquiry',
                    certainty=0.9,
                ),
                "attentive",
                0.9,
            )

        # Relational-causal follow-up bridge:
        # "why does that matter?" should connect to active thread, not produce random drift.
        if working_memory and (
            "why does that matter" in t_low or
            "why is that important" in t_low or
            "why does this matter" in t_low
        ):
            active_topic = working_memory.current_topic or understood.get('topic', '')
            if active_topic and str(active_topic).strip().lower() not in {'matter'}:
                return (
                    _render_runtime_intent(
                        systems,
                        (
                            f"{active_topic} matters because it gives us a stable reference point; "
                            "when reasoning stays anchored to one thread, answers stay coherent instead of fragmenting across turns"
                        ),
                        emotion_tone='reflective',
                        certainty=0.9,
                        supporting_concepts=[active_topic],
                    ),
                    "reflective",
                    0.9,
                )

        # Resolve vague topics using working memory ("what about in Ohio?" → "weather Ohio")
        if working_memory:
            resolved_topic = working_memory.resolve_topic(understood)
            if resolved_topic and resolved_topic != topic:
                understood['topic'] = resolved_topic
                topic = resolved_topic
                if entities:
                    understood['search_query'] = (
                        f"{' '.join(entities[:2])} {resolved_topic}"
                    )
                else:
                    understood['search_query'] = resolved_topic

        # Detect personal perspective questions once — used by Steps 2 and 3.
        # ("to you", "in your view", etc.) — skip search/OETS for those.
        _text_low_oets = user_text.lower()
        _is_personal_perspective_q = any(p in _text_low_oets for p in (
            'to you', 'for you', 'in your view', 'in your opinion',
            'from your perspective', 'what do you think', 'how do you think', 'what do you feel',
            'how do you see', 'how do you feel about', 'your take',
            'your perspective', 'your opinion', 'do you think', 'do you believe',
        ))

        # Step 1: Try to reason from working memory + OETS before searching
        if working_memory or oets:
            answer = _reasoner.reason(resolved_query, understood, working_memory, oets, systems=systems)
            if answer:
                return (answer, "precise", 0.88)

        # Step 2: Search — ONLY for actual questions (not statements)
        # query_type is already gated above — we only reach here for questions
        # Skip search for questions directed at Aurora's own experience/state,
        # or for personal perspective questions ("to you", "what do you think", etc.)
        # Also respect auto_search_enabled=False (e.g. GPT learning sessions)
        if explicit_lookup_requested and (topic or entities) and not _is_aurora_self_question(user_text) and not _is_personal_perspective_q:
            try:
                ev = _poedex_lookup_evidence(
                    resolved_query,
                    systems,
                    request_text=search_prompt_text,
                    timeout=12.0,
                    use_researcher=True,
                    pipeline_state=pipeline_state if isinstance(pipeline_state, dict) else None,
                )
                if ev:
                    if working_memory:
                        working_memory.last_search_results = ev
                        working_memory.last_search_query = resolved_query
                    answer = _reasoner.reason(resolved_query, understood, working_memory, oets, ev, systems=systems)
                    if answer:
                        return (answer, "informative", 0.85)
            except Exception:
                pass

        # Step 3: OETS lookup — only for genuine knowledge questions
        # Skip OETS when the question is asking for Aurora's personal perspective.
        _is_knowledge_q = (
            not _is_personal_perspective_q and (
                user_text.strip().endswith('?') or
                any(user_text.lower().strip().startswith(w) for w in (
                    'what', 'how', 'why', 'where', 'who', 'when', 'which',
                    'define', 'explain', 'tell me', 'look up',
                ))
            )
        )
        if oets and _is_knowledge_q:
            _dps = getattr(systems.get('dimensional'), 'dps', None)
            for tw in topic_words[:3]:
                node = oets.web.get_node(tw)
                if node and node.definitions:
                    best = node.definitions[0].get('text', '')
                    # Skip disambiguation pages (e.g. "Boundary or Boundaries may refer to:")
                    # and raw OETS dump entries that don't constitute a real answer.
                    _best_low = best.lower()
                    if 'may refer to' in _best_low or best.strip().endswith(':'):
                        continue
                    if len(best) > 15:
                        # Calibrate text and confidence to crystal depth
                        _crystal_text = f"{tw.capitalize()}: {best}"
                        _crystal_conf = 0.82
                        if _dps:
                            _crystal = _dps.get_crystal(tw)
                            if _crystal:
                                try:
                                    from aurora_dimensional_systems import CrystalLevel
                                    if _crystal.level == CrystalLevel.BASE:
                                        _crystal_text = (
                                            f"understanding; building; {tw}; {best}"
                                        )
                                        _crystal_conf = 0.60
                                    elif _crystal.level == CrystalLevel.COMPOSITE:
                                        _crystal_conf = 0.72
                                    elif _crystal.level == CrystalLevel.QUASI:
                                        _crystal_conf = 0.95
                                except Exception:
                                    pass
                        return (_crystal_text, "precise", _crystal_conf)

    # ---- No comprehension match  -- fall through to template engine ----
    return (None, None, None)


def _should_use_search_for_question(text: str) -> bool:
    """
    Conservative lookup policy:
      - only runs on QUESTIONS
      - never runs for Aurora-self questions
      - only runs for explicit lookup requests ("look up", "search", "find online")
      - otherwise defaults to internal reasoning and gap detection first
    """
    t = (text or "").lower()

    if not _looks_like_question(text):
        return False

    if _is_aurora_self_question(text):
        return False

    explicit_lookup_markers = (
        "look up", "search", "find online", "check online", "web search",
        "google", "wikipedia", "browse",
    )
    if any(m in t for m in explicit_lookup_markers):
        return True

    return False

def _extract_factual_answer(user_text: str, evidence_list: list) -> str:
    """
    Pick the most relevant sentence from search evidence snippets to use as
    Aurora's factual (resp_A) answer.  Returns empty string if nothing usable.
    """
    import re

    if not evidence_list:
        return ""

    # Keywords from the question (nouns / content words, 3+ chars, no stopwords)
    _stop = {
        'the', 'a', 'an', 'is', 'are', 'was', 'were', 'be', 'been', 'being',
        'do', 'does', 'did', 'what', 'how', 'why', 'where', 'who', 'when',
        'this', 'that', 'these', 'those', 'it', 'its', 'in', 'on', 'at',
        'of', 'to', 'for', 'and', 'or', 'but', 'not', 'with', 'by', 'can',
        'will', 'would', 'could', 'should', 'have', 'has', 'had', 'any',
        'some', 'just', 'your', 'you', 'mean', 'tell', 'know', 'give',
        'color', 'colour',  # keep topic words like color when relevant
    }
    q_words = set()
    for raw in re.findall(r'[a-z]{3,}', user_text.lower()):
        if raw not in _stop:
            q_words.add(raw)

    best_sentence = ""
    best_score = -1

    for ev in evidence_list[:6]:
        snippet = ev.get("snippet", "")
        if not snippet:
            continue

        # Split snippet into sentences
        sentences = re.split(r'(?<=[.!?])\s+', snippet)
        for sent in sentences:
            sent_clean = sent.strip()
            if len(sent_clean) < 8 or len(sent_clean) > 400:
                continue
            sent_lower = sent_clean.lower()
            # Score by overlap with question keywords
            score = sum(1 for w in q_words if w in sent_lower)
            # Prefer sentences that start with the subject (definition-like)
            if any(sent_lower.startswith(w) for w in q_words):
                score += 2
            # Prefer shorter, crisper sentences
            word_count = len(sent_clean.split())
            if word_count <= 20:
                score += 1
            if score > best_score:
                best_score = score
                best_sentence = sent_clean

    # Only return if we found something reasonably relevant
    if best_score >= 1 and best_sentence:
        return best_sentence
    # Fall back to first snippet sentence if no keyword match
    for ev in evidence_list[:3]:
        snippet = ev.get("snippet", "")
        if snippet:
            first = re.split(r'(?<=[.!?])\s+', snippet.strip())[0].strip()
            if 20 <= len(first) <= 400:
                return first
    return ""


def _format_evidence_for_injection(evidence_list):
    """
    Convert evidence dicts into a compact evidence bundle string.
    """
    if not evidence_list:
        return ""

    lines = ["[SEARCH_EVIDENCE_BEGIN]"]
    for i, ev in enumerate(evidence_list[:6], 1):
        title = ev.get("title", "untitled")
        url = ev.get("url", "")
        snippet = ev.get("snippet", "")
        lines.append(f"({i}) {title}")
        if url:
            lines.append(f"    url: {url}")
        if snippet:
            lines.append(f"    snippet: {snippet[:500]}")
# _END
    return "\n".join(lines)


def _register_layer(
    systems: Dict[str, Any],
    layer_id: str,
    label: str,
    component_key: str,
    component: Any,
    functions: Dict[str, str],
) -> None:
    """
    Maintain a compact layer attribution stack while preserving existing keys.
    Each layer entry captures the component plus selected callable names so
    orchestration code can discover capabilities without hard-coding modules.
    """
    if 'layer_stack' not in systems:
        systems['layer_stack'] = []

    bound_functions: Dict[str, Callable[..., Any]] = {}
    if component is not None:
        for alias, method_name in functions.items():
            method = getattr(component, method_name, None)
            if callable(method):
                bound_functions[alias] = method

    systems['layer_stack'].append({
        'id': layer_id,
        'label': label,
        'component_key': component_key,
        'component': component,
        'functions': bound_functions,
    })



def _consolidate_to_base_layers(systems: Dict[str, Any]) -> None:
    """
    Merge all runtime modules into the original 8-layer ontology map without
    removing any existing systems[...] references.

    This creates:
      - systems['base_layers']: canonical L0-L8 layer map
      - systems['base_layer_functions']: callable capability aliases by layer

    Extension modules (6.5+, 9-12) are attached to their associative base layer:
      - sensory/hardware/integration/vision -> L5/L6
      - autonomy/drive/checkpoint/search/persistence -> L8
    """
    base_layers: Dict[str, Dict[str, Any]] = {
        'L0': {'name': 'Foundational Contract', 'modules': {}},
        'L1': {'name': 'IVM Lattice', 'modules': {}},
        'L2': {'name': 'I-State Collective', 'modules': {}},
        'L3': {'name': 'Dimensional Systems', 'modules': {}},
        'L4': {'name': 'Consciousness Engine', 'modules': {}},
        'L5': {'name': 'Expression & Perception', 'modules': {}},
        'L6': {'name': 'Behavioral Identity', 'modules': {}},
        'L7': {'name': 'Simulation Engine', 'modules': {}},
        'L8': {'name': 'Governance/Persistence/Gateway', 'modules': {}},
    }

    module_to_layer = {
        'contract': 'L0',
        'lattice': 'L1',
        'collective': 'L2',
        'dimensional': 'L3',
        'consciousness': 'L4',
        'perception': 'L5',
        # Layer 6.5+ modules consolidated into associative cognitive/identity layers
        'sensory': 'L5',
        'hardware': 'L5',
        'sensory_integration': 'L5',
        'vision_bootstrap': 'L5',
        'identity': 'L6',
        'simulation': 'L7',
        'aurora': 'L8',
        'search_adapter': 'L8',
        'enhanced_persist': 'L8',
        'autonomy': 'L8',
        'drive_sync': 'L8',
        'checkpoint': 'L8',
    }

    for key, layer_id in module_to_layer.items():
        if key in systems:
            base_layers[layer_id]['modules'][key] = systems.get(key)

    def _bind(obj: Any, method_name: str) -> Optional[Callable[..., Any]]:
        if obj is None:
            return None
        fn = getattr(obj, method_name, None)
        return fn if callable(fn) else None

    base_layer_functions: Dict[str, Dict[str, Callable[..., Any]]] = {
        'L0': {}, 'L1': {}, 'L2': {}, 'L3': {}, 'L4': {}, 'L5': {}, 'L6': {}, 'L7': {}, 'L8': {}
    }

    contract = systems.get('contract')
    lattice = systems.get('lattice')
    collective = systems.get('collective')
    dimensional = systems.get('dimensional')
    consciousness = systems.get('consciousness')
    perception = systems.get('perception')
    sensory = systems.get('sensory')
    hardware = systems.get('hardware')
    sensory_integration = systems.get('sensory_integration')
    vision_bootstrap = systems.get('vision_bootstrap')
    identity = systems.get('identity')
    simulation = systems.get('simulation')
    aurora = systems.get('aurora')
    autonomy = systems.get('autonomy')
    drive_sync = systems.get('drive_sync')
    checkpoint = systems.get('checkpoint')

    pairs = [
        ('L0', 'validate', _bind(contract, 'validate_existence_claim')),
        ('L1', 'state', _bind(lattice, 'get_system_state')),
        ('L2', 'synthesize', _bind(collective, 'synthesize_collective_consciousness')),
        ('L3', 'state', _bind(dimensional, 'get_system_state')),
        ('L4', 'process', _bind(consciousness, 'process_input')),
        ('L5', 'perceive', _bind(perception, 'perceive')),
        ('L5', 'express', _bind(perception, 'express')),
        ('L5', 'visual_perceive', _bind(sensory, 'process_visual_input')),
        ('L5', 'audio_perceive', _bind(sensory, 'process_audio_input')),
        ('L5', 'capture', _bind(hardware, 'capture_photo')),
        ('L5', 'listen', _bind(hardware, 'listen_once')),
        ('L5', 'integrate', _bind(sensory_integration, 'integrate_once')),
        ('L5', 'vision_ingest', _bind(vision_bootstrap, 'ingest_image')),
        ('L6', 'traits', _bind(identity, 'display_traits')),
        ('L7', 'state', _bind(simulation, 'get_system_state')),
        ('L8', 'inbound', _bind(aurora, 'inbound')),
        ('L8', 'self_assess', _bind(aurora, 'self_assess')),
        ('L8', 'autonomy_status', _bind(autonomy, 'get_status')),
        ('L8', 'sync', _bind(drive_sync, 'sync_now')),
        ('L8', 'save', _bind(checkpoint, 'save')),
        ('L8', 'restore', _bind(checkpoint, 'restore')),
    ]

    for layer_id, alias, fn in pairs:
        if fn is not None:
            base_layer_functions[layer_id][alias] = fn

    systems['base_layers'] = base_layers
    systems['base_layer_functions'] = base_layer_functions


def _restore_runtime_from_snapshot(
    systems: Dict[str, Any],
    snapshot: Any,
    *,
    verbose: bool = True,
) -> Dict[str, int]:
    """
    Rehydrate runtime objects from persisted L8 snapshot fields.
    This keeps learner memory available after reboot.
    """
    restored: Dict[str, int] = {}
    simulation = systems.get("simulation")
    session = getattr(simulation, "session", None) if simulation else None

    if session:
        try:
            snap_epochs = int(getattr(snapshot, "simulation_epochs", 0) or 0)
        except Exception:
            snap_epochs = 0
        try:
            current_epoch = int(getattr(session, "current_epoch", 0) or 0)
        except Exception:
            current_epoch = 0
        if snap_epochs > current_epoch:
            try:
                session.current_epoch = snap_epochs
                restored["simulation_epochs"] = snap_epochs
            except Exception:
                pass

        learner = getattr(session, "learner", None)
        learner_state = getattr(snapshot, "learner_state", {}) or {}
        if learner and hasattr(learner, "import_state"):
            try:
                restored_count = int(learner.import_state(learner_state) or 0)
                restored["learner_shards"] = restored_count
                if verbose and restored_count > 0:
                    print(f"  [STATE] Rehydrated learner shards: {restored_count}")
            except Exception:
                pass

    identity = systems.get("identity")
    core_identity = systems.get("core_identity")
    if identity and hasattr(identity, "restore_from_snapshot"):
        try:
            identity_restore = identity.restore_from_snapshot(
                snapshot,
                core_identity=core_identity,
            ) or {}
            restored["identity_traits"] = int(identity_restore.get("traits", 0) or 0)
            restored["identity_crystals"] = int(identity_restore.get("crystals", 0) or 0)
            restored["identity_anchors"] = len(getattr(identity.dna.genome, "identity_anchors", []) or [])
            if verbose and (
                restored["identity_traits"] > 0
                or restored["identity_crystals"] > 0
                or restored["identity_anchors"] > 0
            ):
                print(
                    "  [STATE] Rehydrated identity: "
                    f"{restored['identity_traits']} traits, "
                    f"{restored['identity_crystals']} crystal facets, "
                    f"{restored['identity_anchors']} anchors"
                )
        except Exception:
            pass

    if identity:
        personality = {}
        try:
            personality = identity.get_personality() or {}
        except Exception:
            personality = {}
        traits = personality.get("traits", {}) or {}
        perception = systems.get("perception")
        if perception and hasattr(perception, "set_personality"):
            try:
                perception.set_personality(traits)
            except Exception:
                pass
        try:
            _ivm_obj = systems.get("ivm")
            if _ivm_obj and hasattr(perception, "set_ivm"):
                perception.set_ivm(_ivm_obj)
            _gram_obj = systems.get("grammar_engine") or systems.get("working_memory")
            if _gram_obj and hasattr(perception, "set_grammar"):
                perception.set_grammar(_gram_obj)
            _gen_obj = systems.get("genealogy") or systems.get("chamber")
            if _gen_obj and hasattr(perception, "set_genealogy_ref"):
                perception.set_genealogy_ref(_gen_obj)
        except Exception:
            pass
        # Restore ExpressionPerception snapshot from last session so learned
        # interaction patterns survive daemon restarts.
        try:
            import pathlib as _ep_pl, json as _ep_json
            _ep_snap_path = _ep_pl.Path(
                str(systems.get("state_dir") or "aurora_state")
            ) / "expression_perception_state.json"
            if _ep_snap_path.exists() and perception:
                _ep_snap = _ep_json.loads(_ep_snap_path.read_text())
                if _ep_snap.get("dominant_emotion"):
                    perception._dominant_emotion = str(_ep_snap["dominant_emotion"])
                if _ep_snap.get("dominant_axis"):
                    perception._dominant_axis = str(_ep_snap["dominant_axis"])
                if _ep_snap.get("axis_depth"):
                    perception._axis_depth = int(_ep_snap["axis_depth"])
                if _ep_snap.get("total_perceptions"):
                    perception.total_perceptions = int(_ep_snap["total_perceptions"])
                if _ep_snap.get("total_expressions"):
                    perception.total_expressions = int(_ep_snap["total_expressions"])
                if _ep_snap.get("ingest_count"):
                    systems["_perc_ingest_count"] = int(_ep_snap["ingest_count"])
        except Exception:
            pass
        integration = systems.get("sensory_integration")
        if integration and hasattr(integration, "attach_systems"):
            try:
                integration.attach_systems(
                    hardware=systems.get("hardware"),
                    sensory_engine=systems.get("sensory"),
                    perception=perception,
                    identity=identity,
                )
            except Exception:
                pass
        try:
            if perception is not None:
                perception.hardware = systems.get("hardware")
                perception.sensory_engine = systems.get("sensory")
                perception.identity = identity
        except Exception:
            pass

    return restored
